# ── Security Headers Middleware ──
from starlette.middleware.base import BaseHTTPMiddleware

class SecurityHeadersMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        import secrets
        nonce = secrets.token_urlsafe(16)
        request.state.csp_nonce = nonce
        response = await call_next(request)
        response.headers["X-Content-Type-Options"] = "nosniff"
        response.headers["X-Frame-Options"] = "SAMEORIGIN"
        response.headers["X-XSS-Protection"] = "1; mode=block"
        response.headers["Referrer-Policy"] = "strict-origin-when-cross-origin"
        response.headers["Permissions-Policy"] = "camera=(), microphone=(), geolocation=()"
        response.headers["Strict-Transport-Security"] = "max-age=31536000; includeSubDomains"
        if request.url.path.startswith("/sites/"):
            # Public member blog pages carry NO executable scripts. We allow only
            # a single nonce'd JSON-LD data block (for SEO rich results); any other
            # script — including stored-content injection — is blocked.
            response.headers["Content-Security-Policy"] = (
                "default-src 'self'; img-src 'self' https: data:; "
                "style-src 'self' 'unsafe-inline' https:; font-src 'self' https: data:; "
                f"script-src 'nonce-{nonce}'; base-uri 'self'; form-action 'self'; frame-ancestors 'self'")
        return response

app.add_middleware(SecurityHeadersMiddleware)

# GZip compression for responses ≥1KB. Cloudflare's edge already
# Brotli-compresses static assets and cached HTML, but uncached/dynamic
# API responses (dashboard JSON, wallet, /api/me, etc.) go straight to
# the client and benefit from origin-side compression. minimum_size
# avoids the CPU cost on tiny responses where the wire savings would
# be smaller than the compression overhead.
app.add_middleware(GZipMiddleware, minimum_size=1000)

# ── Maintenance / offline mode ─────────────────────────────────
# Default is OFF (platform live) as of the 2026-06-07 reopen. When
# MAINTENANCE_MODE is on, every public/member route serves a holding
# page; only /health (Railway healthcheck), /admin/ (owner cleanup +
# diagnostics), and /static/ pass through. Withdrawals are independently
# frozen via WITHDRAWALS_ENABLED. KILL SWITCH: to take the platform dark
# during an incident, set MAINTENANCE_MODE=on in Railway (out-of-band,
# overrides everything; the dashboard Panic button pauses money flows but
# does not dark the public marketing site). Added last => runs outermost.
MAINTENANCE_MODE = os.getenv("MAINTENANCE_MODE", "off").strip().lower() not in ("off", "false", "0", "no")
MAINTENANCE_HTML = """<!doctype html><html lang="en"><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<meta name="robots" content="noindex">
<title>SuperAdPro — Temporarily Offline</title>
<style>
:root{--cobalt:#0a1438;--royal:#1e3a8a;--cyan:#22d3ee}
*{box-sizing:border-box}body{margin:0;min-height:100vh;display:flex;align-items:center;justify-content:center;
font-family:'DM Sans',system-ui,-apple-system,Segoe UI,Roboto,sans-serif;color:#e8eefc;
background:radial-gradient(1200px 600px at 50% -10%,#13245e 0,var(--cobalt) 55%,#060b22 100%)}
.card{max-width:560px;padding:48px 36px;text-align:center}
h1{font-family:'Sora',sans-serif;font-weight:700;font-size:28px;margin:0 0 14px;letter-spacing:-.5px}
p{font-size:16px;line-height:1.6;color:#aebbe0;margin:0 0 14px}
.bar{height:4px;width:64px;margin:0 auto 28px;border-radius:4px;background:linear-gradient(90deg,var(--royal),var(--cyan))}
.tag{display:inline-block;margin-top:18px;font-size:13px;color:#7d8cba}
</style></head><body><div class="card">
<div class="bar"></div>
<h1>We&#39;re temporarily offline</h1>
<p>SuperAdPro is paused for scheduled maintenance and security improvements. The platform is unavailable right now, including sign-in and payments.</p>
<p>We&#39;ll be back shortly. Thank you for your patience.</p>
<span class="tag">SuperAdPro</span>
</div></body></html>"""

def _maintenance_admin_bypass(request) -> bool:
    """During maintenance, an authenticated admin gets full platform access
    (so the React admin dashboard and all its /api/* calls work); everyone
    else sees the offline page. Verifies the signed session cookie then checks
    is_admin. Fail-safe: any error => treated as non-admin => stays blocked."""
    token = request.cookies.get("session")
    if not token:
        return False
    try:
        user_id = session_serializer.loads(token, max_age=60 * 60 * 24 * 30)
    except Exception:
        return False
    try:
        db = SessionLocal()
        try:
            u = db.query(User).filter(User.id == int(user_id)).first()
            return bool(u and getattr(u, "is_admin", False))
        finally:
            db.close()
    except Exception:
        return False

class MaintenanceMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        if not MAINTENANCE_MODE:
            return await call_next(request)
        path = request.url.path
        # /cron/security-watch and /cron/daily-briefing run during lockdown:
        # both are read-only ops (security scan / metrics email to Steve),
        # gated by CRON_SECRET + the X-Origin-Verify origin lock. The money
        # crons (renewals, BSC scan, withdrawal processing) stay WALLED on
        # purpose while frozen.
        if path == "/health" or path == "/admin" or path.startswith("/admin/") or path.startswith("/static/") or path == "/cron/security-watch" or path == "/cron/daily-briefing" or path == "/webhooks/ses/notifications":
            return await call_next(request)
        # Authenticated admins bypass maintenance entirely. The React admin
        # dashboard at /admin boots, then calls /api/* to load — those are not
        # allowlisted, so without this an admin gets bounced to the offline
        # page. With it, the owner uses the full platform during a lockdown;
        # everyone else still sees maintenance. Requires a valid HMAC-signed
        # admin session cookie, so it cannot be forged.
        if _maintenance_admin_bypass(request):
            return await call_next(request)
        resp = HTMLResponse(MAINTENANCE_HTML, status_code=200)
        resp.headers["Cache-Control"] = "no-store"
        resp.headers["Retry-After"] = "3600"
        return resp

app.add_middleware(MaintenanceMiddleware)

# ── Cloudflare Access origin lock (2026-06-04 hardening) ──────────────
# Cloudflare Access (email-OTP) guards /admin at the edge. But if the raw
# Railway origin URL is reachable, an attacker could bypass Cloudflare and
# hit /admin directly. This middleware validates the signed
# Cf-Access-Jwt-Assertion header that Cloudflare injects on every request it
# forwards from the Access app: a request to /admin lacking a valid token
# did NOT pass through Access, so it is rejected (403). Same Access app,
# enforced a second time at the origin.
#
# SAFE ROLLOUT: fail-OPEN while the two env vars are unset (so shipping this
# can't lock the owner out), then fail-CLOSED for /admin once both are set.
# Emergency disable = unset CF_ACCESS_AUD in Railway.
CF_ACCESS_TEAM_DOMAIN = os.getenv("CF_ACCESS_TEAM_DOMAIN", "").strip().rstrip("/")
CF_ACCESS_AUD = os.getenv("CF_ACCESS_AUD", "").strip()
_CF_ACCESS_ENABLED = bool(CF_ACCESS_TEAM_DOMAIN and CF_ACCESS_AUD)
_cf_jwks_client = None

def _get_cf_jwks_client():
    global _cf_jwks_client
    if _cf_jwks_client is None and _CF_ACCESS_ENABLED:
        import jwt as _pyjwt
        _cf_jwks_client = _pyjwt.PyJWKClient(
            f"https://{CF_ACCESS_TEAM_DOMAIN}/cdn-cgi/access/certs",
            cache_keys=True,
        )
    return _cf_jwks_client

def _cf_access_token_valid(request) -> bool:
    token = request.headers.get("cf-access-jwt-assertion") or request.cookies.get("CF_Authorization")
    if not token:
        return False
    try:
        import jwt as _pyjwt
        signing_key = _get_cf_jwks_client().get_signing_key_from_jwt(token)
        _pyjwt.decode(
            token, signing_key.key, algorithms=["RS256"],
            audience=CF_ACCESS_AUD,
            issuer=f"https://{CF_ACCESS_TEAM_DOMAIN}",
        )
        return True
    except Exception as e:
        try:
            logger.warning(f"[cf-access] origin-lock rejected /admin request: {e}")
        except Exception:
            pass
        return False

class CloudflareAccessOriginMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        if _CF_ACCESS_ENABLED:
            path = request.url.path
            if path == "/admin" or path.startswith("/admin/"):
                if not _cf_access_token_valid(request):
                    return JSONResponse(
                        {"error": "Forbidden — this endpoint is only reachable through Cloudflare Access."},
                        status_code=403,
                    )
        return await call_next(request)

app.add_middleware(CloudflareAccessOriginMiddleware)

# ── /cron origin lock — Cloudflare-only (2026-06-04 hardening) ────────
# /cron/* is deliberately NOT behind Cloudflare Access (machine cron jobs
# call it), which left it reachable from the open internet, gated only by a
# URL secret. This closes that: Cloudflare stamps a secret header
# (X-Origin-Verify, set via a Transform Rule) on every request it forwards;
# the origin requires it on /cron. A direct hit to the raw Railway URL
# (the bypass) lacks the header and is rejected. Crons that call the public
# domain traverse Cloudflare and get the header automatically — no cron
# edits, and the route's own CRON_SECRET check still runs behind this as a
# second factor.
#
# SAFE ROLLOUT: fail-OPEN while ORIGIN_VERIFY_SECRET is unset (shipping this
# can't break anything), fail-CLOSED for /cron once set. Emergency disable =
# unset ORIGIN_VERIFY_SECRET in Railway. Scoped to /cron only, so it can
# never affect main site or member traffic.
ORIGIN_VERIFY_SECRET = os.getenv("ORIGIN_VERIFY_SECRET", "").strip()
_ORIGIN_VERIFY_ENABLED = bool(ORIGIN_VERIFY_SECRET)

class CronOriginVerifyMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        if _ORIGIN_VERIFY_ENABLED and request.url.path.startswith("/cron/"):
            if request.headers.get("x-origin-verify") != ORIGIN_VERIFY_SECRET:
                return JSONResponse({"error": "Forbidden"}, status_code=403)
        return await call_next(request)

app.add_middleware(CronOriginVerifyMiddleware)

# ── Dev/test/seed endpoint guard (2026-06-03 hardening) ───────
# These endpoints are developer tooling (seed admin, grid/course test
# harnesses, force-wipe, migrations). They must NOT be reachable on the
# live platform. They 404 unless DEV_ENDPOINTS_ENABLED=true is set
# (never set it in production). This is independent of the secret check.
from fastapi.responses import JSONResponse as _JSONResponse404
DEV_ENDPOINTS_ENABLED = os.getenv("DEV_ENDPOINTS_ENABLED", "").strip().lower() == "true"
_DEV_ONLY_PATHS = frozenset({
    "/admin/activate-owner", "/admin/test-register", "/admin/test-email",
    "/admin/test-dashboard", "/admin/debug-dashboard", "/admin/fix-owner",
    "/admin/seed-owner-campaigns", "/admin/run-migrations", "/admin/force-migrate",
    "/admin/force-wipe", "/admin/reset-account",
    "/admin/test-grid-fill", "/admin/test-grid-reset", "/admin/test-grid-e2e",
    "/admin/test-grid-cleanup", "/admin/test-course-passup-e2e",
    "/admin/test-course-passup-seed", "/admin/test-course-passup-cleanup",
})
class DevEndpointGuardMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        if (not DEV_ENDPOINTS_ENABLED) and request.url.path in _DEV_ONLY_PATHS:
            return _JSONResponse404({"detail": "Not Found"}, status_code=404)
        return await call_next(request)

app.add_middleware(DevEndpointGuardMiddleware)

# ── Automated-probing throttle (2026-06-03 hardening) ─────────
# Counters AI/scripted recon: an IP that bursts auth failures (403) or
# endpoint-enumeration misses (404) gets temp-banned (429). Path-
# independent — throttles brute-forcing/scanning regardless of which routes
# carry their own @limiter.limit. In-memory per instance: a first layer;
# the durable edge layer is Cloudflare WAF rate-limiting (see SECURITY.md).
import time as _probe_time
from collections import deque as _probe_deque, defaultdict as _probe_dd
_PROBE_WINDOW_S = 60
_PROBE_THRESHOLD = 25       # suspicious responses per IP per window before ban
_PROBE_BAN_S = 600          # ban duration once tripped (10 min)
_probe_hits = _probe_dd(_probe_deque)   # ip -> deque[timestamps]
_probe_bans = {}                        # ip -> ban_until_ts

class ProbeThrottleMiddleware(BaseHTTPMiddleware):
    async def dispatch(self, request, call_next):
        ip = _client_ip(request)
        now = _probe_time.time()
        ban_until = _probe_bans.get(ip)
        if ban_until and now < ban_until:
            return _JSONResponse404({"detail": "Too many requests"}, status_code=429)
        resp = await call_next(request)
        # Count auth failures / enumeration misses, but never /static/ (a page
        # with broken asset refs must not ban a real visitor).
        if resp.status_code in (401, 403, 404, 429) and not request.url.path.startswith("/static/"):
            dq = _probe_hits[ip]
            dq.append(now)
            cutoff = now - _PROBE_WINDOW_S
            while dq and dq[0] < cutoff:
                dq.popleft()
            if len(dq) >= _PROBE_THRESHOLD:
                _probe_bans[ip] = now + _PROBE_BAN_S
                dq.clear()
                try:
                    logging.warning(f"[probe-throttle] temp-banned {ip} for {_PROBE_BAN_S}s")
                except Exception:
                    pass
        if len(_probe_bans) > 5000:   # bound memory
            for _k in [k for k, v in list(_probe_bans.items()) if v < now]:
                _probe_bans.pop(_k, None)
        return resp

app.add_middleware(ProbeThrottleMiddleware)

# ── Rate limit / lockout ──────────────────────────────────────
failed_attempts  = {}
MAX_ATTEMPTS     = 5
LOCKOUT_MINUTES  = 15

def is_locked_out(identifier):
    if identifier not in failed_attempts: return False
    attempts, lockout_time = failed_attempts[identifier]
    if attempts >= MAX_ATTEMPTS:
        if datetime.now() < lockout_time: return True
        del failed_attempts[identifier]
    return False

def record_failed_attempt(identifier):
    if identifier not in failed_attempts:
        failed_attempts[identifier] = [0, None]
    failed_attempts[identifier][0] += 1
    failed_attempts[identifier][1] = datetime.now() + timedelta(minutes=LOCKOUT_MINUTES)
    logger.warning(f"Failed login: {identifier} — attempts: {failed_attempts[identifier][0]}")

def clear_failed_attempts(identifier):
    if identifier in failed_attempts:
        del failed_attempts[identifier]

# ── Unique Slug Generator ─────────────────────────────────────
import re as _re, random as _rand, string as _string
def generate_unique_slug(db, username: str, title: str, exclude_page_id: int = None) -> str:
    """Generate a unique slug for a funnel page: username/title-slug.

    On collision, appends a numeric suffix (-2, -3, ...) until a free slot is
    found. Title is NEVER mutated by this function — only the slug carries
    disambiguation. Falls back to a short hex suffix if even 1000 sequential
    attempts collide (vanishingly unlikely in practice).

    Returns the unique slug. Never returns None — callers no longer need
    to handle a 'collision' error case.
    """
    raw = _re.sub(r'[^a-z0-9]+', '-', title.lower()).strip('-') or 'page'
    base_slug = f"{username.lower()}/{raw}"

    def _is_free(candidate):
        q = db.query(FunnelPage).filter(FunnelPage.slug == candidate)
        if exclude_page_id:
            q = q.filter(FunnelPage.id != exclude_page_id)
        return q.first() is None

    if _is_free(base_slug):
        return base_slug

    # Sequential numeric suffix — produces clean URLs like .../my-page-2
    for n in range(2, 1001):
        candidate = f"{base_slug}-{n}"
        if _is_free(candidate):
            return candidate

    # Pathological collision — fall back to a random hex token
    import secrets
    return f"{base_slug}-{secrets.token_hex(2)}"

# ── DB / Auth helpers ─────────────────────────────────────────
def get_db():
    db = SessionLocal()
    try:
        yield db
    except Exception:
        db.rollback()
        raise
    finally:
        db.close()

def get_current_user(request: Request, db: Session = Depends(get_db)):
    token = request.cookies.get("session")
    if not token: return None
    try:
        # Verify HMAC signature and check max age (30 days)
        user_id = session_serializer.loads(token, max_age=60 * 60 * 24 * 30)
        return db.query(User).filter(User.id == int(user_id)).first()
    except (BadSignature, SignatureExpired, ValueError, TypeError):
        return None

def is_admin(user): return user is not None and getattr(user, "is_admin", False)


def _safe_json(s):
    """Safely parse a JSON string column into a list. Returns [] if the
    column is null, empty, or contains malformed JSON.

    Originally defined in main.py.backup line 16751 — got dropped during
    a refactor but two call sites still reference it (api_leads_sequences
    line 28671, send_sequence_email line 28856). NameError was throwing
    on every /api/leads/sequences call, killing the Promise.all that
    MyLeads.jsx uses to load the leads page, leaving the entire page
    blank. Restored 18 May 2026.
    """
    import json as _j
    if not s:
        return []
    try:
        return _j.loads(s)
    except Exception:
        return []


def is_pro(user):
    """Active paid member or admin. Used to gate features that were
    formerly Pro-only — under flat-pricing (locked 15 May 2026) any
    is_active member has access. The function name is retained for
    historical grep continuity; semantics are 'has paid access'.

    Returns True for admins, Founding members ($15 locked), and
    Partner members ($20/mo). Returns False for free signups and
    deactivated/lapsed members.
    """
    if user is None:
        return False
    if getattr(user, "is_admin", False):
        return True
    return bool(getattr(user, "is_active", False))


def can_earn(user):
    """Comp-plan access: can refer, build a team, earn commissions, and
    withdraw. True for full paid members (via is_pro) AND $10 Launchpad
    members (membership_tier == 'launchpad') — who have bought into the
    comp plan but have NOT unlocked the tools or tiers 1-8.

    The three-rung access ladder:
        free signup    -> membership_tier 'free',      is_active False -> can_earn False
        $10 Launchpad  -> membership_tier 'launchpad',  is_active False -> can_earn True
        full member    -> is_active True                                -> can_earn True

    Gate comp-plan / earning surfaces (referral link, dashboard earnings,
    tier-0 grid, withdrawals) with can_earn(). Gate tool / higher-tier
    surfaces (SuperPages, Creative Studio, Lead Finder, tiers 1-8, the full
    Profit Grid accelerator) with is_pro() — Launchpad must NOT pass those.
    """
    if user is None:
        return False
    if is_pro(user):
        return True
    return getattr(user, "membership_tier", None) == "launchpad"


def set_secure_cookie(response, user_id):
    """Create an HMAC-signed session token. Cannot be forged without SESSION_SECRET."""
    token = session_serializer.dumps(user_id)
    response.set_cookie(
        key="session", value=token,
        httponly=True, secure=True, samesite="lax",
        max_age=60 * 60 * 24 * 30
    )

# ── Validation helpers ────────────────────────────────────────
def validate_username(u): return bool(re.match(r'^[a-zA-Z0-9_]{3,30}$', u))
def validate_email(e):    return bool(re.match(r'^[^\@\s]+@[^\@\s]+\.[^\@\s]+$', e))

# Disposable / throwaway / RFC-2606-reserved email domains rejected at SIGNUP.
# Tripwire against junk registrations and the test.com pattern seen in the
# Jun 2026 breach probes — NOT a security boundary (a determined actor uses a
# real-looking domain). Applied at registration only; password-reset paths
# must still accept these so an already-registered member can recover.
DISPOSABLE_EMAIL_DOMAINS = {
    # RFC 2606 reserved — never deliverable
    'test.com', 'example.com', 'example.org', 'example.net', 'invalid',
    'localhost', 'test', 'test.test',
    # Common disposable / throwaway providers
    'mailinator.com', 'guerrillamail.com', 'guerrillamailblock.com',
    'tempmail.com', 'temp-mail.org', 'throwaway.email', 'yopmail.com',
    'sharklasers.com', 'grr.la', 'dispostable.com', 'trashmail.com',
    'fakeinbox.com', 'mailnesia.com', 'maildrop.cc', 'discard.email',
    'tmpmail.net', '10minutemail.com', 'getnada.com', 'mailcatch.com',
    'mohmal.com', 'emailondeck.com', 'spam4.me', 'tempr.email',
}

def is_disposable_email(e):
    """True if the email's domain (or a parent of it) is a known disposable/
    throwaway/reserved-test domain. Registration-time filter only."""
    try:
        domain = e.strip().lower().rsplit('@', 1)[1]
    except (IndexError, AttributeError):
        return False
    return any(domain == d or domain.endswith('.' + d)
               for d in DISPOSABLE_EMAIL_DOMAINS)


# Network-specific wallet validation. EVM (BSC, formerly Polygon) uses
# 0x-prefixed 20-byte hex addresses. Tron uses base58check addresses
# starting with T, 34 chars total. The base58 alphabet excludes 0/O/I/l
# (the canonical Bitcoin alphabet) so the regex character class reflects
# that — the goal isn't strict base58check checksum verification (members
# pasting from their wallet UI almost never get the format wrong) but
# catching obvious format mismatches like a 0x address typed into a Tron
# field or vice versa.
_BSC_WALLET_RE  = re.compile(r'^0x[a-fA-F0-9]{40}$')
_TRON_WALLET_RE = re.compile(r'^T[1-9A-HJ-NP-Za-km-z]{33}$')

def validate_wallet(w, network=None):
    """Validate a wallet address.

    If network is 'tron' or 'bsc', validates against that network's format.
    If network is None or unrecognised, accepts EITHER format (for backwards
    compatibility with code paths that don't pass network yet — those should
    be migrated, but legacy callers should not silently break).
    """
    if not w:
        return False
    if network == 'tron':
        return bool(_TRON_WALLET_RE.match(w))
    if network == 'bsc':
        return bool(_BSC_WALLET_RE.match(w))
    # Legacy/unknown network — accept either format
    return bool(_BSC_WALLET_RE.match(w) or _TRON_WALLET_RE.match(w))

def sanitize(v):          return bleach.clean(v.strip()) if v else ""
# ── Dashboard context ─────────────────────────────────────────
def get_dashboard_context(request: Request, user: User, db: Session) -> dict:
    from sqlalchemy import func
    stats = get_grid_stats(db, user.id)

    # Recent commissions (general)
    commissions = get_user_commission_history(db, user.id, limit=10)

    # Sponsor username
    sponsor_username = None
    if user.sponsor_id:
        sponsor = db.query(User).filter(User.id == user.sponsor_id).first()
        if sponsor:
            sponsor_username = sponsor.username

    # Active grids per tier
    active_grids = db.query(Grid).filter(
        Grid.owner_id   == user.id,
        Grid.is_complete == False
    ).all()

    renewal = get_renewal_status(db, user.id)

    # ── Earnings breakdown by stream ──
    # NOTE: filter status != 'reversed' so admin-reversed commissions
    # (e.g. duplicate-activation cleanups) don't continue to show in
    # the user's earnings tiles. Without this, the dashboard returns
    # pre-reversal totals indefinitely.
    membership_earned = 0
    boost_earned = 0
    grid_earned = 0
    gen_comms = db.query(Commission).filter(
        Commission.to_user_id == user.id,
        Commission.status != "reversed",
    ).all()
    for c in gen_comms:
        ct = (c.commission_type or "").lower()
        if "membership" in ct and "company" not in ct:
            membership_earned += float(c.amount_usdt or 0)
        elif ct == "boost":
            boost_earned += float(c.amount_usdt or 0)
        elif ct in ("direct_sponsor", "uni_level"):
            # Campaign Tier (grid) commissions — direct 40% to sponsor + 6.25%
            # uni-level chain. Excludes platform/company-absorb rows because
            # those have to_user_id = NULL and don't appear in this query.
            grid_earned += float(c.amount_usdt or 0)

    # ── Recent activity feed (last 8 from all streams) ──
    activity = []
    # Course commissions
    course_recent = db.query(CourseCommission).filter(
        CourseCommission.earner_id == user.id
    ).order_by(CourseCommission.created_at.desc()).limit(5).all()
    # Credit Nexus matrix commissions (added 7 May 2026 — were missing
    # from the dashboard activity feed since the table was introduced)
    matrix_recent = db.query(CreditMatrixCommission).filter(
        CreditMatrixCommission.earner_id == user.id,
        CreditMatrixCommission.status == 'paid',
    ).order_by(CreditMatrixCommission.created_at.desc()).limit(5).all()
    # General commissions (excludes reversed admin cleanups)
    gen_recent = db.query(Commission).filter(
        Commission.to_user_id == user.id,
        Commission.status != "reversed",
        Commission.commission_type.notin_(["admin_adjustment", "admin_fix", "boost_platform_fee", "membership_company"])
    ).order_by(Commission.created_at.desc()).limit(5).all()

    # Bulk-load all the user lookups in 1 query instead of 10. Was a
    # per-row .first() inside each for-loop = N+1.
    counterparty_ids = list({
        *(c.buyer_id for c in course_recent if c.buyer_id),
        *(c.from_user_id for c in matrix_recent if c.from_user_id),
        *(c.from_user_id for c in gen_recent if c.from_user_id),
    })
    counterparty_by_id = {}
    if counterparty_ids:
        counterparty_by_id = {
            u.id: u for u in db.query(User).filter(User.id.in_(counterparty_ids)).all()
        }

    for c in course_recent:
        buyer = counterparty_by_id.get(c.buyer_id)
        activity.append({
            "icon": "🎓", "color": "purple",
            "title": f"{buyer.username if buyer else '?'} purchased Tier {c.course_tier}",
            "sub": "Course " + ("direct sale" if c.commission_type == "direct_sale" else "pass-up"),
            "amount": float(c.amount),
            "date": c.created_at
        })
    for c in matrix_recent:
        from_user = counterparty_by_id.get(c.from_user_id)
        # commission_type is 'matrix_level' for level commissions (1/2/3)
        # or 'matrix_completion' for the cycle bonus.
        is_completion = c.commission_type == 'matrix_completion'
        activity.append({
            "icon": "💎", "color": "purple",
            "title": (
                f"{from_user.username if from_user else '?'} bought a credit pack"
                if not is_completion else "Matrix cycle completed"
            ),
            "sub": "Credit Nexus " + ("completion bonus" if is_completion else f"L{c.level} commission"),
            "amount": float(c.amount or 0),
            "date": c.created_at
        })
    for c in gen_recent:
        from_user = counterparty_by_id.get(c.from_user_id)
        ct = (c.commission_type or "").lower()
        if "membership" in ct:
            icon, color, sub = "👥", "green", "Membership commission"
        elif "boost" in ct:
            icon, color, sub = "🚀", "amber", "Campaign commission"
        else:
            icon, color, sub = "🔲", "cyan", "Grid commission"
        activity.append({
            "icon": icon, "color": color,
            "title": f"{from_user.username if from_user else '?'}" + (" joined" if "membership" in ct else " — commission"),
            "sub": sub,
            "amount": float(c.amount_usdt or 0),
            "date": c.created_at
        })
    activity.sort(key=lambda x: x["date"] or datetime.min, reverse=True)
    activity = activity[:6]
    # Serialize dates for JSON
    for a in activity:
        a["date"] = a["date"].isoformat() if a.get("date") else None

    # Course stats
    course_sale_count = user.course_sale_count or 0

    # ── Live earnings + descendant counts from the ledger ──────────────
    # Replaces the legacy denormalised counters (user.total_earned,
    # user.grid_earnings, user.course_earnings, user.personal_referrals)
    # which drift over time. See compute_user_earnings() / compute_descendant_counts().
    _earn = compute_user_earnings(db, user.id)
    _desc = compute_descendant_counts(db, user.id)

    return {
        "request":           request,
        "user":              user,
        "display_name":      user.first_name or user.username,
        # Member "active since" — formatted from user.created_at for display
        # in the dashboard hero. Safe fallback if created_at is missing.
        "active_since":      user.created_at.strftime("%b %Y") if getattr(user, "created_at", None) else None,
        "balance":           float(user.balance or 0),
        "campaign_balance":  float(user.campaign_balance or 0),
        "total_earned":      _earn["total_earned"],
        "grid_earnings":     _earn["grid_earnings"],
        "level_earnings":    float(user.level_earnings or 0),
        "upline_earnings":   float(user.upline_earnings or 0),
        "sponsor_earnings":  float(user.upline_earnings or 0),
        "course_earnings":   _earn["course_earnings"],
        "membership_earned": membership_earned,
        "boost_earned":      boost_earned,
        "grid_earned":       grid_earned,
        # ── creative_studio_earned (frontend label: "Credit Nexus") ──
        # Legacy field name from when matrix payouts were attached to the
        # Creative Studio feature. Now correctly reads from
        # CreditMatrixCommission table (where Credit Nexus payments
        # actually live) rather than the Commission table.
        # Bug fixed 7 May 2026: previously queried Commission for
        # 'matrix_level'/'matrix_completion' types, which only matched
        # legacy pre-Credit-Nexus-table commissions (very few). Result
        # was Command Centre + Income page showing $0 for Credit Nexus
        # earnings even when CreditMatrixCommission rows existed.
        "creative_studio_earned": _earn["nexus_earnings"],
        "personal_referrals": _earn["personal_referrals"],
        "direct_referrals_count": _earn["personal_referrals"],
        # Replaces the legacy total_team counter. Computed live via recursive
        # CTE walking the full descendant tree. Counter retired as it drifted
        # over time due to scattered += 1 increments without matching decrements.
        # See compute_descendant_counts() for details.
        "total_team":        _desc["total"],
        "network_active":    _desc["active"],
        "network_inactive":  _desc["inactive"],
        # ── Command Centre Layer 1 stats (Apr 2026) ──────────────────────
        # Three-bucket breakdown of direct referrals so members can see who's
        # actually paying, who lapsed (re-activation candidates), and who
        # never paid (cold leads). All use sponsor_id = user.id.
        # See /command-centre on the frontend.
        #
        # NOTE: "lapsed" is computed by looking at confirmed Payment rows
        # for membership* payment_types. A direct who has a confirmed
        # membership payment but is_active=False = lapsed.
        # No payment record + is_active=False = never_paid.
        "directs_active": db.query(User).filter(
            User.sponsor_id == user.id, User.is_active == True
        ).count(),
        "directs_lapsed": db.query(User).filter(
            User.sponsor_id == user.id, User.is_active == False,
            User.id.in_(
                db.query(Payment.from_user_id).filter(
                    Payment.payment_type.like("membership%"),
                    Payment.status.in_(["confirmed", "paid"]),
                )
            )
        ).count(),
        "directs_never_paid": db.query(User).filter(
            User.sponsor_id == user.id, User.is_active == False,
            ~User.id.in_(
                db.query(Payment.from_user_id).filter(
                    Payment.payment_type.like("membership%"),
                    Payment.status.in_(["confirmed", "paid"]),
                )
            )
        ).count(),
        # Distinct members who have positions in any of THIS user's grids.
        # JOIN: GridPosition → Grid where Grid.owner_id = user.id.
        # Excludes the owner themselves (who isn't a position-filler).
        "grid_team_count": db.query(GridPosition.member_id).join(
            Grid, GridPosition.grid_id == Grid.id
        ).filter(Grid.owner_id == user.id).distinct().count(),
        # Distinct members who have positions in this user's credit matrices.
        # Subtract 1 to exclude the owner (level 0 in their own matrix).
        "nexus_team_count": max(0, db.query(CreditMatrixPosition.user_id).join(
            CreditMatrix, CreditMatrixPosition.matrix_id == CreditMatrix.id
        ).filter(CreditMatrix.owner_id == user.id).distinct().count() - 1),
        # Earnings this calendar month — a strict subset of ALL TIME by
        # construction: compute_user_earnings() with a created_at >= month-start
        # window, the SAME paid-only / topup-excluded filter set as the lifetime
        # total. Cannot exceed ALL TIME, and inherits the topup/phantom exclusion
        # automatically. (Was a hand-rolled 3-table sum with NO status and NO
        # commission_type filter — it counted reversed rows, admin_adjustments,
        # and phantom grid_completion_bonus_topup rows, so it over-reported and
        # could exceed ALL TIME. Fixed by routing through the one helper.)
        "earnings_this_month": compute_user_earnings(
            db, user.id,
            since=datetime.utcnow().replace(day=1, hour=0, minute=0, second=0, microsecond=0),
        )["total_earned"],
        # Earnings LAST calendar month — same helper, [last-month-start, this-
        # month-start) window. Used for the +/- momentum delta on the card.
        "earnings_last_month": compute_user_earnings(
            db, user.id,
            since=(datetime.utcnow().replace(day=1, hour=0, minute=0, second=0, microsecond=0) - timedelta(days=1)).replace(day=1, hour=0, minute=0, second=0, microsecond=0),
            until=datetime.utcnow().replace(day=1, hour=0, minute=0, second=0, microsecond=0),
        )["total_earned"],
        "grid_stats":        stats,
        "active_grids":      active_grids,
        "recent_commissions":commissions,
        "recent_activity":   activity,
        "sponsor_username":  sponsor_username,
        "wallet_address":    user.wallet_address or "",
        "wallet_network":    user.wallet_network or "",
        "total_withdrawn":    compute_total_withdrawn(db, user.id),
        "is_active":         user.is_active,
        "is_admin":          user.is_admin,
        "member_id":         format_member_id(user.id, user.is_admin),
        "course_sale_count": course_sale_count,
        "marketplace_earnings": float(user.marketplace_earnings or 0),
        "GRID_PACKAGES":     GRID_PACKAGES,
        "GRID_TOTAL":        NEW_GRID_SEATS,
        "OWNER_PCT":         OWNER_PCT,
        "UPLINE_PCT":        UPLINE_PCT,
        "LEVEL_PCT":         LEVEL_PCT,
        "renewal":           renewal,
        "active_page":       "dashboard",
        "has_linkhub":       db.query(db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user.id).exists()).scalar(),
        "watch_count":       getattr(user, 'videos_watched', 0) or 0,
    }
# ═══════════════════════════════════════════════════════════════
#  SMART DASHBOARD GOALS
