@app.get("/health/assets")
def health_assets(name: str = ""):
    """Deploy diagnostic (2 Jul 2026): list built asset files on THIS
    container's disk matching `name`. Asset filenames are already public
    (referenced by the index bundle), so this leaks nothing. Added while
    chasing a committed chunk that 404s from origin despite sibling files
    from the same commit serving fine."""
    import os as _os
    d = "static/app/assets"
    try:
        files = sorted(_os.listdir(d))
    except Exception as e:
        return JSONResponse({"error": f"{type(e).__name__}: {e}"}, status_code=200)
    frag = (name or "").strip()
    hits = [f for f in files if frag.lower() in f.lower()] if frag else []
    detail = []
    for f in hits[:5]:
        fp = _os.path.join(d, f)
        try:
            st = _os.stat(fp)
            rp = _os.path.realpath(fp)
            droot = _os.path.realpath(d)
            detail.append({"name": f, "repr": repr(f), "size": st.st_size,
                           "is_symlink": _os.path.islink(fp),
                           "realpath_inside_root": rp.startswith(droot)})
        except Exception as e:
            detail.append({"name": f, "stat_error": f"{type(e).__name__}: {e}"})
    return JSONResponse({
        "dir": d, "total_files": len(files),
        "match": frag, "matches": hits, "detail": detail,
        "cwd": _os.getcwd(),
    })


@app.get("/health/db")
def health_db():
    """One-tap probe: can THIS app process reach its database? Public and
    dataless by design — returns only ok/unreachable + latency. Added after
    the 2 Jul 2026 Railway private-network fault, where /health said 200
    while every DB request died; this endpoint makes that split visible in
    one glance (app up + db down = infra fault, restart Postgres and wait
    10-15 min for mesh propagation — see incident runbook)."""
    import time as _t
    from .database import engine as _eng
    from sqlalchemy import text as _text
    t0 = _t.monotonic()
    try:
        with _eng.connect() as conn:
            conn.execute(_text("SELECT 1"))
        return JSONResponse({"db": "ok", "latency_ms": round((_t.monotonic() - t0) * 1000, 1)})
    except Exception as e:
        return JSONResponse({"db": "unreachable", "error_type": type(e).__name__,
                             "waited_ms": round((_t.monotonic() - t0) * 1000, 1)}, status_code=503)


# ═══════════════════════════════════════════════════════════════
#  Helper: sum paid commissions across all 3 commission tables.
#  Added 7 May 2026 to centralise the "sum across Commission +
#  CreditMatrixCommission + CourseCommission" pattern that was
#  previously duplicated incorrectly across many endpoints (each
#  one summing only the Commission table and silently undercounting
#  Credit Nexus + Course payouts).
# ═══════════════════════════════════════════════════════════════
def _sum_all_member_commissions(db: Session, since=None, until=None,
                                user_id: int = None) -> float:
    """Sum paid commissions across all 3 tables, optionally filtered.

    Args:
        db: SQLAlchemy session
        since: datetime lower bound (inclusive). None = no lower bound.
        until: datetime upper bound (exclusive). None = no upper bound.
        user_id: if set, only sum commissions earned BY this user.
                 Otherwise sum platform-wide member-routed commissions.

    Returns:
        Sum as a float, USD. Excludes:
          - Reversed Commission rows (status != 'paid' or 'reversed')
          - Company-routed Commission rows (to_user_id IS NULL — overflow,
            platform fees, etc.)
          - Unpaid CreditMatrixCommission rows (status != 'paid')
        CourseCommission has no status column — always counted when
        present (rows are written when paid).

    The platform-wide call drives the public homepage's "$X paid out
    to members" stat. Per-user call drives wallet/dashboard summaries.
    """
    from sqlalchemy import func as _f
    total = 0.0

    # 1. Commission table (grid + membership)
    q1 = db.query(_f.coalesce(_f.sum(Commission.amount_usdt), 0)).filter(
        Commission.status == "paid",
        Commission.to_user_id.isnot(None),
    )
    if user_id is not None:
        q1 = q1.filter(Commission.to_user_id == user_id)
    if since is not None:
        q1 = q1.filter(Commission.created_at >= since)
    if until is not None:
        q1 = q1.filter(Commission.created_at < until)
    total += float(q1.scalar() or 0)

    # 2. CreditMatrixCommission table (Credit Nexus)
    q2 = db.query(_f.coalesce(_f.sum(CreditMatrixCommission.amount), 0)).filter(
        CreditMatrixCommission.status == "paid",
    )
    if user_id is not None:
        q2 = q2.filter(CreditMatrixCommission.earner_id == user_id)
    if since is not None:
        q2 = q2.filter(CreditMatrixCommission.created_at >= since)
    if until is not None:
        q2 = q2.filter(CreditMatrixCommission.created_at < until)
    total += float(q2.scalar() or 0)

    # 3. CourseCommission table (Course Academy)
    q3 = db.query(_f.coalesce(_f.sum(CourseCommission.amount), 0))
    if user_id is not None:
        q3 = q3.filter(CourseCommission.earner_id == user_id)
    if since is not None:
        q3 = q3.filter(CourseCommission.created_at >= since)
    if until is not None:
        q3 = q3.filter(CourseCommission.created_at < until)
    total += float(q3.scalar() or 0)

    return total


@app.get("/api/public/stats")
def api_public_stats(db: Session = Depends(get_db)):
    """Public stats for homepage — member count, total earned. No auth required.
    Cached 60s to avoid 3x DB aggregation queries on every homepage load."""
    cache_key = "public:stats"
    cached = cache_get(cache_key)
    if cached:
        return cached

    from sqlalchemy import func
    total_members = db.query(User).filter(User.is_active == True).count()
    total_registered = db.query(User).count()
    # Member-routed commissions across all 3 tables. Helper handles the
    # full aggregation pattern. Bug history: previously summed only the
    # Commission table, undercounting platform-wide payouts to members
    # by everything paid via Credit Nexus and Course Academy. Fix
    # 7 May 2026 alongside the wallet bug.
    total_earned = _sum_all_member_commissions(db)
    result = {
        "members": total_members,
        "registered": total_registered,
        "total_earned": total_earned,
    }
    cache_set(cache_key, result, ttl=60)
    return result

# In-memory cache for the public payouts feed (30 s window)
_recent_payouts_cache = {"ts": 0.0, "data": []}

@app.get("/api/public/recent-payouts")
def api_public_recent_payouts(db: Session = Depends(get_db)):
    """
    Public feed for the /earn page's live income toast.
    Returns up to 20 most-recent paid commissions as { name, amount } pairs.
    Only first name (or username as fallback) + rounded integer amount —
    no email, no user_id, no timestamp, no commission_type exposed.
    Cached for 30 s so the poll endpoint doesn't thrash the DB.
    Returns an empty list when there are no paid commissions yet (launch day).
    """
    import time as _time
    now = _time.time()
    if now - _recent_payouts_cache["ts"] < 30 and _recent_payouts_cache["data"]:
        return _recent_payouts_cache["data"]

    # Merge recent paid commissions across all 3 tables. Bug fixed
    # 7 May 2026: previously only queried Commission, so the live
    # income toast on /earn never showed any Credit Nexus or Course
    # commissions even when those were the most recent payouts.
    grid_rows = (
        db.query(Commission.amount_usdt.label('amount'),
                 Commission.created_at.label('ts'),
                 User.first_name.label('first_name'),
                 User.username.label('username'))
          .join(User, User.id == Commission.to_user_id)
          .filter(Commission.status == "paid")
          .filter(Commission.amount_usdt > 0)
          .order_by(Commission.created_at.desc())
          .limit(20)
          .all()
    )
    matrix_rows = (
        db.query(CreditMatrixCommission.amount.label('amount'),
                 CreditMatrixCommission.created_at.label('ts'),
                 User.first_name.label('first_name'),
                 User.username.label('username'))
          .join(User, User.id == CreditMatrixCommission.earner_id)
          .filter(CreditMatrixCommission.status == "paid")
          .filter(CreditMatrixCommission.amount > 0)
          .order_by(CreditMatrixCommission.created_at.desc())
          .limit(20)
          .all()
    )
    course_rows = (
        db.query(CourseCommission.amount.label('amount'),
                 CourseCommission.created_at.label('ts'),
                 User.first_name.label('first_name'),
                 User.username.label('username'))
          .join(User, User.id == CourseCommission.earner_id)
          .filter(CourseCommission.amount > 0)
          .order_by(CourseCommission.created_at.desc())
          .limit(20)
          .all()
    )

    # Merge all 3 lists, sort by timestamp descending, take top 20
    all_rows = list(grid_rows) + list(matrix_rows) + list(course_rows)
    all_rows.sort(key=lambda r: r.ts or datetime.min, reverse=True)
    all_rows = all_rows[:20]

    result = []
    for r in all_rows:
        raw_name = (r.first_name or "").strip() or (r.username or "").strip() or "Member"
        # First token only — "Steve L" -> "Steve", "stevepersonal" -> "stevepersonal"
        display_name = raw_name.split()[0]
        amount = int(round(float(r.amount or 0)))
        if amount <= 0:
            continue
        result.append({"name": display_name, "amount": amount})

    _recent_payouts_cache["ts"] = now
    _recent_payouts_cache["data"] = result
    return result

# ── /explore page endpoints (Phase 1) ─────────────────────────
# Both cached briefly so frontend polling (every ~30s) doesn't thrash the DB.
_explore_stats_cache = {"ts": 0.0, "data": None}
_activity_feed_cache = {"ts": 0.0, "data": None}

@app.get("/api/public/explore-stats")
def api_public_explore_stats(db: Session = Depends(get_db)):
    """Aggregates for /explore: paid by time window, active-member count, tab counts.
    All zero pre-launch — page handles empty states per Q5 decisions."""
    import time as _time
    from sqlalchemy import func
    from datetime import datetime, timedelta

    now_ts = _time.time()
    if now_ts - _explore_stats_cache["ts"] < 30 and _explore_stats_cache["data"]:
        return _explore_stats_cache["data"]

    now = datetime.utcnow()
    hour_ago = now - timedelta(hours=1)
    day_ago = now - timedelta(hours=24)
    month_ago = now - timedelta(days=30)

    def sum_paid(since):
        # 7 May 2026: now sums across all 3 commission tables via the
        # shared helper. Previously only summed Commission, so the
        # /explore page's hour/day/month "paid out" figures were
        # undercounting Credit Nexus and Course commissions.
        return _sum_all_member_commissions(db, since=since)

    hour_paid = sum_paid(hour_ago)
    today_paid = sum_paid(day_ago)
    month_paid = sum_paid(month_ago)

    # Active earners in the past 30 days (distinct recipients of paid
    # commissions) — counted across all 3 tables. Members earning only
    # via Credit Nexus or Courses were previously excluded from this
    # active-member count, falsely lowering the headline figure.
    active_member_ids = set()
    for uid_row in db.query(Commission.to_user_id).filter(
        Commission.status == "paid",
        Commission.created_at >= month_ago,
        Commission.to_user_id.isnot(None),
    ).distinct().all():
        active_member_ids.add(uid_row[0])
    for uid_row in db.query(CreditMatrixCommission.earner_id).filter(
        CreditMatrixCommission.status == "paid",
        CreditMatrixCommission.created_at >= month_ago,
    ).distinct().all():
        active_member_ids.add(uid_row[0])
    for uid_row in db.query(CourseCommission.earner_id).filter(
        CourseCommission.created_at >= month_ago,
    ).distinct().all():
        active_member_ids.add(uid_row[0])
    active_members = len(active_member_ids)

    # Tab counts — count of recent commission ROWS in the last hour
    # across all 3 tables (used as a "X new things in the last hour"
    # badge on the Activity tab).
    activity_count = (
        (db.query(func.count(Commission.id)).filter(
            Commission.status == "paid",
            Commission.created_at >= hour_ago
        ).scalar() or 0)
        + (db.query(func.count(CreditMatrixCommission.id)).filter(
            CreditMatrixCommission.status == "paid",
            CreditMatrixCommission.created_at >= hour_ago
        ).scalar() or 0)
        + (db.query(func.count(CourseCommission.id)).filter(
            CourseCommission.created_at >= hour_ago
        ).scalar() or 0)
    )

    try:
        from app.database import MemberStory, MemberShowcase
        stories_count = db.query(func.count(MemberStory.id)).filter(MemberStory.approved == True).scalar() or 0
        showcase_count = db.query(func.count(MemberShowcase.id)).filter(MemberShowcase.approved == True).scalar() or 0
    except Exception:
        # Tables may not exist yet if migrations haven't run
        stories_count = 0
        showcase_count = 0

    data = {
        "hour_paid": hour_paid,
        "today_paid": today_paid,
        "month_paid": month_paid,
        "active_members": int(active_members),
        "tab_counts": {
            "activity": int(activity_count),
            "stories": int(stories_count),
            "showcase": int(showcase_count),
        },
    }
    _explore_stats_cache["ts"] = now_ts
    _explore_stats_cache["data"] = data
    return data


@app.get("/api/public/activity-feed")
def api_public_activity_feed(limit: int = 25, db: Session = Depends(get_db)):
    """Live activity feed for /explore tab 1.
    Returns up to 25 paid commissions from the last hour.
    Privacy-filtered: first name + country name (no email, no user_id, no city until GeoLite2-City.mmdb is installed).
    Cached 30s to match polling cadence."""
    import time as _time
    from datetime import datetime, timedelta

    cache_key = min(max(limit, 1), 50)
    now_ts = _time.time()
    if now_ts - _activity_feed_cache["ts"] < 30 and _activity_feed_cache["data"] is not None:
        cached = _activity_feed_cache["data"]
        if len(cached) >= cache_key:
            return cached[:cache_key]

    hour_ago = datetime.utcnow() - timedelta(hours=1)
    # Bug fixed 7 May 2026: previously only queried Commission. Members
    # earning via Credit Nexus or Course Academy were invisible in the
    # live activity feed on /explore tab 1, even though those streams
    # are an important part of the platform's payout story.

    grid_rows = (db.query(Commission.amount_usdt.label('amt'),
                          Commission.created_at.label('ts'),
                          Commission.commission_type.label('ct'),
                          User.id.label('uid'),
                          User.first_name.label('fn'),
                          User.username.label('un'),
                          User.display_city.label('city'))
              .join(User, User.id == Commission.to_user_id)
              .filter(Commission.status == "paid")
              .filter(Commission.amount_usdt > 0)
              .filter(Commission.created_at >= hour_ago)
              .order_by(Commission.created_at.desc())
              .limit(min(cache_key, 50))
              .all())

    matrix_rows = (db.query(CreditMatrixCommission.amount.label('amt'),
                            CreditMatrixCommission.created_at.label('ts'),
                            CreditMatrixCommission.commission_type.label('ct'),
                            User.id.label('uid'),
                            User.first_name.label('fn'),
                            User.username.label('un'),
                            User.display_city.label('city'))
              .join(User, User.id == CreditMatrixCommission.earner_id)
              .filter(CreditMatrixCommission.status == "paid")
              .filter(CreditMatrixCommission.amount > 0)
              .filter(CreditMatrixCommission.created_at >= hour_ago)
              .order_by(CreditMatrixCommission.created_at.desc())
              .limit(min(cache_key, 50))
              .all())

    course_rows = (db.query(CourseCommission.amount.label('amt'),
                            CourseCommission.created_at.label('ts'),
                            CourseCommission.commission_type.label('ct'),
                            User.id.label('uid'),
                            User.first_name.label('fn'),
                            User.username.label('un'),
                            User.display_city.label('city'))
              .join(User, User.id == CourseCommission.earner_id)
              .filter(CourseCommission.amount > 0)
              .filter(CourseCommission.created_at >= hour_ago)
              .order_by(CourseCommission.created_at.desc())
              .limit(min(cache_key, 50))
              .all())

    # Merge & sort
    rows = list(grid_rows) + list(matrix_rows) + list(course_rows)
    rows.sort(key=lambda r: r.ts or datetime.min, reverse=True)
    rows = rows[:min(cache_key, 50)]

    # Friendly reason labels — maps raw commission_type to user-facing strings
    # Updated 7 May 2026 with Credit Nexus + Course mappings.
    reason_map = {
        "direct_sponsor":         "Direct referral",
        "uni_level":              "Uni-level",
        "platform":               "Platform",
        "membership":             "Membership · recurring",
        "membership_sponsor":     "Membership · referral",
        "gift_membership_sponsor": "Pay It Forward gift",
        "membership_renewal":     "Membership · renewal",
        "grid_completion_bonus":  "Grid completion bonus",
        "matrix_level":           "Credit Nexus",
        "matrix_completion":      "Credit Nexus · completion",
        "course_sale":            "Course sale",
        "course_passup":          "Course sale · passed up",
        "direct_sale":            "Course sale",
        "pass_up":                "Course sale · passed up",
    }

    now = datetime.utcnow()
    result = []
    for r in rows:
        raw_name = (r.fn or "").strip() or (r.un or "").strip() or "Member"
        display_name = raw_name.split()[0]
        minutes_ago = max(0, int((now - r.ts).total_seconds() / 60))
        # Location: display_city is the country NAME (e.g. "United Kingdom") until city DB is available
        location = r.city or None
        result.append({
            "name":        display_name,
            "location":    location,
            "reason":      reason_map.get(r.ct, r.ct or "Payout"),
            "amount":      int(round(float(r.amt or 0))),
            "minutes_ago": minutes_ago,
            "color":       f"c{(r.uid % 8) + 1}",  # c1..c8 for avatar color variety
        })

    _activity_feed_cache["ts"] = now_ts
    _activity_feed_cache["data"] = result
    return result

# ── /explore Phase 2: Member Stories (opt-in, admin-moderated) ────────────
# POST endpoints mutate DB (user-triggered, no cache).
# Public GET has a 60s in-memory cache matching stats/activity pattern.
_member_stories_cache = {"ts": 0.0, "data": None}

def _compute_display_initials(user):
    """Two-char uppercase initials for stories/showcase cards.
    Priority: first+last name → username[:2] → 'SA' as last resort.
    Historical rows have mixed NULL/empty-string in first_name/last_name, so
    we check both conditions explicitly (truthy guards both)."""
    fn = (user.first_name or "").strip()
    ln = (user.last_name or "").strip()
    if fn and ln:
        return (fn[0] + ln[0]).upper()
    un = (user.username or "").strip()
    if len(un) >= 2:
        return un[:2].upper()
    if un:
        return (un[0] * 2).upper()
    return "SA"


@app.post("/api/member/story")
async def api_member_submit_story(request: Request, db: Session = Depends(get_db)):
    """Member submits a first-dollar story. Creates an unapproved MemberStory row.
    Gated on: (a) authenticated, (b) at least one paid commission received,
    (c) no existing pending or approved row for this user.
    All text fields validated length-wise to match column limits in database.py."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from decimal import Decimal, InvalidOperation
    from sqlalchemy import func

    # Gate: must have received at least one paid commission
    paid_count = db.query(func.count(Commission.id)).filter(
        Commission.to_user_id == user.id,
        Commission.status == "paid",
        Commission.amount_usdt > 0,
    ).scalar() or 0
    if paid_count < 1:
        return JSONResponse({
            "error": "You need at least one paid commission before you can share a first-dollar story."
        }, status_code=403)

    # Gate: one pending + one approved max
    existing = db.query(MemberStory).filter(MemberStory.user_id == user.id).count()
    if existing >= 1:
        return JSONResponse({
            "error": "You already have a story on file. Contact support if you want to edit or replace it."
        }, status_code=409)

    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid JSON"}, status_code=400)

    # Server-side validation (frontend enforces too, but never trust the client)
    niche              = (body.get("niche") or "").strip()[:100]
    display_country    = (body.get("display_country") or "").strip()[:100]
    milestone_label    = (body.get("milestone_label") or "").strip()[:120]
    story_text         = (body.get("story_text") or "").strip()[:400]
    milestone_color    = (body.get("milestone_color") or "green").strip().lower()
    if milestone_color not in ("sky", "indigo", "amber", "green", "pink"):
        milestone_color = "green"

    try:
        days_to_milestone = int(body.get("days_to_milestone") or 0)
        if days_to_milestone < 0 or days_to_milestone > 9999:
            days_to_milestone = None
    except (TypeError, ValueError):
        days_to_milestone = None

    now_monthly_raw = body.get("now_monthly_amount")
    now_monthly_amount = None
    if now_monthly_raw not in (None, ""):
        try:
            v = Decimal(str(now_monthly_raw))
            if 0 <= v <= Decimal("999999.99"):
                now_monthly_amount = v
        except (InvalidOperation, ValueError, TypeError):
            now_monthly_amount = None

    # Required fields guard
    if not niche or not milestone_label or not story_text:
        return JSONResponse({
            "error": "Niche, milestone label, and story text are all required."
        }, status_code=400)

    row = MemberStory(
        user_id            = user.id,
        display_initials   = _compute_display_initials(user),
        display_country    = display_country or None,
        niche              = niche,
        days_to_milestone  = days_to_milestone,
        milestone_label    = milestone_label,
        milestone_color    = milestone_color,
        story_text         = story_text,
        now_monthly_amount = now_monthly_amount,
        approved           = False,
        sort_order         = 0,
    )
    db.add(row)
    db.commit()
    db.refresh(row)
    return {"success": True, "story_id": row.id}


@app.get("/api/member/story/mine")
def api_member_my_story(request: Request, db: Session = Depends(get_db)):
    """Returns the current user's story (if any) so the form can show 'already submitted' state."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    row = db.query(MemberStory).filter(MemberStory.user_id == user.id).first()
    if not row:
        return {"exists": False}
    return {
        "exists": True,
        "approved": bool(row.approved),
        "niche": row.niche,
        "milestone_label": row.milestone_label,
        "story_text": row.story_text,
        "created_at": row.created_at.isoformat() if row.created_at else None,
    }


@app.get("/api/member/story/prompt-check")
def api_member_story_prompt_check(request: Request, db: Session = Depends(get_db)):
    """Single cheap check for the dashboard nudge: should we prompt this user
    to share their story? Returns show=True only if they've received at least
    one paid commission AND haven't submitted a story yet. Also returns the
    amount of their first paid commission and the milestone date, which the
    banner uses to personalise the headline ('You earned your first $10 —
    share your story')."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    # Skip for admin accounts. Admins sit at the top of every referral tree
    # so they'll accrue membership_sponsor commissions on every signup, and
    # the banner copy ('share how you did it') doesn't fit the founder
    # context — they'd see this banner re-fire every time a real member
    # joins. Added 10 May 2026 after Steve's own dashboard kept showing
    # the prompt post-launch.
    if getattr(user, 'is_admin', False):
        return {"show": False, "reason": "admin_account"}

    # Persisted dismissal — survives across devices. Replaces the
    # localStorage-only flag that only worked on the device where the
    # member dismissed. If the user clears localStorage they don't get
    # the banner re-fired, which is the behaviour members expect.
    if getattr(user, 'story_prompt_dismissed_at', None):
        return {"show": False, "reason": "dismissed"}

    # Already submitted? Skip the nudge entirely.
    existing_story = db.query(MemberStory).filter(MemberStory.user_id == user.id).first()
    if existing_story:
        return {"show": False, "reason": "already_submitted"}

    # Find their FIRST paid commission (oldest, ordered by created_at ascending)
    # across all 3 commission tables. Bug fixed 7 May 2026: previously
    # only looked at the Commission table, so members whose first earnings
    # came from Credit Nexus or Course Academy never saw the story prompt
    # banner — they were silently excluded from the qualifying-member flow.
    first_grid = (db.query(Commission)
                    .filter(Commission.to_user_id == user.id,
                            Commission.status == "paid",
                            Commission.amount_usdt > 0)
                    .order_by(Commission.created_at.asc())
                    .first())
    first_matrix = (db.query(CreditMatrixCommission)
                      .filter(CreditMatrixCommission.earner_id == user.id,
                              CreditMatrixCommission.status == "paid",
                              CreditMatrixCommission.amount > 0)
                      .order_by(CreditMatrixCommission.created_at.asc())
                      .first())
    first_course = (db.query(CourseCommission)
                      .filter(CourseCommission.earner_id == user.id,
                              CourseCommission.amount > 0)
                      .order_by(CourseCommission.created_at.asc())
                      .first())

    # Pick the earliest across all 3 (whichever the member earned first)
    candidates = []
    if first_grid and first_grid.created_at:
        candidates.append((first_grid.created_at, float(first_grid.amount_usdt or 0)))
    if first_matrix and first_matrix.created_at:
        candidates.append((first_matrix.created_at, float(first_matrix.amount or 0)))
    if first_course and first_course.created_at:
        candidates.append((first_course.created_at, float(first_course.amount or 0)))

    if not candidates:
        return {"show": False, "reason": "no_paid_commission"}

    candidates.sort(key=lambda x: x[0])
    earliest_date, earliest_amount = candidates[0]

    return {
        "show": True,
        "first_amount": earliest_amount,
        "first_paid_at": earliest_date.isoformat(),
    }


@app.post("/api/member/story/prompt-dismiss")
def api_member_story_prompt_dismiss(request: Request, db: Session = Depends(get_db)):
    """Persist dismissal of the 'You earned your first $X!' banner so a
    member who dismisses on one device doesn't see it again on another.
    Replaces the localStorage-only flag that didn't sync across devices.

    Idempotent — re-calling is safe and a no-op. Returns the dismissal
    timestamp so the frontend can confirm the action without rerunning
    the prompt-check query.
    """
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    if not user.story_prompt_dismissed_at:
        user.story_prompt_dismissed_at = datetime.utcnow()
        db.commit()

    return {
        "ok": True,
        "dismissed_at": user.story_prompt_dismissed_at.isoformat(),
    }


@app.get("/api/public/member-stories")
def api_public_member_stories(db: Session = Depends(get_db)):
    """Public feed for /explore tab 2. Approved rows only, 60s cache.
    Privacy: never exposes user_id, username, email, or any PII beyond
    what the member opted to share (initials + country name)."""
    import time as _time
    now_ts = _time.time()
    if now_ts - _member_stories_cache["ts"] < 60 and _member_stories_cache["data"] is not None:
        return _member_stories_cache["data"]

    rows = (db.query(MemberStory)
              .filter(MemberStory.approved == True)
              .order_by(MemberStory.sort_order.asc(), MemberStory.created_at.desc())
              .limit(60)
              .all())
    result = []
    for r in rows:
        now_monthly = None
        if r.now_monthly_amount is not None:
            try:
                now_monthly = float(r.now_monthly_amount)
            except (TypeError, ValueError):
                now_monthly = None
        result.append({
            "id":                 r.id,
            "display_initials":   r.display_initials or "SA",
            "display_country":    r.display_country,
            "niche":              r.niche,
            "days_to_milestone":  r.days_to_milestone,
            "milestone_label":    r.milestone_label,
            "milestone_color":    r.milestone_color or "green",
            "story_text":         r.story_text,
            "now_monthly_amount": now_monthly,
            "created_at":         r.created_at.isoformat() if r.created_at else None,
        })
    _member_stories_cache["ts"] = now_ts
    _member_stories_cache["data"] = result
    return result


def _invalidate_stories_cache():
    """Called by admin moderation endpoints after approve/reject/edit/reorder.
    Phase 2 Step 3 wires the admin UI; this helper is used then."""
    _member_stories_cache["ts"] = 0.0
    _member_stories_cache["data"] = None


# ── /explore Phase 2: Admin moderation endpoints ──────────────────────────
# All endpoints require admin. Any mutation invalidates the public stories cache.
def _serialise_story_admin(row, user_map):
    """Full story dict for admin UI — includes user context the public endpoint hides."""
    u = user_map.get(row.user_id) if row.user_id else None
    now_monthly = None
    if row.now_monthly_amount is not None:
        try:
            now_monthly = float(row.now_monthly_amount)
        except (TypeError, ValueError):
            now_monthly = None
    return {
        "id":                 row.id,
        "user_id":            row.user_id,
        "username":           (u.username if u else None),
        "member_id":          (u.id if u else None),
        "user_country":       (u.display_city if u else None),
        "display_initials":   row.display_initials or "SA",
        "display_country":    row.display_country,
        "niche":              row.niche,
        "days_to_milestone":  row.days_to_milestone,
        "milestone_label":    row.milestone_label,
        "milestone_color":    row.milestone_color or "green",
        "story_text":         row.story_text,
        "now_monthly_amount": now_monthly,
        "approved":           bool(row.approved),
        "sort_order":         row.sort_order or 0,
        "created_at":         row.created_at.isoformat() if row.created_at else None,
        "updated_at":         row.updated_at.isoformat() if row.updated_at else None,
    }


@app.get("/admin/api/stories")
def admin_api_stories(
    status: str = "pending",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """List member stories for the admin moderation queue.
    status=pending | approved | all (default: pending)."""
    _require_admin(user)
    from sqlalchemy import func
    q = db.query(MemberStory)
    if status == "pending":
        q = q.filter(MemberStory.approved == False)
        q = q.order_by(MemberStory.created_at.asc())  # oldest first — FIFO review queue
    elif status == "approved":
        q = q.filter(MemberStory.approved == True)
        q = q.order_by(MemberStory.sort_order.asc(), MemberStory.created_at.desc())
    else:
        # "all" — approved first (by sort_order), then pending
        q = q.order_by(MemberStory.approved.desc(), MemberStory.sort_order.asc(), MemberStory.created_at.desc())

    rows = q.limit(500).all()

    # Batch-load the users we'll need (one SELECT instead of N)
    user_ids = [r.user_id for r in rows if r.user_id]
    user_map = {}
    if user_ids:
        users = db.query(User).filter(User.id.in_(user_ids)).all()
        user_map = {u.id: u for u in users}

    return {
        "stories": [_serialise_story_admin(r, user_map) for r in rows],
        "counts": {
            "pending":  db.query(func.count(MemberStory.id)).filter(MemberStory.approved == False).scalar() or 0,
            "approved": db.query(func.count(MemberStory.id)).filter(MemberStory.approved == True).scalar() or 0,
        },
    }


@app.post("/admin/api/stories/{story_id}/approve")
def admin_api_story_approve(
    story_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Mark a story as approved and publish it to /explore tab 2."""
    _require_admin(user)
    row = db.query(MemberStory).filter(MemberStory.id == story_id).first()
    if not row:
        raise HTTPException(status_code=404, detail="Story not found")
    row.approved = True
    row.updated_at = datetime.utcnow()
    db.commit()
    _invalidate_stories_cache()
    return {"success": True, "id": row.id, "approved": True}


@app.post("/admin/api/stories/{story_id}/reject")
def admin_api_story_reject(
    story_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Reject and delete a story. Irreversible — the member can submit a new one afterwards."""
    _require_admin(user)
    row = db.query(MemberStory).filter(MemberStory.id == story_id).first()
    if not row:
        raise HTTPException(status_code=404, detail="Story not found")
    was_approved = bool(row.approved)
    db.delete(row)
    db.commit()
    if was_approved:
        _invalidate_stories_cache()  # only needed if it was on the public feed
    return {"success": True, "id": story_id, "deleted": True}


@app.post("/admin/api/stories/{story_id}/edit")
async def admin_api_story_edit(
    story_id: int,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Edit any display field on a story (before or after approval). Same validation as the member endpoint."""
    _require_admin(user)
    row = db.query(MemberStory).filter(MemberStory.id == story_id).first()
    if not row:
        raise HTTPException(status_code=404, detail="Story not found")

    try:
        body = await request.json()
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid JSON")

    from decimal import Decimal, InvalidOperation

    # Every field is optional — only apply ones the admin sent. None/"" passthrough
    # retains the existing value rather than blanking it, except for display_country
    # and now_monthly_amount which are explicitly nullable.
    if "niche" in body and body["niche"] is not None:
        row.niche = (body["niche"] or "").strip()[:100] or row.niche
    if "display_initials" in body and body["display_initials"]:
        row.display_initials = (body["display_initials"] or "").strip()[:4].upper() or row.display_initials
    if "display_country" in body:
        v = (body["display_country"] or "").strip()[:100]
        row.display_country = v or None
    if "milestone_label" in body and body["milestone_label"] is not None:
        row.milestone_label = (body["milestone_label"] or "").strip()[:120] or row.milestone_label
    if "story_text" in body and body["story_text"] is not None:
        row.story_text = (body["story_text"] or "").strip()[:400] or row.story_text
    if "milestone_color" in body and body["milestone_color"]:
        c = (body["milestone_color"] or "").strip().lower()
        if c in ("sky", "indigo", "amber", "green", "pink"):
            row.milestone_color = c
    if "days_to_milestone" in body:
        try:
            v = body["days_to_milestone"]
            if v in (None, ""):
                row.days_to_milestone = None
            else:
                iv = int(v)
                row.days_to_milestone = iv if 0 <= iv <= 9999 else None
        except (TypeError, ValueError):
            pass
    if "now_monthly_amount" in body:
        v = body["now_monthly_amount"]
        if v in (None, ""):
            row.now_monthly_amount = None
        else:
            try:
                d = Decimal(str(v))
                row.now_monthly_amount = d if 0 <= d <= Decimal("999999.99") else row.now_monthly_amount
            except (InvalidOperation, ValueError, TypeError):
                pass

    row.updated_at = datetime.utcnow()
    db.commit()
    if row.approved:
        _invalidate_stories_cache()
    return {"success": True, "id": row.id}


@app.post("/admin/api/stories/{story_id}/reorder")
async def admin_api_story_reorder(
    story_id: int,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Set sort_order on an approved story. Lower values display first."""
    _require_admin(user)
    row = db.query(MemberStory).filter(MemberStory.id == story_id).first()
    if not row:
        raise HTTPException(status_code=404, detail="Story not found")
    try:
        body = await request.json()
        so = int(body.get("sort_order", 0))
    except (Exception, TypeError, ValueError):
        raise HTTPException(status_code=400, detail="Invalid sort_order")
    row.sort_order = so
    row.updated_at = datetime.utcnow()
    db.commit()
    if row.approved:
        _invalidate_stories_cache()
    return {"success": True, "id": row.id, "sort_order": so}


# ═════════════════════════════════════════════════════════════════════════
# /explore Phase 3: Member Showcase — opt-in featured artifacts.
# Three artifact types: bio-link (LinkHubProfile), landing-page (FunnelPage),
# campaign (VideoCampaign). NO course type — platform course model is owner-
# authored only; members buy and resell, they don't create courses.
# ═════════════════════════════════════════════════════════════════════════
_member_showcase_cache = {"key": None, "ts": 0.0, "data": None}

SHOWCASE_ARTIFACT_TYPES = ("bio-link", "landing-page", "campaign")
SHOWCASE_COLOURS = ("sky", "indigo", "amber", "green", "pink")


def _fetch_artifact_for_ownership(db, artifact_type, artifact_id, user_id):
    """Return the artifact row if owned by user_id AND eligible for showcase,
    otherwise None. Eligibility varies by type:
      bio-link:    must be published
      landing-page: must be status='published'
      campaign:    must have views_delivered >= 1
    """
    if artifact_type == "bio-link":
        row = db.query(LinkHubProfile).filter(
            LinkHubProfile.id == artifact_id,
            LinkHubProfile.user_id == user_id,
        ).first()
        if row and row.is_published:
            return row
        return None

    if artifact_type == "landing-page":
        row = db.query(FunnelPage).filter(
            FunnelPage.id == artifact_id,
            FunnelPage.user_id == user_id,
        ).first()
        if row and (row.status or "") == "published":
            return row
        return None

    if artifact_type == "campaign":
        row = db.query(VideoCampaign).filter(
            VideoCampaign.id == artifact_id,
            VideoCampaign.user_id == user_id,
        ).first()
        if row and (row.views_delivered or 0) >= 1:
            return row
        return None

    return None


def _fetch_artifact_display(db, artifact_type, artifact_id):
    """Dereference an artifact to a small dict of display fields.
    Used by the admin preview and by /api/public/member-showcase so cards
    can render with the real title/thumb/slug without a second fetch client-side.
    Returns None if the artifact has been deleted since showcase submission."""
    if artifact_type == "bio-link":
        row = db.query(LinkHubProfile).filter(LinkHubProfile.id == artifact_id).first()
        if not row:
            return None
        return {
            "title":      row.display_name or "",
            "subtitle":   (row.bio or "")[:120],
            "avatar_url": row.avatar_r2_url or None,
            "banner_url": row.banner_r2_url or None,
            "url":        f"/linkhub/{row.user_id}",  # frontend routes to /linkhub/:user_id
            "extra":      {"views": int(row.total_views or 0)},
        }

    if artifact_type == "landing-page":
        row = db.query(FunnelPage).filter(FunnelPage.id == artifact_id).first()
        if not row:
            return None
        return {
            "title":      row.title or "",
            "subtitle":   (row.headline or row.subheadline or row.meta_description or "")[:160],
            "avatar_url": None,
            "banner_url": row.og_image_url or row.image_url or None,
            "url":        f"/p/{row.slug}" if row.slug else None,
            "extra":      {"template": row.template_type or "opportunity"},
        }

    if artifact_type == "campaign":
        row = db.query(VideoCampaign).filter(VideoCampaign.id == artifact_id).first()
        if not row:
            return None
        # Thumbnail: YouTube-derived URL if platform is youtube and video_id present.
        thumb = None
        if (row.platform or "").lower() == "youtube" and row.video_id:
            thumb = f"https://i.ytimg.com/vi/{row.video_id}/hqdefault.jpg"
        return {
            "title":      row.title or "",
            "subtitle":   (row.description or "")[:160],
            "avatar_url": None,
            "banner_url": thumb,
            "url":        row.video_url or row.embed_url or None,
            "extra":      {
                "platform": row.platform or "",
                "views":    int(row.views_delivered or 0),
                "category": row.category or "",
            },
        }

    return None


@app.get("/api/member/showcase/eligible")
def api_member_showcase_eligible(request: Request, db: Session = Depends(get_db)):
    """Returns the user's eligible artifacts per type, so the editor
    pages can show/hide the 'Feature on /explore' button accurately.
    Also returns already-submitted showcase rows so the UI can show state."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    # LinkHub — members have 0 or 1 profile
    lh = db.query(LinkHubProfile).filter(
        LinkHubProfile.user_id == user.id,
        LinkHubProfile.is_published == True,
    ).first()
    bio_links = [{"id": lh.id, "title": lh.display_name or "My LinkHub"}] if lh else []

    # SuperPages — potentially many
    pages = db.query(FunnelPage).filter(
        FunnelPage.user_id == user.id,
        FunnelPage.status == "published",
    ).order_by(FunnelPage.updated_at.desc()).limit(50).all()
    landing_pages = [{"id": p.id, "title": p.title or "(Untitled page)"} for p in pages]

    # Campaigns — only those with ≥1 view delivered
    camps = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id,
        VideoCampaign.views_delivered >= 1,
        VideoCampaign.status != "deleted",
    ).order_by(VideoCampaign.created_at.desc()).limit(50).all()
    campaigns = [{"id": c.id, "title": c.title or "(Untitled campaign)", "views": int(c.views_delivered or 0)} for c in camps]

    # Existing showcase rows for this user — so UI can mark "already submitted"
    existing = db.query(MemberShowcase).filter(MemberShowcase.user_id == user.id).all()
    submitted = {}
    for r in existing:
        submitted[f"{r.artifact_type}:{r.artifact_id}"] = {
            "id": r.id,
            "approved": bool(r.approved),
            "created_at": r.created_at.isoformat() if r.created_at else None,
        }

    return {
        "bio_links":      bio_links,
        "landing_pages":  landing_pages,
        "campaigns":      campaigns,
        "submitted":      submitted,
    }


@app.post("/api/member/showcase")
async def api_member_submit_showcase(request: Request, db: Session = Depends(get_db)):
    """Member opts their artifact into /explore tab 3. Admin must approve before it goes public.
    Gates: auth + ≥1 paid commission + ownership + artifact eligibility + one submission
    per artifact (a member may have multiple showcase rows, but not duplicates for the same artifact)."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from sqlalchemy import func

    # Gate: ≥1 paid commission (same rule as stories — member has tangible stake in platform)
    paid_count = db.query(func.count(Commission.id)).filter(
        Commission.to_user_id == user.id,
        Commission.status == "paid",
        Commission.amount_usdt > 0,
    ).scalar() or 0
    if paid_count < 1:
        return JSONResponse({
            "error": "You need at least one paid commission before featuring work on /explore."
        }, status_code=403)

    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid JSON"}, status_code=400)

    artifact_type = (body.get("artifact_type") or "").strip().lower()
    if artifact_type not in SHOWCASE_ARTIFACT_TYPES:
        return JSONResponse({"error": "Invalid artifact_type"}, status_code=400)
    try:
        artifact_id = int(body.get("artifact_id"))
    except (TypeError, ValueError):
        return JSONResponse({"error": "Invalid artifact_id"}, status_code=400)

    # Ownership + eligibility check
    artifact = _fetch_artifact_for_ownership(db, artifact_type, artifact_id, user.id)
    if not artifact:
        return JSONResponse({
            "error": "We couldn't find that item, or it isn't eligible yet (bio links + landing pages must be published, campaigns must have at least 1 view)."
        }, status_code=404)

    # One submission per artifact
    existing = db.query(MemberShowcase).filter(
        MemberShowcase.user_id == user.id,
        MemberShowcase.artifact_type == artifact_type,
        MemberShowcase.artifact_id == artifact_id,
    ).first()
    if existing:
        return JSONResponse({
            "error": "You already submitted this one. Check your showcase list for status."
        }, status_code=409)

    # Form fields
    display_title = (body.get("display_title") or "").strip()[:160]
    display_niche = (body.get("display_niche") or "").strip()[:80]
    metric_label  = (body.get("metric_label") or "").strip()[:60]
    metric_value  = (body.get("metric_value") or "").strip()[:40]
    accent_color  = (body.get("accent_color") or "sky").strip().lower()
    if accent_color not in SHOWCASE_COLOURS:
        accent_color = "sky"

    if not display_title or not display_niche:
        return JSONResponse({
            "error": "Title and niche are both required."
        }, status_code=400)

    row = MemberShowcase(
        user_id       = user.id,
        artifact_type = artifact_type,
        artifact_id   = artifact_id,
        display_title = display_title,
        display_niche = display_niche,
        metric_label  = metric_label or None,
        metric_value  = metric_value or None,
        accent_color  = accent_color,
        approved      = False,
        sort_order    = 0,
    )
    db.add(row)
    db.commit()
    db.refresh(row)
    return {"success": True, "showcase_id": row.id}


@app.get("/api/member/showcase/mine")
def api_member_my_showcase(request: Request, db: Session = Depends(get_db)):
    """Returns current user's showcase submissions with status."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    rows = db.query(MemberShowcase).filter(
        MemberShowcase.user_id == user.id
    ).order_by(MemberShowcase.created_at.desc()).all()
    return {
        "showcase": [{
            "id":            r.id,
            "artifact_type": r.artifact_type,
            "artifact_id":   r.artifact_id,
            "display_title": r.display_title,
            "display_niche": r.display_niche,
            "metric_label":  r.metric_label,
            "metric_value":  r.metric_value,
            "accent_color":  r.accent_color or "sky",
            "approved":      bool(r.approved),
            "created_at":    r.created_at.isoformat() if r.created_at else None,
        } for r in rows],
    }


@app.get("/api/public/member-showcase")
def api_public_member_showcase(filter: str = "all", db: Session = Depends(get_db)):
    """Public /explore tab 3 feed. Approved rows only, 60s cache keyed per filter.
    Privacy: we expose only display fields + the dereferenced artifact preview.
    Never exposes user_id / username / email."""
    import time as _time

    f = (filter or "all").lower()
    if f not in ("all",) + SHOWCASE_ARTIFACT_TYPES:
        f = "all"

    now_ts = _time.time()
    if (_member_showcase_cache["key"] == f
            and now_ts - _member_showcase_cache["ts"] < 60
            and _member_showcase_cache["data"] is not None):
        return _member_showcase_cache["data"]

    q = db.query(MemberShowcase).filter(MemberShowcase.approved == True)
    if f != "all":
        q = q.filter(MemberShowcase.artifact_type == f)
    rows = q.order_by(MemberShowcase.sort_order.asc(), MemberShowcase.created_at.desc()).limit(60).all()

    result = []
    for r in rows:
        art = _fetch_artifact_display(db, r.artifact_type, r.artifact_id)
        # If the underlying artifact was deleted, skip (don't render a broken card).
        if art is None:
            continue
        result.append({
            "id":            r.id,
            "artifact_type": r.artifact_type,
            "display_title": r.display_title,
            "display_niche": r.display_niche,
            "metric_label":  r.metric_label,
            "metric_value":  r.metric_value,
            "accent_color":  r.accent_color or "sky",
            "created_at":    r.created_at.isoformat() if r.created_at else None,
            "artifact":      art,
        })

    _member_showcase_cache["key"] = f
    _member_showcase_cache["ts"] = now_ts
    _member_showcase_cache["data"] = result
    return result


def _invalidate_showcase_cache():
    """Called after any admin mutation so the public feed refreshes immediately."""
    _member_showcase_cache["key"] = None
    _member_showcase_cache["ts"] = 0.0
    _member_showcase_cache["data"] = None


# ── /explore Phase 3: Admin moderation endpoints ─────────────────────────
def _serialise_showcase_admin(row, user_map, db):
    u = user_map.get(row.user_id) if row.user_id else None
    artifact_preview = _fetch_artifact_display(db, row.artifact_type, row.artifact_id)
    return {
        "id":             row.id,
        "user_id":        row.user_id,
        "username":       (u.username if u else None),
        "artifact_type":  row.artifact_type,
        "artifact_id":    row.artifact_id,
        "artifact_alive": artifact_preview is not None,
        "artifact":       artifact_preview,
        "display_title":  row.display_title,
        "display_niche":  row.display_niche,
        "metric_label":   row.metric_label,
        "metric_value":   row.metric_value,
        "accent_color":   row.accent_color or "sky",
        "approved":       bool(row.approved),
        "sort_order":     row.sort_order or 0,
        "created_at":     row.created_at.isoformat() if row.created_at else None,
        "updated_at":     row.updated_at.isoformat() if row.updated_at else None,
    }


@app.get("/admin/api/showcase")
def admin_api_showcase(
    status: str = "pending",
    artifact_type: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """List showcase rows for admin moderation.
    status = pending | approved | all (default pending).
    artifact_type = bio-link | landing-page | campaign (optional)."""
    _require_admin(user)
    from sqlalchemy import func

    q = db.query(MemberShowcase)
    if status == "pending":
        q = q.filter(MemberShowcase.approved == False)
        q = q.order_by(MemberShowcase.created_at.asc())
    elif status == "approved":
        q = q.filter(MemberShowcase.approved == True)
        q = q.order_by(MemberShowcase.sort_order.asc(), MemberShowcase.created_at.desc())
    else:
        q = q.order_by(MemberShowcase.approved.desc(), MemberShowcase.sort_order.asc(), MemberShowcase.created_at.desc())

    if artifact_type in SHOWCASE_ARTIFACT_TYPES:
        q = q.filter(MemberShowcase.artifact_type == artifact_type)

    rows = q.limit(500).all()

    user_ids = [r.user_id for r in rows if r.user_id]
    user_map = {}
    if user_ids:
        users = db.query(User).filter(User.id.in_(user_ids)).all()
        user_map = {u.id: u for u in users}

    return {
        "showcase": [_serialise_showcase_admin(r, user_map, db) for r in rows],
        "counts": {
            "pending":  db.query(func.count(MemberShowcase.id)).filter(MemberShowcase.approved == False).scalar() or 0,
            "approved": db.query(func.count(MemberShowcase.id)).filter(MemberShowcase.approved == True).scalar() or 0,
        },
    }


@app.post("/admin/api/showcase/{sid}/approve")
def admin_api_showcase_approve(
    sid: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    _require_admin(user)
    row = db.query(MemberShowcase).filter(MemberShowcase.id == sid).first()
    if not row:
        raise HTTPException(status_code=404, detail="Showcase not found")
    row.approved = True
    row.updated_at = datetime.utcnow()
    db.commit()
    _invalidate_showcase_cache()
    return {"success": True, "id": row.id, "approved": True}


@app.post("/admin/api/showcase/{sid}/reject")
def admin_api_showcase_reject(
    sid: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Reject and delete the showcase row. Member can re-submit afterwards."""
    _require_admin(user)
    row = db.query(MemberShowcase).filter(MemberShowcase.id == sid).first()
    if not row:
        raise HTTPException(status_code=404, detail="Showcase not found")
    was_approved = bool(row.approved)
    db.delete(row)
    db.commit()
    if was_approved:
        _invalidate_showcase_cache()
    return {"success": True, "id": sid, "deleted": True}


@app.post("/admin/api/showcase/{sid}/edit")
async def admin_api_showcase_edit(
    sid: int,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    _require_admin(user)
    row = db.query(MemberShowcase).filter(MemberShowcase.id == sid).first()
    if not row:
        raise HTTPException(status_code=404, detail="Showcase not found")
    try:
        body = await request.json()
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid JSON")

    if "display_title" in body and body["display_title"] is not None:
        v = (body["display_title"] or "").strip()[:160]
        if v:
            row.display_title = v
    if "display_niche" in body and body["display_niche"] is not None:
        v = (body["display_niche"] or "").strip()[:80]
        if v:
            row.display_niche = v
    if "metric_label" in body:
        v = (body["metric_label"] or "").strip()[:60]
        row.metric_label = v or None
    if "metric_value" in body:
        v = (body["metric_value"] or "").strip()[:40]
        row.metric_value = v or None
    if "accent_color" in body and body["accent_color"]:
        c = (body["accent_color"] or "").strip().lower()
        if c in SHOWCASE_COLOURS:
            row.accent_color = c

    row.updated_at = datetime.utcnow()
    db.commit()
    if row.approved:
        _invalidate_showcase_cache()
    return {"success": True, "id": row.id}


@app.post("/admin/api/showcase/{sid}/reorder")
async def admin_api_showcase_reorder(
    sid: int,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    _require_admin(user)
    row = db.query(MemberShowcase).filter(MemberShowcase.id == sid).first()
    if not row:
        raise HTTPException(status_code=404, detail="Showcase not found")
    try:
        body = await request.json()
        so = int(body.get("sort_order", 0))
    except (Exception, TypeError, ValueError):
        raise HTTPException(status_code=400, detail="Invalid sort_order")
    row.sort_order = so
    row.updated_at = datetime.utcnow()
    db.commit()
    if row.approved:
        _invalidate_showcase_cache()
    return {"success": True, "id": row.id, "sort_order": so}


# ═══════════════════════════════════════════════════════════════
#  Purchase consent — express-consent capture before money-in
# ═══════════════════════════════════════════════════════════════
# Architecture in app/purchase_consent.py module docstring. Brief here:
# every money-in API endpoint calls require_fresh_consent() at the top
# of its handler. If consent is enforced and the user has no fresh
# consent record, the endpoint 403s. If enforcement is off (the default
# pre-launch), the helper logs but allows the request through — so we
# can ship the rails without breaking purchases before the solicitor
# signs off the disclaimer text.
from .purchase_consent import (
    PURCHASE_CONSENT_VERSION, PURCHASE_CONSENT_TEXT_HASH,
    CONSENT_VALIDITY_SECONDS, is_consent_enforced, get_consent_payload,
)
from .database import PurchaseConsent


@app.get("/api/purchase-consent")
def api_get_purchase_consent(user: User = Depends(get_current_user)):
    """Return the current disclaimer text + version + enforcement
    state for the frontend to render in the consent modal. Public-ish:
    no PII; serving anonymous works too in case we ever want to show
    the disclaimer pre-login."""
    return get_consent_payload()


@app.post("/api/purchase-consent/record")
async def api_record_purchase_consent(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Record a user's express consent to the no-refund / immediate-
    activation terms. Called by the frontend modal after the user
    ticks the consent box and clicks "I Agree & Proceed".

    Body: { "version": "<consent_version>", "text_hash": "<sha256>" }

    The frontend must echo back the version + hash it displayed, so
    we can detect any client/server text mismatch (e.g. a stale
    cached page showing an old version). If they don't match, we
    refuse the consent and return the current version so the
    frontend can re-render and ask the user to consent fresh."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    body = await request.json()
    client_version = (body.get("version") or "").strip()
    client_hash    = (body.get("text_hash") or "").strip().lower()

    if client_version != PURCHASE_CONSENT_VERSION or client_hash != PURCHASE_CONSENT_TEXT_HASH.lower():
        # Client saw a different version than the server thinks is
        # current. Refuse, return the current values so the client
        # can re-render the modal with fresh text.
        return JSONResponse({
            "error": "Disclaimer version mismatch — please refresh and re-consent",
            "current_version":   PURCHASE_CONSENT_VERSION,
            "current_text_hash": PURCHASE_CONSENT_TEXT_HASH,
        }, status_code=409)

    # Capture forensic evidence — IP and user-agent stamped on the row
    ip = (request.client.host if request.client else None)
    # Honour reverse-proxy headers (Railway sits behind one)
    fwd = request.headers.get("x-forwarded-for")
    if fwd:
        ip = fwd.split(",")[0].strip()
    ua = (request.headers.get("user-agent") or "")[:500]

    consent = PurchaseConsent(
        user_id           = user.id,
        consent_version   = PURCHASE_CONSENT_VERSION,
        consent_text_hash = PURCHASE_CONSENT_TEXT_HASH,
        ip_address        = (ip or "")[:50],
        user_agent        = ua,
        # consumed_at + consumed_for are stamped later by
        # require_fresh_consent when the consent is used to authorise
        # an actual purchase.
    )
    db.add(consent)
    db.commit()
    db.refresh(consent)

    logger.info(
        f"PurchaseConsent #{consent.id} recorded for user {user.id} "
        f"version={PURCHASE_CONSENT_VERSION} ip={ip}"
    )

    return {
        "success": True,
        "consent_id":      consent.id,
        "version":         PURCHASE_CONSENT_VERSION,
        "validity_seconds": CONSENT_VALIDITY_SECONDS,
        "expires_at":      (consent.created_at + timedelta(seconds=CONSENT_VALIDITY_SECONDS)).isoformat(),
    }


def require_fresh_consent(db: Session, user_id: int, purpose: str) -> tuple[bool, str | None]:
    """Verify the user has a fresh, unused consent record. If found,
    mark it consumed (stamps consumed_at + consumed_for) and return
    (True, None). If not, return (False, error_message).

    When PURCHASE_CONSENT_ENFORCED is false the helper still logs +
    consumes (so we get telemetry on whether consents are being
    captured correctly) but never returns a blocking failure — the
    second tuple element will be None. Only when enforced=true does
    the helper enforce the gate.

    Call from the top of every money-in endpoint:

        ok, err = require_fresh_consent(db, user.id, purpose='membership_basic')
        if not ok:
            return JSONResponse({'error': err}, status_code=403)

    `purpose` is free-form and gets stored on the consent record so
    forensics can answer "which purchase did this consent authorise?"
    """
    cutoff = datetime.utcnow() - timedelta(seconds=CONSENT_VALIDITY_SECONDS)
    fresh = (
        db.query(PurchaseConsent)
        .filter(PurchaseConsent.user_id == user_id)
        .filter(PurchaseConsent.consumed_at.is_(None))
        .filter(PurchaseConsent.created_at >= cutoff)
        # Only consents recorded against the CURRENT text version
        # count — if the disclaimer was updated, old in-flight
        # consents shouldn't be valid against new text.
        .filter(PurchaseConsent.consent_version == PURCHASE_CONSENT_VERSION)
        .order_by(PurchaseConsent.created_at.desc())
        .first()
    )

    if fresh:
        # Consume it — single-use, prevents one consent authorising
        # multiple back-to-back purchases.
        fresh.consumed_at = datetime.utcnow()
        fresh.consumed_for = purpose[:100] if purpose else None
        db.commit()
        return True, None

    # No fresh consent. Behaviour depends on enforcement flag.
    if is_consent_enforced():
        logger.warning(
            f"Consent gate REJECTED purchase: user={user_id} purpose={purpose} "
            f"version={PURCHASE_CONSENT_VERSION}"
        )
        return False, (
            "You must read and accept the purchase terms before completing this transaction. "
            "Please refresh the page and try again."
        )

    # Enforcement off — log but allow. Tells us whether the modal is
    # being shown / consent recorded for real traffic before we flip
    # enforcement on.
    logger.info(
        f"Consent gate (UN-ENFORCED) — purchase allowed without fresh consent: "
        f"user={user_id} purpose={purpose} version={PURCHASE_CONSENT_VERSION}"
    )
    return True, None


@app.get("/api/me")
def api_me(request: Request, db: Session = Depends(get_db)):
    """Return current user data for the React frontend."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    # Live earnings + descendant counts — see compute_user_earnings()
    _earn = compute_user_earnings(db, user.id)
    _desc = compute_descendant_counts(db, user.id)
    # Available-to-withdraw truth (22 Jun 2026): affiliate wallet PLUS campaign
    # wallet, but campaign only counts when it can actually be withdrawn — the
    # SAME structural gate validate_campaign_withdrawal enforces (active non-
    # complete grid + watch quota not paused; admins exempt). So the dashboard
    # "Available" figure never overstates what a member can take. Members who
    # can't yet withdraw campaign see just their affiliate floor.
    from .withdrawals import _validate_campaign_structural
    _campaign_withdrawable = bool(_validate_campaign_structural(db, user).get("valid", False))
    _available_total = float(user.balance or 0) + (float(user.campaign_balance or 0) if _campaign_withdrawable else 0.0)
    # Founder pricing is NEW-members-only (22 Jun 2026): a member who has paid
    # before is not eligible for the $15 lock, so the /upgrade page must quote
    # them $20. False = has activated before (returning/lapsed member).
    _founder_eligible = not _is_returning_member(db, user)
    # Renewal nudge (30 Jun 2026): an ACTIVE member whose paid window has already
    # elapsed (the Option-B runway cohort) — drives the dashboard renewal banner
    # + modal. Admins exempt; lapsed-INACTIVE members are handled by the /upgrade
    # redirect, not this nudge. membership_expires_at is also exposed so the
    # banner can name the date without a second request.
    _membership_overdue = bool(
        user.is_active and not user.is_admin
        and getattr(user, "membership_expires_at", None)
        and user.membership_expires_at < datetime.utcnow()
    )
    return {
        "id": user.id,
        "username": user.username,
        "email": user.email,
        "first_name": user.first_name,
        "last_name": user.last_name,
        "is_admin": user.is_admin,
        "is_active": user.is_active,
        "access_level": getattr(user, "access_level", "free") or "free",
        "membership_expires_at": (user.membership_expires_at.isoformat()
                                  if getattr(user, "membership_expires_at", None) else None),
        "membership_overdue": _membership_overdue,
        "membership_tier": user.membership_tier or "free",
        "membership_billing": user.membership_billing or "monthly",
        # Flat-pricing model: founding is a separate dimension from tier.
        # Frontend reads is_founding_member to render the FOUNDER badge
        # (membership_tier is just 'partner'/'free' under the new model).
        "is_founding_member": bool(getattr(user, "is_founding_member", False)),
        "founding_spot_number": getattr(user, "founding_spot_number", None),
        "membership_price_locked": (float(user.membership_price_locked) if getattr(user, "membership_price_locked", None) is not None else None),
        # 23 May 2026: payment_method exposed so the Account page can show
        # the "Manage Subscription" card (Stripe Customer Portal link) for
        # card-paying members. Defaults to 'crypto' for all legacy members.
        "payment_method": getattr(user, "payment_method", None) or "crypto",
        # Accurate "is on card auto-renew" signal: a subscription id is set ONLY
        # for membership subscriptions (not one-time card purchases like campaign
        # tiers), so the renew flow can tell genuine auto-renewers apart from
        # members who merely paid for something once by card. Exposed as a bool;
        # the id itself stays server-side.
        "has_card_subscription": bool(getattr(user, "stripe_subscription_id", None)),
        "balance": float(user.balance or 0), "campaign_balance": float(user.campaign_balance or 0),
        "campaign_withdrawable": _campaign_withdrawable,
        "available_total": _available_total,
        "founder_eligible": _founder_eligible,
        "total_earned": _earn["total_earned"],
        "total_withdrawn": compute_total_withdrawn(db, user.id),
        "grid_earnings": _earn["grid_earnings"],
        "level_earnings": float(user.level_earnings or 0),
        "upline_earnings": float(user.upline_earnings or 0),
        "course_earnings": _earn["course_earnings"],
        "marketplace_earnings": float(user.marketplace_earnings or 0),
        "bonus_earnings": float(user.bonus_earnings or 0),
        "personal_referrals": _earn["personal_referrals"],
        "total_team": _desc["total"],
        "sponsor_id": user.sponsor_id,
        "sponsor_username": (db.query(User).filter(User.id == user.sponsor_id).first().username if user.sponsor_id else None),
        "created_at": user.created_at.isoformat() if user.created_at else None,
        "onboarding_completed": user.onboarding_completed,
        "kyc_status": user.kyc_status,
        "totp_enabled": user.totp_enabled,
        "avatar_url": user.avatar_url or None,
        "country": user.country or "",
        "display_city": getattr(user, "display_city", None) or "",
        "interests": user.interests or "",
        "gender": user.gender or "",
        "age_range": user.age_range or "",
        "wallet_address": user.wallet_address or "",
        "wallet_network": user.wallet_network or "",
        "sending_wallet": getattr(user, "sending_wallet", "") or "",
        "member_id": getattr(user, "member_id", None),
        # Highest active Campaign Tier (0 if none). Drives Watch-to-Earn access
        # gate on the frontend so members without a tier see the lock UI.
        "highest_tier": get_user_highest_tier(db, user.id),
    }
@app.get("/api/notifications")
def api_notifications(request: Request, db: Session = Depends(get_db)):
    """Return recent notifications for the current user."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    notifs = db.query(Notification).filter(
        Notification.user_id == user.id
    ).order_by(Notification.created_at.desc()).limit(20).all()
    unread = sum(1 for n in notifs if not n.is_read)
    return {
        "notifications": [{
            "id": n.id, "type": n.type, "icon": n.icon, "title": n.title,
            "message": n.message, "link": n.link, "is_read": n.is_read,
            "created_at": n.created_at.isoformat() if n.created_at else None,
        } for n in notifs],
        "unread_count": unread,
    }
@app.post("/api/notifications/mark-read")
def api_mark_notifications_read(request: Request, db: Session = Depends(get_db)):
    """Mark all notifications as read."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    db.query(Notification).filter(
        Notification.user_id == user.id, Notification.is_read == False
    ).update({"is_read": True})
    db.commit()
    return {"ok": True}
@app.post("/api/notifications/clear-all")
def api_clear_all_notifications(request: Request, db: Session = Depends(get_db)):
    """Delete all notifications for the current user."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    db.query(Notification).filter(Notification.user_id == user.id).delete()
    db.commit()
    return {"ok": True}
@app.delete("/api/notifications/{notif_id}")
def api_delete_notification(notif_id: int, request: Request, db: Session = Depends(get_db)):
    """Delete a single notification."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    n = db.query(Notification).filter(Notification.id == notif_id, Notification.user_id == user.id).first()
    if n:
        db.delete(n)
        db.commit()
    return {"ok": True}

