def _old_leaderboard_DISABLED(request: Request, tab: str = "referrals", user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if not user:
        return RedirectResponse("/login", status_code=302)
    from sqlalchemy import func, desc

    # Tab 1: Members Referred
    ref_leaders = db.query(User).filter(User.is_active == True, User.personal_referrals > 0).order_by(desc(User.personal_referrals)).limit(50).all()

    # Tab 2: Grid Members (sum of positions_filled across all grids owned)
    grid_counts = db.query(
        Grid.owner_id, func.sum(Grid.positions_filled).label("grid_members")
    ).group_by(Grid.owner_id).order_by(desc("grid_members")).limit(50).all()
    grid_user_ids = [g[0] for g in grid_counts]
    grid_amounts = {g[0]: int(g[1] or 0) for g in grid_counts}
    grid_users = db.query(User).filter(User.id.in_(grid_user_ids)).all() if grid_user_ids else []
    grid_users.sort(key=lambda u: grid_amounts.get(u.id, 0), reverse=True)
    for u in grid_users:
        u._grid_count = grid_amounts.get(u.id, 0)

    # Tab 3: Course Sales (purchases by people the user referred)
    course_counts = db.query(
        User.sponsor_id, func.count(CoursePurchase.id).label("course_sales")
    ).join(CoursePurchase, CoursePurchase.user_id == User.id).filter(
        User.sponsor_id.isnot(None)
    ).group_by(User.sponsor_id).order_by(desc("course_sales")).limit(50).all()
    course_user_ids = [c[0] for c in course_counts]
    course_amounts = {c[0]: int(c[1] or 0) for c in course_counts}
    course_users = db.query(User).filter(User.id.in_(course_user_ids)).all() if course_user_ids else []
    course_users.sort(key=lambda u: course_amounts.get(u.id, 0), reverse=True)
    for u in course_users:
        u._course_count = course_amounts.get(u.id, 0)

    return templates.TemplateResponse("leaderboard.html", {
        "request": request, "user": user, "active_page": "leaderboard",
        "tab": tab,
        "ref_leaders": ref_leaders,
        "grid_users": grid_users, "grid_amounts": grid_amounts,
        "course_users": course_users, "course_amounts": course_amounts,
        "balance": float(user.balance or 0)
    })



@app.get("/api/grid-visualiser")
def api_grid_visualiser(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db), tier: int = 1):
    """Return spillover grid data for the current user at a given tier.

    Reads from the ACTUAL GridPosition table — that's where _spillover_fill in
    grid.py writes seats when someone buys a tier. Previous version inferred
    seats from sponsor-chain walks + Payment lookups for `grid_tier_{tier}`
    rows, but that payment_type isn't what the IPN handler writes (it writes
    `nowpayments_grid`), so seats appeared empty even though the grid was
    populated. Fixed 29 Apr 2026.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    # Get the active grid record for this user at this tier
    grid_record = db.query(Grid).filter(
        Grid.owner_id == user.id,
        Grid.package_tier == tier,
        Grid.is_complete == False
    ).first()

    grid_seats = []
    if grid_record:
        # Read the actual seats from GridPosition — these were written by
        # _spillover_fill when downline members purchased the tier.
        positions = db.query(GridPosition).filter(
            GridPosition.grid_id == grid_record.id
        ).order_by(GridPosition.grid_level.asc(), GridPosition.position_num.asc()).all()

        for i, gp in enumerate(positions[:grid_record.total_seats]):
            member = db.query(User).filter(User.id == gp.member_id).first()
            if not member:
                continue
            grid_seats.append({
                "position": i + 1,
                "username": member.username,
                "depth": gp.grid_level,
                "id": member.id,
                "member_id": "SAP-" + str(member.id).zfill(5),
                "is_direct": (member.sponsor_id == user.id),
            })

    # Total downline (everyone in the sponsor chain who has a Grid at this tier)
    # — separate from seats-in-this-grid, gives a sense of network size.
    total_downline = 0
    queue = [user.id]
    visited_dl = {user.id}
    while queue:
        cid = queue.pop(0)
        children = db.query(User).filter(User.sponsor_id == cid).all()
        for child in children:
            if child.id in visited_dl:
                continue
            visited_dl.add(child.id)
            has_grid = db.query(Grid).filter(
                Grid.owner_id == child.id,
                Grid.package_tier == tier,
            ).first()
            if has_grid:
                total_downline += 1
            queue.append(child.id)

    # Completed advances
    completed = db.query(Grid).filter(
        Grid.owner_id == user.id,
        Grid.package_tier == tier,
        Grid.is_complete == True,
        Grid.retired_at.is_(None),  # 3 Jul: retired cutover grids are NOT completions
    ).count()

    # Bonus pool
    bonus_accrued = float(grid_record.bonus_pool_accrued or 0) if grid_record else 0
    from .database import GRID_COMPLETION_BONUS
    bonus_max = (completion_bonus_for(grid_record.total_seats, GRID_PACKAGES.get(tier, 0)) if grid_record else completion_bonus_for(16, GRID_PACKAGES.get(tier, 0)))

    # Per-grid commission breakdown (added 21 May 2026 for the redesigned
    # visualiser). Live ledger reads — sum Commission rows where grid_id
    # matches the current grid and to_user_id is this user. Additive only:
    # the old GridVisualiser.jsx ignores these fields; the new component
    # uses them to render the Commissions Earned card.
    from sqlalchemy import func as _func
    direct_earned = 0.0
    unilevel_earned = 0.0
    direct_fills = 0
    unilevel_fills = 0
    completion_bonus_paid = 0.0
    completion_bonus_count = 0
    v2_bonus_cash_earned = 0.0
    v2_bonus_stepup_earned = 0.0
    v2_welcome_earned = 0.0

    # Cumulative grid commission breakdown — ALL tiers, lifetime.
    #
    # NOTE (7 Jun 2026): previously filtered by package_tier to show
    # "earnings at this tier". After the 3-June detail loss, the per-event
    # commission rows (which carried package_tier) were gone; the rebuilt
    # rows are reconstructed from lifetime counters and are tier-agnostic
    # (package_tier NULL). A per-tier filter therefore matched zero and the
    # card showed $0 even for members with real earnings across completed
    # grids. We now sum direct_sponsor + uni_level across ALL tiers for this
    # user — the cumulative, carry-over figure that mirrors
    # compute_user_earnings and never resets when a new grid advance starts.
    # (grid_id was never populated either, so strict per-grid attribution
    # remains a future enhancement needing a backfill + writer change.)
    if grid_record or completed > 0:
        direct_row = db.query(
            _func.coalesce(_func.sum(Commission.amount_usdt), 0),
            _func.count(Commission.id),
        ).filter(
            Commission.to_user_id == user.id,
            Commission.status == "paid",  # exclude reversed (e.g. 12-Jun topup claw-back)
            Commission.commission_type == "direct_sponsor",
        ).first()
        if direct_row:
            direct_earned = float(direct_row[0] or 0)
            direct_fills = int(direct_row[1] or 0)

        unilevel_row = db.query(
            _func.coalesce(_func.sum(Commission.amount_usdt), 0),
            _func.count(Commission.id),
        ).filter(
            Commission.to_user_id == user.id,
            Commission.status == "paid",  # exclude reversed
            Commission.commission_type == "uni_level",
        ).first()
        if unilevel_row:
            unilevel_earned = float(unilevel_row[0] or 0)
            unilevel_fills = int(unilevel_row[1] or 0)

        # Grid completion bonuses PAID to this user — the third earning stream.
        # status='paid' ONLY, and 'grid_completion_bonus' ONLY (NOT the topup type):
        # the 12-Jun grid_completion_bonus_topup rows were the erroneous migration
        # double-pays we clawed back (now status='reversed'). Counting them — which
        # this query previously did — inflated both the completion total and the
        # "N grids" count here vs the Analytics page (which already filters paid).
        # Mirrors the direct/unilevel sums above. Lifetime, tier-agnostic (post-breach
        # reconstructed rows carry NULL package_tier).
        bonus_row = db.query(
            _func.coalesce(_func.sum(Commission.amount_usdt), 0),
            _func.count(Commission.id),
        ).filter(
            Commission.to_user_id == user.id,
            Commission.status == "paid",
            Commission.commission_type == "grid_completion_bonus",
        ).first()
        if bonus_row:
            completion_bonus_paid = float(bonus_row[0] or 0)
            completion_bonus_count = int(bonus_row[1] or 0)

        # v2 bonus streams (New Profit Grid) — cash + step-up + welcome rebate.
        # These commission types only exist post-go-live; summing them now reads
        # 0 until the flip, then populates the v2 panel correctly.
        for _ctype, _key in (("grid_bonus_cash", "cash"),
                             ("grid_bonus_stepup", "stepup"),
                             ("welcome_bonus", "welcome")):
            _r = db.query(_func.coalesce(_func.sum(Commission.amount_usdt), 0)).filter(
                Commission.to_user_id == user.id,
                Commission.status == "paid",
                Commission.commission_type == _ctype,
            ).scalar()
            if _key == "cash":
                v2_bonus_cash_earned = float(_r or 0)
            elif _key == "stepup":
                v2_bonus_stepup_earned = float(_r or 0)
            else:
                v2_welcome_earned = float(_r or 0)

    total_earned = direct_earned + unilevel_earned + completion_bonus_paid

    # Direct sponsor count — members where sponsor_id is this user. Used
    # by the new visualiser's "Directs" stat tile. Same value the old
    # page was computing client-side from /api/me.
    direct_count = db.query(User).filter(User.sponsor_id == user.id).count()

    # Completed grids at this tier, WITH their seats — so the page can show a
    # "Grid 1 ✓ 36/36 · $bonus paid" summary and let the member tap to view the
    # full completed board (instead of staring at the empty current advance).
    completed_grids_detail = []
    completed_grid_rows = db.query(Grid).filter(
        Grid.owner_id == user.id,
        Grid.package_tier == tier,
        Grid.is_complete == True,
    ).order_by(Grid.advance_number.asc()).all()
    for cg in completed_grid_rows:
        cg_positions = db.query(GridPosition).filter(
            GridPosition.grid_id == cg.id
        ).order_by(GridPosition.grid_level.asc(), GridPosition.position_num.asc()).all()
        cg_seats = []
        for j, gp in enumerate(cg_positions[:cg.total_seats]):
            m = db.query(User).filter(User.id == gp.member_id).first()
            if not m:
                continue
            cg_seats.append({
                "position": j + 1, "username": m.username, "depth": gp.grid_level,
                "id": m.id, "member_id": "SAP-" + str(m.id).zfill(5),
                "is_direct": (m.sponsor_id == user.id),
            })
        completed_grids_detail.append({
            "advance": cg.advance_number,
            "completed_at": cg.completed_at.isoformat() if cg.completed_at else None,
            "filled": len(cg_seats),
            "total_seats": (cg.total_seats or 36),
            "bonus_paid": (round(float(cg.bonus_pool_accrued or 0), 2) if cg.bonus_paid else 0.0),
            # 3 Jul 2026 (grid-truth audit): retired_at marks 12-Jun legacy-
            # cutover grids — is_complete=True but NOT genuine completions.
            # Their completion topups were REVERSED in the phantom cleanup;
            # the UI was still claiming "bonus was paid" for 80 such grids
            # ($13,948 of reversed fiction). Frontend renders retired grids
            # honestly and excludes them from the advances tile.
            "retired": bool(cg.retired_at),
            "seats": cg_seats,
        })

    # ── Plan-aware economics (v1 live / v2 New Profit Grid) ──────────────────
    # The page renders whatever plan is ACTUALLY live. v2 numbers only surface
    # once GRID_V2_LIVE flips — OR for an admin passing ?preview_v2=1, so the
    # live page can be eyeballed in v2 mode before the global flip (members never
    # see the preview path). Additive: the v1 page ignores the new keys.
    from .grid import v2_live as _v2_live
    # Read the LIVE v2 economics from the single source of truth (database.py
    # constants) rather than hardcoding — hardcoded values drifted to the old
    # *proposed* plan (40% direct / 4 levels / 15% welcome) after the 22-Jun
    # fold-in to 50/25/25 and were displaying numbers the payout never paid.
    from .database import (
        V2_DIRECT_PCT, V2_PER_LEVEL_PCT, V2_UNILEVEL_DEPTH, V2_WELCOME_PCT,
        V2_BONUS_POOL_PCT, V2_BONUS_CASH_SHARE, V2_STEPUP_MAX_TIER_PRICE,
    )
    _price = GRID_PACKAGES.get(tier, 0)
    _is_admin = bool(getattr(user, "is_admin", False))
    _preview_v2 = _is_admin and (request.query_params.get("preview_v2") in ("1", "true", "yes"))
    plan_version = 2 if (_v2_live() or _preview_v2) else 1

    if plan_version == 2:
        v2_direct_per_fill   = round(_price * V2_DIRECT_PCT, 2)        # 50% → direct sponsor
        v2_unilevel_per_fill = round(_price * V2_PER_LEVEL_PCT, 2)     # 5% per level
        v2_unilevel_levels   = V2_UNILEVEL_DEPTH                       # 5 levels
        v2_welcome_per_fill  = round(_price * V2_WELCOME_PCT, 2)       # 0 — scrapped 22 Jun
        v2_bonus_positions   = [4, 8, 12, 16]
        # Bonus pool = 25% × 16 seats = 4 × price, paid in 4 equal installments
        # at seats 4/8/12/16 → one tier-price per starred seat.
        v2_bonus_pool_total = round(_price * V2_BONUS_POOL_PCT * NEW_GRID_SEATS, 2)
        v2_bonus_per_pos    = round(v2_bonus_pool_total / len(v2_bonus_positions), 2)
        if _price <= V2_STEPUP_MAX_TIER_PRICE:
            v2_bonus_cash   = round(v2_bonus_per_pos * V2_BONUS_CASH_SHARE, 2)
            v2_bonus_stepup = round(v2_bonus_per_pos - v2_bonus_cash, 2)
        else:
            v2_bonus_cash   = round(v2_bonus_per_pos, 2)               # >$400: full cash, no step-up
            v2_bonus_stepup = 0.0
        # Step-up wallet balance (guard: table may not exist before the schema
        # endpoint is tapped; never break the page on its absence).
        v2_step_up_balance = 0.0
        try:
            from .database import StepUpBalance
            _su = db.query(StepUpBalance).filter(StepUpBalance.user_id == user.id).first()
            if _su:
                v2_step_up_balance = round(float(_su.amount or 0), 2)
        except Exception:
            v2_step_up_balance = 0.0
    else:
        v2_direct_per_fill   = round(_price * 0.30, 2)
        v2_unilevel_per_fill = round(_price * 0.0625, 2)
        v2_unilevel_levels   = 8
        v2_welcome_per_fill  = 0.0
        v2_bonus_positions   = [16]
        v2_bonus_per_pos     = bonus_max
        v2_bonus_cash        = bonus_max
        v2_bonus_stepup      = 0.0
        v2_bonus_pool_total  = bonus_max
        v2_step_up_balance   = 0.0

    return JSONResponse({
        "seats": grid_seats,
        "filled": len(grid_seats),
        "total": ((grid_record.total_seats if grid_record else None) or 16),
        "tier": tier,
        "price": GRID_PACKAGES.get(tier, 0),
        "advance": grid_record.advance_number if grid_record else completed + 1,
        "completed_advances": completed,
        "total_downline": total_downline,
        "bonus_accrued": bonus_accrued,
        "bonus_max": bonus_max,
        # Commission breakdown for the redesigned visualiser
        "direct_earned": round(direct_earned, 2),
        "unilevel_earned": round(unilevel_earned, 2),
        "completion_bonus_paid": round(completion_bonus_paid, 2),
        "completion_bonus_count": completion_bonus_count,
        "total_earned": round(total_earned, 2),
        "direct_fills": direct_fills,
        "unilevel_fills": unilevel_fills,
        "direct_per_fill": v2_direct_per_fill,
        "unilevel_per_fill": v2_unilevel_per_fill,
        "direct_count": direct_count,
        "completed_grids": completed_grids_detail,
        # ── Plan-aware fields (v1 page ignores these; v2 page reads them) ──
        "plan_version": plan_version,
        "unilevel_levels": v2_unilevel_levels,
        "welcome_per_fill": v2_welcome_per_fill,
        "bonus_positions": v2_bonus_positions,
        "bonus_per_position": v2_bonus_per_pos,
        "bonus_cash_per_position": v2_bonus_cash,
        "bonus_stepup_per_position": v2_bonus_stepup,
        "bonus_pool_total": v2_bonus_pool_total,
        "step_up_balance": v2_step_up_balance,
        "bonus_cash_earned": round(v2_bonus_cash_earned, 2),
        "bonus_stepup_earned": round(v2_bonus_stepup_earned, 2),
        "welcome_earned": round(v2_welcome_earned, 2),
    })


# ────────────────────────────────────────────────────────────────────
# Grid Earnings Verification — admin-only diagnostic endpoint (21 May 2026)
#
# Reconciles what the Grid Visualiser page shows against the raw
# Commission ledger, broken down by tier. Built to let Steve sanity-
# check the numbers before using the page in marketing material.
#
# Returns three things:
#   1. Per-tier breakdown matching what the Visualiser shows (same
#      filter logic — direct_sponsor + uni_level commissions, filtered
#      by to_user_id and package_tier)
#   2. Grand totals across all 8 Grid tiers
#   3. Wallet reconciliation: current balance + lifetime withdrawn,
#      with the Grid-stream total as a percentage of the combined
#      total (so you can sanity-check that Grid is a reasonable
#      slice of overall earnings)
#
# Admin-only (returns 403 to non-admins) — this is a diagnostic, not
# a member-facing feature.
# ────────────────────────────────────────────────────────────────────
@app.get("/admin/grid-earnings-verification")
def admin_grid_earnings_verification(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    from sqlalchemy import func as _func
    from .database import GRID_COMPLETION_BONUS

    breakdown = []
    grand_direct = 0.0
    grand_unilevel = 0.0
    grand_bonus = 0.0
    grand_direct_fills = 0
    grand_unilevel_fills = 0

    for tier in range(0, 9):
        # Direct-sponsor commissions at this tier
        d_row = db.query(
            _func.coalesce(_func.sum(Commission.amount_usdt), 0),
            _func.count(Commission.id),
        ).filter(
            Commission.to_user_id == user.id,
            Commission.commission_type == "direct_sponsor",
            Commission.package_tier == tier,
        ).first()
        d_amount = float(d_row[0] or 0) if d_row else 0
        d_count  = int(d_row[1] or 0) if d_row else 0

        # Uni-level commissions at this tier
        u_row = db.query(
            _func.coalesce(_func.sum(Commission.amount_usdt), 0),
            _func.count(Commission.id),
        ).filter(
            Commission.to_user_id == user.id,
            Commission.commission_type == "uni_level",
            Commission.package_tier == tier,
        ).first()
        u_amount = float(u_row[0] or 0) if u_row else 0
        u_count  = int(u_row[1] or 0) if u_row else 0

        # Grid completion bonuses earned at this tier (separate type)
        b_row = db.query(
            _func.coalesce(_func.sum(Commission.amount_usdt), 0),
            _func.count(Commission.id),
        ).filter(
            Commission.to_user_id == user.id,
            Commission.commission_type == "grid_completion_bonus",
            Commission.package_tier == tier,
        ).first()
        b_amount = float(b_row[0] or 0) if b_row else 0
        b_count  = int(b_row[1] or 0) if b_row else 0

        # Active grid status at this tier (for context)
        active_grid = db.query(Grid).filter(
            Grid.owner_id == user.id,
            Grid.package_tier == tier,
            Grid.is_complete == False,
        ).first()
        completed_at_tier = db.query(Grid).filter(
            Grid.owner_id == user.id,
            Grid.package_tier == tier,
            Grid.is_complete == True,
        ).count()
        positions_in_active = 0
        if active_grid:
            positions_in_active = db.query(GridPosition).filter(
                GridPosition.grid_id == active_grid.id,
            ).count()

        tier_total = round(d_amount + u_amount + b_amount, 2)

        breakdown.append({
            "tier": tier,
            "price": GRID_PACKAGES.get(tier, 0),
            "direct_referral": {
                "earned": round(d_amount, 2),
                "fills": d_count,
                "per_fill_expected": round(GRID_PACKAGES.get(tier, 0) * 0.30, 2),
            },
            "uni_level": {
                "earned": round(u_amount, 2),
                "fills": u_count,
                "per_fill_expected": round(GRID_PACKAGES.get(tier, 0) * 0.0625, 2),
            },
            "completion_bonus": {
                "earned": round(b_amount, 2),
                "advances_completed": b_count,
                "per_advance_expected": completion_bonus_for(NEW_GRID_SEATS, GRID_PACKAGES.get(tier, 0)),
            },
            "tier_total": tier_total,
            "active_grid": {
                "exists": bool(active_grid),
                "positions_filled": positions_in_active,
                "advance_number": active_grid.advance_number if active_grid else None,
                "bonus_accrued": float(active_grid.bonus_pool_accrued or 0) if active_grid else 0,
            },
            "completed_advances_at_tier": completed_at_tier,
        })

        grand_direct += d_amount
        grand_unilevel += u_amount
        grand_bonus += b_amount
        grand_direct_fills += d_count
        grand_unilevel_fills += u_count

    grid_lifetime_total = round(grand_direct + grand_unilevel + grand_bonus, 2)

    # Wallet reconciliation
    current_balance = float(user.balance or 0)
    current_campaign_balance = float(user.campaign_balance or 0)

    # Total successfully withdrawn (status='paid' rows in withdrawals)
    withdrawn_row = db.query(
        _func.coalesce(_func.sum(Withdrawal.amount_usdt), 0),
    ).filter(
        Withdrawal.user_id == user.id,
        Withdrawal.status == "paid",
    ).first()
    total_withdrawn = float(withdrawn_row[0] or 0) if withdrawn_row else 0

    # Total of ALL commissions ever (all types — Grid + Nexus + course
    # + membership) for cross-check
    all_comm_row = db.query(
        _func.coalesce(_func.sum(Commission.amount_usdt), 0),
        _func.count(Commission.id),
    ).filter(
        Commission.to_user_id == user.id,
    ).first()
    all_commissions = float(all_comm_row[0] or 0) if all_comm_row else 0
    all_commissions_count = int(all_comm_row[1] or 0) if all_comm_row else 0

    grid_percent_of_total = round(grid_lifetime_total / all_commissions * 100, 1) if all_commissions > 0 else 0

    return JSONResponse({
        "user": {
            "id": user.id,
            "username": user.username,
        },
        "grand_totals": {
            "grid_lifetime_total": grid_lifetime_total,
            "direct_referral_total": round(grand_direct, 2),
            "direct_referral_fills": grand_direct_fills,
            "uni_level_total": round(grand_unilevel, 2),
            "uni_level_fills": grand_unilevel_fills,
            "completion_bonus_total": round(grand_bonus, 2),
        },
        "per_tier_breakdown": breakdown,
        "wallet_reconciliation": {
            "current_balance_usd": current_balance,
            "current_campaign_balance_usd": current_campaign_balance,
            "lifetime_withdrawn_usd": round(total_withdrawn, 2),
            "lifetime_received_all_streams": round(all_commissions, 2),
            "lifetime_commissions_count": all_commissions_count,
            "grid_stream_percent_of_lifetime": grid_percent_of_total,
            "note": "current_balance_usd is the affiliate wallet (always withdrawable). current_campaign_balance_usd is the campaign wallet (requires active tier + watch quota to spend on ads). lifetime_received_all_streams includes Grid + Nexus matrix + course + membership commissions. balance + campaign_balance + withdrawn = lifetime received minus any failed/refunded payments minus any non-withdrawal deductions (e.g. membership-from-balance activations, campaign deposits).",
        },
        "verification_note": "These are the numbers the /grid-visualiser page sums and displays per tier. If a tier's tier_total here doesn't match what the page shows when that tier tab is selected, there's a query bug. The grid_id filter that originally returned $0 was removed on 21 May 2026 (commit 00f80e5) — now filtered by package_tier + to_user_id + commission_type.",
    })


# ════════════════════════════════════════════════════════════════════
# Custom Domains for SuperPages (21 May 2026)
#
# Per-user CNAME model. Members CNAME pages.theirbrand.com at our
# Railway host, we verify the CNAME, then serve their published pages
# from pages.theirbrand.com/<page-slug> instead of (or in addition to)
# superadpro.com/p/<username>/<page-slug>.
#
# v1 ships free. Member handles TLS via their own Cloudflare. We do
# not run Let's Encrypt automation server-side.
#
# Endpoints:
#   GET    /api/custom-domains             — list current user's domains
#   POST   /api/custom-domains             — claim a new domain
#   POST   /api/custom-domains/{id}/verify — manual re-verify ("Check now")
#   DELETE /api/custom-domains/{id}        — release a domain
#   GET    /cron/verify-custom-domains     — hourly verification scan
# ════════════════════════════════════════════════════════════════════
from .database import CustomDomain
from . import custom_domains as _customdomain_helper


@app.get("/api/custom-domains")
def api_custom_domains_list(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """List the current user's custom domains. Visible to all
    authenticated users so free-tier members see the feature
    exists; the create endpoint is the actual paid-tier gate.

    v2 (25 May 2026): Response now includes per-domain dns_records
    + tls_status so the UI can show the exact CNAME + TXT records
    Railway expects, plus the certificate progression."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    rows = db.query(CustomDomain).filter(
        CustomDomain.user_id == user.id,
    ).order_by(CustomDomain.created_at.desc()).all()
    return JSONResponse({
        "domains":              [_customdomain_to_dict(r) for r in rows],
        "cname_target":         _customdomain_helper.CNAME_TARGET,  # v1 fallback only
        "max_domains_per_user": 3,
        "can_claim":            bool(user.is_active),
        "api_mode":             "v2-railway-api" if _customdomain_railway_configured() else "v1-dns-fallback",
    })


def _customdomain_railway_configured() -> bool:
    """Cheap config check for UI to know whether Railway integration is live."""
    try:
        from . import railway_api as _r
        return _r.is_configured()
    except Exception:
        return False


def _customdomain_to_dict(row: CustomDomain) -> dict:
    """Serialise a CustomDomain row including v2 (Railway) fields.
    dns_records_json is decoded back to a list so the React UI doesn't
    have to JSON.parse it client-side."""
    dns_records = []
    if row.dns_records_json:
        try:
            import json as _json
            dns_records = _json.loads(row.dns_records_json) or []
        except Exception:
            dns_records = []
    return {
        "id":                  row.id,
        "domain":              row.domain,
        "verification_status": row.verification_status,
        "last_error":          row.last_error,
        "last_checked_at":     row.last_checked_at.isoformat() if row.last_checked_at else None,
        "verified_at":         row.verified_at.isoformat() if row.verified_at else None,
        "created_at":          row.created_at.isoformat() if row.created_at else None,
        # v2 fields — Railway API integration
        "tls_status":          row.tls_status,
        "dns_records":         dns_records,
        "railway_registered":  bool(row.railway_domain_id),
    }


@app.post("/api/custom-domains")
def api_custom_domains_create(payload: dict = Body(...), user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Claim a new custom domain. Validates format + uniqueness,
    creates the row in 'pending' state, immediately attempts one
    verification (so common-case 'I CNAMEd already' members see
    instant green). Returns the new row.

    Gating: paid members only (user.is_active = True). Free-tier
    members get a clean "upgrade to claim" message rather than a
    confusing access-denied — the feature exists for serious
    affiliates building their brand."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not user.is_active:
        return JSONResponse({
            "error": "Custom domains are available for active members. Activate your membership to claim a domain.",
            "upgrade_required": True,
        }, status_code=403)

    raw = (payload.get("domain") or "").strip()
    domain = _customdomain_helper.normalize_domain(raw)

    if not domain:
        return JSONResponse({"error": "Domain is required"}, status_code=400)
    if not _customdomain_helper.is_valid_domain_format(domain):
        return JSONResponse({"error": f"'{domain}' isn't a valid domain. Use the form: pages.yourbrand.com"}, status_code=400)
    if _customdomain_helper.is_blocked_domain(domain):
        return JSONResponse({"error": f"'{domain}' cannot be used as a custom domain."}, status_code=400)

    # Uniqueness — across all users, no two members can claim the same host
    existing = db.query(CustomDomain).filter(CustomDomain.domain == domain).first()
    if existing:
        if existing.user_id == user.id:
            return JSONResponse({"error": "You already claimed this domain."}, status_code=400)
        return JSONResponse({"error": "This domain is already claimed by another member."}, status_code=400)

    # Per-user soft cap
    user_count = db.query(CustomDomain).filter(CustomDomain.user_id == user.id).count()
    if user_count >= 3:
        return JSONResponse({"error": "Maximum 3 custom domains per account."}, status_code=400)

    row = CustomDomain(
        user_id=user.id,
        domain=domain,
        verification_status="pending",
    )
    db.add(row)
    db.commit()
    db.refresh(row)

    # Immediate verification attempt — handles the "I already set it up
    # before claiming it on the platform" case so the member sees green
    # the moment they click Save instead of waiting for the hourly cron.
    # In v2 this is also the moment we register the domain with Railway,
    # which kicks off Let's Encrypt issuance.
    _customdomain_helper.verify_one(row, db)
    db.commit()
    db.refresh(row)

    return JSONResponse(_customdomain_to_dict(row))


@app.post("/api/custom-domains/{domain_id}/verify")
def api_custom_domains_verify(domain_id: int, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Manual 'Check now' button — re-runs verification immediately for
    one specific domain. In v2 this polls Railway's API to check the
    current cert/DNS status; the member sees instant feedback after
    configuring DNS at their registrar."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    row = db.query(CustomDomain).filter(
        CustomDomain.id == domain_id,
        CustomDomain.user_id == user.id,
    ).first()
    if not row:
        return JSONResponse({"error": "Domain not found"}, status_code=404)

    _customdomain_helper.verify_one(row, db)
    db.commit()
    db.refresh(row)

    return JSONResponse(_customdomain_to_dict(row))


@app.delete("/api/custom-domains/{domain_id}")
def api_custom_domains_delete(domain_id: int, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Release a custom domain. Member-initiated. Doesn't affect their
    pages — they remain accessible at superadpro.com/p/<username>/<slug>
    as always.

    v2: Also deletes the domain from Railway via GraphQL so we don't
    accumulate orphaned domain registrations (and so members can re-add
    the same domain later if they change their mind). Railway-side delete
    is best-effort — if it fails (e.g. API outage), we still delete our
    DB row and log the orphan for an admin to clean up later."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    row = db.query(CustomDomain).filter(
        CustomDomain.id == domain_id,
        CustomDomain.user_id == user.id,
    ).first()
    if not row:
        return JSONResponse({"error": "Domain not found"}, status_code=404)

    # Best-effort Railway cleanup
    if row.railway_domain_id:
        try:
            from . import railway_api as _rapi
            ok, err = _rapi.delete_custom_domain(row.railway_domain_id)
            if not ok:
                import logging
                logging.getLogger(__name__).warning(
                    f"Railway delete failed for domain {row.domain} (railway_id={row.railway_domain_id}): {err}. "
                    f"Continuing with local delete — manual cleanup may be needed."
                )
        except Exception as e:
            import logging
            logging.getLogger(__name__).warning(f"Railway delete exception: {e}")

    db.delete(row)
    db.commit()
    return JSONResponse({"ok": True})


@app.get("/cron/verify-custom-domains")
def cron_verify_custom_domains(request: Request):
    """Hourly cron — re-verifies all pending custom domains so members
    who set up DNS after claiming get marked verified automatically.
    Protected by CRON_SECRET (same pattern as the other crons)."""
    secret = request.query_params.get("secret")
    if not secret or secret != os.getenv("CRON_SECRET", ""):
        return JSONResponse({"error": "forbidden"}, status_code=403)

    summary = _customdomain_helper.verify_all_pending()
    return JSONResponse(summary)


@app.get("/admin/api/domain-config")
def admin_domain_config(request: Request,
                        user: User = Depends(get_current_user),
                        db: Session = Depends(get_db)):
    """Read-only: is the seamless (auto-TLS) custom-domain path actually
    configured in production? This one switch governs BOTH the blog
    (/api/blog/domain) and SuperPages (/api/custom-domains) — they share the
    same Railway plumbing. Reports only booleans/counts, never secret values.
    Tappable from an admin session: /admin/api/domain-config
    """
    _require_admin(user)
    from . import railway_api as _rapi
    cfg = _rapi._config()
    configured = _rapi.is_configured()

    # Evidence from the DB — has any domain ever actually provisioned?
    total = db.query(CustomDomain).count()
    railway_registered = db.query(CustomDomain).filter(CustomDomain.railway_domain_id.isnot(None)).count()
    tls_issued = db.query(CustomDomain).filter(CustomDomain.tls_status.ilike("%ISSUED%")).count()
    verified = db.query(CustomDomain).filter(CustomDomain.verification_status == "verified").count()

    if not configured:
        verdict = ("Seamless HTTPS is NOT configured — both blog and SuperPages are in fallback "
                   "mode (member sets up TLS themselves). Set the four RAILWAY_* vars in Railway to "
                   "turn it on, or I'll soften the page copy to match.")
    elif tls_issued > 0:
        verdict = ("Seamless HTTPS is configured AND has issued at least one real certificate — "
                   "the blog page's 'we handle the cert' copy is accurate as-is.")
    else:
        verdict = ("Settings are present but no domain has provisioned a certificate yet — "
                   "configured but unproven. Connecting one test domain would confirm it end-to-end.")

    return {
        "seamless_certificates": "ON" if configured else "OFF (fallback mode)",
        "applies_to": "both blog and SuperPages custom domains — same Railway plumbing",
        "railway_env_vars_present": {
            "RAILWAY_API_TOKEN":      bool(cfg.get("token")),
            "RAILWAY_PROJECT_ID":     bool(cfg.get("project_id")),
            "RAILWAY_SERVICE_ID":     bool(cfg.get("service_id")),
            "RAILWAY_ENVIRONMENT_ID": bool(cfg.get("environment_id")),
        },
        "evidence": {
            "total_custom_domains":    total,
            "registered_with_railway": railway_registered,
            "tls_certificate_issued":  tls_issued,
            "dns_verified":            verified,
        },
        "verdict": verdict,
    }


# ════════════════════════════════════════════════════════════════════
# SENDING DOMAINS — per-member email sending domains (29 Jun 2026)
# Members verify their OWN domain inside our SES account so they send
# from their own brand. Mirrors the custom-domains endpoints above.
# Gated to active paid members (is_active) — part of the autoresponder
# toolkit. See app/sending_domains.py for the SES verification engine.
# ════════════════════════════════════════════════════════════════════

def _sendingdomain_row_dict(row):
    """Serialise a SendingDomain row for the member UI."""
    import json as _json
    try:
        records = _json.loads(row.dns_records_json or "[]")
    except Exception:
        records = []
    return {
        "id": row.id,
        "domain": row.domain,
        "from_name": row.from_name,
        "from_local": row.from_local or "hello",
        "from_address": f"{row.from_local or 'hello'}@{row.domain}",
        "status": row.status,
        "identity_status": row.identity_status,
        "dkim_status": row.dkim_status,
        "dns_records": records,
        "last_error": row.last_error,
        "verified_at": row.verified_at.isoformat() if row.verified_at else None,
        "created_at": row.created_at.isoformat() if row.created_at else None,
    }


@app.get("/api/sending-domains")
def api_sending_domains_list(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """List the member's sending domains + their DNS records and status."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from .database import SendingDomain
    from . import sending_domains as _sd
    rows = db.query(SendingDomain).filter(
        SendingDomain.user_id == user.id
    ).order_by(SendingDomain.created_at.desc()).all()
    return JSONResponse({
        "domains": [_sendingdomain_row_dict(r) for r in rows],
        "ses_ready": _sd.is_configured(),
    })


@app.post("/api/sending-domains")
def api_sending_domains_create(payload: dict = Body(...), user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Add a new sending domain. Validates, creates the row, then provisions
    with SES (generates DKIM tokens + the DNS records the member must add).
    Gated to active paid members.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not user.is_active:
        return JSONResponse({
            "error": "Sending domains are available for active members. Activate your membership to send from your own brand.",
            "upgrade_required": True,
        }, status_code=403)

    from .database import SendingDomain
    from . import sending_domains as _sd

    raw = (payload.get("domain") or "").strip()
    domain = _sd.normalize_domain(raw)
    ok, err = _sd.is_valid_sending_domain(domain)
    if not ok:
        return JSONResponse({"error": err}, status_code=400)

    # Uniqueness across the platform (one SES identity per domain)
    existing = db.query(SendingDomain).filter(SendingDomain.domain == domain).first()
    if existing:
        if existing.user_id == user.id:
            return JSONResponse({"error": "You've already added this domain."}, status_code=400)
        return JSONResponse({"error": "This domain is already in use by another member."}, status_code=400)

    # Per-user soft cap
    count = db.query(SendingDomain).filter(SendingDomain.user_id == user.id).count()
    if count >= 3:
        return JSONResponse({"error": "Maximum 3 sending domains per account."}, status_code=400)

    from_name = (payload.get("from_name") or "").strip() or (user.first_name or user.username)
    from_local = (payload.get("from_local") or "").strip().lower() or "hello"

    row = SendingDomain(
        user_id=user.id,
        domain=domain,
        from_name=from_name,
        from_local=from_local,
        status="pending",
    )
    db.add(row)
    db.commit()
    db.refresh(row)

    # Provision with SES — generates the DKIM tokens + DNS records to show.
    prov_ok, prov_msg = _sd.provision_domain(row, db)
    db.refresh(row)
    resp = _sendingdomain_row_dict(row)
    resp["provisioned"] = prov_ok
    resp["message"] = prov_msg
    if not prov_ok and not _sd.is_configured():
        resp["ses_not_configured"] = True
    return JSONResponse(resp, status_code=201)


