@app.get("/admin/rotator-audit")
def admin_rotator_audit(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Inspect the rotator_queue and verify every active Founder is enrolled.

    Returns three lists:
      - queue: full rotator queue sorted by queue_position (the order the
        /start funnel will serve new signups in)
      - founders_missing_from_queue: active Founders who are NOT in the
        queue (something went wrong with their enrolment)
      - non_founders_in_queue: queue members who aren't Founders (rare;
        usually only legacy data)
    """
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "forbidden", "detail": "admin login required"}, status_code=403)

    # Full queue with user details
    queue_rows = db.execute(text("""
        SELECT rq.user_id, rq.queue_position, rq.joined_at,
               u.username, u.is_active, u.is_founding_member,
               u.founding_spot_number, u.rotator_opted_in
          FROM rotator_queue rq
          LEFT JOIN users u ON u.id = rq.user_id
         ORDER BY rq.queue_position ASC
    """)).fetchall()

    queue = [
        {
            "user_id":              r[0],
            "queue_position":       r[1],
            "joined_at":            r[2].isoformat() if r[2] else None,
            "username":             r[3],
            "is_active":            bool(r[4]) if r[4] is not None else None,
            "is_founding_member":   bool(r[5]) if r[5] is not None else None,
            "founding_spot_number": r[6],
            "rotator_opted_in":     bool(r[7]) if r[7] is not None else None,
        }
        for r in queue_rows
    ]

    # Active Founders not in queue
    missing_rows = db.execute(text("""
        SELECT u.id, u.username, u.founding_spot_number,
               u.is_active, u.rotator_opted_in
          FROM users u
          LEFT JOIN rotator_queue rq ON rq.user_id = u.id
         WHERE u.is_active = TRUE
           AND u.is_founding_member = TRUE
           AND COALESCE(u.is_admin, FALSE) = FALSE
           AND rq.user_id IS NULL
         ORDER BY u.founding_spot_number NULLS LAST, u.id
    """)).fetchall()

    missing = [
        {
            "user_id":              r[0],
            "username":             r[1],
            "founding_spot_number": r[2],
            "is_active":            bool(r[3]) if r[3] is not None else None,
            "rotator_opted_in":     bool(r[4]) if r[4] is not None else None,
        }
        for r in missing_rows
    ]

    # Non-Founders sitting in queue (shouldn't normally happen)
    extra_rows = db.execute(text("""
        SELECT rq.user_id, u.username, u.is_founding_member, u.is_active
          FROM rotator_queue rq
          LEFT JOIN users u ON u.id = rq.user_id
         WHERE COALESCE(u.is_founding_member, FALSE) = FALSE
    """)).fetchall()

    extras = [
        {
            "user_id":            r[0],
            "username":           r[1],
            "is_founding_member": bool(r[2]) if r[2] is not None else None,
            "is_active":          bool(r[3]) if r[3] is not None else None,
        }
        for r in extra_rows
    ]

    return JSONResponse({
        "queue_size":                   len(queue),
        "queue":                        queue,
        "founders_missing_from_queue":  missing,
        "non_founders_in_queue":        extras,
    })


@app.get("/admin/promote-partner-to-founder/{user_id}")
def admin_promote_partner_to_founder(
    user_id: int,
    reason: str = "policy: first-100 signup was meant to be Founder",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Promote an active Partner to Founder.

    Atomic spot claim using the same pg_advisory_xact_lock the regular
    Founder signup flow uses (lock key 7423957) so concurrent admin
    actions can't double-claim a spot.

    Sets:
      is_founding_member  = True
      founding_spot_number = next available
      membership_price_locked = 15.00
      membership_tier     = "founding"
    Also enrols them in the rotator (idempotent) and writes a
    Notification + log entry for audit.

    Refuses if:
      - User not found
      - User isn't currently active
      - User is already a Founder
      - All 100 Founder spots are claimed
    """
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "forbidden", "detail": "admin login required"}, status_code=403)

    target = db.query(User).filter(User.id == user_id).first()
    if not target:
        return JSONResponse({"error": f"user {user_id} not found"}, status_code=404)
    if not target.is_active:
        return JSONResponse({
            "error": "user_not_active",
            "detail": "Only active Partners can be promoted to Founder",
        }, status_code=400)
    if target.is_founding_member:
        return JSONResponse({
            "ok": True,
            "noop": True,
            "reason": "user is already a Founder",
            "user_id": target.id,
            "username": target.username,
            "founding_spot_number": target.founding_spot_number,
        })

    from decimal import Decimal
    FOUNDING_TOTAL = 100
    FOUNDING_LOCK_KEY = 7423957

    # Atomic spot claim — same key as the regular Founder signup gate
    db.execute(text("SELECT pg_advisory_xact_lock(:k)"), {"k": FOUNDING_LOCK_KEY})

    current = db.execute(text(
        "SELECT COUNT(*) AS cnt FROM users WHERE is_founding_member = TRUE"
    )).fetchone()
    current_count = current.cnt if current else 0
    if current_count >= FOUNDING_TOTAL:
        return JSONResponse({
            "error": "no_spots_remaining",
            "detail": f"All {FOUNDING_TOTAL} Founder spots are claimed",
            "current_count": current_count,
        }, status_code=400)

    next_spot = current_count + 1

    # Apply Founder status
    target.is_founding_member       = True
    target.founding_spot_number     = next_spot
    target.membership_price_locked  = Decimal("15.00")
    target.membership_tier          = "founding"
    db.flush()

    # Idempotent rotator enrolment so they start receiving distributed signups
    try:
        _enrol_user_to_rotator(db, target.id)
    except Exception:
        logger.exception(f"promote-to-founder: rotator enrol failed for user {target.id} — non-fatal")

    # Audit notification on the target's account
    try:
        from .database import Notification
        db.add(Notification(
            user_id=target.id,
            type="account",
            icon="👑",
            title=f"You're now Founder #{next_spot}",
            message=(
                f"Welcome to the Founder cohort. Your monthly membership is now locked "
                f"at $15/month for life. This was applied because you were one of the "
                f"first 100 members to join SuperAdPro."
            ),
            link="/dashboard",
        ))
    except Exception:
        logger.exception("promote-to-founder: notification write failed — non-fatal")

    db.commit()
    db.refresh(target)

    logger.warning(
        f"PROMOTION: user {target.id} ({target.username}) promoted to "
        f"Founder #{next_spot} by admin {user.id} ({user.username}). Reason: {reason}"
    )

    return JSONResponse({
        "ok": True,
        "promoted": True,
        "user_id":  target.id,
        "username": target.username,
        "is_founding_member":     target.is_founding_member,
        "founding_spot_number":   target.founding_spot_number,
        "membership_price_locked": str(target.membership_price_locked),
        "membership_tier":        target.membership_tier,
        "promoted_by_admin":      user.username,
        "reason":                 reason,
        "spots_remaining_after":  FOUNDING_TOTAL - next_spot,
    })


@app.post("/cron/stripe-recover-user")
def cron_stripe_recover_user(request: Request, payload: dict = Body(...), db: Session = Depends(get_db)):
    """Activate a user who paid Stripe but is stuck on free tier.

    Body:
      secret:           CRON_SECRET (string)
      user_id:          int — the SuperAdPro user ID
      tier:             "founding" | "partner" (string, optional, default "founding")
      stripe_session_id:  cs_live_... (string, optional, for audit)
      stripe_subscription_id:  sub_... (string, optional, for audit)
      stripe_payment_intent_id: pi_... (string, optional, for audit)
      amount_cents:     int (optional, default 1500 for founder, 2000 for partner)

    Logic:
      - Reject if secret wrong
      - Look up user; reject if not found OR already active
      - Call _activate_membership with source='stripe-manual-recovery'
      - Write a StripeCharge audit row so the reconciliation tool sees the recovery
    """
    secret = (payload or {}).get("secret", "")
    if not secret or secret != os.getenv("CRON_SECRET", ""):
        return JSONResponse({"error": "forbidden"}, status_code=403)

    try:
        user_id = int(payload.get("user_id", 0))
    except Exception:
        return JSONResponse({"error": "user_id is required and must be int"}, status_code=400)
    if user_id <= 0:
        return JSONResponse({"error": "user_id is required"}, status_code=400)

    user = db.query(User).filter(User.id == user_id).first()
    if not user:
        return JSONResponse({"error": f"user {user_id} not found"}, status_code=404)

    if user.is_active:
        return JSONResponse({
            "ok": True,
            "noop": True,
            "reason": "user already active",
            "user_id": user.id,
            "username": user.username,
            "is_active": True,
            "membership_tier": user.membership_tier,
            "is_founding_member": bool(user.is_founding_member),
            "founding_spot_number": user.founding_spot_number,
        })

    tier_input = (payload.get("tier") or "founding").lower()
    tier_for_activation = "founding" if tier_input in ("founder", "founding") else "partner"

    # Default amounts: founder $15, partner $20
    default_amount = 1500 if tier_for_activation == "founding" else 2000
    try:
        amount_cents = int(payload.get("amount_cents", default_amount))
    except Exception:
        amount_cents = default_amount

    session_id    = payload.get("stripe_session_id") or None
    sub_id        = payload.get("stripe_subscription_id") or None
    pi_id         = payload.get("stripe_payment_intent_id") or None

    try:
        _activate_membership(
            db=db,
            user=user,
            tier=tier_for_activation,
            source="stripe-manual-recovery",
            subscription_id=sub_id,
            is_upgrade=False,
            billing="monthly",
        )
    except Exception as e:
        logger.exception(f"stripe-recover-user: _activate_membership failed for user {user_id}")
        return JSONResponse({"error": "activation_failed", "detail": str(e)}, status_code=500)

    # Audit charge row — mirrors what checkout.session.completed would have written
    product_kind = "founder_signup" if tier_for_activation == "founding" else "membership_signup"
    try:
        company_share, refundable = _stripe.calculate_refundable(product_kind, amount_cents)
    except Exception:
        company_share, refundable = 0, amount_cents

    charge = StripeCharge(
        user_id=user.id,
        stripe_session_id=session_id,
        stripe_subscription_id=sub_id,
        stripe_payment_intent_id=pi_id,
        kind="charge",
        product=product_kind,
        amount_cents=amount_cents,
        currency="usd",
        company_share_cents=company_share,
        refundable_cents=refundable,
        description=f"Manual recovery via /cron/stripe-recover-user (missed checkout.session.completed)",
        raw_event_json=None,
    )
    db.add(charge)
    user.stripe_refund_eligible_until = _stripe.refund_window_expiry()
    user.payment_method = "stripe"
    db.commit()
    db.refresh(user)

    return JSONResponse({
        "ok": True,
        "recovered": True,
        "user_id": user.id,
        "username": user.username,
        "is_active": user.is_active,
        "membership_tier": user.membership_tier,
        "is_founding_member": bool(user.is_founding_member),
        "founding_spot_number": user.founding_spot_number,
        "activated_at": user.activated_at.isoformat() if user.activated_at else None,
        "charge_id": charge.id,
    })


# ════════════════════════════════════════════════════════════════════
# Host-based routing for custom domains.
#
# When a request arrives with a Host header that isn't one of our
# platform hosts (superadpro.com / *.railway.app), look up the
# CustomDomain row, find the user, and resolve the URL path to one
# of their FunnelPages. If the path is /, serve their first published
# page; otherwise serve the page matching slug "<username>/<path>".
#
# Implementation: a single catch-all route that fires before the
# generic 404 handler. We register it late so it never shadows real
# routes — only catches what would otherwise 404 on our normal host
# AND happens to arrive with a non-platform Host header.
# ════════════════════════════════════════════════════════════════════
PLATFORM_HOSTS = {
    "superadpro.com",
    "www.superadpro.com",
    "app.superadpro.com",
    "api.superadpro.com",
    "localhost",
    "127.0.0.1",
}


def _is_platform_host(host: str) -> bool:
    """True if the request Host header is one of our own hosts (so we
    fall through to normal routing)."""
    if not host:
        return True
    h = host.split(":", 1)[0].lower().strip()
    if h in PLATFORM_HOSTS:
        return True
    if h.endswith(".railway.app") or h.endswith(".up.railway.app"):
        return True
    return False


@app.middleware("http")
async def custom_domain_router(request: Request, call_next):
    """If the request arrives with a custom-domain Host header, rewrite
    the URL path to /p/<username>/<page-slug> so the existing
    render_funnel_page handler serves the right page. Falls through
    to normal routing for platform hosts and for unverified domains."""
    host = request.headers.get("host", "")
    if _is_platform_host(host):
        return await call_next(request)

    host_clean = host.split(":", 1)[0].lower().strip()

    # Look up the CustomDomain — read-only, fast index lookup
    db = SessionLocal()
    try:
        row = db.query(CustomDomain).filter(
            CustomDomain.domain == host_clean,
            CustomDomain.verification_status == "verified",
        ).first()
        if not row:
            db.close()
            return await call_next(request)

        owner = db.query(User).filter(User.id == row.user_id).first()
        if not owner:
            db.close()
            return await call_next(request)

        # Blog binding takes precedence: if a Blog is attached to this domain,
        # serve the blog (feed/posts/pages) rather than funnel pages. We rewrite
        # the path to /sites/{slug}{tail} and flag blog_host so the blog handlers
        # render root-relative links + custom-domain canonicals.
        bound_blog = db.query(Blog).filter(Blog.custom_domain_id == row.id).first()
        if bound_blog:
            db.close()
            tail = request.url.path
            request.scope["path"] = f"/sites/{bound_blog.subdomain_slug}" + ("" if tail == "/" else tail)
            request.scope["raw_path"] = request.scope["path"].encode()
            request.scope["blog_host"] = host_clean
            return await call_next(request)

        # Resolve path → page
        path = request.url.path.lstrip("/")
        if not path:
            # Root request on the custom domain: serve owner's first
            # published page (the "home" of their custom-domain site).
            first_page = db.query(FunnelPage).filter(
                FunnelPage.user_id == owner.id,
                FunnelPage.status == "published",
            ).order_by(FunnelPage.id.asc()).first()
            if not first_page:
                db.close()
                return HTMLResponse(
                    "<h1>No published pages yet</h1>"
                    "<p>This site is set up but the owner hasn't published a page yet.</p>",
                    status_code=404,
                )
            db.close()
            # Internal rewrite: forward to /p/<username>/<slug-tail>
            slug_tail = first_page.slug.split("/", 1)[1] if "/" in first_page.slug else first_page.slug
            request.scope["path"] = f"/p/{owner.username}/{slug_tail}"
            request.scope["raw_path"] = request.scope["path"].encode()
            return await call_next(request)

        # Specific path on the custom domain: serve owner's page with
        # matching slug tail. Slug format is "username/page-name", so
        # we prepend the owner's username before lookup.
        db.close()
        request.scope["path"] = f"/p/{owner.username}/{path}"
        request.scope["raw_path"] = request.scope["path"].encode()
        return await call_next(request)
    except Exception as e:
        try:
            db.close()
        except Exception:
            pass
        # Don't break the request on an unexpected error in the router —
        # fall through to normal routing and log
        import traceback
        try:
            print(f"⚠️ custom_domain_router error for host={host_clean}: {e}\n{traceback.format_exc()}")
        except Exception:
            pass
        return await call_next(request)



