@app.post("/register")
@limiter.limit("5/minute")
def register_process(
    request: Request,
    first_name:       str  = Form(),
    username:         str  = Form(),
    email:            str  = Form(),
    password:         str  = Form(),
    confirm_password: str  = Form(),
    ref:              str  = Form(""),
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    # Pre-launch registration gate REMOVED 10 May 2026 (launch day).
    # Was: blocked all non-admin signups. Now: open to everyone.
    # Orphan signups (no ref) fall through to the SuperAdPro company
    # account at line ~3346 below.

    # ── Maintenance gate (hard only) ──
    # Signups are halted in hard maintenance because they may trigger
    # commission writes, gift-voucher redemption, and other money flows
    # in the activation path.
    if is_hard_maintenance(db):
        return JSONResponse(
            {"error": "Registration is temporarily paused while we resolve a platform issue. Please try again shortly."},
            status_code=503,
        )

    username   = sanitize(username)
    email      = sanitize(email)
    first_name = sanitize(first_name)
    ref        = sanitize(ref)

    def err(msg):
        return JSONResponse({"error": msg}, status_code=400)

    if not first_name.strip():
        return err("Please enter your first name.")
    if not validate_username(username):
        return err("Username must be 3–30 characters, letters, numbers and underscores only.")
    if not validate_email(email):
        return err("Please enter a valid email address.")
    if is_disposable_email(email):
        return err("Please register with a permanent email address — disposable or test addresses aren't accepted.")
    if len(password) < 8:
        return err("Password must be at least 8 characters.")
    if len(password.encode("utf-8")) > 72:
        return err("Password must be 72 characters or less.")
    if password != confirm_password:
        return err("Passwords do not match.")

    existing = db.query(User).filter(
        (User.username == username) | (User.email == email)
    ).first()
    if existing:
        return err("Username or email already registered.")

    sponsor_id = None
    if ref:
        sponsor = db.query(User).filter(User.username == ref).first()
        if sponsor:
            sponsor_id = sponsor.id
            # Atomic SQL increment to avoid lost updates when multiple
            # signups land on the same sponsor in the same millisecond.
            # Read-modify-write would otherwise race between replicas.
            from sqlalchemy import func as _sqlfunc
            db.query(User).filter(User.id == sponsor_id).update(
                {User.total_team: _sqlfunc.coalesce(User.total_team, 0) + 1},
                synchronize_session=False,
            )
    
    # Default to company account if no sponsor
    if not sponsor_id:
        company = db.query(User).filter(User.username == "SuperAdPro").first()
        if company:
            sponsor_id = company.id
            from sqlalchemy import func as _sqlfunc
            db.query(User).filter(User.id == sponsor_id).update(
                {User.total_team: _sqlfunc.coalesce(User.total_team, 0) + 1},
                synchronize_session=False,
            )

    # GeoIP: derive country ISO + country name from signup IP.
    # Feeds /explore activity feed + any country-targeted features.
    # Currently only GeoLite2-Country.mmdb is available → country-level only (no city).
    # display_city stores the country NAME as a readable label for the public feed.
    signup_country_iso = ""
    signup_country_name = ""
    try:
        from app.database import _geoip_reader
        client_ip = request.headers.get("x-forwarded-for", "").split(",")[0].strip() or request.client.host
        if _geoip_reader and client_ip not in ("127.0.0.1", "::1", "localhost"):
            geo = _geoip_reader.country(client_ip)
            signup_country_iso = geo.country.iso_code or ""
            signup_country_name = geo.country.name or ""
    except Exception:
        pass

    user = create_user(
        db, username, email, password,
        sponsor_id=sponsor_id,
        first_name=first_name,
        last_name="",
        wallet_address="",
        country=signup_country_iso,
    )
    if signup_country_name:
        user.display_city = signup_country_name

    # Assign pass-up sponsor for course commission chain
    if sponsor_id:
        sponsor_obj = db.query(User).filter(User.id == sponsor_id).first()
        assign_passup_sponsor(db, user, sponsor_obj)

    db.commit()

    # ── Post-registration notifications ──

    # 0. Welcome the NEW MEMBER by email (was missing on this path — only
    #    api_register sent it, so free signups via register_process got
    #    silence. Fires the free-signup-accurate welcome. Fails silently so
    #    a send error never breaks registration.)
    try:
        from app.email_utils import send_welcome_free_email
        send_welcome_free_email(email, first_name, username)
    except Exception as e:
        logger.warning(f"Free welcome email failed for {email}: {e}")

    # 1. Email the sponsor: "New member joined your team!"
    if sponsor_id:
        try:
            sponsor_obj = db.query(User).filter(User.id == sponsor_id).first()
            if sponsor_obj and sponsor_obj.email:
                from .email_utils import send_email
                send_email(
                    to_email=sponsor_obj.email,
                    subject=f"🎉 {first_name} just joined your SuperAdPro team!",
                    html_body=f"""
                    <div style="font-family:Helvetica Neue,Arial,sans-serif;max-width:560px;margin:0 auto;padding:32px 24px;">
                        <div style="background:linear-gradient(135deg,#0f1d3a,#172554);border-radius:16px;padding:24px;margin-bottom:20px;">
                            <div style="display:flex;align-items:center;gap:10px;margin-bottom:20px;">
                                <div style="width:36px;height:36px;border-radius:50%;background:linear-gradient(135deg,#0ea5e9,#6366f1);text-align:center;line-height:36px;font-size:16px;color:#fff;font-weight:900;padding-left:2px;">&#9654;</div>
                                <span style="font-size:18px;font-weight:900;color:#fff;">Super</span><span style="font-size:18px;font-weight:900;color:#0ea5e9;">Ad</span><span style="font-size:18px;font-weight:900;color:#a78bfa;">Pro</span>
                            </div>
                            <div style="text-align:center;padding:16px 0;">
                                <div style="font-size:42px;margin-bottom:12px;">🎉</div>
                                <h1 style="color:#fff;font-size:22px;font-weight:800;margin:0 0 8px;">New Team Member!</h1>
                                <p style="color:rgba(255,255,255,.6);font-size:15px;margin:0;line-height:1.6;">
                                    <strong style="color:#38bdf8;">{first_name}</strong> ({username}) just joined through your referral link.
                                </p>
                            </div>
                        </div>
                        <div style="background:#f8fafc;border-radius:12px;padding:20px 24px;margin-bottom:20px;">
                            <p style="font-size:14px;color:#334155;line-height:1.7;margin:0 0 12px;">
                                Welcome them with a message in <strong>Team Messenger</strong> — members who connect with their sponsor in the first 24 hours are 5x more likely to stay active.
                            </p>
                            <a href="https://www.superadpro.com/team-messenger" style="display:inline-block;padding:10px 24px;background:#0ea5e9;color:#fff;border-radius:8px;font-weight:700;font-size:14px;text-decoration:none;">Send a Welcome Message →</a>
                        </div>
                        <p style="font-size:12px;color:#94a3b8;text-align:center;">SuperAdPro — AI Marketing & Advertising Platform</p>
                    </div>
                    """,
                    text_body=f"{first_name} ({username}) just joined your SuperAdPro team! Send them a welcome message."
                )
        except Exception:
            pass

    # 2. Auto welcome message from sponsor via Team Messenger
    if sponsor_id:
        try:
            sponsor_obj = db.query(User).filter(User.id == sponsor_id).first()
            if sponsor_obj:
                from .database import TeamMessage
                welcome_msg = TeamMessage(
                    from_user_id=sponsor_id,
                    to_user_id=user.id,
                    message=f"Hey {first_name}! 👋 Welcome to SuperAdPro! I'm {sponsor_obj.first_name or sponsor_obj.username}, your sponsor. If you need any help getting started, just message me here. First steps: set up your profile, check out the Training Centre, and share your referral link to start building your team. Let's go! 🚀",
                    is_read=False,
                )
                db.add(welcome_msg)
                db.commit()
        except Exception:
            pass

    # 3. In-app notification for sponsor
    if sponsor_id:
        try:
            # Sponsor commission is flat $10 under flat-pricing (locked
            # 15 May 2026) regardless of whether the referral is Partner
            # ($20/mo) or Founding ($15/mo locked). Old logic showed
            # $17.50 for 'pro' tier — that tier no longer exists.
            commission = '$10.00'
            create_notification(db, sponsor_id, 'team',
                f'{first_name} joined your team!',
                f'{first_name} ({username}) just signed up through your referral link. You\'ll earn {commission}/month from this referral.',
                icon='🎉', link='/network')
        except Exception:
            pass

    response = RedirectResponse(url="/home-preview", status_code=303)
    set_secure_cookie(response, user.id)
    response.delete_cookie("ref")
    return response

@app.get("/login")
def login_form(request: Request):
    """Phase 2: serve React SPA — React Router handles /login."""
    if _react_index.exists():
        return _spa_shell()
    return RedirectResponse(url="/", status_code=302)

@app.post("/login")
@limiter.limit("10/minute")
def login_process(
    request: Request,
    username: str = Form(), password: str = Form(),
    db: Session = Depends(get_db)
):
    username = sanitize(username)
    if is_locked_out(username):
        return JSONResponse({"error": f"Account locked — too many failed attempts. Try again in {LOCKOUT_MINUTES} minutes."}, status_code=429)
    user = db.query(User).filter(
        (User.username == username) | (User.email == username)
    ).first()
    if user and verify_password(password, user.password):
        clear_failed_attempts(username)
        # Check if 2FA is enabled — require code before granting session
        if getattr(user, 'totp_enabled', False) and user.totp_secret:
            # Store user ID in a temporary pre-auth cookie (not a full session)
            response = RedirectResponse(url="/login/2fa", status_code=303)
            response.set_cookie("pre_auth", str(user.id), max_age=300, httponly=True, samesite="lax")
            return response
        # No 2FA — log in directly
        response = RedirectResponse(url="/home-preview", status_code=303)
        set_secure_cookie(response, user.id)
        return response
    record_failed_attempt(username)
    return JSONResponse({"error": "Invalid username or password."}, status_code=401)
@app.post("/api/login")
@limiter.limit("10/minute")
async def api_login(
    request: Request,
    db: Session = Depends(get_db)
):
    """JSON login endpoint for the modal — returns JSON instead of redirect."""
    from fastapi.responses import JSONResponse
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    username = sanitize(body.get("username", "").strip())
    password = body.get("password", "")

    if is_locked_out(username):
        return JSONResponse({
            "error": f"Account locked — too many failed attempts. Try again in {LOCKOUT_MINUTES} minutes."
        }, status_code=429)

    user = db.query(User).filter(
        (User.username == username) | (User.email == username)
    ).first()

    if user and verify_password(password, user.password):
        clear_failed_attempts(username)
        if getattr(user, 'totp_enabled', False) and user.totp_secret:
            response = JSONResponse({"success": True, "requires_2fa": True, "redirect": "/login/2fa"})
            response.set_cookie("pre_auth", str(user.id), max_age=300, httponly=True, samesite="lax")
            return response
        response = JSONResponse({"success": True, "redirect": "/dashboard"})
        set_secure_cookie(response, user.id)
        return response

    record_failed_attempt(username)
    return JSONResponse({"error": "Invalid username or password."}, status_code=401)
@app.get("/logout")
def logout():
    response = RedirectResponse(url="/")
    response.delete_cookie("session")
    response.delete_cookie("user_id")
    response.delete_cookie("pre_auth")
    return response
@app.post("/api/2fa/verify-login")
@limiter.limit("10/minute")
async def api_2fa_verify_login(request: Request, db: Session = Depends(get_db)):
    """JSON: verify 2FA code during login flow."""
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    import pyotp
    pre_auth = request.cookies.get("pre_auth")
    if not pre_auth:
        return JSONResponse({"error": "Session expired. Please log in again."}, status_code=401)

    user = db.query(User).filter(User.id == int(pre_auth)).first()
    if not user or not user.totp_secret:
        return JSONResponse({"error": "Invalid session."}, status_code=401)

    code = body.get("code", "").strip()
    totp = pyotp.TOTP(user.totp_secret)
    if totp.verify(code, valid_window=1):
        response = JSONResponse({"success": True, "redirect": "/dashboard"})
        set_secure_cookie(response, user.id)
        response.delete_cookie("pre_auth")
        return response
    record_failed_attempt(user.username)
    return JSONResponse({"error": "Invalid code. Please try again."}, status_code=400)
@app.get("/api/2fa/setup")
async def api_2fa_setup(request: Request, user: User = Depends(get_current_user),
                         db: Session = Depends(get_db)):
    """JSON: generate TOTP secret and QR code for setup."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    import pyotp, qrcode, io, base64
    if not user.totp_secret or user.totp_enabled:
        secret = pyotp.random_base32()
        user.totp_secret = secret
        db.commit()
    else:
        secret = user.totp_secret
    totp = pyotp.TOTP(secret)
    uri = totp.provisioning_uri(name=user.email or user.username, issuer_name="SuperAdPro")
    img = qrcode.make(uri)
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    qr_b64 = base64.b64encode(buf.getvalue()).decode()
    return {"qr_b64": qr_b64, "secret": secret, "email": user.email or user.username}
@app.post("/api/2fa/confirm-setup")
async def api_2fa_confirm_setup(request: Request, user: User = Depends(get_current_user),
                                  db: Session = Depends(get_db)):
    """JSON: confirm 2FA setup with a valid code."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    import pyotp
    body = await request.json()
    code = body.get("code", "").strip()
    if not user.totp_secret:
        return JSONResponse({"error": "No secret generated. Please start setup again."}, status_code=400)
    totp = pyotp.TOTP(user.totp_secret)
    if totp.verify(code, valid_window=1):
        user.totp_enabled = True
        db.commit()
        return {"success": True, "message": "2FA enabled successfully"}
    return JSONResponse({"error": "Invalid code. Please try again."}, status_code=400)
@app.post("/api/forgot-password")
@limiter.limit("3/minute")
async def api_forgot_password(request: Request, db: Session = Depends(get_db)):
    """JSON: request a password reset email."""
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)
    email = sanitize(body.get("email", "").strip().lower())
    # Always return success — prevents email enumeration
    if not validate_email(email):
        return JSONResponse({"error": "Please enter a valid email address."}, status_code=400)
    user = db.query(User).filter(User.email == email).first()
    if user:
        db.query(PasswordResetToken).filter(
            PasswordResetToken.user_id == user.id,
            PasswordResetToken.used == False
        ).delete()
        token = secrets.token_hex(32)
        reset_token = PasswordResetToken(
            user_id=user.id, token=token,
            expires_at=datetime.utcnow() + timedelta(hours=1),
        )
        db.add(reset_token)
        db.commit()
        reset_url = f"https://www.superadpro.com/reset-password?token={token}"
        send_password_reset_email(
            to_email=user.email,
            first_name=user.first_name or user.username,
            reset_url=reset_url,
        )
    return {"success": True, "message": "If that email is registered, a reset link has been sent."}
@app.post("/api/reset-password")
@limiter.limit("5/minute")
async def api_reset_password(request: Request, db: Session = Depends(get_db)):
    """JSON: reset password using a valid token."""
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)
    token = body.get("token", "").strip()
    password = body.get("new_password", "") or body.get("password", "")
    confirm = body.get("confirm_password", "")
    if not token:
        return JSONResponse({"error": "Invalid reset link."}, status_code=400)
    reset = db.query(PasswordResetToken).filter(
        PasswordResetToken.token == token,
        PasswordResetToken.used == False
    ).first()
    if not reset or reset.expires_at < datetime.utcnow():
        return JSONResponse({"error": "This reset link has expired. Please request a new one."}, status_code=400)
    if len(password) < 8:
        return JSONResponse({"error": "Password must be at least 8 characters."}, status_code=400)
    if len(password.encode("utf-8")) > 72:
        return JSONResponse({"error": "Password must be 72 characters or less."}, status_code=400)
    if password != confirm:
        return JSONResponse({"error": "Passwords do not match."}, status_code=400)
    import bcrypt
    user = db.query(User).filter(User.id == reset.user_id).first()
    if not user:
        return JSONResponse({"error": "User not found."}, status_code=400)
    user.password = bcrypt.hashpw(password.encode(), bcrypt.gensalt()).decode()
    reset.used = True
    db.commit()
    return {"success": True, "message": "Password reset successfully. You can now log in."}
@app.get("/login/2fa")
def login_2fa_form(request: Request):
    """Phase 2: serve React SPA — React Router handles /login/2fa."""
