@app.get("/api/dashboard/new-members")
def api_new_members(request: Request, since: str = None,
                    user: User = Depends(get_current_user),
                    db: Session = Depends(get_db)):
    """Return new direct referrals since a given timestamp (ISO format).
    Used by dashboard polling for real-time join notifications."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from datetime import datetime, timedelta
    if since:
        try:
            since_dt = datetime.fromisoformat(since.replace('Z', '+00:00')).replace(tzinfo=None)
        except Exception:
            since_dt = datetime.utcnow() - timedelta(minutes=5)
    else:
        since_dt = datetime.utcnow() - timedelta(minutes=5)

    new_members = db.query(User).filter(
        User.sponsor_id == user.id,
        User.is_active == True,
        User.activated_at.isnot(None),
        User.activated_at > since_dt
    ).order_by(User.activated_at.desc()).limit(10).all()

    members = []
    for m in new_members:
        # ── Flat-pricing tier mapping (15 May 2026) ──
        # Under the new model: every paying member is 'partner' tier,
        # with founding members flagged via is_founding_member=True.
        # The 'basic'/'pro' legacy values still exist on some users
        # (rare — pre-migration accounts that didn't get re-tagged) and
        # are mapped to 'partner' for display.
        # Commission is a flat $10/mo regardless of tier (legacy spec
        # had $17.50 for Pro / $10 for Basic; flat-pricing simplified).
        raw_tier = (m.membership_tier or '').lower()
        is_founder = bool(getattr(m, 'is_founding_member', False))
        if is_founder:
            tier = 'founding'
        elif raw_tier in ('partner', 'basic', 'pro'):
            tier = 'partner'
        else:
            tier = raw_tier or 'partner'
        commission = 10.00  # flat sponsor commission under new model
        members.append({
            "id": m.id,
            "username": m.username,
            "first_name": m.first_name or m.username,
            "last_name": m.last_name or '',
            "tier": tier,
            "is_founding_member": is_founder,
            "founding_spot_number": getattr(m, 'founding_spot_number', None),
            "commission": commission,
            "joined_at": m.activated_at.isoformat() if m.activated_at else None,
        })

    return {"members": members, "checked_at": datetime.utcnow().isoformat()}
# ═══════════════════════════════════════════════════════════════
#  NOTIFICATION HELPER (used by registration, commissions, etc.)
# ═══════════════════════════════════════════════════════════════

def create_notification(db, user_id, ntype, title, message, icon="🔔", link=None):
    """Create an in-app notification for a user. Alias for send_notification.
    
    Invalidates the user's cache on creation — matches send_notification's
    behaviour (consolidated 10 May 2026 as part of cache invalidation
    sweep). If commission-type notification, also invalidates leaderboard.
    """
    from .database import Notification
    notif = Notification(
        user_id=user_id, type=ntype, title=title,
        message=message, icon=icon, link=link
    )
    db.add(notif)
    try:
        db.commit()
    except Exception:
        db.rollback()
        return
    # Cache invalidation — only after successful commit. Users who fall
    # through the rollback above don't get cache invalidated, which is
    # correct (nothing changed).
    try:
        cache_invalidate_user(user_id)
        if ntype == "commission":
            cache_invalidate_leaderboard()
    except Exception as e:
        logger.warning(f"cache_invalidate_user({user_id}) failed in create_notification: {e}")
@app.get("/api/analytics")
def api_analytics(request: Request, user: User = Depends(get_current_user),
                  db: Session = Depends(get_db)):
    """Analytics data — earnings trends, breakdowns, grid progress, team growth."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from datetime import datetime, timedelta
    from sqlalchemy import func, cast, Date
    from collections import defaultdict

    now = datetime.utcnow()
    thirty_days_ago = now - timedelta(days=30)
    twelve_weeks_ago = now - timedelta(weeks=12)
    six_months_ago = now - timedelta(days=180)

    # ── Daily earnings (last 30 days) ──
    # Aggregates across all 3 commission tables: Commission (paid_at),
    # CourseCommission (created_at), CreditMatrixCommission (created_at).
    # CreditMatrixCommission added 7 May 2026 — was previously missing,
    # which caused the daily earnings chart to under-report any day a
    # member earned via Credit Nexus.
    daily_commissions = db.query(
        cast(Commission.paid_at, Date).label('day'),
        func.sum(Commission.amount_usdt).label('total')
    ).filter(
        Commission.to_user_id == user.id,
        Commission.paid_at >= thirty_days_ago
    ).group_by(cast(Commission.paid_at, Date)).all()

    daily_courses = db.query(
        cast(CourseCommission.created_at, Date).label('day'),
        func.sum(CourseCommission.amount).label('total')
    ).filter(
        CourseCommission.earner_id == user.id,
        CourseCommission.created_at >= thirty_days_ago
    ).group_by(cast(CourseCommission.created_at, Date)).all()

    daily_matrix = db.query(
        cast(CreditMatrixCommission.created_at, Date).label('day'),
        func.sum(CreditMatrixCommission.amount).label('total')
    ).filter(
        CreditMatrixCommission.earner_id == user.id,
        CreditMatrixCommission.status == 'paid',
        CreditMatrixCommission.created_at >= thirty_days_ago
    ).group_by(cast(CreditMatrixCommission.created_at, Date)).all()

    daily_map = defaultdict(float)
    for row in daily_commissions:
        if row.day:
            daily_map[str(row.day)] += float(row.total or 0)
    for row in daily_courses:
        if row.day:
            daily_map[str(row.day)] += float(row.total or 0)
    for row in daily_matrix:
        if row.day:
            daily_map[str(row.day)] += float(row.total or 0)

    # Build 30-day array
    daily_earnings = []
    for i in range(30):
        d = (now - timedelta(days=29-i)).strftime('%Y-%m-%d')
        daily_earnings.append({"date": d, "amount": round(daily_map.get(d, 0), 2)})

    # ── Income breakdown by type ──
    # IMPORTANT: filter on status='paid' so REVERSED commissions don't inflate
    # the stream cards. Without this, a reversed $X commission keeps showing
    # in the stream-by-type sum but is correctly excluded from total_earned,
    # creating a "streams sum > total earned" visible discrepancy on the
    # Analytics page. Caught 1 May 2026 — SuperAdPro account showed grid
    # stream $30.25 vs total_earned $39 because of one reversed $1.25 row.
    grid_total = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
        Commission.to_user_id == user.id,
        Commission.status == 'paid',
        Commission.commission_type.in_(['direct_sponsor', 'uni_level', 'grid_completion_bonus'])
    ).scalar() or 0)

    membership_total = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
        Commission.to_user_id == user.id,
        Commission.status == 'paid',
        Commission.commission_type.in_(['membership', 'membership_renewal', 'membership_sponsor', 'Membership Sponsor', 'gift_membership_sponsor'])
    ).scalar() or 0)

    course_total = float(db.query(func.coalesce(func.sum(CourseCommission.amount), 0)).filter(
        CourseCommission.earner_id == user.id,
    ).scalar() or 0)

    # SuperMarket placeholder
    supermarket_total = 0

    # Credit Nexus earnings — reads from CreditMatrixCommission (where
    # the actual money lives) plus any legacy Commission rows tagged
    # with matrix_*/nexus_* types. Bug fixed 7 May 2026: previously
    # only looked at Commission table, returning $0 for every modern
    # Credit Nexus earner.
    nexus_legacy = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
        Commission.to_user_id == user.id,
        Commission.status == 'paid',
        Commission.commission_type.in_(['matrix_level', 'matrix_completion', 'nexus_sponsor', 'nexus_level', 'nexus_completion'])
    ).scalar() or 0)
    nexus_matrix = float(db.query(func.coalesce(func.sum(CreditMatrixCommission.amount), 0)).filter(
        CreditMatrixCommission.earner_id == user.id,
        CreditMatrixCommission.status == 'paid',
    ).scalar() or 0)
    nexus_total = nexus_legacy + nexus_matrix

    # ── Grid progress ──
    active_grids = db.query(Grid).filter(
        Grid.owner_id == user.id, Grid.is_complete == False
    ).order_by(Grid.package_tier).all()

    grid_progress = [{
        "tier": g.package_tier,
        "price": float(g.package_price),
        "filled": g.positions_filled,
        "total": g.total_seats,
        "advance": g.advance_number,
        "bonus_pool": float(g.bonus_pool_accrued or 0),
    } for g in active_grids]

    # ── Campaign performance ──
    active_campaigns = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id,
        VideoCampaign.is_completed == False
    ).order_by(VideoCampaign.campaign_tier).all()

    campaigns = [{
        "tier": c.campaign_tier,
        "views_delivered": c.views_delivered or 0,
        "views_target": c.views_target or 0,
        "status": c.status,
    } for c in active_campaigns]

    # ── Team growth (weekly, last 12 weeks) ──
    team_weekly = []
    for w in range(12):
        week_start = now - timedelta(weeks=12-w)
        week_end = now - timedelta(weeks=11-w)
        count = db.query(func.count(User.id)).filter(
            User.sponsor_id == user.id,
            User.created_at >= week_start,
            User.created_at < week_end
        ).scalar() or 0
        team_weekly.append({"week": w+1, "count": count})

    # ── Monthly earnings by stream (last 6 months) ──
    monthly_streams = []
    for m in range(6):
        month_start = (now.replace(day=1) - timedelta(days=30*m)).replace(day=1)
        if m > 0:
            month_end = (now.replace(day=1) - timedelta(days=30*(m-1))).replace(day=1)
        else:
            month_end = now

        m_grid = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == user.id,
            Commission.status == 'paid',
            Commission.commission_type.in_(['direct_sponsor', 'uni_level', 'grid_completion_bonus']),
            Commission.paid_at >= month_start, Commission.paid_at < month_end
        ).scalar() or 0)

        m_memb = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == user.id,
            Commission.status == 'paid',
            Commission.commission_type.in_(['membership', 'membership_renewal', 'membership_sponsor', 'Membership Sponsor', 'gift_membership_sponsor']),
            Commission.paid_at >= month_start, Commission.paid_at < month_end
        ).scalar() or 0)

        m_course = float(db.query(func.coalesce(func.sum(CourseCommission.amount), 0)).filter(
            CourseCommission.earner_id == user.id,
            CourseCommission.created_at >= month_start, CourseCommission.created_at < month_end
        ).scalar() or 0)

        m_nexus = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == user.id,
            Commission.status == 'paid',
            Commission.commission_type.in_(['matrix_level', 'matrix_completion', 'nexus_sponsor', 'nexus_level', 'nexus_completion']),
            Commission.paid_at >= month_start, Commission.paid_at < month_end
        ).scalar() or 0)

        monthly_streams.insert(0, {
            "month": month_start.strftime('%b'),
            "grid": round(m_grid, 2),
            "membership": round(m_memb, 2),
            "courses": round(m_course, 2),
            "supermarket": 0,
            "nexus": round(m_nexus, 2),
        })

    # ── Recent commissions ──
    recent_grid = db.query(Commission).filter(
        Commission.to_user_id == user.id,
        Commission.status != "reversed",
    ).order_by(Commission.created_at.desc()).limit(15).all()

    recent_course = db.query(CourseCommission).filter(
        CourseCommission.earner_id == user.id
    ).order_by(CourseCommission.created_at.desc()).limit(5).all()

    recent = []
    for c in recent_grid:
        from_user = db.query(User).filter(User.id == c.from_user_id).first() if c.from_user_id else None
        recent.append({
            "date": c.created_at.strftime('%b %d') if c.created_at else '',
            "type": c.commission_type or 'unknown',
            "from": ('@' + from_user.username) if from_user else 'System',
            "tier": c.package_tier,
            "amount": float(c.amount_usdt or 0),
        })
    for c in recent_course:
        buyer = db.query(User).filter(User.id == c.buyer_id).first() if c.buyer_id else None
        recent.append({
            "date": c.created_at.strftime('%b %d') if c.created_at else '',
            "type": 'course_' + (c.commission_type or 'sale'),
            "from": ('@' + buyer.username) if buyer else 'System',
            "tier": c.course_tier,
            "amount": float(c.amount or 0),
        })
    recent.sort(key=lambda x: x['date'], reverse=True)

    # ── Watch to Earn stats ──
    from datetime import date as _date
    quota = db.query(WatchQuota).filter(WatchQuota.user_id == user.id).first()
    # daily_required can legitimately be 0 (admin/owner exemption). Use an
    # explicit None-check rather than `or 1` which would coerce 0 to 1.
    _dr = getattr(quota, 'daily_required', None)
    watch_stats = {
        "total_watched": getattr(quota, 'total_watched', 0) or 0,
        "streak_days": getattr(quota, 'streak_days', 0) or 0,
        "today_watched": getattr(quota, 'today_watched', 0) or 0,
        "daily_required": _dr if _dr is not None else 1,
        "consecutive_missed": getattr(quota, 'consecutive_missed', 0) or 0,
        "commissions_paused": getattr(quota, 'commissions_paused', False),
    }

    # Daily watch history (last 30 days, completed watches only)
    daily_watches = []
    for day_offset in range(30):
        d = (now - timedelta(days=29-day_offset)).date()
        count = db.query(func.count(VideoWatch.id)).filter(
            VideoWatch.user_id == user.id,
            VideoWatch.watch_date == str(d),
            VideoWatch.is_complete == True,  # noqa: E712
        ).scalar() or 0
        daily_watches.append({"date": str(d), "count": count})

    # ── Network map — member countries ──
    from sqlalchemy import distinct as _distinct
    all_team_ids = [user.id]
    # Get direct referrals
    direct_refs = db.query(User.id).filter(User.sponsor_id == user.id).all()
    all_team_ids.extend([r[0] for r in direct_refs])
    # Get country distribution for the user's team
    country_data = db.query(
        User.country, func.count(User.id)
    ).filter(
        User.sponsor_id == user.id,
        User.country != None,
        User.country != ""
    ).group_by(User.country).all()
    network_countries = [{"code": c[0] or "??", "count": c[1]} for c in country_data]
    # Add the user's own country (with IP fallback)
    my_country = user.country
    if not my_country:
        try:
            from app.database import _geoip_reader
            client_ip = request.headers.get("x-forwarded-for", "").split(",")[0].strip() or request.client.host
            if _geoip_reader and client_ip not in ("127.0.0.1", "::1", "localhost"):
                geo = _geoip_reader.country(client_ip)
                my_country = geo.country.iso_code
        except Exception:
            pass
    if my_country:
        found = False
        for nc in network_countries:
            if nc["code"] == my_country:
                nc["count"] += 1
                found = True
                break
        if not found:
            network_countries.append({"code": my_country, "count": 1})

    # ── Link clicks summary ──
    from datetime import date as _date_type
    total_clicks = db.query(func.count(LinkClick.id)).filter(
        LinkClick.link_type == "short_link",
    ).join(ShortLink, ShortLink.id == LinkClick.link_id).filter(
        ShortLink.user_id == user.id
    ).scalar() or 0

    # Clicks by device
    device_clicks = db.query(
        LinkClick.device, func.count(LinkClick.id)
    ).join(ShortLink, ShortLink.id == LinkClick.link_id).filter(
        ShortLink.user_id == user.id,
        LinkClick.link_type == "short_link"
    ).group_by(LinkClick.device).all()
    device_breakdown = {(d[0] or "unknown").lower(): d[1] for d in device_clicks}

    # Top countries by clicks
    country_clicks = db.query(
        LinkClick.country_name, func.count(LinkClick.id)
    ).join(ShortLink, ShortLink.id == LinkClick.link_id).filter(
        ShortLink.user_id == user.id,
        LinkClick.link_type == "short_link",
        LinkClick.country_name != None
    ).group_by(LinkClick.country_name).order_by(func.count(LinkClick.id).desc()).limit(5).all()
    top_click_countries = [{"country": c[0], "clicks": c[1]} for c in country_clicks]

    # Clicks last 7 days
    seven_days_ago = now - timedelta(days=7)
    clicks_7d = db.query(func.count(LinkClick.id)).join(
        ShortLink, ShortLink.id == LinkClick.link_id
    ).filter(
        ShortLink.user_id == user.id,
        LinkClick.link_type == "short_link",
        LinkClick.clicked_at >= seven_days_ago
    ).scalar() or 0

    link_stats = {
        "total_clicks": total_clicks,
        "clicks_7d": clicks_7d,
        "devices": device_breakdown,
        "top_countries": top_click_countries,
    }

    # ── Withdrawal summary ──
    total_withdrawn = compute_total_withdrawn(db, user.id)
    last_withdrawal = db.query(Withdrawal).filter(
        Withdrawal.user_id == user.id,
        # 'paid' is the canonical success status set by process_withdrawal.
        # 'completed' is included for any legacy rows from earlier code paths.
        Withdrawal.status.in_(["paid", "completed"])
    ).order_by(Withdrawal.processed_at.desc()).first()
    pending_withdrawals = db.query(func.coalesce(func.sum(Withdrawal.amount_usdt), 0)).filter(
        Withdrawal.user_id == user.id,
        Withdrawal.status == "pending"
    ).scalar() or 0

    withdrawal_stats = {
        "total_withdrawn": round(total_withdrawn, 2),
        "pending": round(float(pending_withdrawals), 2),
        "last_date": last_withdrawal.processed_at.strftime("%b %d, %Y") if last_withdrawal and last_withdrawal.processed_at else None,
        "last_amount": round(float(last_withdrawal.amount_usdt or 0), 2) if last_withdrawal else 0,
    }

    # ── AI tools usage ──
    ai_quota = db.query(AIUsageQuota).filter(AIUsageQuota.user_id == user.id).first()
    ai_usage = {
        "campaign_studio": getattr(ai_quota, "campaign_studio_total", 0) or 0,
        "social_posts": getattr(ai_quota, "social_posts_total", 0) or 0,
        "video_scripts": getattr(ai_quota, "video_scripts_total", 0) or 0,
        "niche_finder": getattr(ai_quota, "niche_finder_total", 0) or 0,
        "total": (getattr(ai_quota, "campaign_studio_total", 0) or 0) +
                 (getattr(ai_quota, "social_posts_total", 0) or 0) +
                 (getattr(ai_quota, "video_scripts_total", 0) or 0) +
                 (getattr(ai_quota, "niche_finder_total", 0) or 0),
    }

    return {
        "daily_earnings": daily_earnings,
        "watch_stats": watch_stats,
        "daily_watches": daily_watches,
        "network_countries": network_countries,
        "link_stats": link_stats,
        "withdrawal_stats": withdrawal_stats,
        "ai_usage": ai_usage,
        "income_breakdown": {
            "grid": round(grid_total, 2),
            "membership": round(membership_total, 2),
            "courses": round(course_total, 2),
            "supermarket": round(supermarket_total, 2),
            "nexus": round(nexus_total, 2),
        },
        "grid_progress": grid_progress,
        "campaigns": campaigns,
        "team_weekly": team_weekly,
        "monthly_streams": monthly_streams,
        "recent_commissions": recent[:15],
        "totals": {
            "balance": float(user.balance or 0), "campaign_balance": float(user.campaign_balance or 0),
            "total_earned": round(grid_total + membership_total + course_total + nexus_total, 2),
            "grid_earnings": round(grid_total, 2),
            "nexus_earnings": round(nexus_total, 2),
            "course_earnings": round(course_total, 2),
            "membership_earnings": round(membership_total, 2),
            "team_size": compute_descendant_counts(db, user.id)["total"],
        }
    }
