@app.get("/api/wallet")
def api_wallet_data(request: Request, user: User = Depends(get_current_user),
                    db: Session = Depends(get_db)):
    """JSON wallet data for React frontend."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    commissions = get_user_commission_history(db, user.id, limit=50)
    withdrawals_raw = db.query(Withdrawal).filter(
        Withdrawal.user_id == user.id
    ).order_by(Withdrawal.requested_at.desc()).limit(20).all()
    renewal = get_renewal_status(db, user.id)
    p2p_history = get_p2p_history(db, user.id, limit=20)
    for t in p2p_history:
        if t.get("created_at"):
            t["created_at"] = t["created_at"].strftime("%d %b %Y %H:%M")
    withdrawals = [{
        "id": w.id, "amount": float(w.amount_usdt or 0),
        "status": w.status, "wallet_address": w.wallet_address,
        "requested_at": w.requested_at.isoformat() if w.requested_at else None,
        "processed_at": w.processed_at.isoformat() if w.processed_at else None,
    } for w in withdrawals_raw]
    _earn = compute_user_earnings(db, user.id)
    return {
        "balance": float(user.balance or 0), "campaign_balance": float(user.campaign_balance or 0),
        "total_earned": _earn["total_earned"],
        "total_withdrawn": compute_total_withdrawn(db, user.id),
        # ── Earnings broken down by source — ALL from the live ledger via
        # compute_user_earnings() so the four numbers always reconcile to
        # total_earned. Previously this endpoint mixed live ledger reads
        # with the legacy `user.level_earnings` denormalised counter,
        # which double-counted uni_level commissions (they live inside
        # grid_earnings AND were re-added via level_earnings) and made
        # the wallet page's "Membership" card a phantom remainder.
        # The data integrity refactor was supposed to kill these
        # denormalised reads — this endpoint had been missed. (2 May 2026)
        "grid_earnings":       _earn["grid_earnings"],        # direct_sponsor + uni_level + grid_completion_bonus
        "membership_earnings": _earn["membership_earnings"],  # membership_sponsor + membership_renewal + ...
        "nexus_earnings":      _earn["nexus_earnings"],       # matrix_level + matrix_completion + nexus_*
        "course_earnings":     _earn["course_earnings"],
        "marketplace_earnings": float(user.marketplace_earnings or 0),
        "membership_tier": user.membership_tier or "free",
        "is_founding_member": bool(getattr(user, "is_founding_member", False)),
        "founding_spot_number": getattr(user, "founding_spot_number", None),
        "wallet_address": user.wallet_address or "",
        "wallet_network": user.wallet_network or "",
        "kyc_status": getattr(user, 'kyc_status', 'none'),
        "watched_today": _wallet_watched_today(db, user),
        "commissions": commissions,
        "withdrawals": withdrawals,
        "renewal": renewal,
        "p2p_history": p2p_history,
    }


def _wallet_watched_today(db, user) -> bool:
    """Has the member met today's one-video Watch-to-Earn requirement? Drives
    the affiliate-wallet withdraw gate (21 Jun 2026) on the wallet page. Mirrors
    validate_affiliate_withdrawal exactly. Admins + watch-exempt always True."""
    if getattr(user, "is_admin", False):
        return True
    from datetime import date as _date
    today_str = str(_date.today())
    q = db.query(WatchQuota).filter(WatchQuota.user_id == user.id).first()
    required = 0 if (q and q.daily_required == 0) else 1
    watched = (q.today_watched or 0) if (q and q.today_date == today_str) else 0
    return watched >= required
