@app.post("/upload")
def upload_video_post(
    request: Request,
    title:       str = Form(),
    video_url:   str = Form(),
    category:    str = Form(""),
    description: str = Form(""),
    target_country: str = Form(""),
    target_interests: str = Form(""),
    cta_url:     str = Form(""),
    db: Session = Depends(get_db),
    user: User  = Depends(get_current_user)
):
    if not user: return JSONResponse({"error": "Not authenticated"}, status_code=401)

    def err(msg):
        return JSONResponse({"error": msg}, status_code=400)

    title       = sanitize(title)[:120]
    description = sanitize(description)[:500]
    category    = sanitize(category)[:50]
    video_url   = video_url.strip()

    user_tier = get_user_highest_tier(db, user.id)
    from .database import CAMPAIGN_TIER_FEATURES, GRID_TIER_NAMES

    # ── Money-flow gate (Apr 2026) ──
    # Block campaign creation for users without an active Campaign Tier.
    # Previously this silently fell through to Tier 1's allowance via `or 1`
    # which let unpaid members create campaigns for free - the entire point
    # of paying for a Campaign Tier was being bypassed. Their videos would
    # then enter the watch rotation alongside paying members' campaigns,
    # diluting the pool. Admin users bypass this gate (get_user_highest_tier
    # returns 8 for is_admin=true).
    if user_tier < 0:
        return err(
            "You need an active Campaign Tier to create a campaign. "
            "Purchase a Campaign Tier from /campaign-tiers to get started."
        )

    tier_features = CAMPAIGN_TIER_FEATURES.get(user_tier, CAMPAIGN_TIER_FEATURES[1])

    # Enforce campaign limit
    active_count = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id,
        VideoCampaign.status == "active"
    ).count()
    if active_count >= tier_features["max_campaigns"]:
        tier_name = GRID_TIER_NAMES.get(user_tier, "Starter")
        return err(f"Your {tier_name} tier allows {tier_features['max_campaigns']} active campaign(s). Upgrade your tier or pause an existing campaign.")

    parsed = parse_video_url(video_url)
    if not parsed:
        return err("Unsupported video URL. Please paste a YouTube or Vimeo link.")

    campaign = VideoCampaign(
        user_id     = user.id,
        title       = title,
        description = description,
        category    = category,
        platform    = parsed["platform"],
        video_url   = video_url,
        embed_url   = parsed["embed_url"],
        video_id    = parsed["video_id"],
        status      = "active",
        owner_tier  = user_tier,
        views_target = tier_features["monthly_views"],
    )

    # Priority queue placement (Tier 5+)
    campaign.priority_level = tier_features["priority"]

    # CTA URL (optional) — only accept http/https to prevent javascript: injection
    cta_url_clean = (cta_url or "").strip()
    if cta_url_clean:
        if cta_url_clean.lower().startswith(("http://", "https://")) and len(cta_url_clean) <= 500:
            campaign.cta_url = cta_url_clean
        else:
            return err("CTA URL must start with http:// or https:// and be under 500 characters.")

    # Geo & interest targeting (Tier 4+)
    if tier_features["targeting"]:
        campaign.target_country = sanitize(target_country)[:200] if target_country else None
        campaign.target_interests = sanitize(target_interests)[:200] if target_interests else None

    # Demographics targeting (Tier 4+)
    if tier_features["demographics"]:
        target_age_min = request.query_params.get("target_age_min", "") or ""
        target_age_max = request.query_params.get("target_age_max", "") or ""
        target_gender = request.query_params.get("target_gender", "") or ""
        if target_age_min.isdigit():
            campaign.target_age_min = int(target_age_min)
        if target_age_max.isdigit():
            campaign.target_age_max = int(target_age_max)
        if target_gender in ("male", "female", "all"):
            campaign.target_gender = target_gender

    # Auto-featured on public page (Tier 6+)
    campaign.is_featured = tier_features["featured"]

    # Brand spotlight — large card on public page (Tier 7+)
    campaign.is_spotlight = tier_features["spotlight"]

    db.add(campaign)
    db.commit()

    return JSONResponse({"success": True, "status": campaign.status, "id": campaign.id, "title": campaign.title})

# ═══════════════════════════════════════════════════════════════
#  CAMPAIGN CTA — click tracking + redirect to advertiser URL
# ═══════════════════════════════════════════════════════════════

@app.get("/campaign-cta/{campaign_id}")
def campaign_cta_click(campaign_id: int, db: Session = Depends(get_db)):
    """Track a CTA click and redirect to the advertiser's destination URL.

    Deliberately not authenticated — members click these after watching.
    Increments cta_clicks atomically via an UPDATE statement to avoid
    race conditions under load.
    """
    campaign = db.query(VideoCampaign).filter(VideoCampaign.id == campaign_id).first()
    if not campaign or not campaign.cta_url:
        return RedirectResponse(url="/", status_code=302)

    # Atomic increment — avoids read-modify-write race under concurrent clicks
    db.query(VideoCampaign).filter(VideoCampaign.id == campaign_id).update(
        {VideoCampaign.cta_clicks: (VideoCampaign.cta_clicks or 0) + 1},
        synchronize_session=False,
    )
    db.commit()

    # Final safety check — only redirect to http/https even though input was validated
    dest = campaign.cta_url.strip()
    if not dest.lower().startswith(("http://", "https://")):
        return RedirectResponse(url="/", status_code=302)

    return RedirectResponse(url=dest, status_code=302)

