# ─────────────────────────────────────────────────────────────────────
# Founder offer deadline (added 27 May 2026)
# ─────────────────────────────────────────────────────────────────────
# The Founder offer (first 100 paying members at $15/mo locked for life)
# was originally a pure count-based cap. From 27 May 2026 Steve added a
# time-based deadline alongside the count cap: the offer closes on
# whichever comes first.
#
# Stored in app_config as a string ISO-8601 UTC timestamp under key
# 'founder_offer_close_at'. NULL/missing key means no time cap (the
# original count-only behaviour). Set via admin tool or directly in DB.
#
# Used by every Founder spot allocation site (5 sites in this module
# plus 1 in the gift-claim flow) so the deadline is honoured uniformly
# across all activation rails.
#
# Returns True if Founder spots are still claimable, False if the offer
# has closed (count cap OR time cap). Uses the CURRENT db session so
# any uncommitted writes (e.g. mid-transaction count updates) are seen.
def _founder_offer_still_open(db) -> bool:
    """Check both the count cap (100 spots) AND the deadline (if set).
    Returns True only if BOTH limits are still in the open state.

    Safe to call inside the pg_advisory_xact_lock-protected critical
    section — does its own COUNT query that respects the lock.
    """
    from .database import AppConfig
    from datetime import datetime as _dt

    # Deadline check — fail-open if the key is missing or unparseable.
    # We'd rather sell a Founder spot we shouldn't have than block one
    # we should sell, in the case of a config-parsing edge case.
    try:
        cfg = db.query(AppConfig).filter(AppConfig.key == "founder_offer_close_at").first()
        if cfg and cfg.value:
            close_at = _dt.fromisoformat(cfg.value.replace("Z", "+00:00").replace("+00:00", ""))
            if _dt.utcnow() >= close_at:
                return False
    except Exception as e:
        logger.warning(f"founder_offer_close_at parse failed: {e} — treating as no deadline")

    # Count cap check — still 100.
    current_count_row = db.execute(text(
        "SELECT COUNT(*) AS cnt FROM users WHERE is_founding_member = TRUE"
    )).fetchone()
    current_count = current_count_row.cnt if current_count_row else 0
    return current_count < 100


def _is_returning_member(db, user) -> bool:
    """True if this user has activated a paid membership before — used to deny
    the $15 Founder price + spot to lapsed/returning members (Founder = NEW
    members only). Closes the lapse-and-rejoin loophole: a Partner can't let
    their membership lapse and reactivate at the Founder price.

    Signal: `activated_at` is the first-activation timestamp, set AFTER the
    founder claim on first activation, preserved across renewals, and never
    cleared on lapse — so it reliably marks anyone who has ever paid. The
    renewal-record check is a belt-and-braces fallback (also created after the
    claim, unique per user, never deleted). A genuine first-time activator has
    neither at claim time."""
    if not user:
        return False
    if getattr(user, "activated_at", None) is not None:
        return True
    try:
        from .database import MembershipRenewal
        return db.query(MembershipRenewal.id).filter(
            MembershipRenewal.user_id == user.id
        ).first() is not None
    except Exception:
        return False


def _classify_membership_activation(user, target_tier: str, target_billing: str) -> str:
    """Determine what kind of activation this is from the user's CURRENT state.

    This is the single source of truth for the question 'should sponsor
    get paid commission on this activation?'. Replaces the previous
    pattern of trusting an is_upgrade flag passed in by the caller, which
    was inconsistent across the three callsite paths (upgrade-to-pro,
    nowpayments-create-invoice, walletconnect-intent) and led to silent
    commission double-pays for same-tier monthly→annual switches and
    Basic→Pro Annual upgrades via wallet.

    Returns one of:
      - "fresh"          User is inactive. Fresh activation.
                         Pays sponsor commission.
      - "reactivation"   User was active but lapsed (membership_expires_at
                         in the past). They came back. Pays sponsor
                         commission — sponsor brought them back too.
      - "tier_upgrade"   Basic → Pro. Existing Basic time absorbed.
                         No sponsor commission (the upgrade fee goes
                         100% to company per commission spec).
      - "cadence_switch" Same-tier Monthly → Annual. Existing monthly
                         time absorbed. No sponsor commission (already
                         paid on the original monthly activation).
      - "redundant"      User already has exactly what they're trying to
                         buy. Caller should reject this BEFORE calling
                         _activate_membership; if it gets here it's a
                         bug — log loudly.

    Call this BEFORE mutating user.is_active, user.membership_tier, or
    user.membership_billing, otherwise the classification is wrong.
    """
    target_tier = (target_tier or "partner").lower()
    target_billing = (target_billing or "monthly").lower()

    if not user.is_active:
        # Was the user previously active and now lapsed? Check expiry —
        # if they have an activated_at timestamp and the expiry is in
        # the past, they're returning, not fresh. Either way we pay
        # sponsor commission, so the distinction is informational
        # (showing up in logs and the source field).
        if user.activated_at and user.membership_expires_at:
            from datetime import datetime
            if user.membership_expires_at < datetime.utcnow():
                return "reactivation"
        return "fresh"

    # User is active. Compare current state against target.
    current_tier = (user.membership_tier or "free").lower()
    current_billing = (getattr(user, "membership_billing", None) or "monthly").lower()

    if current_tier == target_tier and current_billing == target_billing:
        return "redundant"
    # Pre-flat-pricing this handled Basic→Pro tier upgrades. Under
    # flat-pricing (locked 15 May 2026) there's only one paid tier so
    # tier_upgrade is impossible — left here as defensive dead code
    # because the engine still classifies cadence_switch separately
    # below.
    if current_tier == target_tier and current_billing == "monthly" and target_billing == "annual":
        return "cadence_switch"

    # Edge cases:
    #   - tier changes (Basic↔Pro) — no longer exist under flat-pricing
    #   - annual → monthly within same tier (no UI surfaces this)
    # Treat as fresh activation defensively.
    return "fresh"


def _activate_membership(db, user, tier, source="crypto", subscription_id=None, is_upgrade=False, billing="monthly", source_event_id=None):
    """
    Shared membership activation — used by BOTH Stripe and Crypto.
    Handles: activation, payment record, sponsor commission, renewal record, welcome email.

    source_event_id (added 27 May 2026 late evening): an upstream event
    identifier used as an idempotency key on the commission row that
    gets written for the sponsor. For Stripe: the Stripe event.id
    (e.g. 'evt_1Q...'). For NOWPayments: the np_payment_id. For wallet
    rail: the WalletConnect order_id. Database partial unique index
    enforces (from_user, to_user, commission_type, source_event_id)
    uniqueness — same event can never produce two commission rows
    even if application logic races. None = legacy/no-idempotency path
    (older callsites still work without modification).

    AS OF 9 MAY 2026 (engine-level upgrade detection):

    The is_upgrade parameter is now ADVISORY ONLY. The engine determines
    upgrade-vs-fresh from the user's current state (via
    _classify_membership_activation) rather than trusting the caller.

    Why: prior architecture had three separate callsite paths each doing
    their own partial classification (upgrade-to-pro endpoint, nowpayments
    create-invoice, and walletconnect-intent). Each had different bugs
    around same-tier monthly→annual switches and Basic→Pro Annual via
    wallet, leading to silent commission double-pays.

    The is_upgrade parameter is kept for callsite compatibility but a
    warning is logged when it disagrees with the engine's classification
    so we can find and clean up stale callers.

    Commission rules (unchanged, just enforced consistently now):
    - Sponsor commission paid on fresh activation and reactivation
    - Sponsor commission NOT paid on cadence switches (Monthly→Annual)
    - Flat pricing: a single Partner tier, so sponsor commission is a flat
      $10/month ($100/year annual) per active referral — no tier cap applies
    """
    from datetime import datetime, timedelta
    from decimal import Decimal
    import uuid

    # ── Idempotency guard (belt-and-braces, 26 May 2026) ───────────────────
    # Both Stripe webhook events (checkout.session.completed + invoice.paid)
    # can fire on a single fresh signup. invoice.paid was made self-healing
    # 25 May 2026 to recover the jerrygoff-class bug where checkout missed,
    # but the consequence was that the NORMAL case now risks double-firing
    # both handlers and double-paying the sponsor commission.
    #
    # The caller-side guard in _stripe_handle_checkout_completed is the
    # primary defence. This is the chokepoint backstop: if a fresh-activation
    # is attempted on a user who's already active and not being upgraded,
    # bail before touching anything money-affecting. Renewals + tier upgrades
    # (cadence switches, Basic→Pro, etc.) still flow through normally — they
    # have user.is_active=True by design AND set is_upgrade=True.
    #
    # Bug caught 26 May via daily-briefing audit: starthere paid TWICE for
    # earnwithdarius signup ($10 each, commissions 601 'stripe-invoice-
    # recovery' + 603 'stripe', 500ms apart). starthere kept the duplicate
    # $10; company short $10.
    if (user.is_active
            and not is_upgrade
            and source in ("stripe", "stripe-invoice-recovery",
                           "crypto", "nowpayments", "balance", "gift")
            and (user.membership_tier or "") in (tier, "founding")):
        import logging as _logging
        _logging.getLogger(__name__).warning(
            f"_activate_membership called for already-active user {user.id} "
            f"({user.username}) tier={tier} source={source} — likely duplicate "
            f"event (e.g. Stripe checkout + invoice.paid both firing). Skipping "
            f"to prevent double sponsor commission."
        )
        return

    # ── Flat partner pricing (15 May 2026) ─────────────────────────────────
    # Single source of truth: $20/mo standard, $15/mo for founding partners
    # (signalled by user.membership_price_locked being set at migration time).
    # Annual billing: $200 standard, $150 founding (10× the monthly rate, ~2
    # months free, matches the old basic-annual savings ratio).
    # Sponsor commission: flat $10 per membership payment regardless of buyer's
    # price — protects founding partner economics (sponsor unaffected by which
    # cohort their recruit lands in).
    STANDARD_PARTNER_PRICE   = Decimal("20.00")
    FOUNDING_PARTNER_PRICE   = Decimal("15.00")
    STANDARD_ANNUAL_PRICE    = Decimal("200.00")
    FOUNDING_ANNUAL_PRICE    = Decimal("150.00")
    FLAT_SPONSOR_COMMISSION  = Decimal("10.00")

    # Determine fee. If the user has a locked price (founders, grandfathered
    # accounts), honour it. Otherwise standard partner price applies.
    is_annual = (billing == "annual")

    # ── Founding partner spot allocation ───────────────────────────────────
    # Before reading membership_price_locked, check whether this is a fresh
    # activation and whether founding spots remain. If both, atomically claim
    # the next spot for this user. Race-safe via SELECT FOR UPDATE on the
    # founding members row count.
    #
    # Why we need atomic locking: two simultaneous signups could both read
    # "85 spots remaining" and both try to claim spot #100, leaving us with
    # 101 founders. The SELECT FOR UPDATE on users (filtered to founding)
    # blocks the second transaction until the first commits, at which point
    # the second sees the updated count and either claims #100 (if first
    # claimed #99) or falls through to standard pricing (if first claimed #100).
    #
    # Only NEW activations claim founding status — upgrades, cadence switches,
    # and renewals of existing members do NOT (they're already settled into
    # their cohort, founding or standard, at first activation).
    activation_type = _classify_membership_activation(user, tier, billing)
    if activation_type == "fresh" and not getattr(user, "is_founding_member", False):
        try:
            FOUNDING_TOTAL = 100
            # ── Race-safe founding spot claim (RE-APPLIED 15 May 2026 evening) ──
            # Previous version used `SELECT COUNT(*) ... FOR UPDATE` which
            # PostgreSQL rejects (FOR UPDATE not allowed with aggregate
            # functions). The exception was caught by the surrounding
            # try/except and the user fell through to standard $20 pricing
            # despite paying the $15 founding amount.
            #
            # Fix: pg_advisory_xact_lock serialises concurrent claims via
            # a transaction-scoped Postgres advisory lock. Released
            # automatically on commit/rollback. The COUNT() is then a
            # plain aggregate, no FOR UPDATE needed.
            #
            # Lock key 7423957 is arbitrary but must match across all
            # activation rails (currently only this one — the balance
            # rail at line ~5418 used to use the same key before revert).
            #
            # 26 May 2026 (Sylvia Douna case) — allocation switched from
            # COUNT+1 to MAX(spot)+1. COUNT+1 assumed sequential allocation
            # with no gaps, which breaks the moment any historical founder
            # was demoted (is_founding_member=False but founding_spot_number
            # left non-null), or any test/cleanup created gaps. Symptom:
            # 62 active founders but MAX(spot)=63 from an old demoted user,
            # so COUNT+1=63 collides with the existing #63 → IntegrityError
            # → session rollback → activation totally fails. MAX-based
            # allocation always picks the next unused spot above the high
            # water mark, immune to gaps.
            FOUNDING_LOCK_KEY = 7423957
            db.execute(text("SELECT pg_advisory_xact_lock(:k)"),
                       {"k": FOUNDING_LOCK_KEY})
            # Use COUNT to check whether we're still under FOUNDING_TOTAL
            # (the cap), but use MAX to determine which spot number is
            # actually safe to assign next. The two diverge when spots
            # have been freed (count drops) but spot numbers were never
            # recycled (max stays high).
            current_count_row = db.execute(text(
                "SELECT COUNT(*) AS cnt FROM users WHERE is_founding_member = TRUE"
            )).fetchone()
            current_count = current_count_row.cnt if current_count_row else 0
            # 28 May 2026 — CRITICAL FIX. Previous logic used both
            # `current_count < 100` AND `max_spot_taken < 100` as the cap
            # gate, and assigned next_spot = MAX+1. That conflated two
            # different things:
            #   - "how many founders exist" (COUNT) — the real cap
            #   - "highest spot number ever assigned" (MAX) — NOT the cap
            # When demoted/cleaned-up accounts leave gaps in the spot
            # numbering (e.g. spot #62 vacated but never recycled), MAX
            # climbs to 100 while COUNT is still only 91. The
            # `max_spot_taken < 100` guard then SLAMMED THE OFFER SHUT 9
            # spots early — new signups silently fell through to $20
            # Partner pricing despite 9 real spots being available.
            # (Caught when 4 members paid Partner overnight with 9 founder
            # spots open: williamnormanii, earnwithjason, earningcreator,
            # michellg.)
            #
            # Correct behaviour:
            #   - CAP gate uses COUNT only (how many founders exist < 100)
            #   - SPOT NUMBER fills the LOWEST UNUSED gap <= 100, not MAX+1.
            #     This recycles vacated spot numbers and can never exceed
            #     100 as long as COUNT < 100. Gap-fill is still collision-
            #     safe under the advisory lock (we hold FOUNDING_LOCK_KEY).
            deadline_open = _founder_offer_still_open(db)
            if current_count < FOUNDING_TOTAL and deadline_open and not _is_returning_member(db, user):
                # Find the lowest unused spot number in [1, FOUNDING_TOTAL].
                # generate_series(1,100) LEFT JOIN against taken spots;
                # pick the smallest with no match. Single query, race-safe
                # under the advisory lock.
                gap_row = db.execute(text(
                    "SELECT s.n AS spot FROM generate_series(1, :total) AS s(n) "
                    "LEFT JOIN users u ON u.founding_spot_number = s.n "
                    "WHERE u.id IS NULL "
                    "ORDER BY s.n LIMIT 1"
                ), {"total": FOUNDING_TOTAL}).fetchone()
                next_spot = gap_row.spot if gap_row else None
                if next_spot is None:
                    # No gap found — genuinely full. Fall through to partner.
                    logger.warning(
                        f"Founder allocation: COUNT={current_count} < 100 but "
                        f"no gap found in spot numbering — treating as full."
                    )
                else:
                    user.is_founding_member = True
                    user.founding_spot_number = next_spot
                    user.membership_price_locked = Decimal("15.00")
                    # 23 May 2026 (evening): also set membership_tier='founding'
                    # so admin UI + any other code reading membership_tier sees
                    # this user as a Founder. Without this, is_founding_member
                    # would be True but tier would fall through to 'partner' at
                    # line ~8649 below, leaving inconsistent state (FOUNDER
                    # badge on dashboard, but PARTNER badge on admin).
                    user.membership_tier = "founding"
                    # Flush so the locked_price read below sees the new value.
                    db.flush()
                    # Auto-enrol the new Founder into the rotator queue so they
                    # start receiving distributed /start signups immediately.
                    # Idempotent — safe if somehow already enrolled (gift→paid
                    # upgrade path, manual admin intervention, etc.).
                    _enrol_user_to_rotator(db, user.id)
                    logger.info(
                        f"Founding spot #{next_spot} (gap-fill) claimed by user {user.id} "
                        f"({user.username}) — count={current_count}, "
                        f"{FOUNDING_TOTAL - current_count - 1} spots remaining"
                    )
        except Exception as e:
            # If the founding claim fails for any reason, ROLLBACK the
            # poisoned session before falling through to standard partner
            # pricing — otherwise every subsequent db operation in this
            # activation fails with "transaction has been rolled back due
            # to a previous exception during flush".
            # Better to charge $20 than to fail the signup entirely.
            try:
                db.rollback()
            except Exception:
                pass
            # Re-read user from the rolled-back session so subsequent
            # _activate_membership work sees a clean object state.
            try:
                db.refresh(user)
            except Exception:
                pass
            logger.error(
                f"Founding spot claim failed for user {user.id}: {e} — "
                f"session rolled back, proceeding with standard partner pricing"
            )

    locked_price = getattr(user, "membership_price_locked", None)
    if locked_price is not None:
        # Founding partner: monthly = locked price, annual = locked × 10
        fee = (Decimal(str(locked_price)) * Decimal("10")) if is_annual else Decimal(str(locked_price))
    else:
        fee = STANDARD_ANNUAL_PRICE if is_annual else STANDARD_PARTNER_PRICE

    # Reject redundant activations defensively. Callers should catch this
    # before reaching here, but if they don't, refusing is safer than
    # double-charging or double-activating.
    if activation_type == "redundant":
        logger.warning(
            f"_activate_membership called for redundant activation: "
            f"user {user.id} already on {user.membership_tier} "
            f"{getattr(user, 'membership_billing', 'monthly')}, "
            f"asked to activate {tier} {billing}. Refusing."
        )
        return JSONResponse(
            {"error": f"You're already on {tier} {billing}."},
            status_code=400,
        )

    # No-commission scenarios per commission spec:
    #   - tier_upgrade (Basic→Pro): upgrade fee is 100% company
    #   - cadence_switch (Monthly→Annual same tier): already paid on monthly
    pays_sponsor_commission = activation_type in ("fresh", "reactivation")

    # Caller-passed is_upgrade is now ADVISORY. Compare it against the
    # engine's classification and warn if they disagree — this finds
    # stale callsites that didn't update with the new pattern.
    caller_thinks_upgrade = bool(is_upgrade)
    engine_thinks_no_commission = (not pays_sponsor_commission)
    if caller_thinks_upgrade != engine_thinks_no_commission:
        logger.warning(
            f"is_upgrade flag disagrees with engine classification — "
            f"user {user.id}, target {tier}/{billing}, current "
            f"{user.membership_tier}/{getattr(user, 'membership_billing', 'monthly')} "
            f"(active={user.is_active}). caller={caller_thinks_upgrade}, "
            f"engine={activation_type} (pays_commission={pays_sponsor_commission}). "
            f"Engine wins."
        )

    # The activation_type variable is the source of truth from here on.
    # is_upgrade local var below is set from engine, NOT from caller.
    is_upgrade = (activation_type in ("tier_upgrade", "cadence_switch"))

    # Activate user
    user.is_active = True
    user.activated_at = user.activated_at or datetime.utcnow()
    # Under flat partner pricing, all new activations are tagged 'partner'.
    # Founding partners (the migrated first 100) keep their 'founding' tag —
    # don't overwrite that if the user already has it. Incoming `tier` from
    # legacy callers (still passing 'basic'/'pro') is normalised to 'partner'.
    if user.membership_tier != "founding":
        user.membership_tier = "partner"
    # Set billing type (safe — column may not exist yet in DB)
    try:
        user.membership_billing = "annual" if is_annual else "monthly"
    except Exception:
        pass  # Column not yet created in DB
    user.membership_expires_at = datetime.utcnow() + timedelta(days=365 if is_annual else 31)
    if subscription_id:
        user.stripe_subscription_id = subscription_id

    # Record payment. payment_type and actual_charge depend on activation_type.
    if activation_type == "tier_upgrade":
        actual_charge = Decimal("15.00")  # Basic→Pro Monthly difference
        # Pro Annual purchase from a Basic Monthly user pays full $350,
        # not the $15 difference, because annual replaces the whole window.
        if is_annual:
            actual_charge = fee
        payment_type = "membership_upgrade"
    elif activation_type == "cadence_switch":
        actual_charge = fee  # full annual price
        payment_type = "membership_cadence_switch"
    else:
        actual_charge = fee
        payment_type = "membership"

    existing = db.query(Payment).filter(
        Payment.from_user_id == user.id,
        Payment.payment_type == payment_type,
        Payment.status == "confirmed",
    ).first()
    if not existing:
        tx_ref = f"{source}_{uuid.uuid4().hex[:16]}"
        payment = Payment(
            from_user_id=user.id, to_user_id=None,
            amount_usdt=actual_charge, payment_type=payment_type,
            tx_hash=tx_ref, status="confirmed",
        )
        db.add(payment)
        db.flush()

    # Credit sponsor commission only when the engine says so.
    # Replaces the old `not is_upgrade` check, which was vulnerable to
    # callers passing the wrong flag.
    sponsor_share = Decimal("0.00")  # default: no sponsor commission paid
    if user.sponsor_id and pays_sponsor_commission:
        sponsor = db.query(User).filter(User.id == user.sponsor_id).first()
        if sponsor:
            sponsor_tier = getattr(sponsor, "membership_tier", "free") or "free"
            # Flat $10 sponsor commission on every membership payment, regardless
            # of buyer's tier or billing cycle. Locked in 15 May 2026 alongside
            # flat partner pricing:
            #   - founding partner ($15/mo) → sponsor gets $10 (66% of fee)
            #   - standard partner ($20/mo) → sponsor gets $10 (50% of fee)
            #   - annual founding ($150/yr) → sponsor gets $100 (10× monthly)
            #   - annual standard ($200/yr) → sponsor gets $100
            # The annual commission is 10× monthly so annual recruits aren't
            # disadvantaged for sponsors (matches old "2 months free" ratio).
            # Behaviour for free sponsors is unchanged: they accrue commission
            # to their balance and the cascade notification below prompts them
            # to activate to access it (Option B — never auto-consume without
            # consent).
            if is_annual:
                sponsor_share = Decimal("100.00")
            else:
                sponsor_share = FLAT_SPONSOR_COMMISSION

            sponsor.balance = Decimal(str(sponsor.balance or 0)) + sponsor_share
            sponsor.total_earned = Decimal(str(sponsor.total_earned or 0)) + sponsor_share
            # Atomic SQL increment for personal_referrals to avoid lost
            # updates under concurrent webhook deliveries. balance and
            # total_earned above SHOULD also be atomic but the same sponsor
            # object is mutated again later in this function — converting
            # those to atomic UPDATEs would require careful tracking of the
            # in-memory sponsor state. Counter-only fix here is the
            # high-leverage one because referral counts directly drive the
            # leaderboard and any dropped count is visible to the affected
            # member. Money fields TODO post-launch.
            from sqlalchemy import func as _sqlfunc
            db.query(User).filter(User.id == sponsor.id).update({
                User.personal_referrals: _sqlfunc.coalesce(User.personal_referrals, 0) + 1,
            }, synchronize_session=False)
            # Commission with idempotency key (27 May 2026 late evening):
            # source_event_id is enforced unique via partial index on
            # (from_user_id, to_user_id, commission_type, source_event_id).
            # If the same upstream event somehow drives two activation
            # paths (race across replicas, retry storm, manual rerun),
            # the second INSERT raises IntegrityError and is caught
            # below — counter increment above is also rolled back because
            # we're inside the activation transaction.
            comm = Commission(
                to_user_id=sponsor.id, from_user_id=user.id,
                amount_usdt=sponsor_share, commission_type="membership_sponsor",
                package_tier=0,
                notes=f"Partner membership commission from {user.username} ({source})",
                status="paid",
                paid_at=datetime.utcnow(),
                source_event_id=source_event_id,  # idempotency key
            )
            db.add(comm)
            try:
                db.flush()
            except IntegrityError as ie:
                # The unique partial index caught a duplicate. This is
                # the layer-2 safety net working. Log loudly, roll back
                # this savepoint, and skip the rest of the sponsor-side
                # work — the canonical row from the first activation is
                # already in place.
                db.rollback()
                logger.warning(
                    f"DUPLICATE COMMISSION BLOCKED by source_event_id "
                    f"({source_event_id}): from_user={user.id} "
                    f"to_user={sponsor.id} type=membership_sponsor. "
                    f"This is the idempotency guarantee working — "
                    f"another path activated this user first."
                )
                # Return early — user IS already active from the prior
                # activation; we don't need to do anything else.
                return {"message": f"{tier.title()} membership already active (idempotent re-fire ignored)."}

            # If sponsor is a free member whose balance just crossed the
            # membership threshold, send them a one-time offer notification
            # (Option B — never auto-consume their earnings without consent).
            try:
                from .payment import _cascade_auto_activation
                _cascade_auto_activation(
                    db=db, recipient=sponsor,
                    tx_hash=f"act_{user.id}", chain_depth=1,
                    activated_users=[],
                )
            except Exception as exc:
                logger.warning(f"Membership-offer notification check failed for sponsor {sponsor.id}: {exc}")

            # Send cha-ching commission email to sponsor
            try:
                from .email_utils import send_commission_email
                if sponsor.email:
                    send_commission_email(
                        to_email=sponsor.email,
                        first_name=sponsor.first_name or sponsor.username,
                        commission_type="Membership Sponsor",
                        from_username=user.username,
                    )
            except Exception as exc:
                logger.warning(f"Commission email failed for sponsor {sponsor.id} ({sponsor.username}): {exc}")

    # Company-share bookkeeping row.
    # Every membership activation results in money to the company:
    #   - fresh/reactivation with sponsor:   actual_charge - sponsor_share
    #   - fresh/reactivation without sponsor: 100% of actual_charge
    #   - tier_upgrade / cadence_switch:      100% of actual_charge (no sponsor cut)
    # Without this row, the commissions ledger only records sponsor outflows
    # and the company's revenue from memberships is invisible to financial
    # reconciliation tools (financial_sanity, commission_audit, etc).
    # The legacy Coinbase webhook path (main.py ~5459) does this correctly;
    # this mirrors that pattern for the WalletConnect / NOWPayments paths.
    company_share = Decimal(str(actual_charge)) - sponsor_share
    if company_share > 0:
        db.add(Commission(
            from_user_id=user.id,
            to_user_id=None,
            amount_usdt=company_share,
            commission_type="membership_company",
            package_tier=0,
            status="platform",
            paid_at=datetime.utcnow(),
            notes=(
                f"Membership company share (${company_share}) — "
                f"{activation_type} via {source}, "
                f"actual_charge=${actual_charge}, sponsor_share=${sponsor_share}"
            ),
        ))

    # Create renewal record
    # CRITICAL: if this fails the user is activated but the renewal cron
    # will never bill them again — silent revenue loss. Log loudly so we
    # see it in production logs and can backfill manually if needed.
    try:
        initialise_renewal_record(db, user.id, source=source)
    except Exception as exc:
        logger.error(
            f"Membership renewal record creation FAILED for user {user.id} "
            f"({user.username}, tier={tier}, source={source}): {exc}",
            exc_info=True,
        )
        # Don't re-raise — activation succeeded, we just lose auto-renewal.
        # Manual intervention required to backfill the renewal record.

    # Send welcome email
    # Email failures are non-critical; activation should still succeed.
    # Log at warning level so we can see deliverability issues over time.
    try:
        from .email_utils import send_membership_activated_email
        send_membership_activated_email(
            user.email,
            user.first_name or user.username,
            billing=user.membership_billing or "monthly",
            is_upgrade=is_upgrade,
            tier=tier,
            is_founding_member=bool(getattr(user, "is_founding_member", False)),
            founding_spot_number=getattr(user, "founding_spot_number", None),
        )
    except Exception as exc:
        logger.warning(f"Welcome email failed for user {user.id} ({user.username}): {exc}")

    # In-app notification for the buyer — confirms activation in the bell.
    # Best-effort, won't break the activation transaction if it fails.
    try:
        from .database import Notification
        is_founder = bool(getattr(user, "is_founding_member", False))
        spot_no = getattr(user, "founding_spot_number", None)
        if activation_type == "tier_upgrade":
            # Dead branch under flat-pricing — /api/upgrade-to-pro returns
            # 410 Gone. Kept for safety in case any legacy path still
            # passes activation_type="tier_upgrade", but the message is
            # now generic rather than Pro-specific.
            title = "✅ Membership upgraded"
            message = "Your membership has been updated. Visit your dashboard to confirm."
        elif activation_type == "cadence_switch":
            title = f"✅ Switched to annual {tier} membership"
            message = f"You're locked in for 365 days at the discounted annual rate. Active until {user.membership_expires_at.strftime('%d %b %Y')}."
        elif is_founder:
            spot_text = f" #{spot_no}" if spot_no else ""
            title = f"⭐ Founding Partner{spot_text} — welcome!"
            message = f"Your $15/month price is locked for life. Active until {user.membership_expires_at.strftime('%d %b %Y')}. Next step: activate a Campaign Tier to start earning."
        elif is_annual:
            title = f"✅ Partner membership activated (annual)"
            message = f"Annual Partner membership active until {user.membership_expires_at.strftime('%d %b %Y')}. Next step: activate a Campaign Tier to start earning."
        else:
            title = f"✅ Partner membership activated"
            message = f"Your Partner membership is active until {user.membership_expires_at.strftime('%d %b %Y')}. Next step: activate a Campaign Tier to start earning."
        notif = Notification(
            user_id=user.id,
            type="system",
            icon=("⭐" if is_founder else "✅"),
            title=title,
            message=message,
            link="/campaign-tiers",
        )
        db.add(notif)
    except Exception as exc:
        logger.warning(f"Membership activation notification failed for user {user.id}: {exc}")

    db.commit()
    # Cache invalidation — both the user (membership state changed,
    # which affects dashboard "active member" stats) AND the sponsor
    # (commission posted, balance + earnings changed).
    try:
        from .stats_cache import cache_invalidate_user
        cache_invalidate_user(user.id)
        if user.sponsor_id and pays_sponsor_commission:
            cache_invalidate_user(user.sponsor_id)
    except Exception as e:
        logger.warning(f"cache_invalidate_user failed in _activate_membership: {e}")
    return {"message": f"{tier.title()} membership activated! Expires {user.membership_expires_at.strftime('%d %b %Y')}."}


# _stripe_renew_membership REMOVED 28 May 2026. It was dead code (zero callers)
# and buggy: wrote the renewal commission as status='pending' (invisible to the
# paid-only earnings/audit model) with no idempotency key. Stripe renewal
# commissions now go through payment.pay_renewal_commission, called from the
# invoice.paid handler's subscription_cycle branch — the same shared engine the
# wallet renewal cron uses, with period-keyed idempotency.


# ── Founding partners status (added 15 May 2026 with flat-pricing migration) ──
@app.get("/api/founding-members/status")
async def api_founding_members_status(db: Session = Depends(get_db)):
    """Public-readable: current founding partner allocation.

    Returns:
      - spots_total: 100 (hard cap)
      - spots_claimed: count of users with is_founding_member=TRUE
      - spots_remaining: spots_total - spots_claimed
      - is_open: True if spots remain AND deadline not passed
      - deadline_utc: ISO timestamp of deadline (null if no deadline set)
      - closed_by: null while open; 'count_cap' or 'deadline' once closed
      - current_price: what a new signup is currently quoted

    Used by:
      - Dashboard gold banner (Sprint 2) — polled every 60s
      - Public homepage CTA — quotes current price
      - Sprint 1 verification — sanity-check live count
    Cached at 60s in stats_cache to avoid hammering the DB.

    27 May 2026 — extended to include deadline_utc and closed_by so the
    dashboard banner can render a live countdown alongside the count.
    """
    from decimal import Decimal
    from .database import AppConfig
    try:
        spots_claimed = db.execute(text(
            "SELECT COUNT(*) FROM users WHERE is_founding_member = TRUE"
        )).scalar() or 0
    except Exception as e:
        logger.error(f"founding status query failed: {e}")
        spots_claimed = 0

    SPOTS_TOTAL = 100
    spots_remaining = max(0, SPOTS_TOTAL - spots_claimed)

    # Read deadline from app_config (set 27 May 2026 — defaults to
    # 2026-05-29T23:59:00 UTC). Helper _founder_offer_still_open does the
    # canonical check; we re-derive the diagnostic fields here for the API
    # response.
    deadline_utc = None
    closed_by = None
    deadline_passed = False
    try:
        cfg = db.query(AppConfig).filter(AppConfig.key == "founder_offer_close_at").first()
        if cfg and cfg.value:
            deadline_utc = cfg.value
            deadline_dt = datetime.fromisoformat(cfg.value.replace("Z", "+00:00").replace("+00:00", ""))
            if datetime.utcnow() >= deadline_dt:
                deadline_passed = True
    except Exception:
        pass

    is_open = (spots_remaining > 0) and not deadline_passed
    if not is_open:
        if spots_remaining == 0:
            closed_by = "count_cap"
        elif deadline_passed:
            closed_by = "deadline"

    return {
        "spots_total": SPOTS_TOTAL,
        "spots_claimed": spots_claimed,
        "spots_remaining": spots_remaining,
        "is_open": is_open,
        "deadline_utc": deadline_utc,
        "closed_by": closed_by,
        "now_utc": datetime.utcnow().isoformat() + "Z",
        "current_price_monthly": "15.00" if is_open else "20.00",
        "current_price_annual": "150.00" if is_open else "200.00",
        "standard_price_monthly": "20.00",
        "standard_price_annual": "200.00",
        "founding_price_monthly": "15.00",
        "founding_price_annual": "150.00",
    }


# ── Signup funnel instrumentation (added 24 May 2026) ──────────────────
# Tracks Free user drop-off between registration and paid activation.
# As of 23 May 2026: 67 signups in last 7 days, only 12 activated (18%).
# Without funnel events we can't tell whether the leak is at /dashboard
# (they never come back), at /upgrade (they look but don't click pay),
# or at the payment step itself. These two endpoints give us a denominator
# at each step so the leakage point becomes diagnosable next week.

@app.post("/api/funnel/track")
async def api_funnel_track(
    request: Request,
    db: Session = Depends(get_db),
    user: User = Depends(get_current_user),
):
    """Record a signup-funnel event for the current Free user.

    Body: {"event": "dashboard_view_inactive" | "upgrade_view_inactive"}

    Idempotent per (user_id, event, UTC date) — multiple page views in the
    same day record once. This keeps the denominator honest: 67 unique
    signups, not 670 page-refresh inflated views.

    No-ops silently for:
      - unauthenticated requests (just returns ok — no point making the
        client error-handle a fire-and-forget tracker)
      - active members (we only care about the pre-activation funnel)
      - unknown event names (whitelisted below to prevent log spam from
        future client changes or probing)
    """
    if not user or user.is_active:
        # Not an error from the client's perspective — they fire and forget.
        return {"ok": True, "recorded": False}

    try:
        body = await request.json()
    except Exception:
        body = {}
    event = (body.get("event") or "").strip()

    ALLOWED_EVENTS = {"dashboard_view_inactive", "upgrade_view_inactive"}
    if event not in ALLOWED_EVENTS:
        return {"ok": True, "recorded": False}

    from .database import SignupFunnelEvent

    # Idempotency: skip if (user, event) already fired today UTC.
    today_start = datetime.utcnow().replace(hour=0, minute=0, second=0, microsecond=0)
    existing = db.query(SignupFunnelEvent.id).filter(
        SignupFunnelEvent.user_id == user.id,
        SignupFunnelEvent.event == event,
        SignupFunnelEvent.created_at >= today_start,
    ).first()
    if existing:
        return {"ok": True, "recorded": False}

    try:
        db.add(SignupFunnelEvent(user_id=user.id, event=event))
        db.commit()
        return {"ok": True, "recorded": True}
    except Exception as e:
        logger.warning(f"funnel/track insert failed for user {user.id} event {event}: {e}")
        db.rollback()
        return {"ok": True, "recorded": False}


@app.get("/admin/api/signup-funnel-stats")
async def admin_api_signup_funnel_stats(
    days: int = 7,
    db: Session = Depends(get_db),
    user: User = Depends(get_current_user),
):
    """Admin-only: signup funnel report over the last N days (default 7).

    Returns the count of users at each funnel step:
      - registered:        count of users created in window
      - dashboard_viewed:  count who fired dashboard_view_inactive
      - upgrade_viewed:    count who fired upgrade_view_inactive
      - activated:         count whose is_active = True

    Rates are computed pairwise so we can see where the largest drop is.
    Use this to decide which step deserves attention next.
    """
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    from .database import SignupFunnelEvent
    since = datetime.utcnow() - timedelta(days=max(1, min(days, 90)))

    # Cohort of users registered in the window
    cohort_user_ids = [
        row[0] for row in db.query(User.id).filter(User.created_at >= since).all()
    ]
    registered = len(cohort_user_ids)

    if registered == 0:
        return {
            "window_days": days,
            "since": since.isoformat(),
            "registered": 0,
            "dashboard_viewed": 0,
            "upgrade_viewed": 0,
            "activated": 0,
            "rates": {},
            "note": "No registrations in window — increase ?days= to widen.",
        }

    # Distinct users in the cohort who fired each event
    dashboard_viewed = db.query(SignupFunnelEvent.user_id).filter(
        SignupFunnelEvent.user_id.in_(cohort_user_ids),
        SignupFunnelEvent.event == "dashboard_view_inactive",
    ).distinct().count()

    upgrade_viewed = db.query(SignupFunnelEvent.user_id).filter(
        SignupFunnelEvent.user_id.in_(cohort_user_ids),
        SignupFunnelEvent.event == "upgrade_view_inactive",
    ).distinct().count()

    # Activated = is_active=True from the same cohort. Counted by current
    # state, not by event, because the cohort may have activated after
    # registering — that still counts as a conversion.
    activated = db.query(User.id).filter(
        User.id.in_(cohort_user_ids),
        User.is_active == True,  # noqa: E712
    ).count()

    def pct(num, den):
        if den == 0:
            return 0.0
        return round(100.0 * num / den, 1)

    return {
        "window_days": days,
        "since": since.isoformat(),
        "registered": registered,
        "dashboard_viewed": dashboard_viewed,
        "upgrade_viewed": upgrade_viewed,
        "activated": activated,
        "rates": {
            "dashboard_view_rate": pct(dashboard_viewed, registered),
            "upgrade_view_rate": pct(upgrade_viewed, registered),
            "activation_rate": pct(activated, registered),
            "dashboard_to_upgrade": pct(upgrade_viewed, dashboard_viewed) if dashboard_viewed else 0.0,
            "upgrade_to_activation": pct(activated, upgrade_viewed) if upgrade_viewed else 0.0,
        },
    }


# ── Auto-renew preference (added 9 May 2026 with new checkout flow) ─────
@app.get("/api/auto-renew-preference")
async def api_get_auto_renew_preference(db: Session = Depends(get_db),
                                          user: User = Depends(get_current_user)):
    """Return the user's current auto-renew-from-balance preference.

    Used by:
      - Account settings page (so the toggle reflects current state)
      - Checkout flow (so we can pre-fill the checkbox if user already opted in)
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from .database import MembershipRenewal
    renewal = db.query(MembershipRenewal).filter(MembershipRenewal.user_id == user.id).first()
    if not renewal:
        # No renewal row yet (member hasn't activated) — return default
        return {"auto_renew_from_balance": True, "has_renewal": False}
    return {
        "auto_renew_from_balance": bool(getattr(renewal, "auto_renew_from_balance", True)),
        "has_renewal": True,
    }


@app.post("/api/auto-renew-preference")
async def api_set_auto_renew_preference(request: Request, db: Session = Depends(get_db),
                                          user: User = Depends(get_current_user)):
    """Set the user's auto-renew-from-balance preference.

    Body: {"enabled": true|false}

    Called from:
      - Account settings toggle
      - Checkout flow (when user opts in/out of auto-renewal at signup/upgrade)

    Idempotent — calling with the same value as current state is a no-op
    that still returns success.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    try:
        payload = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid JSON body"}, status_code=400)
    enabled = bool(payload.get("enabled", True))

    from .database import MembershipRenewal
    renewal = db.query(MembershipRenewal).filter(MembershipRenewal.user_id == user.id).first()
    if not renewal:
        return JSONResponse({"error": "No active renewal record (activate your membership first)"}, status_code=400)

    renewal.auto_renew_from_balance = enabled
    db.commit()
    return {"ok": True, "auto_renew_from_balance": enabled}


# ── Switch Monthly → Annual within same tier (added 9 May 2026) ─────────
@app.post("/api/switch-to-annual")
async def api_switch_to_annual(request: Request, db: Session = Depends(get_db),
                                 user: User = Depends(get_current_user)):
    """Switch a Monthly member to Annual billing within the same tier.

    Used when a Basic Monthly or Pro Monthly member wants to lock in the
    cheaper annual rate. The existing monthly time is absorbed (rather
    than prorated/credited) — annual is permanently discounted ($40 off
    Basic, $70 off Pro), so the value prop is "switch now, save going
    forward" rather than "we'll credit your unused time."

    Body: {"payment_method": "balance"}

    For NOWPayments and MetaMask rails, the existing endpoints handle
    this case correctly via the membership_basic_annual /
    membership_pro_annual product keys — frontend routes those flows
    directly through /api/nowpayments/create-invoice and the
    WalletConnect intent endpoints. This endpoint is balance-only.

    Pricing:
      - Basic Monthly → Basic Annual: $200 (vs $20/mo monthly)
      - Pro Monthly   → Pro Annual:   $350 (vs $35/mo monthly)
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not user.is_active:
        return JSONResponse({"error": "You need an active membership first"}, status_code=400)

    current_billing = (getattr(user, "membership_billing", None) or "monthly").lower()
    if current_billing == "annual":
        return JSONResponse({"error": "You're already on annual billing"}, status_code=400)

    tier = (user.membership_tier or "free").lower()
    # Under flat partner pricing, legacy 'basic'/'pro' values still resolve as
    # active partners — they were migrated to 'founding' on cutover but pre-
    # cutover callers might still hit this endpoint with 'basic'/'pro' values.
    if tier not in ("basic", "pro", "partner", "founding"):
        return JSONResponse({"error": f"Unknown tier '{tier}'"}, status_code=400)

    # Purchase consent gate
    ok, err = require_fresh_consent(db, user.id, purpose=f"switch_to_annual_{tier}")
    if not ok:
        return JSONResponse({"error": err}, status_code=403)

    body = {}
    try:
        body = await request.json()
    except Exception:
        pass
    payment_method = (body.get("payment_method") or "balance").strip().lower()

    # Annual fee honours locked price (founders pay $150) else standard $200
    locked_price = getattr(user, "membership_price_locked", None)
    annual_fee = (decimal.Decimal(str(locked_price)) * decimal.Decimal("10")) if locked_price is not None else decimal.Decimal("200.00")

    if payment_method != "balance":
        # Crypto and wallet rails route through their own endpoints.
        # NOWPayments: /api/nowpayments/create-invoice with product_key
        # of membership_{tier}_annual. WalletConnect: same product_key
        # via /api/onchain/create-intent. Both correctly call
        # _activate_membership(billing="annual") on confirmation, which
        # handles the same-tier monthly→annual switch transparently.
        return JSONResponse(
            {"error": f"Use the appropriate rail endpoint for {payment_method} payments"},
            status_code=400,
        )

    # Balance rail
    balance = decimal.Decimal(str(user.balance or 0))
    if balance < annual_fee:
        shortfall = annual_fee - balance
        return JSONResponse(
            {
                "error": (
                    f"You need ${float(annual_fee):.2f} to switch to annual. "
                    f"Current balance: ${float(balance):.2f} (short ${float(shortfall):.2f}). "
                    f"Top up your wallet or pay with crypto/MetaMask instead."
                )
            },
            status_code=400,
        )

    # Deduct BEFORE activating so the state change is atomic
    user.balance = balance - annual_fee
    # _activate_membership with billing=annual sets:
    #   - user.membership_billing = "annual"
    #   - user.membership_expires_at = now + 365 days (replaces remaining monthly time)
    #   - records the $X payment
    #   - notifies sponsor (commission was already paid on the original monthly
    #     activation, so is_upgrade=True suppresses double-paying)
    return _activate_membership(db, user, tier, source="switch_to_annual", is_upgrade=True, billing="annual")


