@app.post("/api/nowpayments/create-invoice")
async def nowpayments_create_invoice(request: Request, db: Session = Depends(get_db),
                                      user: User = Depends(get_current_user)):
    """
    Create a NOWPayments invoice for any product.

    Body: {
        "product_key": "membership_basic" | "grid_3" | "email_boost_5000" | ...,
        "meta": { ... optional extra data ... }
    }

    Returns: { "success": true, "invoice_url": "...", "order_id": int }
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    # ── Maintenance gate (hard only — soft = withdrawals only) ──
    if is_hard_maintenance(db):
        return JSONResponse({"error": _MAINTENANCE_MESSAGE}, status_code=503)

    from . import nowpayments_service as nps
    from .database import NowPaymentsOrder
    from decimal import Decimal
    import json as _json

    if not nps.is_configured():
        return JSONResponse({"error": "Payment service not configured"}, status_code=503)

    body = await request.json()
    product_key = body.get("product_key", "").strip()
    product_meta = body.get("meta", {})

    # ── Purchase consent gate ──
    # User must have a fresh, unused consent record for the no-refund /
    # immediate-activation terms before we let any money in. When
    # PURCHASE_CONSENT_ENFORCED is false this only logs; when true it
    # hard-rejects with 403. See app/purchase_consent.py for rationale.
    ok, err = require_fresh_consent(db, user.id, purpose=f"nowpayments:{product_key[:80]}")
    if not ok:
        return JSONResponse({"error": err}, status_code=403)

    # ── Validate product ──
    if product_key in nps.PRODUCT_CATALOG:
        product = nps.PRODUCT_CATALOG[product_key]
        price_usd = product["price"]
        product_type = product["type"]
    elif product_key.startswith("superscene_custom_"):
        # Custom credit amount: superscene_custom_XXX
        try:
            custom_credits = int(product_key.split("_")[-1])
            if custom_credits < 10 or custom_credits > 5000:
                return JSONResponse({"error": "Credits must be between 10 and 5000"}, status_code=400)
            price_usd = Decimal(str(custom_credits)) * SUPERSCENE_CREDIT_RATE
            product_type = "superscene"
        except (ValueError, IndexError):
            return JSONResponse({"error": "Invalid custom credit amount"}, status_code=400)
    else:
        return JSONResponse({"error": f"Unknown product: {product_key}"}, status_code=400)

    if price_usd <= 0:
        return JSONResponse({"error": "Invalid price"}, status_code=400)

    # ── Membership: check if upgrading ──
    if product_type == "membership":
        # Flat-pricing: every membership product activates as "partner".
        # The "founder" vs "partner" pricing distinction is owned by the
        # user record (is_founding_member + membership_price_locked), not
        # the product_key.
        tier = "partner"
        is_annual = "annual" in product_key
        # ── Founding partner pricing (15 May 2026) ─────────────────────
        # If user is not yet active and founding spots remain, quote $15
        # ($150 annual) instead of $20. The atomic claim runs at activation
        # time in _activate_membership — this only sets the AMOUNT they're
        # asked to send to NOWPayments.
        if not user.is_active:
            try:
                founding_count = db.execute(text(
                    "SELECT COUNT(*) FROM users WHERE is_founding_member = TRUE"
                )).scalar() or 0
                if founding_count < 100 and not _is_returning_member(db, user):
                    price_usd = Decimal("150.00") if is_annual else Decimal("15.00")
                    logger.info(
                        f"NOWPayments: founding price ${price_usd} quoted to "
                        f"user {user.id} (spot #{founding_count + 1} reservable)"
                    )
            except Exception as e:
                logger.error(
                    f"NOWPayments founding price check failed for user "
                    f"{user.id}: {e} — using standard pricing"
                )
        # Already-paying guard. Under flat-pricing the only paid tier is
        # 'partner' (with the 'founding' subset for the first 100). If the
        # user is already is_active they can't re-buy membership — they're
        # on the renewal track. Old logic had separate Basic/Pro guards
        # plus a Basic→Pro upgrade price path (the $15 difference); flat
        # pricing has no upgrade path because there's nothing to upgrade to.
        if tier in ("basic", "pro", "partner") and user.is_active and not is_annual:
            return JSONResponse({"error": "You already have an active membership"}, status_code=400)

    # ── Grid: check active membership ──
    if product_type == "grid" and not user.is_active:
        return JSONResponse({"error": "Active membership required to purchase Campaign Tiers"}, status_code=400)

    # ── Grid: repurchase guard ──
    # Refuse if the user has an in-flight VideoCampaign at this tier (views
    # not yet fully delivered). The campaign is the actual product they paid
    # for last time; until its views_delivered >= views_target, repurchasing
    # is paying for the same undelivered service twice.
    #
    # Note: this is GATED ON THE CAMPAIGN, NOT THE GRID. The grid is a
    # passive earnings mechanism that can complete and renew many times
    # against a single campaign; gating on grid completion would block
    # legitimate fresh purchases. See commission-spec.md.
    if product_type == "grid":
        try:
            tier_num = int(product_key.split("_")[1])
            in_flight = db.query(VideoCampaign).filter(
                VideoCampaign.user_id == user.id,
                VideoCampaign.campaign_tier == tier_num,
                VideoCampaign.is_completed == False,
            ).first()
            if in_flight:
                delivered = int(in_flight.views_delivered or 0)
                target = int(in_flight.views_target or 0)
                return JSONResponse({
                    "error": (
                        f"You already have an active Campaign Tier {tier_num} that hasn't "
                        f"completed delivery yet — {delivered:,} of {target:,} views delivered "
                        f"so far. Wait for it to deliver all {target:,} views, then you can "
                        f"purchase again."
                    ),
                    "code": "campaign_in_flight",
                    "tier": tier_num,
                    "views_delivered": delivered,
                    "views_target": target,
                    "progress_pct": round((delivered / target * 100) if target else 0, 1),
                }, status_code=409)

            # ── Sequential tier purchase gate ──
            # Refuse Tier N if member doesn't own Tier N-1 yet. Same
            # rule enforced server-side at activation time in
            # process_tier_purchase — this just catches the violation
            # earlier so we don't take their crypto and then refuse to
            # activate. See grid.py for full rationale.
            if tier_num > 1:
                prerequisite = tier_num - 1
                from .database import Grid
                owns_prereq = db.query(Grid).filter(
                    Grid.owner_id == user.id,
                    Grid.package_tier == prerequisite,
                ).first()
                if not owns_prereq:
                    return JSONResponse({
                        "error": (
                            f"Tier {tier_num} requires Tier {prerequisite} first. "
                            f"Campaign Tiers must be purchased in order — buy Tier "
                            f"{prerequisite} before Tier {tier_num}."
                        ),
                        "code": "tier_sequence_violation",
                        "required_tier": prerequisite,
                    }, status_code=400)
        except (ValueError, IndexError):
            return JSONResponse({"error": f"Invalid grid product key: {product_key}"}, status_code=400)

    # ── Cancel existing pending NOWPayments orders for same product ──
    db.query(NowPaymentsOrder).filter(
        NowPaymentsOrder.user_id == user.id,
        NowPaymentsOrder.product_key == product_key,
        NowPaymentsOrder.status == "pending",
    ).update({"status": "cancelled"})
    db.flush()

    # ── Create local order record first ──
    order = NowPaymentsOrder(
        user_id=user.id,
        product_type=product_type,
        product_key=product_key,
        product_meta=_json.dumps(product_meta) if product_meta else None,
        price_usd=price_usd,
        status="pending",
    )
    db.add(order)
    db.flush()  # Get order.id

    internal_order_id = f"SAP-{user.id}-{order.id}"
    order.internal_order_id = internal_order_id

    # ── Create NOWPayments invoice ──
    # IMPORTANT: always pass custom_price=price_usd (not just for upgrades).
    # Otherwise create_invoice falls back to PRODUCT_CATALOG[product_key]['price']
    # which is the standard $20, bypassing our founding-price override at line ~8637.
    # Test13 hit this bug on 16 May 2026: backend computed $15 founding price
    # correctly, but the NOWPayments invoice was created at $20 because
    # custom_price was None unless is_upgrade was True.
    result = nps.create_invoice(
        product_key=product_key,
        user_id=user.id,
        order_id=order.id,
        custom_price=price_usd,
        custom_description=(
            "SuperAdPro Pro Membership Upgrade"
            if product_meta.get("is_upgrade")
            else f"SuperAdPro — {nps.PRODUCT_CATALOG.get(product_key, {}).get('desc', product_key)}"
        ),
    )

    if not result["success"]:
        order.status = "failed"
        db.commit()
        return JSONResponse({"error": result["error"]}, status_code=502)

    order.np_invoice_id = result.get("np_id")
    order.invoice_url = result.get("invoice_url")
    db.commit()

    return {
        "success": True,
        "invoice_url": result["invoice_url"],
        "order_id": order.id,
        "internal_order_id": internal_order_id,
    }
@app.post("/api/webhook/nowpayments")
async def nowpayments_ipn_webhook(request: Request, db: Session = Depends(get_db)):
    """
    NOWPayments IPN (Instant Payment Notification) webhook.
    Called by NOWPayments on every payment status change.

    Verifies HMAC-SHA512 signature, updates order, activates product on success.
    """
    from . import nowpayments_service as nps
    from .database import NowPaymentsOrder
    from decimal import Decimal
    from datetime import datetime
    import json as _json

    # ── Read raw body + signature ──
    body_bytes = await request.body()
    signature = request.headers.get("x-nowpayments-sig", "")

    # ── Verify signature ──
    if not nps.verify_ipn_signature(body_bytes, signature):
        logger.warning("NOWPayments IPN: invalid signature")
        return JSONResponse({"error": "Invalid signature"}, status_code=403)

    data = nps.parse_ipn_body(body_bytes)
    if not data:
        return JSONResponse({"error": "Invalid body"}, status_code=400)

    payment_status = data.get("payment_status", "")
    order_id_str = data.get("order_id", "")  # "SAP-{user_id}-{order_id}"
    np_payment_id = data.get("payment_id")

    logger.info(f"NOWPayments IPN: status={payment_status} order={order_id_str} payment_id={np_payment_id}")

    if not order_id_str or not order_id_str.startswith("SAP-"):
        logger.warning(f"NOWPayments IPN: unrecognized order_id format: {order_id_str}")
        return {"status": "ignored", "reason": "unrecognized order_id"}

    # ── Find our order ──
    order = db.query(NowPaymentsOrder).filter(
        NowPaymentsOrder.internal_order_id == order_id_str
    ).first()

    if not order:
        logger.warning(f"NOWPayments IPN: order not found: {order_id_str}")
        return {"status": "ignored", "reason": "order_not_found"}

    # ── Update payment details ──
    order.np_payment_id = np_payment_id
    order.pay_currency = data.get("pay_currency")
    order.pay_amount = data.get("pay_amount")
    order.actually_paid = data.get("actually_paid")
    order.outcome_amount = data.get("outcome_amount")
    order.outcome_currency = data.get("outcome_currency")

    prev_status = order.status

    # ── CRITICAL GUARD: refuse status downgrades from a terminal state ──
    # NOWPayments sometimes delivers IPNs out-of-order or retries late.
    # Without this guard, a late "sending"/"confirming" IPN arriving AFTER
    # "finished" overwrites status back to "sending". The order then
    # appears in the Stuck Orders monitor; an admin clicks Recover and
    # the activation runs a SECOND time, paying duplicate commissions.
    # Confirmed root cause of the test1 $18.50 duplicate on 30 Apr 2026.
    TERMINAL_STATES = ("finished", "confirmed")
    if prev_status in TERMINAL_STATES and payment_status not in TERMINAL_STATES:
        logger.warning(
            f"NOWPayments IPN: refused to downgrade order {order_id_str} from "
            f"prev_status={prev_status} to payment_status={payment_status}. "
            f"NP IPN arrived out-of-order or as a retry. Ignoring."
        )
        return {"status": "ignored", "reason": "would_downgrade_terminal_state",
                "prev_status": prev_status, "incoming_status": payment_status}

    # ── Handle status transitions ──
    if payment_status in ("waiting", "confirming", "sending"):
        order.status = payment_status
        db.commit()
        return {"status": "updated", "payment_status": payment_status}

    # ── Partial payment: tolerance-aware auto-recovery ──
    # Crypto payments routinely arrive 1-2% short of the requested amount
    # because of exchange withdrawal fees (Coinbase ~$1, Binance ~$0.50-2,
    # etc.) and tiny spreads in the conversion rate. Before 12 May 2026
    # we treated EVERY partial payment as needing manual admin recovery,
    # which created a real customer-friction issue:
    #
    #   - Today: customer paid 19.94 of 19.95 USDT (1 cent short on a $20
    #     product). Funds reached the treasury. Membership locked until
    #     admin clicked Recover. Auto-recovery would have saved a support
    #     ticket and a confused customer.
    #   - Coinbase users routinely lose ~$1 to the platform's own
    #     withdrawal fee. Without auto-recovery they ALL hit this issue.
    #   - Binance users with rounding in their UI hit the same thing.
    #
    # Tolerance policy:
    #   ratio = actually_paid / pay_amount
    #   ratio >= 0.95  → AUTO-RECOVER. Funds are with NOWPayments and will
    #                    be forwarded to treasury. Activate immediately
    #                    via the same path as a fully-paid order.
    #   ratio <  0.95  → leave as partially_paid for admin review. A 5%
    #                    shortfall on a $35 product is $1.75 — outside
    #                    any plausible exchange fee, suggests something
    #                    else is wrong.
    #
    # The 95% threshold was chosen because:
    #   - $20 product: $1 shortfall absorbed (typical Coinbase fee)
    #   - $35 product: $1.75 shortfall absorbed (Coinbase + small slip)
    #   - $100 pack:   $5 shortfall absorbed (generous for any exchange)
    #   - $1000 pack:  $50 shortfall absorbed (still well inside any
    #     realistic fee structure for moving USDT across chains)
    #
    # We deliberately do NOT auto-recover below 95%. Those go to the
    # admin queue with a notification so a human reviews. This is the
    # right boundary because below 95% is rarely "innocent shortfall"
    # — it's usually wrong amount, wrong network, or attempted
    # underpayment.
    if payment_status == "partially_paid":
        try:
            pay_required = float(data.get("pay_amount") or 0)
            paid_actual = float(data.get("actually_paid") or 0)
            ratio = (paid_actual / pay_required) if pay_required > 0 else 0
        except (TypeError, ValueError):
            ratio = 0
            pay_required = 0
            paid_actual = 0

        TOLERANCE = 0.95
        within_tolerance = ratio >= TOLERANCE and pay_required > 0

        if within_tolerance and prev_status not in ("finished", "confirmed"):
            # Auto-recover: rewrite payment_status so the standard "finished"
            # activation block below runs. This deliberately reuses the
            # existing activation path rather than duplicating it — using
            # the same Payment record creation, _nowpayments_activate_product
            # call, idempotency guards, wrong-asset check, etc.
            shortfall_usd = round(pay_required - paid_actual, 4)
            shortfall_pct = round((1 - ratio) * 100, 2)
            logger.warning(
                f"NOWPayments IPN: AUTO-RECOVERING partial payment for order "
                f"{order_id_str}. paid={paid_actual} of {pay_required} "
                f"({shortfall_pct}% short / ${shortfall_usd} short). "
                f"Within {int(TOLERANCE*100)}% tolerance — activating."
            )
            # Tag the order so we can audit auto-recovered payments later
            order.partial_recovery_logged = True
            order.partial_recovery_shortfall_usd = shortfall_usd
            # Rewrite local variable so the activation block runs
            payment_status = "finished"
            # Fall through to the activation flow below (NOT a return)
        else:
            order.status = "partially_paid"
            db.commit()
            logger.warning(
                f"NOWPayments IPN: partial payment NEEDS REVIEW for order "
                f"{order_id_str}. paid={paid_actual} of {pay_required} "
                f"(ratio={ratio:.3f}). Outside {int(TOLERANCE*100)}% tolerance — "
                f"admin recovery required."
            )
            # Notify admins via the support email path — same channel as a
            # customer support ticket, so it lands in the admin's inbox.
            try:
                admin_users = db.query(User).filter(User.is_admin == True).all()
                for admin_u in admin_users:
                    db.add(Notification(
                        user_id=admin_u.id,
                        type="payment_review",
                        icon="⚠️",
                        title=f"Partial payment needs review",
                        message=f"Order {order_id_str}: paid ${paid_actual:.2f} of "
                                f"${pay_required:.2f} ({int(ratio*100)}%). "
                                f"Outside auto-recovery tolerance.",
                        link="/admin",
                    ))
                db.commit()
            except Exception as _exc:
                logger.warning(f"Failed to send admin partial-payment notification: {_exc}")
            return {"status": "updated", "payment_status": "partially_paid",
                    "auto_recovered": False, "ratio": round(ratio, 3)}

    if payment_status in ("failed", "refunded", "expired"):
        order.status = payment_status
        db.commit()
        logger.info(f"NOWPayments IPN: order {order_id_str} → {payment_status}")
        return {"status": "updated", "payment_status": payment_status}

    # ── Payment confirmed/finished — activate the product ──
    if nps.is_payment_finished(payment_status):
        # Prevent double-activation
        if prev_status in ("confirmed", "finished"):
            logger.info(f"NOWPayments IPN: order {order_id_str} already fulfilled (status={prev_status})")
            return {"status": "already_processed"}

        # ── Wrong-asset guard (rewritten 26 May 2026 after Robert case) ──
        # NOWPayments still fires the IPN with status="confirmed" when a
        # buyer sends the wrong cryptocurrency, but the right protection
        # is VALUE delivered vs VALUE invoiced, NOT currency string
        # equality.
        #
        # Why the change: the old guard rejected ANY mismatch between
        # pay_currency and outcome_currency strings. That correctly
        # caught "sent TRX for a USDT invoice" (different value, scam-
        # adjacent) but WRONGLY rejected legitimate cross-chain USDT
        # conversions like "sent USDT-ERC20 to a USDT-BSC invoice"
        # (same value, NOWPayments handled the bridge, treasury received
        # full amount). Robert Brooks (user 416, 26 May 2026) sent
        # USDTETH against a USDTBSC invoice for $15.00; NOWPayments
        # delivered 15.005681 USDT to our BSC treasury; old guard
        # rejected him; he sat stuck until he messaged in.
        #
        # New guard: compare value delivered (in USD-equivalent USDT)
        # against the invoice price_usd. If delivered ≥ 95% of invoice,
        # fulfil. If less, reject as underpayment (the actual scam
        # vector this guard was designed to catch — someone sending $4
        # of TRX for a $20 USDT invoice would deliver ~$4 of value).
        #
        # 5% tolerance accounts for: NOWPayments' 0.5% conversion fee,
        # network fees deducted from the conversion, normal USDT-vs-USD
        # pricing rounding, and BSC vs ETH gas variability. Anything
        # below 95% is a genuine underpayment we should refuse.
        invoice_usd = float(order.price_usd or 0)
        delivered_usdt = float(data.get("actually_paid") or 0)
        # NOWPayments delivers USDT-pegged amounts; treat 1 USDT ≈ $1
        # for the value check. Acceptable simplification — USDT
        # depegs are rare and small (< 0.5% historically).
        delivered_usd_equivalent = delivered_usdt
        # Underpayment threshold: deliver at least 95% of invoiced value
        UNDERPAYMENT_THRESHOLD = 0.95
        if invoice_usd > 0 and delivered_usd_equivalent > 0:
            ratio = delivered_usd_equivalent / invoice_usd
            if ratio < UNDERPAYMENT_THRESHOLD:
                logger.warning(
                    f"NOWPayments IPN: UNDERPAYMENT on order {order_id_str} — "
                    f"invoiced ${invoice_usd}, delivered ${delivered_usd_equivalent:.4f} "
                    f"USDT (ratio={ratio:.3f} < {UNDERPAYMENT_THRESHOLD}). "
                    f"pay_currency={data.get('pay_currency')}, "
                    f"outcome_currency={data.get('outcome_currency')}. "
                    f"Refusing to fulfil. Manual review required."
                )
                order.status = "wrong_asset"
                db.commit()
                return {
                    "status": "rejected",
                    "reason": "underpayment",
                    "invoice_usd": invoice_usd,
                    "delivered_usd_equivalent": delivered_usd_equivalent,
                    "ratio": round(ratio, 3),
                }
            else:
                # Log the cross-chain conversion for forensics — useful when
                # diagnosing "I sent X but it shows as Y in my account."
                expected_currency = (data.get("pay_currency") or "").lower()
                actual_currency = (data.get("outcome_currency") or "").lower()
                if expected_currency and actual_currency and expected_currency != actual_currency:
                    logger.info(
                        f"NOWPayments IPN: cross-chain conversion on order "
                        f"{order_id_str} — pay={expected_currency}, "
                        f"delivered={actual_currency}, value=${delivered_usd_equivalent:.4f} "
                        f"(ratio={ratio:.3f}). Fulfilling — value check passed."
                    )

        # Atomic activation block. If any step raises, rollback so we don't
        # leave inconsistent state (e.g. order marked finished but Payment
        # row missing, or activation half-applied). Returning 500 causes
        # NOWPayments to retry — the prev_status check above makes retry
        # safe because already-processed orders short-circuit.
        #
        # Note: engine functions (_activate_membership, purchase_credit_pack,
        # etc.) commit internally. If they commit successfully but a later
        # step here raises, the engine's work persists and we log loudly
        # for manual reconciliation. This is a known limitation — full
        # atomicity would require refactoring engine signatures, which is
        # tracked as a post-launch improvement.
        try:
            order.status = "finished"
            order.confirmed_at = datetime.utcnow()
            db.flush()

            # Load the user
            user = db.query(User).filter(User.id == order.user_id).first()
            if not user:
                logger.error(f"NOWPayments IPN: user {order.user_id} not found for order {order_id_str}")
                db.rollback()
                return JSONResponse({"error": "User not found"}, status_code=404)

            meta = _json.loads(order.product_meta) if order.product_meta else {}

            # Record payment in main payments table.
            # Idempotent: if a Payment with this tx_hash already exists (e.g.
            # from a prior IPN retry where the engine committed but we rolled
            # back), reuse it rather than creating a duplicate. Same retry
            # protection as the prev_status guard, but at row-level.
            import uuid
            tx_ref = f"np_{np_payment_id}" if np_payment_id else f"np_{uuid.uuid4().hex[:12]}"
            existing_payment = db.query(Payment).filter(Payment.tx_hash == tx_ref).first()
            if existing_payment:
                logger.info(f"NOWPayments IPN: Payment row already exists for tx_hash={tx_ref}, reusing")
                payment = existing_payment
            else:
                payment = Payment(
                    from_user_id=user.id, to_user_id=None,
                    amount_usdt=order.price_usd,
                    payment_type=f"nowpayments_{order.product_type}",
                    tx_hash=tx_ref,
                    status="confirmed",
                )
                db.add(payment)
                db.flush()

            # ── Activate product using same shared logic as crypto payments ──
            _nowpayments_activate_product(db, user, order, meta)

            db.commit()
            logger.info(f"NOWPayments IPN: order {order_id_str} FULFILLED — {order.product_type}/{order.product_key}")
            return {"status": "fulfilled", "payment_status": payment_status}
        except Exception as exc:
            db.rollback()
            logger.error(
                f"NOWPayments IPN: ACTIVATION FAILED for order {order_id_str} "
                f"(user={order.user_id}, product_type={order.product_type}, "
                f"product_key={order.product_key}): {exc}",
                exc_info=True,
            )
            # Return 500 so NOWPayments retries. The order is left in its
            # previous status (still pending or whatever it was), so the retry
            # will re-attempt activation cleanly. If an engine commit
            # succeeded internally before the exception, we'll see it in the
            # logs and can manually reconcile.
            return JSONResponse(
                {"error": "Activation failed, will retry", "order_id": order_id_str},
                status_code=500,
            )

    # Unknown status
    order.status = payment_status
    db.commit()
    return {"status": "updated", "payment_status": payment_status}
def _nowpayments_activate_product(db, user, order, meta):
    """Activate the correct product after NOWPayments payment is confirmed.
    Mirrors _crypto_activate_product logic exactly."""
    from datetime import datetime, timedelta
    from decimal import Decimal
    import uuid

    product_key = order.product_key

    # ── Membership ──
    if order.product_type == "membership":
        # Flat-pricing: every membership product activates as "partner".
        # The "founder" vs "partner" pricing distinction is owned by the
        # user record (is_founding_member + membership_price_locked), not
        # the product_key.
        tier = "partner"
        billing = "annual" if "annual" in product_key else "monthly"
        is_upgrade = meta.get("is_upgrade", False)
        # Renewal: a 'renew' product paid by an ALREADY-ACTIVE member must NOT
        # go through activation. _activate_membership bails for active members
        # (anti-double-sponsor) and would re-run fresh-activation work (grid,
        # founding-spot claim). Route to the shared renewal engine, which pays
        # the sponsor exactly once per member-month (idempotent) and extends the
        # membership window. Both crypto rails (BSC self-custody + NOWPayments)
        # land here, so this covers them all.
        if "renew" in (product_key or "") and getattr(user, "is_active", False):
            from .payment import process_membership_renewal
            _oid = (getattr(order, "internal_order_id", None)
                    or getattr(order, "np_payment_id", None)
                    or f"order:{getattr(order, 'id', '?')}")
            process_membership_renewal(db, user, rail="crypto", source_event_id=str(_oid))
        else:
            _activate_membership(db, user, tier, source="nowpayments", is_upgrade=is_upgrade, billing=billing)

    # ── Grid / Campaign Tier ──
    elif order.product_type == "grid":
        package_tier = int(product_key.split("_")[1])
        from .grid import process_tier_purchase
        # Idempotency: key on the order id so a re-fired callback can't
        # double-pay the grid commission chain (28 May 2026). internal_order_id
        # and np_payment_id exist on NOWPayments orders but NOT on
        # WalletConnectPaymentOrder, which the BSC scanner ALSO routes through
        # this shared activator -- bare attribute access threw AttributeError and
        # silently failed EVERY WalletConnect grid activation (surfaced by the
        # reconcile endpoint on SAP-00352 grid_2). getattr-guard both and fall
        # back to a stable per-order key so WC grids still get a replay guard.
        _np_event = (getattr(order, "internal_order_id", None)
                     or (f"np_{order.np_payment_id}" if getattr(order, "np_payment_id", None) else None)
                     or f"wcorder_{order.id}")
        result = process_tier_purchase(db=db, buyer_id=user.id, package_tier=package_tier,
                                       source_event_id=_np_event)
        if not result["success"]:
            logger.error(f"NOWPayments grid purchase failed for user {user.id} tier {package_tier}: {result.get('error')}")
        else:
            # ── Launchpad entry (tier 0) ───────────────────────────────────
            # A free (non-member) user who buys the $10 Launchpad enters the
            # comp plan at the 'launchpad' rung: can_earn() becomes True
            # (refer / earn / withdraw) while is_pro() stays False (tools and
            # tiers 1-8 locked) until they upgrade to full membership. Set
            # ONLY on a genuine free->launchpad transition — never downgrade
            # an active member who happens to buy tier 0, and idempotent if
            # they re-enter at tier 0. Follows the fast_start pattern below:
            # db.add, no commit here — the BSC-scan caller commits (verified
            # at cron_scan_bsc_payments, db.commit() right after this call).
            if package_tier == 0 and not user.is_active and getattr(user, "membership_tier", None) != "launchpad":
                user.membership_tier = "launchpad"
                db.add(user)
                logger.info(f"Launchpad activated: user {user.id} -> membership_tier='launchpad'")
            # Fast Start hero — once the user activates Grid Tier 1 the hero
            # has done its job and should never reappear. Set hidden_at so
            # the dashboard React surface stops rendering it. (Higher tiers
            # don't gate the hero — the hero is specifically for users with
            # zero grid positions, so only T1 activation matters here, but
            # we set it on any grid activation as a defensive measure since
            # any grid purchase means the user has crossed the activation
            # threshold.) Added 17 May 2026.
            try:
                if user.fast_start_hidden_at is None:
                    user.fast_start_hidden_at = datetime.utcnow()
                    db.add(user)
                    # No commit here — caller's transaction will flush.
            except Exception as _e:
                logger.warning(f"fast_start_hidden_at set failed for user {user.id}: {_e}")
            # ── Notifications: best-effort, MUST NOT break the activation transaction ──
            # process_tier_purchase calls db.commit() internally so commissions and
            # grid placements are already persisted. Notifications below are pure
            # add-on. Any exception is logged and swallowed — we explicitly DO NOT
            # call db.rollback() because the IPN handler's outer transaction still
            # needs to commit the order.status='finished' and Payment row that
            # were added BEFORE this function was called.
            try:
                from .database import Commission
                # Buyer notification — tier active + daily quota reminder
                daily_count = DAILY_VIDEO_QUOTA.get(package_tier, package_tier)
                buyer_notif = Notification(
                    user_id=user.id,
                    type="commission",
                    icon="⚡",
                    title=f"Campaign Tier {package_tier} activated!",
                    message=(f"Watch {daily_count} video{'s' if daily_count > 1 else ''} every day "
                             f"to keep your commissions flowing. Miss too many days in a row "
                             f"and commissions pause until you catch up."),
                    link="/watch",
                )
                db.add(buyer_notif)

                # Sponsor notifications — read the ACTUAL Commission rows just created
                # for this buyer at this tier. Only notify uplines whose commission
                # was actually paid (to_user_id IS NOT NULL). Commissions where the
                # 40% / 6.25% was company-absorbed (sponsor unqualified) intentionally
                # do not generate notifications — telling someone "you earned $8"
                # when they didn't would be a lie. Yesterday's session ate $9 of
                # company absorb on this exact path because test1 had no active
                # video campaign at Tier 1 — the qualification rule.
                #
                # Once the commission flow is changed (so tier purchase alone
                # qualifies), this query will start finding paid commissions and
                # firing notifications naturally.
                paid_commissions = db.query(Commission).filter(
                    Commission.from_user_id == user.id,
                    Commission.package_tier == package_tier,
                    Commission.to_user_id.isnot(None),
                    Commission.commission_type.in_(["direct_sponsor", "uni_level"]),
                ).order_by(Commission.id.desc()).limit(10).all()

                buyer_username = user.username or f"User {user.id}"
                for comm in paid_commissions:
                    is_direct = (comm.commission_type == "direct_sponsor")
                    amount = float(comm.amount_usdt or 0)
                    if is_direct:
                        title = f"💰 New direct referral! +${amount:.2f}"
                        message = (f"{buyer_username} just bought Tier {package_tier}. "
                                   f"You earned ${amount:.2f} commission and a seat opened in your Tier {package_tier} grid.")
                    else:
                        title = f"💰 Downline activity! +${amount:.2f}"
                        message = (f"{buyer_username} bought Tier {package_tier}. "
                                   f"You earned ${amount:.2f} uni-level commission.")
                    sp_notif = Notification(
                        user_id=comm.to_user_id,
                        type="commission",
                        icon="💰",
                        title=title,
                        message=message,
                        link="/grid-visualiser",
                    )
                    db.add(sp_notif)
                # No db.flush() / db.rollback() — let the outer IPN handler's
                # commit() handle these alongside order.status and Payment row.
            except Exception as e:
                # Log only — DO NOT rollback. Notifications failing should not
                # take down the activation transaction.
                logger.warning(
                    f"Failed to create activation notifications for user {user.id} "
                    f"tier {package_tier}: {e}"
                )

    # ── Email Boost ──
    elif order.product_type == "al_lifetime":
        # AdvantageLife $100 lifetime join via crypto — flat activation,
        # sponsor earns nothing on the join (locked model).
        try:
            _al_activate_lifetime(db, order.user_id, source="nowpayments",
                                  ref=f"np_{order.id}")
        except Exception:
            logger.exception(f"al_lifetime NOWPayments activation crashed for order {order.id}")

    elif order.product_type == "email_boost":
        pack_map = {
            "email_boost_1000": 1000,
            "email_boost_5000": 5000,
            "email_boost_10000": 10000,
            "email_boost_50000": 50000,
        }
        credits = pack_map.get(product_key, 0)
        if credits:
            user.email_credits = (user.email_credits or 0) + credits

    # ── SuperScene Credit Packs (preset + custom) ──
    elif order.product_type == "superscene":
        credits = _resolve_superscene_credits(product_key)
        if credits:
            from .database import SuperSceneCredit
            sc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == user.id).first()
            if not sc:
                sc = SuperSceneCredit(user_id=user.id, balance=0)
                db.add(sc)
                db.flush()
            sc.balance = (sc.balance or 0) + credits
            # Also record in superscene_orders for history
            try:
                from .database import SuperSceneOrder
                slug = product_key.replace("superscene_", "")
                sc_order = SuperSceneOrder(
                    user_id=user.id,
                    pack_slug=slug,
                    credits=credits,
                    amount_usd=order.price_usd,
                    payment_method="nowpayments",
                    status="completed",
                )
                sc_order.completed_at = datetime.utcnow()
                db.add(sc_order)
            except Exception as e:
                logger.error(f"SuperScene order record failed: {e}")

    # ── Credit Matrix Packs ──
    elif order.product_type == "credit_matrix":
        pack_key = product_key.replace("credit_matrix_", "")  # starter/builder/pro/elite/ultimate
        try:
            from .credit_matrix import purchase_credit_pack
            # Derive payment ref prefix from the order class — keeps audit
            # trails distinct between NOWPayments and WalletConnect rails
            # (avoids np_47 colliding with a real NOWPayments order 47
            # when the WalletConnect rail has its own id-space).
            _ref_prefix = "wc" if type(order).__name__ == "WalletConnectPaymentOrder" else "np"
            result = purchase_credit_pack(
                db, user, pack_key,
                payment_ref=f"{_ref_prefix}_{order.id}",
                payment_method="crypto",
            )
            if not result["success"]:
                logger.error(f"Credit Matrix purchase failed for user {user.id}: {result.get('error')}")
            else:
                logger.info(f"Credit Matrix: {user.username} bought {pack_key} pack via {_ref_prefix}, {result.get('credits_awarded')} credits awarded")
        except Exception as e:
            logger.error(f"Credit Matrix fulfilment error: {e}")

    # ── Pay It Forward voucher (Step 4 triple-rail audit, 7 May 2026) ──
    # Creates the GiftVoucher row in 'available' state once payment confirms.
    # Mirrors the wallet-balance branch in /api/pay-it-forward/create — same
    # voucher creation logic, just triggered async after on-chain or NP IPN
    # confirmation. Idempotent against tx_hash via the order's status check
    # earlier in this function (already 'confirmed' when we land here).
    elif order.product_type == "pif":
        try:
            from .database import GiftVoucher
            # Locate the buyer's existing gift chain (if any) — same as
            # the wallet path in /api/pay-it-forward/create.
            received = db.query(GiftVoucher).filter(GiftVoucher.claimed_by_user_id == user.id).first()
            parent_id = received.id if received else None
            chain_depth = (received.pif_chain_depth + 1) if received else 1

            # Generate unique code (same algorithm as wallet path).
            for _ in range(10):
                code = _generate_voucher_code()
                existing = db.query(GiftVoucher).filter(GiftVoucher.voucher_code == code).first()
                if not existing:
                    break
            else:
                logger.error(f"PIF activation: could not generate unique voucher code for user {user.id}")
                return

            # Pull recipient_name + personal_message from product_meta if
            # the page passed them through. Frontend SHOULD set these in
            # productMeta on the WalletPayLink for full parity with the
            # wallet path.
            meta_raw = order.product_meta or "{}"
            try:
                import json as _json
                meta = _json.loads(meta_raw) if isinstance(meta_raw, str) else (meta_raw or {})
            except Exception:
                meta = {}
            _ref_prefix = "wc" if type(order).__name__ == "WalletConnectPaymentOrder" else "np"

            voucher = GiftVoucher(
                gifter_user_id=user.id,
                voucher_code=code,
                gift_type="membership",
                gift_value=20,
                recipient_name=(meta.get("recipient_name") or "")[:100] or None,
                personal_message=(meta.get("personal_message") or "")[:500] or None,
                is_free_voucher=False,
                payment_method="crypto",
                payment_ref=f"{_ref_prefix}_{order.id}",
                status="available",
                pif_chain_depth=chain_depth,
                parent_voucher_id=parent_id,
            )
            db.add(voucher)
            db.commit()
            logger.info(f"PIF activation: {user.username} bought voucher {code} via {_ref_prefix} (chain depth {chain_depth})")
        except Exception as e:
            logger.error(f"PIF activation error for user {user.id}: {e}", exc_info=True)

    # ── Membership Pro Upgrade — retired 15 May 2026 ──
    # Flat-pricing eliminated tier upgrades. The 'membership_upgrade'
    # product_type can still appear on historical orders that confirm
    # late, but there's no upgrade to apply — every active member
    # already has full platform access. Log and skip cleanly.
    elif order.product_type == "membership_upgrade":
        logger.warning(
            f"Legacy membership_upgrade order {order.id} confirmed for user "
            f"{user.id} — tier upgrades retired under flat-pricing. No "
            f"activation applied; refund manually if the customer expected one."
        )
@app.get("/api/nowpayments/order/{order_id}")
async def nowpayments_order_status(order_id: int, request: Request,
                                    db: Session = Depends(get_db),
                                    user: User = Depends(get_current_user)):
    """Check the status of a NOWPayments order."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from .database import NowPaymentsOrder
    order = db.query(NowPaymentsOrder).filter(
        NowPaymentsOrder.id == order_id,
        NowPaymentsOrder.user_id == user.id,
    ).first()

    if not order:
        return JSONResponse({"error": "Order not found"}, status_code=404)

    return {
        "order_id": order.id,
        "status": order.status,
        "product_key": order.product_key,
        "price_usd": str(order.price_usd),
        "invoice_url": order.invoice_url,
        "pay_currency": order.pay_currency,
        "actually_paid": str(order.actually_paid) if order.actually_paid else None,
        "confirmed_at": order.confirmed_at.isoformat() if order.confirmed_at else None,
        "created_at": order.created_at.isoformat() if order.created_at else None,
    }
@app.post("/withdraw")
def withdraw(
    request:     Request,
    amount: float = Form(),
    totp_code: str = Form(default=""),
    wallet_type: str = Form(default="affiliate"),
    idempotency_key: str = Form(default=""),
    db:          Session = Depends(get_db),
    user:        User = Depends(get_current_user)
):
    """Process withdrawal request. Returns JSON for SPA consumption.
    On success: {success: true, message, tx_hash, net_amount, fee, remaining, wallet_type}
    On failure: {success: false, error}

    idempotency_key: optional UUID supplied by the frontend per Withdraw
    button click. The server uses it to short-circuit duplicate
    submissions (double-clicks, flaky 4G retries) and return the original
    attempt's result instead of firing a second on-chain transfer.
    """
    if not user:
        return JSONResponse({"success": False, "error": "Not signed in"}, status_code=401)
    # ── Maintenance gate ──
    # Withdrawals are halted in BOTH soft and hard maintenance modes.
    # Soft mode = withdrawals only. Hard mode = withdrawals + other money flows.
    if is_any_maintenance(db):
        return JSONResponse({"success": False, "error": _MAINTENANCE_MESSAGE}, status_code=503)
    # ── KYC Gate ──
    if getattr(user, 'kyc_status', 'none') != 'approved':
        return JSONResponse({"success": False, "error": "KYC verification required before withdrawal. Go to Account to complete."}, status_code=403)
    # ── 2FA Gate — must be enabled AND code must be valid ──
    if not getattr(user, 'totp_enabled', False):
        return JSONResponse({"success": False, "error": "Two-factor authentication required before withdrawal. Go to Account to enable."}, status_code=403)
    import pyotp
    if not totp_code or not totp_code.strip():
        return JSONResponse({"success": False, "error": "Please enter your 2FA code to authorise this withdrawal."}, status_code=400)
    totp = pyotp.TOTP(user.totp_secret)
    if not totp.verify(totp_code.strip(), valid_window=1):
        return JSONResponse({"success": False, "error": "Invalid 2FA code. Please try again."}, status_code=400)
    # ── Validate wallet_type ──
    if wallet_type not in ("affiliate", "campaign"):
        wallet_type = "affiliate"
    # ── Sanitise idempotency_key ── treat empty string as "not supplied"
    # and length-cap to defend against crafted huge payloads landing in
    # the unique index.
    idem = (idempotency_key or "").strip()
    if not idem:
        idem = None
    elif len(idem) > 64:
        idem = idem[:64]
    # ── 2FA verified — process withdrawal ──
    result = request_withdrawal(db, user.id, amount, wallet_type=wallet_type, idempotency_key=idem)
    if result["success"]:
        return JSONResponse({
            "success":     True,
            "message":     result.get("message", "Withdrawal processed"),
            "tx_hash":     result.get("tx_hash", ""),
            "net_amount":  result.get("net_amount"),
            "fee":         result.get("fee"),
            "remaining":   result.get("remaining"),
            "wallet_type": result.get("wallet_type", wallet_type),
            "queued":      result.get("queued", False),
        })
    return JSONResponse({"success": False, "error": result.get("error", "Withdrawal failed")}, status_code=400)
