@app.get("/admin/api/publish-offer-page")
def admin_publish_offer_page(
    apply: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Publish/refresh the member offer page (5 Jul 2026) into the
    marketing_assets system from app/marketing_templates/offer.html.
    Idempotent upsert on slug='offer' — future template edits are a file
    change + re-tap. Served at /m/offer/{username} (?t=midnight|emerald|
    voltage for the theme; default Ocean), with the standard ref-cookie
    sponsor attribution and per-member OG tags via {{FIRST_NAME}}
    substitution."""
    _require_admin(user)
    try:
        from pathlib import Path as _P
        tpl_path = _P(__file__).parent / "marketing_templates" / "offer.html"
        if not tpl_path.exists():
            return JSONResponse({"error": "template file missing from deploy"}, status_code=200)
        html = tpl_path.read_text()
        existing = db.query(MarketingAsset).filter(MarketingAsset.slug == "offer").first()
        plan = {"slug": "offer", "template_bytes": len(html),
                "placeholders": html.count("{{"),
                "currently": ("published" if (existing and existing.is_published)
                              else "exists-unpublished" if existing else "absent"),
                "example_urls": [
                    "https://www.superadpro.com/m/offer/SuperAdPro",
                    "https://www.superadpro.com/m/offer/SuperAdPro?t=midnight",
                    "https://www.superadpro.com/m/offer/SuperAdPro?t=emerald",
                    "https://www.superadpro.com/m/offer/SuperAdPro?t=voltage"]}
        if not apply:
            return JSONResponse({"applied": False, "note": "dry run — re-tap with &apply=1", **plan})
        now = datetime.utcnow()
        if existing:
            existing.html_template = html
            existing.is_published = True
            existing.published_at = existing.published_at or now
            existing.updated_at = now
        else:
            db.add(MarketingAsset(
                slug="offer",
                title="Get Paid to Watch — Member Offer Page",
                description="Income-forward offer/onboarding landing page. Four themes via ?t= (ocean default, midnight, emerald, voltage). Per-member sponsor attribution + OG unfurls.",
                asset_type="page", html_template=html,
                is_published=True, published_at=now))
        db.commit()
        return JSONResponse({"applied": True, **plan})
    except Exception as e:
        import traceback
        logger.error(f"publish-offer-page failed: {e}\n{traceback.format_exc()}")
        try:
            db.rollback()
        except Exception:
            pass
        return JSONResponse({"error": f"{type(e).__name__}: {str(e)[:400]}"}, status_code=200)


@app.get("/admin/api/manual-renewal")
def admin_manual_renewal(
    user_id: int,
    months: int = 1,
    anchor: str = "now",
    apply: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Record an OFF-PLATFORM membership renewal (5 Jul 2026, built for the
    @itsamazing case: member paid Steve wallet-to-wallet; paid-activation
    correctly refused because it's fresh-signups-only). Extends the renewal
    clock + expiry, clears grace, keeps the member active, and writes a
    Payment row (payment_type='membership_manual', status='paid') so
    gateway-forensics and the ledger reflect reality.

    NO commission rows and NO wallet credits are created — the money never
    entered platform rails. Fine when the sponsor is the house account;
    if the sponsor is a real member, their renewal commission needs a
    deliberate separate decision (the dry run names the sponsor so you see
    exactly who's affected before applying).

    anchor=now  (default): paid month starts today.
    anchor=due: paid month starts at the missed due date (stricter).
    Dry-run by default; &apply=1 executes."""
    _require_admin(user)
    try:
        target = db.query(User).filter(User.id == user_id).first()
        if not target:
            return JSONResponse({"error": f"user {user_id} not found"}, status_code=404)
        renewal = db.query(MembershipRenewal).filter(
            MembershipRenewal.user_id == user_id).first()
        now = datetime.utcnow()
        months = max(1, min(months, 12))
        due = renewal.next_renewal_date if renewal and renewal.next_renewal_date else now
        base = due if (anchor == "due" and due) else now
        new_due = base + timedelta(days=30 * months)
        price = float(getattr(target, "membership_price_locked", None) or 20.0)
        sponsor = db.query(User).filter(User.id == target.sponsor_id).first()             if getattr(target, "sponsor_id", None) else None
        plan = {
            "user": {"id": target.id, "username": target.username,
                     "is_active": bool(target.is_active),
                     "founder": bool(getattr(target, "is_founder", False)),
                     "price_locked": price},
            "sponsor": ({"id": sponsor.id, "username": sponsor.username}
                        if sponsor else None),
            "current_next_renewal": due.isoformat() if due else None,
            "overdue_days": max(0, (now - due).days) if due else 0,
            "anchor": "due" if anchor == "due" else "now",
            "months": months,
            "new_next_renewal": new_due.isoformat(),
            "commission_note": "no commission rows / wallet credits created — payment was off-platform",
        }
        if not apply:
            return JSONResponse({"applied": False,
                                 "note": "dry run — re-tap with &apply=1", **plan})
        if renewal:
            renewal.next_renewal_date = new_due
            renewal.last_renewed_at = now
            renewal.renewal_source = "manual"
            renewal.in_grace_period = False
            renewal.grace_period_start = None
            renewal.total_renewals = (renewal.total_renewals or 0) + 1
        else:
            db.add(MembershipRenewal(user_id=target.id, activated_at=now,
                                     next_renewal_date=new_due, last_renewed_at=now,
                                     renewal_source="manual", in_grace_period=False,
                                     total_renewals=1))
        target.is_active = True
        if hasattr(target, "membership_expires_at"):
            target.membership_expires_at = new_due
        db.add(Payment(from_user_id=target.id, to_user_id=None,
                       amount_usdt=price * months,
                       payment_type="membership_manual",
                       tx_hash=f"manual-renewal-{target.id}-{now.strftime('%Y%m%d%H%M%S')}",
                       status="paid"))
        db.commit()
        plan["applied"] = True
        return JSONResponse(plan)
    except Exception as e:
        import traceback
        logger.error(f"manual-renewal failed: {e}\n{traceback.format_exc()}")
        try:
            db.rollback()
        except Exception:
            pass
        return JSONResponse({"error": f"{type(e).__name__}: {str(e)[:400]}"}, status_code=200)


@app.get("/admin/api/reverse-house-topup")
def admin_reverse_house_topup(
    apply: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot (3 Jul 2026): the phantom-topup cleanup missed $18 of PAID
    grid_completion_bonus_topup on the house account (user 1) — the only
    paid topup left platform-wide per grid-truth-audit. Reverse = row
    status -> 'reversed' + campaign_balance debit (topups credited the
    campaign wallet). Dry-run by default; idempotent (re-runs find zero)."""
    _require_admin(user)
    try:
        rows = db.execute(text("""
            SELECT id, amount_usdt, package_tier, status
            FROM commissions
            WHERE to_user_id = 1
              AND commission_type = 'grid_completion_bonus_topup'
              AND status = 'paid'
        """)).mappings().all()
        total = round(sum(float(r["amount_usdt"] or 0) for r in rows), 2)
        house = db.query(User).filter(User.id == 1).first()
        plan = {
            "rows": [{"id": r["id"], "amount": float(r["amount_usdt"]),
                      "tier": r["package_tier"]} for r in rows],
            "total_to_reverse_usd": total,
            "campaign_balance_before": float(getattr(house, "campaign_balance", 0) or 0),
        }
        if not rows:
            return JSONResponse({"applied": False, "note": "nothing to reverse — already clean", **plan})
        if not apply:
            return JSONResponse({"applied": False, "note": "dry run — re-tap with &apply=1", **plan})
        for r in rows:
            db.execute(text(
                "UPDATE commissions SET status='reversed', "
                "notes = COALESCE(notes,'') || ' [3 Jul 2026: house-account topup missed by phantom cleanup — reversed via grid-truth-audit follow-up]' "
                "WHERE id=:i"), {"i": r["id"]})
        house.campaign_balance = float(getattr(house, "campaign_balance", 0) or 0) - total
        db.commit()
        plan["campaign_balance_after"] = float(house.campaign_balance or 0)
        return JSONResponse({"applied": True, **plan})
    except Exception as e:
        import traceback
        logger.error(f"reverse-house-topup failed: {e}\n{traceback.format_exc()}")
        try:
            db.rollback()
        except Exception:
            pass
        return JSONResponse({"error": f"{type(e).__name__}: {str(e)[:400]}"}, status_code=200)


@app.get("/admin/api/grid-truth-audit")
def admin_grid_truth_audit(
    summary: int = 0,
    top: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """READ-ONLY platform-wide audit (3 Jul 2026, cynniam case): every
    Grid row claiming is_complete=True, classified against the commission
    ledger and the retirement cutover. Classes:

      genuine   — retired_at NULL, completion money PAID in the ledger
      retired   — retired_at set (12 Jun legacy-36-seat cutover artifact;
                  NOT a real completion — UI must not claim 'bonus paid')
      unbacked  — is_complete, not retired, but NO paid completion money
                  (or only REVERSED topups) — restoration-era fabrication;
                  the class the member UI is lying about
      phantom$  — any PAID grid_completion_bonus_topup (money that became
                  spendable; worst class, none expected after the cleanup)
    """
    _require_admin(user)
    try:
        grids = db.execute(text("""
            SELECT g.id, g.owner_id, u.username, g.package_tier, g.advance_number,
                   g.is_complete, g.bonus_paid, g.retired_at, g.created_at
            FROM grids g JOIN users u ON u.id = g.owner_id
            WHERE g.is_complete = TRUE
            ORDER BY g.owner_id, g.package_tier, g.advance_number
        """)).mappings().all()
        comm = db.execute(text("""
            SELECT to_user_id, package_tier, commission_type, status,
                   SUM(amount_usdt) AS total, COUNT(*) AS n
            FROM commissions
            WHERE commission_type IN ('grid_completion_bonus', 'grid_completion_bonus_topup')
            GROUP BY to_user_id, package_tier, commission_type, status
        """)).mappings().all()
        cmap = {}
        for c in comm:
            key = (c["to_user_id"], c["package_tier"])
            cmap.setdefault(key, {"paid_bonus": 0.0, "paid_topup": 0.0,
                                  "reversed_topup": 0.0, "reversed_bonus": 0.0})
            bucket = ("paid_" if c["status"] == "paid" else "reversed_") +                      ("topup" if c["commission_type"].endswith("topup") else "bonus")
            cmap[key][bucket] = round(cmap[key][bucket] + float(c["total"] or 0), 2)

        users, summary_out = {}, {"complete_grids": len(grids), "genuine": 0,
                              "retired": 0, "unbacked": 0,
                              "phantom_paid_topup_usd": 0.0,
                              "reversed_topup_usd": 0.0}
        for g in grids:
            key = (g["owner_id"], g["package_tier"])
            money = cmap.get(key, {"paid_bonus": 0, "paid_topup": 0,
                                   "reversed_topup": 0, "reversed_bonus": 0})
            if g["retired_at"]:
                verdict = "retired"
            elif money["paid_bonus"] > 0 or money["paid_topup"] > 0:
                verdict = "genuine"
            else:
                verdict = "unbacked"
            summary_out[verdict] += 1
            u = users.setdefault(g["owner_id"], {
                "user_id": g["owner_id"], "username": g["username"], "grids": [],
                "paid_completion_usd": money["paid_bonus"],
                "paid_topup_usd": money["paid_topup"],
                "reversed_topup_usd": money["reversed_topup"],
            })
            # money keys are per (user,tier); merge across tiers
            u["paid_completion_usd"] = round(sum(
                cmap.get((g["owner_id"], t), {}).get("paid_bonus", 0)
                for t in {gr["tier"] for gr in u["grids"]} | {g["package_tier"]}), 2)
            u["paid_topup_usd"] = round(sum(
                cmap.get((g["owner_id"], t), {}).get("paid_topup", 0)
                for t in {gr["tier"] for gr in u["grids"]} | {g["package_tier"]}), 2)
            u["reversed_topup_usd"] = round(sum(
                cmap.get((g["owner_id"], t), {}).get("reversed_topup", 0)
                for t in {gr["tier"] for gr in u["grids"]} | {g["package_tier"]}), 2)
            u["grids"].append({"grid_id": g["id"], "tier": g["package_tier"],
                               "advance": g["advance_number"],
                               "bonus_paid_flag": bool(g["bonus_paid"]),
                               "retired": bool(g["retired_at"]),
                               "verdict": verdict})
        for u in users.values():
            summary_out["phantom_paid_topup_usd"] = round(
                summary_out["phantom_paid_topup_usd"] + u["paid_topup_usd"], 2)
            summary_out["reversed_topup_usd"] = round(
                summary_out["reversed_topup_usd"] + u["reversed_topup_usd"], 2)
        summary_out["users_affected_unbacked"] = sum(
            1 for u in users.values() if any(x["verdict"] == "unbacked" for x in u["grids"]))
        ordered = sorted(users.values(), key=lambda u: (
            -u["paid_topup_usd"],
            -sum(1 for x in u["grids"] if x["verdict"] == "unbacked"),
            -u["reversed_topup_usd"]))
        if summary and not top:
            return JSONResponse({"summary": summary_out})
        if top:
            return JSONResponse({"summary": summary_out, "users": ordered[:top]})
        return JSONResponse({"summary": summary_out, "users": ordered})
    except Exception as e:
        import traceback
        logger.error(f"grid-truth-audit failed: {e}\n{traceback.format_exc()}")
        return JSONResponse({"error": f"{type(e).__name__}: {str(e)[:400]}"}, status_code=200)


@app.get("/admin/api/broadcast-state")
def admin_broadcast_state(
    user_id: int = 0,
    probe: int = 0,
    fix: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Diagnose a member's broadcasts in one tap: durable header rows (status,
    counters) + recipient-claim states per broadcast_key. Built 3 Jul while
    chasing the wedged-'sending' claims bug."""
    _require_admin(user)
    try:
        if not user_id:
            return JSONResponse({"error": "user_id required"}, status_code=200)
        _ensure_member_broadcasts_table(db)
        rows = db.execute(text(
            "SELECT id, broadcast_key, status, total, sent, failed, skipped, "
            "created_at, updated_at, subject FROM member_broadcasts "
            "WHERE user_id=:u ORDER BY id DESC LIMIT 10"), {"u": user_id}).mappings().all()
        out = []
        for r in rows:
            claims = db.execute(text(
                "SELECT status, COUNT(*) AS n FROM broadcast_log "
                "WHERE broadcast_key=:k GROUP BY status"), {"k": r["broadcast_key"]}).mappings().all()
            out.append({
                "id": r["id"], "status": r["status"],
                "subject": (r["subject"] or "")[:60],
                "total": r["total"], "sent": r["sent"], "failed": r["failed"],
                "skipped": r["skipped"],
                "created_at": str(r["created_at"]), "updated_at": str(r["updated_at"]),
                "claims": {c["status"]: c["n"] for c in claims},
            })
        fix_result = None
        if fix:
            try:
                _ensure_broadcast_log_table(db)
                fix_result = {"ok": True, "note": "dedupe + unique index ensured"}
            except Exception as fe:
                fix_result = {"ok": False, "error": f"{type(fe).__name__}: {str(fe)[:300]}"}
        probe_result = None
        if probe:
            # Execute the EXACT claim statement inside a rolled-back
            # transaction — reports the real database error (or success)
            # without writing anything.
            try:
                row = db.execute(text("""
                    INSERT INTO broadcast_log (broadcast_key, user_id, email_address, status)
                    VALUES ('probe-diagnostic', 999999901, 'probe@diagnostic.local', 'sending')
                    ON CONFLICT (broadcast_key, user_id) DO UPDATE
                        SET status = 'sending', error_message = NULL, sent_at = NOW()
                        WHERE broadcast_log.status = 'failed'
                           OR (broadcast_log.status = 'sending'
                               AND broadcast_log.sent_at < NOW() - INTERVAL '10 minutes')
                    RETURNING id
                """)).fetchone()
                probe_result = {"ok": True, "returned_id": row[0] if row else None}
            except Exception as pe:
                probe_result = {"ok": False, "error": f"{type(pe).__name__}: {str(pe)[:400]}"}
            finally:
                try:
                    db.rollback()
                except Exception:
                    pass
        return JSONResponse({"user_id": user_id, "broadcasts": out, "fix": fix_result, "claim_probe": probe_result})
    except Exception as e:
        return JSONResponse({"error": f"{type(e).__name__}: {str(e)[:300]}"}, status_code=200)


