# ── Finances ─────────────────────────────────────────────────
_REVENUE_STRIPE_CACHE_TTL = 1800  # 30 min — Stripe enumeration is paginated; cache it

def _compute_platform_revenue(db, force=False):
    """Real platform revenue (GMV / gross money in) from surviving truth.

    The old admin card summed SUM(Payment WHERE confirmed), but the payments
    table is an internal MIRROR that was hollowed out in the 31-May restore,
    so it under-reported to ~$55. Money's actual truth lives in Stripe (card,
    fully enumerable via the live API — NEVER lost) and on-chain (crypto). So:

      total = stripe_gross (live API)               # all card revenue, complete
            + crypto_baseline                        # analysed on-chain member
                                                     #   crypto revenue at reopen
            + crypto_recorded_since_reopen           # new confirmed non-Stripe
                                                     #   payments after the cutoff

    The baseline + cutoff split prevents double-counting: the baseline covers
    everything up to reopen; the recorded-since term only counts crypto rows
    created after it. Both baseline and cutoff are AppConfig values the admin
    can correct if the BscScan view differs. Stripe gross is cached 30 min and
    fails safe to the last cached value so a slow/down Stripe API never breaks
    the dashboard load.
    """
    from sqlalchemy import func as _func
    import time as _t
    from datetime import datetime as _dt

    # crypto historical baseline (seed once)
    base_raw = _secwatch_get(db, "revenue_crypto_baseline_usd", "")
    if base_raw == "":
        base_raw = "2773.0"
        _secwatch_set(db, "revenue_crypto_baseline_usd", base_raw); db.commit()
    try:
        crypto_baseline = float(base_raw)
    except (ValueError, TypeError):
        crypto_baseline = 2773.0

    cutoff_raw = _secwatch_get(db, "revenue_crypto_baseline_cutoff", "")
    if cutoff_raw == "":
        cutoff_raw = "2026-06-07T00:00:00"
        _secwatch_set(db, "revenue_crypto_baseline_cutoff", cutoff_raw); db.commit()
    try:
        cutoff_dt = _dt.fromisoformat(cutoff_raw)
    except Exception:
        cutoff_dt = _dt(2026, 6, 7)

    # new crypto/non-Stripe confirmed payments since reopen (null tx_hash = non-Stripe)
    try:
        crypto_since = float(db.query(_func.coalesce(_func.sum(Payment.amount_usdt), 0)).filter(
            Payment.status == "confirmed",
            ~_func.coalesce(Payment.tx_hash, "").like("stripe_%"),
            Payment.created_at >= cutoff_dt,
        ).scalar() or 0)
    except Exception:
        crypto_since = 0.0

    # Stripe gross (live, cached, fail-safe)
    cache_val = _secwatch_get(db, "revenue_stripe_gross_usd", "")
    cache_at = _secwatch_get(db, "revenue_stripe_gross_at", "")
    fresh = False
    if cache_val and cache_at:
        try:
            fresh = (_t.time() - float(cache_at)) < _REVENUE_STRIPE_CACHE_TTL
        except (ValueError, TypeError):
            fresh = False
    stripe_gross = None
    if fresh and not force:
        try:
            stripe_gross = float(cache_val)
        except (ValueError, TypeError):
            stripe_gross = None
    if stripe_gross is None:
        try:
            from . import stripe_service as _ss
            if _ss.is_configured():
                _ss._ensure_sdk()
                import stripe as _stripe
                g = 0.0
                params = {"limit": 100, "type": "charge"}
                while True:
                    page = _stripe.BalanceTransaction.list(**params)
                    for bt in page.data:
                        g += (bt.amount or 0) / 100.0
                    if page.has_more and page.data:
                        params["starting_after"] = page.data[-1].id
                    else:
                        break
                stripe_gross = round(g, 2)
                _secwatch_set(db, "revenue_stripe_gross_usd", str(stripe_gross))
                _secwatch_set(db, "revenue_stripe_gross_at", str(_t.time()))
                db.commit()
            else:
                stripe_gross = float(cache_val) if cache_val else 0.0
        except Exception:
            try:
                stripe_gross = float(cache_val) if cache_val else 0.0
            except (ValueError, TypeError):
                stripe_gross = 0.0
    if stripe_gross is None:
        stripe_gross = 0.0

    total = round(stripe_gross + crypto_baseline + crypto_since, 2)
    return {
        "total_usd": total,
        "stripe_gross_usd": round(stripe_gross, 2),
        "crypto_baseline_usd": round(crypto_baseline, 2),
        "crypto_recorded_since_reopen_usd": round(crypto_since, 2),
        "stripe_cache_fresh": bool(fresh),
        "source": "stripe_live + crypto_baseline + crypto_since_reopen",
    }


@app.get("/admin/api/finances")
def admin_api_finances(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    _require_admin(user)
    from sqlalchemy import func

    # Real revenue (GMV) from surviving truth — Stripe live + crypto baseline +
    # crypto recorded since reopen. Replaces SUM(Payment WHERE confirmed), which
    # under-reported to ~$55 because the payments mirror was wiped in the restore.
    _rev = _compute_platform_revenue(db)
    total_revenue = _rev["total_usd"]
    # Only "paid" commissions count — "pending" hasn't actually been distributed yet,
    # and including it overstates total_commissions_paid and understates platform_profit.
    # Bug fixed 7 May 2026: total_commissions previously summed only the
    # Commission table, so the admin finance dashboard underreported total
    # commission spend (and overstated platform_profit) by every dollar
    # paid via Credit Nexus and Course Academy.
    total_commissions_grid = float(db.query(func.sum(Commission.amount_usdt)).filter(Commission.status == "paid").scalar() or 0)
    total_commissions_matrix = float(db.query(func.sum(CreditMatrixCommission.amount)).filter(CreditMatrixCommission.status == "paid").scalar() or 0)
    total_commissions_course = float(db.query(func.sum(CourseCommission.amount)).scalar() or 0)
    total_commissions = total_commissions_grid + total_commissions_matrix + total_commissions_course

    total_withdrawn = db.query(func.sum(Withdrawal.amount_usdt)).filter(Withdrawal.status == "paid").scalar() or 0
    pending_withdrawals = db.query(func.sum(Withdrawal.amount_usdt)).filter(Withdrawal.status == "pending").scalar() or 0
    total_balances = db.query(func.sum(User.balance)).scalar() or 0

    # Revenue by type
    payments_by_type = db.query(
        Payment.payment_type, func.sum(Payment.amount_usdt), func.count(Payment.id)
    ).filter(Payment.status == "confirmed").group_by(Payment.payment_type).all()

    # Commissions by type — across all 3 commission tables. Each table's
    # types prefixed with the source so admin can distinguish (e.g.
    # 'matrix:matrix_level' vs 'grid:direct_sponsor').
    comms_by_type_combined = []
    for t, s, c in db.query(
        Commission.commission_type, func.sum(Commission.amount_usdt), func.count(Commission.id)
    ).filter(Commission.status == "paid").group_by(Commission.commission_type).all():
        comms_by_type_combined.append({"type": t, "total": float(s or 0), "count": c})
    for t, s, c in db.query(
        CreditMatrixCommission.commission_type, func.sum(CreditMatrixCommission.amount), func.count(CreditMatrixCommission.id)
    ).filter(CreditMatrixCommission.status == "paid").group_by(CreditMatrixCommission.commission_type).all():
        comms_by_type_combined.append({"type": f"nexus:{t}", "total": float(s or 0), "count": c})
    for t, s, c in db.query(
        CourseCommission.commission_type, func.sum(CourseCommission.amount), func.count(CourseCommission.id)
    ).group_by(CourseCommission.commission_type).all():
        comms_by_type_combined.append({"type": f"course:{t}", "total": float(s or 0), "count": c})

    # User counts (include all members including admin — admin IS a member)
    total_users = db.query(func.count(User.id)).scalar() or 0
    active_users = db.query(func.count(User.id)).filter(User.is_active == True).scalar() or 0
    active_grids = db.query(func.count(Grid.id)).filter(Grid.is_complete == False).scalar() or 0
    pending_withdrawals_count = db.query(func.count(Withdrawal.id)).filter(Withdrawal.status == "pending").scalar() or 0

    return {
        # Flat fields for overview cards
        "total_users": total_users,
        "active_users": active_users,
        "total_revenue": float(total_revenue),
        "revenue_breakdown": _rev,
        "total_commissions_paid": float(total_commissions),
        "pending_withdrawals_count": pending_withdrawals_count,
        "active_grids": active_grids,
        # Detailed breakdown
        "overview": {
            "total_revenue": float(total_revenue),
            "total_commissions_paid": float(total_commissions),
            "total_withdrawn": float(total_withdrawn),
            "pending_withdrawals": float(pending_withdrawals),
            "total_user_balances": float(total_balances),
            "platform_profit": float(total_revenue) - float(total_commissions),
        },
        "revenue_by_type": [{
            "type": t, "total": float(s or 0), "count": c
        } for t, s, c in payments_by_type],
        "commissions_by_type": comms_by_type_combined,
    }
@app.get("/admin/api/email-analytics")
def admin_api_email_analytics(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """Email usage analytics for admin — track costs and volume."""
    _require_admin(user)
    from sqlalchemy import func, cast, Date
    from .database import EmailSendLog, MemberLead, EmailSequence
    from datetime import datetime, timedelta

    now = datetime.utcnow()
    today = now.replace(hour=0, minute=0, second=0, microsecond=0)
    week_ago = today - timedelta(days=7)
    month_ago = today - timedelta(days=30)

    # Total emails ever sent
    total_sent = db.query(func.count(EmailSendLog.id)).scalar() or 0

    # Sent today
    sent_today = db.query(func.count(EmailSendLog.id)).filter(
        EmailSendLog.sent_at >= today
    ).scalar() or 0

    # Sent this week
    sent_week = db.query(func.count(EmailSendLog.id)).filter(
        EmailSendLog.sent_at >= week_ago
    ).scalar() or 0

    # Sent this month
    sent_month = db.query(func.count(EmailSendLog.id)).filter(
        EmailSendLog.sent_at >= month_ago
    ).scalar() or 0

    # Daily breakdown for last 30 days
    daily_sends = db.query(
        cast(EmailSendLog.sent_at, Date).label('day'),
        func.count(EmailSendLog.id).label('count')
    ).filter(
        EmailSendLog.sent_at >= month_ago
    ).group_by('day').order_by('day').all()

    # Brevo cost estimates (based on Brevo Starter tier pricing)
    # Free tier: 300/day = 9,000/month = $0
    # Starter: 5K=$9, 10K=$16, 20K=$25, 40K=$39, 60K=$49, 100K=$69
    def estimate_monthly_cost(volume):
        if volume <= 9000: return 0
        if volume <= 5000: return 9
        if volume <= 10000: return 16
        if volume <= 20000: return 25
        if volume <= 40000: return 39
        if volume <= 60000: return 49
        if volume <= 100000: return 69
        return 69 + ((volume - 100000) / 1000) * 0.65  # rough overage estimate

    estimated_cost = estimate_monthly_cost(sent_month)
    cost_per_email = round(estimated_cost / max(sent_month, 1), 4)

    # Top senders (which Pro members send the most)
    top_senders = db.query(
        MemberLead.user_id,
        func.count(EmailSendLog.id).label('sent_count')
    ).join(
        EmailSendLog, EmailSendLog.lead_id == MemberLead.id
    ).filter(
        EmailSendLog.sent_at >= month_ago
    ).group_by(MemberLead.user_id).order_by(func.count(EmailSendLog.id).desc()).limit(10).all()

    sender_details = []
    for user_id, count in top_senders:
        u = db.query(User).filter(User.id == user_id).first()
        if u:
            sender_details.append({
                "user_id": u.id, "username": u.username,
                "name": u.first_name or u.username,
                "emails_sent": count,
                "boost_credits": u.email_credits or 0,
            })

    # Boost pack revenue (from wallet deductions for email packs)
    total_boost_credits_outstanding = db.query(func.sum(User.email_credits)).scalar() or 0

    # Active sequences count
    active_sequences = db.query(func.count(EmailSequence.id)).filter(
        EmailSequence.is_active == True
    ).scalar() or 0

    # Total leads across all users
    total_leads = db.query(func.count(MemberLead.id)).scalar() or 0
    leads_nurturing = db.query(func.count(MemberLead.id)).filter(
        MemberLead.status == "nurturing"
    ).scalar() or 0

    return {
        "totals": {
            "all_time": total_sent,
            "today": sent_today,
            "this_week": sent_week,
            "this_month": sent_month,
        },
        "costs": {
            "estimated_monthly_brevo": round(estimated_cost, 2),
            "cost_per_email": cost_per_email,
            "brevo_tier": "Free" if sent_month <= 9000 else "Starter",
            "free_daily_cap": 300,
            "monthly_free_cap": 9000,
        },
        "daily_breakdown": [{
            "date": str(d), "count": c
        } for d, c in daily_sends],
        "top_senders": sender_details,
        "platform_stats": {
            "active_sequences": active_sequences,
            "total_leads": total_leads,
            "leads_nurturing": leads_nurturing,
            "total_boost_credits": int(total_boost_credits_outstanding),
        },
    }
@app.get("/admin/api/superscene-status")
def admin_api_superscene_status(
    user_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """Per-user Creative Studio diagnostic: credit balance + recent generation tasks.
    Built 17 Jun 2026 to triage 'Network error' generation tickets — shows whether a
    member's credits are intact and whether any generation orphaned (took credits but
    never returned a video because the member's connection dropped at the gateway)."""
    _require_admin(user)
    from .database import SuperSceneCredit, SuperSceneVideo
    from datetime import datetime
    from collections import Counter

    target = db.query(User).filter(User.id == user_id).first()
    if not target:
        return JSONResponse({"error": f"No user with id {user_id}"}, status_code=404)

    credit = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == user_id).first()
    balance = int(credit.balance) if credit else 0

    vids = (db.query(SuperSceneVideo)
              .filter(SuperSceneVideo.user_id == user_id)
              .order_by(SuperSceneVideo.created_at.desc())
              .limit(15).all())

    now = datetime.utcnow()
    tasks, orphans = [], []
    for v in vids:
        age_min = round((now - v.created_at).total_seconds() / 60, 1) if v.created_at else None
        is_orphan = (v.status in ("pending", "processing")) and (not v.video_url) and (age_min is not None and age_min > 20)
        row = {
            "id": v.id, "task_id": v.task_id, "model": v.model_name or v.model_key,
            "status": v.status, "credits_used": int(v.credits_used or 0),
            "has_video": bool(v.video_url),
            "created_at": v.created_at.isoformat() if v.created_at else None,
            "age_min": age_min, "possible_orphan": is_orphan,
        }
        tasks.append(row)
        if is_orphan:
            orphans.append(row)

    return {
        "user_id": user_id, "username": target.username,
        "credit_balance": balance,
        "recent_task_count": len(vids),
        "by_status": dict(Counter(v.status for v in vids)),
        "possible_orphans": orphans,
        "tasks": tasks,
        "note": "possible_orphan = pending/processing >20min, credits_used but no video_url — request reached origin but member never got the task_id.",
    }


@app.get("/admin/api/superscene-analytics")
def admin_api_superscene_analytics(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db)
):
    """SuperScene credit usage analytics — track AI provider costs and revenue."""
    _require_admin(user)
    from sqlalchemy import func, cast, Date
    from .database import SuperSceneVideo, SuperSceneOrder, SuperSceneCredit
    from datetime import datetime, timedelta

    now = datetime.utcnow()
    today = now.replace(hour=0, minute=0, second=0, microsecond=0)
    week_ago = today - timedelta(days=7)
    month_ago = today - timedelta(days=30)

    # ── Generation volume ──
    total_generations = db.query(func.count(SuperSceneVideo.id)).scalar() or 0
    gens_today = db.query(func.count(SuperSceneVideo.id)).filter(SuperSceneVideo.created_at >= today).scalar() or 0
    gens_week = db.query(func.count(SuperSceneVideo.id)).filter(SuperSceneVideo.created_at >= week_ago).scalar() or 0
    gens_month = db.query(func.count(SuperSceneVideo.id)).filter(SuperSceneVideo.created_at >= month_ago).scalar() or 0

    # ── Credits consumed ──
    total_credits_used = db.query(func.sum(SuperSceneVideo.credits_used)).scalar() or 0
    credits_month = db.query(func.sum(SuperSceneVideo.credits_used)).filter(SuperSceneVideo.created_at >= month_ago).scalar() or 0
    credits_week = db.query(func.sum(SuperSceneVideo.credits_used)).filter(SuperSceneVideo.created_at >= week_ago).scalar() or 0

    # ── Revenue from credit packs ──
    total_revenue = float(db.query(func.sum(SuperSceneOrder.amount_usd)).filter(SuperSceneOrder.status == "completed").scalar() or 0)
    revenue_month = float(db.query(func.sum(SuperSceneOrder.amount_usd)).filter(SuperSceneOrder.status == "completed", SuperSceneOrder.completed_at >= month_ago).scalar() or 0)

    # ── Outstanding credits (liability) ──
    total_credits_outstanding = db.query(func.sum(SuperSceneCredit.balance)).scalar() or 0

    # ── Usage by model (this month) ──
    model_usage = db.query(
        SuperSceneVideo.model_key,
        func.count(SuperSceneVideo.id).label('count'),
        func.sum(SuperSceneVideo.credits_used).label('credits')
    ).filter(
        SuperSceneVideo.created_at >= month_ago
    ).group_by(SuperSceneVideo.model_key).order_by(func.sum(SuperSceneVideo.credits_used).desc()).all()

    # ── Provider cost (estimate) + REAL sponsor commissions ──
    # Provider cost: fal.ai ~$0.03-0.08, EvoLink ~$0.05-0.15, avg ~$0.08.
    # This stays a per-credit estimate (per-credit AI provider spend).
    ESTIMATED_PROVIDER_COST = 0.08
    estimated_provider_cost_month = int(credits_month or 0) * ESTIMATED_PROVIDER_COST

    # Sponsor commission is NOT per-credit. Since 30 May 2026 the matrix is
    # retired: each credit-PACK purchase pays a flat 20% of the pack price to the
    # buyer's direct sponsor. Read the ACTUAL paid amounts for the month from
    # credit_matrix_commissions instead of estimating $/credit (which over- or
    # under-stated margin depending on pack mix).
    from .database import CreditMatrixCommission as _CMC
    sponsor_commissions_month = float(
        db.query(func.coalesce(func.sum(_CMC.amount), 0))
          .filter(_CMC.status == "paid", _CMC.created_at >= month_ago)
          .scalar() or 0
    )
    total_cost_month = estimated_provider_cost_month + sponsor_commissions_month
    margin = revenue_month - total_cost_month if revenue_month > 0 else 0
    # Effective sponsor cost per credit this month (real $ / credits used) — for
    # display continuity only; the real model is 20% of pack price, not per credit.
    effective_sponsor_per_credit = round(sponsor_commissions_month / credits_month, 4) if credits_month else 0.0

    # ── Top users (this month) ──
    top_users = db.query(
        SuperSceneVideo.user_id,
        func.count(SuperSceneVideo.id).label('gen_count'),
        func.sum(SuperSceneVideo.credits_used).label('credits')
    ).filter(
        SuperSceneVideo.created_at >= month_ago
    ).group_by(SuperSceneVideo.user_id).order_by(func.sum(SuperSceneVideo.credits_used).desc()).limit(10).all()

    top_user_details = []
    for uid, gen_count, creds in top_users:
        u = db.query(User).filter(User.id == uid).first()
        cr = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == uid).first()
        if u:
            top_user_details.append({
                "user_id": u.id, "username": u.username,
                "name": u.first_name or u.username,
                "generations": gen_count, "credits_used": int(creds or 0),
                "credits_remaining": cr.balance if cr else 0,
            })

    # ── Daily breakdown ──
    daily_gens = db.query(
        cast(SuperSceneVideo.created_at, Date).label('day'),
        func.count(SuperSceneVideo.id).label('count'),
        func.sum(SuperSceneVideo.credits_used).label('credits')
    ).filter(
        SuperSceneVideo.created_at >= month_ago
    ).group_by('day').order_by('day').all()

    # ── Pack sales breakdown ──
    pack_sales = db.query(
        SuperSceneOrder.pack_slug,
        func.count(SuperSceneOrder.id).label('count'),
        func.sum(SuperSceneOrder.amount_usd).label('revenue'),
        func.sum(SuperSceneOrder.credits).label('credits')
    ).filter(
        SuperSceneOrder.status == "completed"
    ).group_by(SuperSceneOrder.pack_slug).all()

    # Model name mapping
    model_names = {
        "wan26": "WAN 2.6", "kling3": "Kling 3.0", "seedance": "Seedance 1.5",
        "kling-o3": "Kling O3", "sora2": "Sora 2 Pro", "veo31": "VEO 3.1",
        "veo31-pro": "VEO 3.1 Pro", "hailuo23": "Hailuo 2.3", "grok-video": "Grok Video",
        "sora2-max": "Sora 2 Max", "hailuo23-fast": "Hailuo Fast", "hailuo02": "Hailuo 02",
    }

    return {
        "volume": {
            "total": total_generations, "today": gens_today,
            "this_week": gens_week, "this_month": gens_month,
        },
        "credits": {
            "total_used": int(total_credits_used),
            "used_this_month": int(credits_month or 0),
            "used_this_week": int(credits_week or 0),
            "outstanding_balance": int(total_credits_outstanding),
            "credit_sell_price": 0.22,
        },
        "financials": {
            "total_revenue": round(total_revenue, 2),
            "revenue_this_month": round(revenue_month, 2),
            "estimated_provider_cost": round(estimated_provider_cost_month, 2),
            "sponsor_commissions": round(sponsor_commissions_month, 2),
            "total_cost": round(total_cost_month, 2),
            "estimated_margin": round(margin, 2),
            "margin_pct": round((margin / revenue_month * 100) if revenue_month > 0 else 0, 1),
            "provider_cost_per_credit": ESTIMATED_PROVIDER_COST,
            "sponsor_rate_per_credit": effective_sponsor_per_credit,
            "total_cost_per_credit": round(ESTIMATED_PROVIDER_COST + effective_sponsor_per_credit, 4),
        },
        "model_usage": [{
            "model": model_names.get(m, m), "key": m,
            "generations": c, "credits": int(cr or 0),
        } for m, c, cr in model_usage],
        "top_users": top_user_details,
        "daily_breakdown": [{
            "date": str(d), "generations": c, "credits": int(cr or 0),
        } for d, c, cr in daily_gens],
        "pack_sales": [{
            "pack": p, "sales": c, "revenue": float(r or 0), "credits_sold": int(cr or 0),
        } for p, c, r, cr in pack_sales],
    }
@app.get("/admin/api/commissions")
def admin_api_commissions(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    commission_type: str = "",
    source: str = "",
    limit: int = 50,
    offset: int = 0
):
    """Admin commission browser — across all 3 commission tables.

    Query params:
        commission_type: filter by type (e.g. 'direct_sponsor',
                         'matrix_level', 'pass_up'). Type names overlap
                         across tables; combined with `source` for
                         disambiguation.
        source:          filter by source table — 'grid' (Commission),
                         'nexus' (CreditMatrixCommission), 'course'
                         (CourseCommission). Empty = all 3.
        limit, offset:   pagination across the merged result set.

    Bug fixed 7 May 2026: previously only browsed the Commission
    table, so Credit Nexus and Course commissions were invisible
    to admin entirely. Admin couldn't audit, refund, or troubleshoot
    those commission types.
    """
    _require_admin(user)
    rows = []

    # 1. Commission (grid + membership)
    if not source or source == "grid":
        q = db.query(Commission).order_by(Commission.created_at.desc())
        if commission_type:
            q = q.filter(Commission.commission_type == commission_type)
        for c in q.limit(500).all():  # generous per-table cap; merged + paginated below
            rows.append({
                "id": c.id,
                "source": "grid",
                "to_user_id": c.to_user_id, "from_user_id": c.from_user_id,
                "amount": float(c.amount_usdt or 0),
                "type": c.commission_type, "status": c.status,
                "notes": c.notes,
                "date": c.created_at.isoformat() if c.created_at else None,
                "_sort": c.created_at,
            })

    # 2. CreditMatrixCommission (Credit Nexus)
    if not source or source == "nexus":
        q = db.query(CreditMatrixCommission).order_by(CreditMatrixCommission.created_at.desc())
        if commission_type:
            q = q.filter(CreditMatrixCommission.commission_type == commission_type)
        for c in q.limit(500).all():
            rows.append({
                "id": c.id,
                "source": "nexus",
                "to_user_id": c.earner_id, "from_user_id": c.from_user_id,
                "amount": float(c.amount or 0),
                "type": c.commission_type, "status": c.status,
                "notes": f"L{c.level} on ${float(c.pack_price or 0):.0f} pack" if c.commission_type != "matrix_completion" else "Cycle completion",
                "date": c.created_at.isoformat() if c.created_at else None,
                "_sort": c.created_at,
            })

    # 3. CourseCommission (Course Academy)
    if not source or source == "course":
        q = db.query(CourseCommission).order_by(CourseCommission.created_at.desc())
        if commission_type:
            q = q.filter(CourseCommission.commission_type == commission_type)
        for c in q.limit(500).all():
            rows.append({
                "id": c.id,
                "source": "course",
                "to_user_id": c.earner_id, "from_user_id": c.buyer_id,
                "amount": float(c.amount or 0),
                "type": c.commission_type, "status": "paid",
                "notes": f"Course Tier {c.course_tier}",
                "date": c.created_at.isoformat() if c.created_at else None,
                "_sort": c.created_at,
            })

    # Merge sort by date desc, then paginate
    rows.sort(key=lambda r: r["_sort"] or datetime.min, reverse=True)
    total = len(rows)
    paged = rows[offset:offset + limit]
    # Strip the _sort key from output
    for r in paged:
        r.pop("_sort", None)

    return {
        "total": total,
        "commissions": paged,
    }

# ═══════════════════════════════════════════════════════════════════
#  2FA-GATED WITHDRAWAL RELEASE  (security rebuild, 4 Jun 2026)
#  -------------------------------------------------------------------
#  Root cause of the 3-Jun incident: a compromised admin endpoint could
#  move money with no factor that lived off the server. Fix: withdrawals
#  are created in 'awaiting_approval' (request_withdrawal) and never
#  auto-send. The retry cron only sweeps status='pending', so it can't
#  touch them. The ONLY way money leaves is an admin releasing a row here
#  with a live TOTP code from their authenticator — which an endpoint
#  attacker does not have.
#
#  Reuses the platform's existing TOTP system (User.totp_secret /
#  totp_enabled, pyotp) — the SAME authenticator entry used for admin
#  login authorises withdrawals. No second secret, no duplicate code.
#
#  Belt-and-suspenders guardrails (independent of the TOTP check):
#    - per-transaction cap (WITHDRAWAL_MAX_PER_TX env, default $200)
#    - destination must match the member's saved wallet (stamped at
#      request time under the member's own 2FA)
#    - balance was already atomically earmarked at request from the real
#      balance column — can't release more than was reserved
#    - master kill-switch WITHDRAWALS_ENABLED still gates the on-chain send
# ═══════════════════════════════════════════════════════════════════

def _withdrawal_max_per_tx():
    """Per-transaction release cap. Env-tunable so a larger legit payout
    can be allowed without a code change; defaults to $200."""
    from decimal import Decimal as _D
    try:
        return _D(str(os.getenv("WITHDRAWAL_MAX_PER_TX", "200")))
    except Exception:
        return _D("200")


@app.get("/admin/withdrawals-queue", response_class=HTMLResponse)
def admin_withdrawals_queue_page(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Phone-friendly admin page: lists withdrawals awaiting release and
    lets the admin approve (with their 2FA code) or reject each one.
    No console, no hand-built URLs — the buttons issue POSTs to the
    endpoints below."""
    _require_admin(user)
    from decimal import Decimal as _D

    rows = (
        db.query(Withdrawal)
        .filter(Withdrawal.status == "awaiting_approval")
        .order_by(Withdrawal.requested_at.asc())
        .all()
    )
    twofa_on = bool(getattr(user, "totp_enabled", False) and user.totp_secret)
    cap = _withdrawal_max_per_tx()
    sends_live = (os.getenv("WITHDRAWALS_ENABLED") == "true")

    def _esc(s):
        return (str(s or "")
                .replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
                .replace('"', "&quot;"))

    cards = []
    for w in rows:
        member = db.query(User).filter(User.id == w.user_id).first()
        uname = _esc(member.username if member else f"user {w.user_id}")
        amt = float(w.amount_usdt or 0)
        net = max(0.0, amt - 1.0)
        over_cap = _D(str(amt)) > cap
        addr_mismatch = bool(
            member and member.wallet_address and w.wallet_address
            and member.wallet_address.strip().lower() != w.wallet_address.strip().lower()
        )
        req = w.requested_at.strftime("%Y-%m-%d %H:%M UTC") if w.requested_at else "—"
        warn = ""
        if over_cap:
            warn += f'<div class="warn">⚠ Over per-tx cap (${float(cap):.0f}). Raise WITHDRAWAL_MAX_PER_TX to release.</div>'
        if addr_mismatch:
            warn += '<div class="warn">⚠ Destination ≠ member\'s saved wallet. Reject and ask them to re-request.</div>'

        # ── Risk signals (7 Jun 2026) — help catch a malicious approval ──
        # Computed from existing data: account age, KYC, balance provenance
        # (balance exceeding lifetime earnings = the synthetic-balance shape),
        # and 24h withdrawal velocity. Surfaced so a crafted "boring" payout
        # from a fresh/synthetic account doesn't get waved through.
        risk_rows = ""
        if member:
            if member.created_at:
                age_days = (datetime.utcnow() - member.created_at).days
                age_txt = f"{age_days}d old"
                if age_days < 7:
                    warn += f'<div class="warn">⚠ New account ({age_days}d old) — verify before releasing.</div>'
            else:
                age_txt = "age unknown"
            kyc = (getattr(member, "kyc_status", None) or "none")
            if kyc != "approved":
                warn += f'<div class="warn">⚠ KYC not approved (status: {_esc(kyc)}).</div>'
            bal = float(member.balance or 0)
            earned = float(member.total_earned or 0)
            excess = bal - earned
            if excess > 0.01:
                warn += (f'<div class="warn">⚠ Balance ${bal:,.2f} exceeds lifetime earnings '
                         f'${earned:,.2f} by ${excess:,.2f} — possible synthetic balance. '
                         f'Cross-check provenance before releasing.</div>')
            since_24h = datetime.utcnow() - timedelta(hours=24)
            wd_24h = (db.query(Withdrawal)
                        .filter(Withdrawal.user_id == w.user_id,
                                Withdrawal.requested_at >= since_24h).count())
            if wd_24h >= 3:
                warn += f'<div class="warn">⚠ {wd_24h} withdrawals from this member in 24h — velocity spike.</div>'
            risk_rows = (
                f'<div class="row"><span class="lbl">Account</span><span class="val">{age_txt} · KYC {_esc(kyc)}</span></div>'
                f'<div class="row"><span class="lbl">Balance / Earned</span><span class="val">${bal:,.2f} / ${earned:,.2f}</span></div>'
                f'<div class="row"><span class="lbl">Withdrawals 24h</span><span class="val">{wd_24h}</span></div>'
            )
        cards.append(f"""
        <div class="card" id="wd-{w.id}">
          <div class="row"><span class="lbl">Member</span><span class="val">{uname} (#{w.user_id})</span></div>
          <div class="row"><span class="lbl">Amount</span><span class="val">${amt:.2f} <span class="muted">(net ${net:.2f} after $1 fee)</span></span></div>
          <div class="row"><span class="lbl">Wallet</span><span class="val">{_esc(w.wallet_type)}</span></div>
          <div class="row"><span class="lbl">To</span><span class="val mono">{_esc(w.wallet_address)}</span></div>
          <div class="row"><span class="lbl">Network</span><span class="val">{_esc((w.network or '—').upper())}</span></div>
          <div class="row"><span class="lbl">Requested</span><span class="val">{req}</span></div>
          {risk_rows}
          {warn}
          <div class="actions">
            <input class="code" id="code-{w.id}" inputmode="numeric" autocomplete="one-time-code" maxlength="6" placeholder="2FA code" />
            <button class="approve" onclick="release({w.id})">Approve &amp; send</button>
            <button class="reject" onclick="reject({w.id})">Reject &amp; refund</button>
          </div>
          <div class="result" id="res-{w.id}"></div>
        </div>""")

    body_cards = "".join(cards) if cards else '<div class="empty">No withdrawals awaiting release.</div>'

    banner = ""
    if not twofa_on:
        banner += '<div class="banner err">You have not enabled 2FA on this admin account. Enable it in Account → Security before you can release withdrawals.</div>'
    if not sends_live:
        banner += '<div class="banner info">Sends are currently FROZEN (WITHDRAWALS_ENABLED is off). You can review and reject, but Approve will not send until the freeze is lifted in Railway.</div>'

    html = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Withdrawal Release Queue — SuperAdPro</title>
<link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Sora:wght@600;700;800&family=DM+Sans:wght@400;500;600;700&family=JetBrains+Mono:wght@500;600&display=swap" rel="stylesheet">
<style>
  :root {{ --cobalt:#0a1438; --royal:#1e3a8a; --sky:#0ea5e9; --cyan:#06b6d4; --electric:#22d3ee; }}
  * {{ box-sizing:border-box; }}
  body {{ margin:0; font-family:'DM Sans',-apple-system,system-ui,sans-serif; background:#eef2f9; color:#0f172a; padding:28px 16px; }}
  .wrap {{ max-width:640px; margin:0 auto; }}
  .topbar {{ display:flex; align-items:center; margin-bottom:14px; }}
  .back {{ display:inline-flex; align-items:center; gap:6px; text-decoration:none; background:#fff; border:1px solid #d8e0ee; color:#1e3a8a; font-weight:700; font-size:14px; padding:9px 14px; border-radius:10px; }}
  h1 {{ font-family:'Sora',sans-serif; font-size:28px; font-weight:800; letter-spacing:-0.02em; margin:8px 0 4px; color:#0a1438; }}
  .sub {{ color:#64748b; font-size:15px; font-weight:500; margin-bottom:20px; }}
  .banner {{ padding:12px 14px; border-radius:10px; font-size:14px; margin-bottom:14px; line-height:1.45; }}
  .banner.err {{ background:#fef2f2; color:#b91c1c; border:1px solid #fecaca; }}
  .banner.info {{ background:#eff6ff; color:#1e40af; border:1px solid #bfdbfe; }}
  .card {{ background:#fff; border:1px solid #e2e8f3; border-radius:18px; padding:24px 26px; margin-bottom:16px; box-shadow:0 6px 22px rgba(15,23,42,.07); }}
  .row {{ display:flex; justify-content:space-between; gap:18px; padding:11px 0; font-size:16px; align-items:baseline; border-bottom:1px solid #eef2f9; }}
  .row:last-of-type {{ border-bottom:0; }}
  .lbl {{ color:#475569; font-weight:600; flex:0 0 auto; }}
  .val {{ text-align:right; word-break:break-word; color:#0a1438; font-weight:700; }}
  .muted {{ color:#94a3b8; font-size:13px; font-weight:500; }}
  .mono {{ font-family:'JetBrains Mono',ui-monospace,monospace; font-size:13px; font-weight:600; }}
  .warn {{ background:#fffbeb; color:#92400e; border:1px solid #fde68a; border-radius:8px; padding:9px 11px; font-size:13.5px; margin-top:10px; line-height:1.4; }}
  .actions {{ display:flex; gap:10px; margin-top:16px; flex-wrap:wrap; align-items:center; }}
  .code {{ flex:1 1 120px; min-width:110px; padding:13px; border-radius:11px; border:1px solid #cbd5e1; background:#fff; color:#0f172a; font-size:17px; letter-spacing:2px; text-align:center; }}
  button {{ border:0; border-radius:11px; padding:13px 18px; font-weight:700; font-size:15px; cursor:pointer; }}
  button:disabled {{ opacity:.5; cursor:default; }}
  .approve {{ background:linear-gradient(90deg,#0ea5e9,#06b6d4); color:#fff; }}
  .reject {{ background:#f1f5f9; color:#b91c1c; border:1px solid #e2e8f3; }}
  .result {{ margin-top:12px; font-size:14px; min-height:0; }}
  .result.ok {{ background:#f0fdf4; border:1px solid #86efac; color:#15803d; padding:13px 15px; border-radius:10px; font-weight:600; line-height:1.5; }}
  .result.bad {{ background:#fef2f2; border:1px solid #fecaca; color:#b91c1c; padding:11px 13px; border-radius:10px; font-weight:600; }}
  .result a {{ color:#0369a1; font-weight:700; }}
  .empty {{ color:#64748b; text-align:center; padding:48px 0; font-size:15px; }}
  .foot {{ color:#94a3b8; font-size:12.5px; margin-top:22px; line-height:1.5; }}
</style></head><body>
  <div class="wrap">
  <div class="topbar"><a class="back" href="/admin">← Back to Admin</a></div>
  <h1>Withdrawal Release Queue</h1>
  <div class="sub"><span id="qcount">{len(rows)}</span> awaiting your release · per-tx cap ${float(cap):.0f}</div>
  {banner}
  <div id="flash"></div>
  <div id="cards">{body_cards}</div>
  <div class="foot">Each release needs a fresh 6-digit code from your authenticator app — the same one you use for admin login. Money does not move without it.</div>
  </div>
<script>
async function post(url, code) {{
  const r = await fetch(url, {{ method:'POST', headers:{{'Content-Type':'application/json'}}, body: JSON.stringify(code ? {{totp_code: code}} : {{}}) }});
  let d = {{}}; try {{ d = await r.json(); }} catch(e) {{}}
  return {{ ok: r.ok, d }};
}}
async function release(id) {{
  const code = (document.getElementById('code-'+id).value || '').trim();
  const res = document.getElementById('res-'+id);
  if (!code) {{ res.className='result bad'; res.textContent='Enter your 2FA code first.'; return; }}
  res.className='result'; res.textContent='Releasing…';
  const {{ok, d}} = await post('/admin/api/withdrawals/'+id+'/approve', code);
  if (ok && d.success) {{
    var link = d.tx_hash ? ' <a href="https://bscscan.com/tx/'+d.tx_hash+'" target="_blank" rel="noopener">View on BSCScan ↗</a>' : '';
    var flash=document.getElementById('flash');
    if(flash){{ flash.innerHTML='<div class="result ok">✓ '+(d.message||'Released')+'.'+link+'</div>'; }}
    var c=document.getElementById('wd-'+id);
    if(c){{ c.style.transition='opacity .3s'; c.style.opacity='0'; setTimeout(function(){{ c.remove(); afterRelease(); }}, 300); }}
    else {{ afterRelease(); }}
  }}
  else {{ res.className='result bad'; res.innerHTML='✗ '+((d&&d.error)||'Failed'); }}
}}
async function reject(id) {{
  if (!confirm('Reject this withdrawal and refund the member?')) return;
  const res = document.getElementById('res-'+id);
  res.className='result'; res.textContent='Rejecting…';
  const r = await fetch('/admin/api/withdrawals/'+id+'/refund', {{ method:'POST', headers:{{'Content-Type':'application/json'}}, body: JSON.stringify({{reason:'Rejected at release queue'}}) }});
  let d={{}}; try {{ d = await r.json(); }} catch(e) {{}}
  if (r.ok && !d.error) {{
    var flash=document.getElementById('flash');
    if(flash){{ flash.innerHTML='<div class="result ok">✓ Withdrawal #'+id+' rejected and refunded to the member.</div>'; }}
    var c=document.getElementById('wd-'+id);
    if(c){{ c.style.transition='opacity .3s'; c.style.opacity='0'; setTimeout(function(){{ c.remove(); afterRelease(); }}, 300); }} else {{ afterRelease(); }}
  }}
  else {{ res.className='result bad'; res.textContent='✗ '+((d&&d.error)||'Failed'); }}
}}
function afterRelease(){{
  var cards=document.getElementById('cards');
  var remaining=cards?cards.querySelectorAll('.card').length:0;
  var qc=document.getElementById('qcount'); if(qc) qc.textContent=remaining;
  if(remaining===0 && cards){{ cards.innerHTML='<div class="empty">No withdrawals awaiting release.</div>'; }}
}}
</script></body></html>"""
    return HTMLResponse(html)


@app.post("/admin/api/withdrawals/{withdrawal_id}/approve")
async def admin_withdrawal_approve(
    withdrawal_id: int,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Release ONE awaiting_approval withdrawal. Requires the admin's live
    TOTP code (verified against their own totp_secret — same factor as
    login). Re-checks the per-tx cap and destination, flips the row to
    'pending' and processes it once. This is the only path that moves a
    withdrawal toward sending."""
    _require_admin(user)
    from decimal import Decimal as _D

    if not (getattr(user, "totp_enabled", False) and user.totp_secret):
        return JSONResponse({"success": False, "error": "Enable 2FA on your admin account before releasing withdrawals (Account → Security)."}, status_code=403)

    try:
        body = await request.json()
    except Exception:
        body = {}
    code = str(body.get("totp_code") or body.get("code") or "").strip()
    if not code:
        return JSONResponse({"success": False, "error": "Enter your 2FA code to release this withdrawal."}, status_code=400)

    import pyotp
    if not pyotp.TOTP(user.totp_secret).verify(code, valid_window=1):
        return JSONResponse({"success": False, "error": "Invalid 2FA code."}, status_code=400)

    withdrawal = db.query(Withdrawal).filter(Withdrawal.id == withdrawal_id).first()
    if not withdrawal:
        return JSONResponse({"success": False, "error": "Withdrawal not found"}, status_code=404)
    if withdrawal.status != "awaiting_approval":
        return JSONResponse({"success": False, "error": f"Withdrawal is '{withdrawal.status}', not awaiting approval."}, status_code=400)

    # Guardrail: per-transaction cap
    cap = _withdrawal_max_per_tx()
    if _D(str(withdrawal.amount_usdt or 0)) > cap:
        return JSONResponse({"success": False, "error": f"Amount ${float(withdrawal.amount_usdt or 0):.2f} exceeds the per-transaction cap of ${float(cap):.2f}. Raise WITHDRAWAL_MAX_PER_TX in Railway to release a larger amount."}, status_code=400)

    # Guardrail: destination must still match the member's saved wallet
    member = db.query(User).filter(User.id == withdrawal.user_id).first()
    if member and member.wallet_address and withdrawal.wallet_address and \
       member.wallet_address.strip().lower() != withdrawal.wallet_address.strip().lower():
        return JSONResponse({"success": False, "error": "Destination address no longer matches the member's saved wallet. Reject and ask the member to re-request."}, status_code=400)

    # Record the 2FA-verified approval BEFORE flipping to 'pending'. The send
    # path (process_withdrawal) refuses to broadcast without this row, so the
    # ordering is load-bearing: no approval record => no send, even if the
    # status flips. Snapshot the amount + destination so the send path can
    # detect any post-approval mutation. If the table is missing (migration
    # not yet run), fail loud and leave the row awaiting_approval — never send.
    # Sign the approval with the env-only secret so the send gate can verify
    # this row was written here (TOTP-gated) and not forged/injected into the
    # DB. Fail closed if the secret isn't configured — an unsigned approval is
    # rejected at send time anyway, so refuse here with a clear message.
    from app.withdrawals import compute_approval_signature
    appr_sig = compute_approval_signature(
        withdrawal.id, withdrawal.amount_usdt, withdrawal.wallet_address)
    if not appr_sig:
        return JSONResponse({"success": False, "error": "WITHDRAWAL_APPROVAL_SECRET is not set in Railway. Set it before approving withdrawals — approvals must be cryptographically signed."}, status_code=500)
    try:
        from app.database import WithdrawalApproval
        if not db.query(WithdrawalApproval).filter(
                WithdrawalApproval.withdrawal_id == withdrawal.id).first():
            db.add(WithdrawalApproval(
                withdrawal_id=withdrawal.id,
                approved_by_user_id=user.id,
                approved_by_username=user.username,
                approved_amount_usdt=withdrawal.amount_usdt,
                approved_wallet_address=withdrawal.wallet_address,
                approved_at=datetime.utcnow(),
                signature=appr_sig,
            ))
            db.flush()
    except Exception as e:
        logger.error(f"approve: could not record approval for #{withdrawal_id}: {e}")
        db.rollback()
        return JSONResponse({"success": False, "error": "Could not record approval — the approval store may need a migration (withdrawal_approvals). Withdrawal left awaiting approval; nothing sent."}, status_code=500)

    # Release: flip to 'pending' (so process_withdrawal will accept it) and
    # process once. If the on-chain send fails (e.g. WITHDRAWALS_ENABLED off,
    # or transient RPC), the row stays 'pending' — already-approved, safe for
    # the retry cron — or you can reject it to refund.
    withdrawal.status = "pending"
    stamp = f" | released by {user.username} @ {datetime.utcnow().isoformat()}Z"
    withdrawal.notes = ((withdrawal.notes or "") + stamp)[:500]
    db.commit()

    try:
        from app.withdrawals import process_withdrawal
        result = process_withdrawal(db, withdrawal.id)
    except Exception as e:
        logger.error(f"approve: process_withdrawal raised for #{withdrawal_id}: {e}")
        db.rollback()
        result = {"success": False, "error": "Send failed — see logs. Row left pending; retry from the queue or reject to refund."}

    db.refresh(withdrawal)
    if result.get("success"):
        _gross = float(withdrawal.amount_usdt or 0)
        _net = max(0.0, _gross - 1.0)
        return JSONResponse({"success": True, "message": f"Released — ${_net:.2f} sent on-chain (net of $1 fee)", "net_amount": _net, "gross_amount": _gross, "tx_hash": withdrawal.tx_hash or "", "status": withdrawal.status})
    return JSONResponse({"success": False, "error": result.get("error", "Send failed"), "status": withdrawal.status}, status_code=400)


@app.get("/admin/api/withdrawals")
def admin_api_withdrawals(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    status: str = ""
):
    _require_admin(user)
    query = db.query(Withdrawal).order_by(Withdrawal.requested_at.desc())
    if status:
        query = query.filter(Withdrawal.status == status)
    ws = query.limit(100).all()

    # Get usernames
    user_ids = {w.user_id for w in ws}
    users_map = {u.id: u.username for u in db.query(User).filter(User.id.in_(user_ids)).all()} if user_ids else {}

    return {
        "withdrawals": [{
            "id": w.id, "user_id": w.user_id,
            "username": users_map.get(w.user_id, "?"),
            "amount": float(w.amount_usdt or 0),
            "wallet": w.wallet_address, "status": w.status,
            "tx_hash": w.tx_hash,
            "requested": w.requested_at.isoformat() if w.requested_at else None,
            "processed": w.processed_at.isoformat() if w.processed_at else None,
            # Hardening fields (added 2 May 2026) — let admin UI show why
            # a row stuck and which balance to refund.
            "wallet_type": w.wallet_type or "affiliate",
            "attempts": w.attempts or 0,
            "last_attempted_at": w.last_attempted_at.isoformat() if w.last_attempted_at else None,
            "last_error": w.last_error,
        } for w in ws]
    }
@app.get("/admin/api/withdrawals/stuck")
def admin_withdrawals_stuck(user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """List withdrawals stuck in pending/processing for over 24 hours.
    These have had balance deducted but no USDT sent — candidates for refund."""
    _require_admin(user)
    from datetime import datetime, timedelta
    cutoff = datetime.utcnow() - timedelta(hours=24)
    stuck = db.query(Withdrawal).filter(
        Withdrawal.status.in_(["pending", "processing"]),
        Withdrawal.requested_at < cutoff,
    ).order_by(Withdrawal.requested_at.asc()).limit(100).all()
    user_ids = {w.user_id for w in stuck}
    users_map = {u.id: u.username for u in db.query(User).filter(User.id.in_(user_ids)).all()} if user_ids else {}
    return {
        "stuck": [{
            "id": w.id, "user_id": w.user_id,
            "username": users_map.get(w.user_id, "?"),
            "amount": float(w.amount_usdt or 0),
            "wallet": w.wallet_address, "status": w.status,
            "requested": w.requested_at.isoformat() if w.requested_at else None,
            "age_hours": round((datetime.utcnow() - w.requested_at).total_seconds() / 3600, 1) if w.requested_at else None,
            # Hardening fields — surface why this is stuck.
            "wallet_type": w.wallet_type or "affiliate",
            "attempts": w.attempts or 0,
            "last_attempted_at": w.last_attempted_at.isoformat() if w.last_attempted_at else None,
            "last_error": w.last_error,
        } for w in stuck]
    }
@app.post("/admin/api/withdrawals/{withdrawal_id}/refund")
async def admin_withdrawal_refund(
    withdrawal_id: int,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin-only: cancel a stuck withdrawal and refund the balance.
    Reverses the atomic deduction that happened when the withdrawal was requested.
    Only works on pending/processing withdrawals — paid ones cannot be refunded here.

    Body (all optional):
      reason:      string, written to withdrawal.notes
      wallet_type: 'affiliate' | 'campaign' — ONLY used as an explicit
                   override when the row's wallet_type is missing/wrong.
                   Default behaviour is to read wallet_type from the row,
                   which is the source of truth post the 2 May 2026
                   schema migration.
      override_wallet_type: boolean, must be true to honour wallet_type
                   override. Without this flag, any wallet_type in the
                   body is ignored — closes the silent-corruption hole
                   where an admin could refund the wrong balance column.
    """
    _require_admin(user)
    from sqlalchemy import text
    from datetime import datetime

    try:
        body = await request.json()
    except Exception:
        body = {}

    reason = (body.get("reason") or "Admin refund — stuck withdrawal").strip()[:500]

    withdrawal = db.query(Withdrawal).filter(Withdrawal.id == withdrawal_id).first()
    if not withdrawal:
        return JSONResponse({"error": "Withdrawal not found"}, status_code=404)

    if withdrawal.status not in ("pending", "processing", "awaiting_approval"):
        return JSONResponse({
            "error": f"Cannot refund — withdrawal is '{withdrawal.status}'. Only awaiting_approval/pending/processing withdrawals can be refunded."
        }, status_code=400)

    # Default wallet_type from the row. Admin can override only with an
    # explicit override_wallet_type=true flag (e.g. for repairing a row
    # whose wallet_type was set wrong before the migration backfilled it).
    row_wallet_type = (withdrawal.wallet_type or "affiliate").strip().lower()
    body_wallet_type = (body.get("wallet_type") or "").strip().lower()
    if body.get("override_wallet_type") and body_wallet_type in ("affiliate", "campaign"):
        wallet_type = body_wallet_type
        if wallet_type != row_wallet_type:
            logger.warning(
                f"Admin {user.username} OVERRODE wallet_type on withdrawal "
                f"#{withdrawal_id}: row={row_wallet_type} → refund={wallet_type}"
            )
    else:
        wallet_type = row_wallet_type

    if wallet_type not in ("affiliate", "campaign"):
        # Defensive: should be impossible after the migration backfill,
        # but if the row somehow has a junk wallet_type and no override,
        # bail rather than guessing.
        return JSONResponse({
            "error": f"Withdrawal has invalid wallet_type='{withdrawal.wallet_type}'. "
                     f"Provide wallet_type + override_wallet_type=true in body."
        }, status_code=400)

    target_user = db.query(User).filter(User.id == withdrawal.user_id).first()
    if not target_user:
        return JSONResponse({"error": "User not found"}, status_code=404)

    balance_col = "campaign_balance" if wallet_type == "campaign" else "balance"
    amount = float(withdrawal.amount_usdt or 0)

    # Atomic refund — also decrement total_withdrawn to keep it consistent
    db.execute(
        text(f"UPDATE users SET {balance_col} = COALESCE({balance_col}, 0) + :amt, "
             f"total_withdrawn = GREATEST(COALESCE(total_withdrawn, 0) - :amt, 0) WHERE id = :uid"),
        {"amt": amount, "uid": withdrawal.user_id},
    )
    withdrawal.status = "failed_refunded"
    withdrawal.processed_at = datetime.utcnow()
    existing_notes = (withdrawal.notes or "")
    refund_note = f"[Admin refund {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} by {user.username}] {reason}"
    withdrawal.notes = (existing_notes + " | " + refund_note).strip(" |") if existing_notes else refund_note

    # Notify the member
    try:
        from .database import Notification
        db.add(Notification(
            user_id=target_user.id,
            type="withdrawal",
            title="Withdrawal refunded",
            message=f"Your ${amount:.2f} withdrawal could not be sent and has been refunded to your {wallet_type} balance. You can try again from the Wallet page.",
            icon="💰",
        ))
    except Exception as e:
        logger.warning(f"Refund notification failed: {e}")
        db.rollback()

    db.commit()
    # Cache invalidation — balance restored AND total_withdrawn decreased.
    # The new broadened cache_invalidate_user covers both 'withdrawn:'
    # and 'earnings:' prefixes, which would otherwise show stale numbers
    # on the user's wallet page after refund.
    try:
        cache_invalidate_user(target_user.id)
    except Exception as e:
        logger.warning(f"cache_invalidate_user({target_user.id}) failed in withdrawal refund: {e}")
    logger.info(f"Admin {user.username} refunded withdrawal #{withdrawal_id} (${amount} to user {target_user.username} {wallet_type} balance) — {reason}")

    return {"success": True, "withdrawal_id": withdrawal_id, "refunded_amount": amount,
            "wallet_type": wallet_type, "user": target_user.username}
