def compute_descendant_counts(db: Session, user_id: int) -> dict:
    """
    Walks the full descendant tree of `user_id` via a recursive CTE and
    returns three counts: total descendants, active (own at least one
    incomplete Grid = paid for a Campaign Tier), inactive (signed up but
    haven't bought a tier).

    Replaces the legacy `total_team` column which was a denormalised counter
    that drifted because it was being `+= 1`'d in scattered code paths
    (signup, spillover fills, etc) without corresponding decrements on
    user deletion or commission reversals.

    No depth cap — counts every descendant regardless of level. Members
    care about the true size of their network; the 8-level uni-level cap
    is an economic boundary, not a network-membership boundary.

    Cached for 60s per-user — recursive CTE is cheap on small networks but
    we'd rather not run it on every dashboard hit.
    """
    cache_key = f"descendants:{user_id}"
    cached = cache_get(cache_key)
    if cached is not None:
        return cached

    # Recursive CTE: start with direct referrals of user_id, then iteratively
    # add descendants of each found user until no new rows. PostgreSQL
    # handles the recursion + de-dup natively.
    sql = text("""
        WITH RECURSIVE descendants AS (
            SELECT id FROM users WHERE sponsor_id = :start_id
            UNION
            SELECT u.id FROM users u
            INNER JOIN descendants d ON u.sponsor_id = d.id
        )
        SELECT
            COUNT(*) AS total,
            COUNT(*) FILTER (
                WHERE EXISTS (
                    SELECT 1 FROM grids g
                    WHERE g.owner_id = descendants.id
                    AND g.is_complete = FALSE
                )
            ) AS active
        FROM descendants
    """)
    try:
        row = db.execute(sql, {"start_id": user_id}).fetchone()
        total = int(row[0] or 0)
        active = int(row[1] or 0)
        inactive = max(0, total - active)
    except Exception as exc:
        # If the CTE fails for any reason (older Postgres, permissions, etc),
        # fall back to a non-recursive direct-referrals-only count rather
        # than crashing the dashboard. Better to under-report than blow up.
        logger.warning(f"compute_descendant_counts CTE failed for user {user_id}: {exc}")
        directs = db.query(User).filter(User.sponsor_id == user_id).count()
        actives = db.query(User).filter(
            User.sponsor_id == user_id,
            User.id.in_(db.query(Grid.owner_id).filter(Grid.is_complete == False))
        ).count()
        result = {"total": directs, "active": actives, "inactive": directs - actives}
        return result

    result = {"total": total, "active": active, "inactive": inactive}
    # Cache TTL: 60s. Originally 60s, dropped to 5s as a workaround for
    # stale-balance issues 9 May 2026, restored to 60s 12 May 2026 once
    # cache_invalidate_user() coverage was verified (26 call sites cover
    # every commission/balance write). The 5s value was load-bearing for
    # 2 days only because invalidation wasn't yet proven in production;
    # it now is, and the 5s value was causing the dashboard endpoint to
    # re-run a recursive CTE on nearly every page hit during the 12 May
    # signup surge (29 → 66 members in one day). See app/stats_cache.py
    # for the full invalidation coverage list.
    cache_set(cache_key, result, ttl=60)
    return result


def compute_total_withdrawn(db: Session, user_id: int) -> float:
    """
    Compute a user's lifetime total withdrawn from the Withdrawal ledger.
    Sums amount_usdt where status is in the success states ('paid' or
    'completed' — both used in the codebase historically).

    Replaces direct reads of the legacy user.total_withdrawn column which
    drifted from old test data and was never properly maintained. Same
    pattern as compute_descendant_counts() — denormalised counters that
    aren't religiously incremented/decremented in every code path will
    drift; the ledger is the truth.

    Cached 60s per-user.
    """
    cache_key = f"withdrawn:{user_id}"
    cached = cache_get(cache_key)
    if cached is not None:
        return cached

    total = db.query(func.coalesce(func.sum(Withdrawal.amount_usdt), 0)).filter(
        Withdrawal.user_id == user_id,
        Withdrawal.status.in_(["paid", "completed"]),
    ).scalar() or 0

    result = float(total)
    # Cache TTL restored to 60s on 12 May 2026 — see compute_user_earnings.
    cache_set(cache_key, result, ttl=60)
    return result


def compute_user_earnings(db: Session, user_id: int, since=None, until=None) -> dict:
    """
    Compute a user's earnings live from the ledger, broken down by income
    stream.

    Optional since/until (datetime) restrict EVERY slice to a created_at
    window [since, until). When both are None this returns lifetime totals
    (the ALL TIME figure, cached 60s). A windowed call is, by construction,
    the SAME paid-only / topup-excluded filter set as the lifetime total
    plus a created_at bound — so the dashboard "this month" tile is a strict
    subset of ALL TIME and can never exceed it. Windowed calls are not cached
    (the month boundary makes the lifetime cache key unsafe to share).

    NOTE on grid_completion_bonus_topup: deliberately NOT counted. Those rows
    are never a legitimate earning — they are either reversed (clawed-back
    migration double-pays) or phantom-still-live errors that grid-settlement-
    truth flags as "must be 0". Same exclusion the grid visualiser query
    already makes (see the grid_completion_bonus-only bonus_row above). A
    bare status=='paid' filter is NOT enough because phantom topups carry
    status=='paid'; the TYPE is excluded here so neither ALL TIME nor the
    month tiles ever inherit phantom bonus money.

    Returns:
        {
          "total_earned": float,       # sum of all paid commissions + course commissions
          "grid_earnings": float,      # direct_sponsor + uni_level + grid_completion_bonus
          "course_earnings": float,    # CourseCommission table
          "nexus_earnings": float,     # matrix_*, nexus_*
          "membership_earnings": float, # membership / membership_renewal / membership_sponsor
          "personal_referrals": int,   # count of users with sponsor_id = me
        }

    Replaces direct reads of the legacy user.total_earned / user.grid_earnings
    / user.course_earnings / user.personal_referrals denormalised counters.
    Same drift pattern as descendant counts and total_withdrawn — counters
    that get += 1'd at scattered call sites without matching decrements on
    reversal/deletion will silently grow stale, then surface to members as
    "the income stream cards don't sum to my Total Earned" type bugs.

    All sums filter on Commission.status == 'paid' so reversed commissions
    don't inflate the totals.

    Cached 60s per-user.
    """
    windowed = (since is not None) or (until is not None)
    cache_key = None if windowed else f"earnings:{user_id}"
    if cache_key is not None:
        cached = cache_get(cache_key)
        if cached is not None:
            return cached

    def _win(q, col):
        # Apply the optional [since, until) created_at window to a query.
        if since is not None:
            q = q.filter(col >= since)
        if until is not None:
            q = q.filter(col < until)
        return q

    grid = float(_win(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
        Commission.to_user_id == user_id,
        Commission.status == 'paid',
        Commission.commission_type.in_(['direct_sponsor', 'uni_level', 'grid_completion_bonus'])
    ), Commission.created_at).scalar() or 0)

    membership = float(_win(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
        Commission.to_user_id == user_id,
        Commission.status == 'paid',
        Commission.commission_type.in_(['membership', 'membership_renewal', 'membership_sponsor', 'Membership Sponsor', 'gift_membership_sponsor'])
    ), Commission.created_at).scalar() or 0)

    # Nexus earnings come from TWO tables:
    #   1. Commission rows tagged with legacy nexus_*/matrix_* types (very few,
    #      from the pre-Credit-Nexus-table era). Kept for historical accuracy.
    #   2. CreditMatrixCommission rows — the dedicated Credit Nexus table that
    #      every modern matrix payment writes to. This is where the actual
    #      money lives. (7 May 2026: Steve spotted the wallet's Credit Nexus
    #      card stuck at $0 even though his balance had a confirmed $3 from
    #      test3's Starter pack purchase. Same root cause as the activity-feed
    #      bug fixed earlier — when Credit Nexus shipped its own table, this
    #      aggregator was never updated to read from it.)
    nexus_legacy = float(_win(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
        Commission.to_user_id == user_id,
        Commission.status == 'paid',
        Commission.commission_type.in_(['matrix_level', 'matrix_completion', 'nexus_sponsor', 'nexus_level', 'nexus_completion'])
    ), Commission.created_at).scalar() or 0)

    nexus_matrix = float(_win(db.query(func.coalesce(func.sum(CreditMatrixCommission.amount), 0)).filter(
        CreditMatrixCommission.earner_id == user_id,
        CreditMatrixCommission.status == 'paid',
    ), CreditMatrixCommission.created_at).scalar() or 0)

    nexus = nexus_legacy + nexus_matrix

    course = float(_win(db.query(func.coalesce(func.sum(CourseCommission.amount), 0)).filter(
        CourseCommission.earner_id == user_id,
    ), CourseCommission.created_at).scalar() or 0)

    direct_refs = db.query(User).filter(User.sponsor_id == user_id).count()

    total = grid + membership + nexus + course

    result = {
        "total_earned": round(total, 2),
        "grid_earnings": round(grid, 2),
        "course_earnings": round(course, 2),
        "nexus_earnings": round(nexus, 2),
        "membership_earnings": round(membership, 2),
        "personal_referrals": direct_refs,
    }
    # Cache TTL: 60s. Originally 60s. History:
    # - 9 May 2026: Steve's $20 WalletConnect smoke test showed stale
    #   balance for ~60 seconds after commission posted — would cause
    #   panic-refresh support tickets at launch. Dropped to 5s as
    #   workaround.
    # - 10 May 2026: Proper fix shipped. cache_invalidate_user() in
    #   stats_cache.py now covers all four user-keyed prefixes (dash,
    #   descendants, withdrawn, earnings) and is wired into every
    #   commission/balance write site: _activate_membership,
    #   _record_commission (grid), pay_matrix_commissions (credit nexus),
    #   complete_matrix (matrix completion bonus), _credit_earner +
    #   _credit_platform (course), gift voucher claim, withdrawal refund,
    #   admin balance adjust, PIF wallet deduction, email credits, and
    #   wallet credit-pack purchase.
    # - 12 May 2026: RESTORED to 60s. The 5s value caused dashboard
    #   timeouts during the signup surge (29 → 66 members in one day,
    #   with 10 new in the last hour). Live-ledger reads against the
    #   Commission, CreditMatrixCommission, and CourseCommission tables
    #   were re-running on near-every dashboard load because the cache
    #   expired before the next hit could land. With 26 invalidation
    #   call sites now verified in production for 2 days, the 5s belt-
    #   and-braces value is no longer warranted. Balance still feels
    #   live because cache_invalidate_user() fires synchronously on
    #   every relevant write.
    if cache_key is not None:
        cache_set(cache_key, result, ttl=60)
    return result


def get_user_highest_tier(db: Session, user_id: int) -> int:
    """AdvantageLife: the member's highest ACTIVE pack level (-1 if none).

    WAS "highest active GRID tier". Grids are the retired SuperAdPro system and
    the AL engine never creates Grid rows — so every real AL member resolved to
    -1 and was locked out of campaign creation. Admins bypassed via the
    hardcoded return below, which is exactly why it went unnoticed.

    AL gates on PACK OWNERSHIP: buy a pack -> unlock Create Campaign -> the
    pack's views are delivered to the campaigns you make. That's the whole
    advertising premise, so this must read PackPurchase, not Grid.

    Contract preserved for the 13 call sites: -1 = owns nothing, >= 1 = owned
    pack level. Never return 0 — callers test `< 0` and `>= 0`.
    """
    user = db.query(User).filter(User.id == user_id).first()
    if user and user.is_admin:
        # Kept at 8 rather than al_engine._ADMIN_LEVEL (1e9), which would blow
        # up TIER_AI_MULTIPLIERS lookups and any tier label rendered in the UI.
        return 8
    lvl = _ale.owned_level(db, user_id)
    return lvl if lvl > 0 else -1

def check_and_increment_ai_quota(db: Session, user_id: int, tool: str) -> dict:
    """Check daily limit based on user's tier. If within limit, increment and return allowed=True."""
    from datetime import date
    today = date.today().isoformat()
    
    # Get tier-based limit
    user_tier = get_user_highest_tier(db, user_id)
    base_limit = DAILY_LIMITS.get(tool, 10)
    multiplier = TIER_AI_MULTIPLIERS.get(user_tier, 0.2)
    limit = max(2, int(base_limit * multiplier))  # minimum 2/day always

    quota = db.query(AIUsageQuota).filter(AIUsageQuota.user_id == user_id).first()
    if not quota:
        quota = AIUsageQuota(user_id=user_id, quota_date=today)
        db.add(quota)
        db.commit()
        db.refresh(quota)

    if quota.quota_date != today:
        quota.quota_date = today
        quota.campaign_studio_uses = 0
        quota.niche_finder_uses = 0
        quota.social_posts_uses = 0
        quota.video_scripts_uses = 0
        quota.swipe_file_uses = 0
        db.commit()

    field = f"{tool}_uses"
    current = getattr(quota, field, 0)

    if current >= limit:
        from datetime import datetime, timedelta
        now = datetime.utcnow()
        tomorrow = (now + timedelta(days=1)).replace(hour=0, minute=0, second=0, microsecond=0)
        diff = tomorrow - now
        hours = diff.seconds // 3600
        mins  = (diff.seconds % 3600) // 60
        resets_in = f"{hours}h {mins}m" if hours > 0 else f"{mins}m"
        return {"allowed": False, "used": current, "limit": limit, "resets_in": resets_in}

    setattr(quota, field, current + 1)
    total_field = f"{tool}_total"
    setattr(quota, total_field, getattr(quota, total_field, 0) + 1)
    db.commit()
    return {"allowed": True, "used": current + 1, "limit": limit, "resets_in": ""}
