@app.get("/api/registration-status")
def api_registration_status(
    request: Request,
    current_user: User = Depends(get_current_user),
):
    """Tells the frontend whether new public registration is open.

    Returns open=True for everyone now (launched 10 May 2026). The
    referral / gift / bypass-token branches below are kept inert in
    case we ever need to re-close registration for emergency
    maintenance — flip `closed` back to True and they activate again.
    """
    closed = False  # OPEN — flipped from True on launch day 10 May 2026

    # Admin always bypasses
    if current_user and getattr(current_user, "is_admin", False):
        return {"open": True, "admin_bypass": True}

    # When closed: open for those arriving via referral / gift / bypass token.
    # Currently inert because closed=False above. Kept for emergency maintenance.
    if closed:
        ref_qp = request.query_params.get("ref", "")
        ref_cookie = request.cookies.get("ref", "")
        gift_qp = request.query_params.get("gift", "")
        bypass_token = os.getenv("PRE_LAUNCH_BYPASS_TOKEN", "")
        bypass_cookie = request.cookies.get("prelaunch_bypass", "")
        if ref_qp or ref_cookie:
            return {"open": True, "referral_bypass": True}
        if gift_qp:
            return {"open": True, "gift_bypass": True}
        if bypass_token and bypass_cookie == bypass_token:
            return {"open": True, "token_bypass": True}

    return {"open": not closed, "admin_bypass": False}
@app.post("/api/register")
@limiter.limit("5/minute")
async def api_register(
    request: Request,
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user),
):
    """JSON register endpoint for the modal."""
    from fastapi.responses import JSONResponse

    # Pre-launch registration gate REMOVED 10 May 2026 (launch day).
    # Previously gated public registration behind: admin OR has ref OR
    # has gift OR has bypass token. Now open to everyone.
    # Orphan signups (no ref) fall through to the SuperAdPro company
    # account at line ~13838 below as sponsor.

    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    try:
        first_name       = sanitize(body.get("first_name", "").strip())
        username         = sanitize(body.get("username", "").strip())
        email            = sanitize(body.get("email", "").strip())
        password         = body.get("password", "")
        confirm_password = body.get("confirm_password", "")
        ref              = sanitize(body.get("ref", "").strip())

        if not first_name:
            return JSONResponse({"error": "Please enter your first name."}, status_code=400)
        if not validate_username(username):
            return JSONResponse({"error": "Username must be 3-30 characters, letters, numbers and underscores only."}, status_code=400)
        if not validate_email(email):
            return JSONResponse({"error": "Please enter a valid email address."}, status_code=400)
        if is_disposable_email(email):
            return JSONResponse({"error": "Please register with a permanent email address — disposable or test addresses aren't accepted."}, status_code=400)
        if len(password) < 8:
            return JSONResponse({"error": "Password must be at least 8 characters."}, status_code=400)
        if len(password.encode("utf-8")) > 72:
            return JSONResponse({"error": "Password must be 72 characters or less."}, status_code=400)
        if password != confirm_password:
            return JSONResponse({"error": "Passwords do not match."}, status_code=400)

        existing = db.query(User).filter(
            (User.username == username) | (User.email == email)
        ).first()
        if existing:
            return JSONResponse({"error": "Username or email already registered."}, status_code=400)

        # Funnel marker — when via=start the visitor came through the
        # company /start funnel. The frontend Register page is wired
        # to ignore the referral cookie on this path; the only ref
        # that arrives here with via=start is the explicit one the
        # peek-next-sponsor handler put in the URL (the rotator's
        # already-advanced pick). Honour it directly.
        via = sanitize(body.get("via", "").strip())

        sponsor_id = None
        logger.info(f"[REG-REF] incoming ref={ref!r} for new username={body.get('username')!r}")
        if ref:
            from sqlalchemy import func as _f
            _ref_clean = ref.strip().lstrip("@")
            sponsor = (db.query(User)
                         .filter(_f.lower(User.username) == _ref_clean.lower())
                         .first())
            if sponsor:
                sponsor_id = sponsor.id
                logger.info(f"[REG-REF] resolved ref={_ref_clean!r} -> sponsor_id={sponsor_id}")
            else:
                logger.warning(f"[REG-REF] ref={_ref_clean!r} did NOT match any user — will use house fallback")
                # Atomic SQL increment to avoid lost updates under
                # concurrent registrations on the same sponsor.
                from sqlalchemy import func as _sqlfunc
                db.query(User).filter(User.id == sponsor_id).update(
                    {User.total_team: _sqlfunc.coalesce(User.total_team, 0) + 1},
                    synchronize_session=False,
                )

        # ── AdvantageLife: no rotator. ──────────────────────────────
        # The SuperAdPro-era rotator (which distributed no-ref signups
        # across random members) is RETIRED here (11 Jul 2026, Steve):
        # in a pass-up model the sponsor tree is load-bearing, so a signup
        # must attach to its actual referrer or to the house account — never
        # to a random rotated member. Affiliate referrals resolve above via
        # explicit ref. Any signup reaching here has no valid ref, so it
        # attaches to the AdvantageLife house account (user id 1, top of the
        # tree) as a predictable, honest default.
        rotator_assignment_made = False
        rotator_assigned_sponsor_id = None
        if not sponsor_id:
            house = db.query(User).filter(User.id == 1).first()
            if house:
                sponsor_id = house.id
                from sqlalchemy import func as _sqlfunc
                db.query(User).filter(User.id == sponsor_id).update(
                    {User.total_team: _sqlfunc.coalesce(User.total_team, 0) + 1},
                    synchronize_session=False,
                )

        # GeoIP: derive country ISO + name from signup IP (see /register handler above for rationale)
        signup_country_iso = ""
        signup_country_name = ""
        try:
            from app.database import _geoip_reader
            client_ip = request.headers.get("x-forwarded-for", "").split(",")[0].strip() or request.client.host
            if _geoip_reader and client_ip not in ("127.0.0.1", "::1", "localhost"):
                geo = _geoip_reader.country(client_ip)
                signup_country_iso = geo.country.iso_code or ""
                signup_country_name = geo.country.name or ""
        except Exception:
            pass

        user = create_user(
            db, username, email, password,
            sponsor_id=sponsor_id,
            first_name=first_name,
            last_name="",
            wallet_address="",
            country=signup_country_iso,
        )
        if signup_country_name:
            user.display_city = signup_country_name

        # Assign pass-up sponsor for course commission chain
        if sponsor_id:
            sponsor_obj = db.query(User).filter(User.id == sponsor_id).first()
            assign_passup_sponsor(db, user, sponsor_obj)
            db.commit()

        # ── Rotator audit log (added 16 May 2026) ──
        # If this signup came through the rotator path, record the
        # assignment for auditability. Two consumers care: (1) admins
        # diagnosing "where did this signup come from?", (2) the
        # rotator UI showing each member their last-assigned timestamp.
        if rotator_assignment_made and rotator_assigned_sponsor_id and user.id:
            try:
                from sqlalchemy import text as _text
                db.execute(_text(
                    "INSERT INTO rotator_assignments "
                    "(signup_user_id, assigned_sponsor_id, funnel_source) "
                    "VALUES (:signup, :sponsor, 'start')"
                ), {"signup": user.id, "sponsor": rotator_assigned_sponsor_id})
                db.execute(_text(
                    "UPDATE rotator_queue SET last_assigned_at = NOW() "
                    "WHERE user_id = :sponsor"
                ), {"sponsor": rotator_assigned_sponsor_id})
                db.commit()
            except Exception as e:
                logger.warning(f"rotator: audit log write failed: {e}")
                db.rollback()

        # Send welcome email (fails silently if not configured)
        try:
            from app.email_utils import send_welcome_email
            send_welcome_email(email, first_name, username)
        except Exception as e:
            logger.warning(f"Welcome email failed for {email}: {e}")

        # Notify sponsor: "New member joined your team!"
        if sponsor_id:
            try:
                sponsor_obj = db.query(User).filter(User.id == sponsor_id).first()
                if sponsor_obj and sponsor_obj.email:
                    from .email_utils import send_email
                    send_email(
                        to_email=sponsor_obj.email,
                        subject=f"\U0001f389 {first_name} just joined your SuperAdPro team!",
                        html_body=f"""
                        <div style="font-family:Helvetica Neue,Arial,sans-serif;max-width:560px;margin:0 auto;padding:32px 24px;">
                            <div style="background:linear-gradient(135deg,#172554,#1e3a8a);border-radius:16px;padding:24px;margin-bottom:20px;">
                                <div style="text-align:center;padding:16px 0;">
                                    <div style="font-size:42px;margin-bottom:12px;">\U0001f389</div>
                                    <h1 style="color:#fff;font-size:22px;font-weight:800;margin:0 0 8px;">New Team Member!</h1>
                                    <p style="color:rgba(255,255,255,.6);font-size:15px;margin:0;line-height:1.6;">
                                        <strong style="color:#38bdf8;">{first_name}</strong> ({username}) just joined through your referral link.
                                    </p>
                                </div>
                            </div>
                            <div style="background:#f8fafc;border-radius:12px;padding:20px 24px;margin-bottom:20px;">
                                <p style="font-size:14px;color:#334155;line-height:1.7;margin:0 0 12px;">
                                    Welcome them with a message in <strong>Team Messenger</strong> — members who connect with their sponsor in the first 24 hours are 5x more likely to stay active.
                                </p>
                                <a href="https://www.superadpro.com/team-messenger" style="display:inline-block;padding:10px 24px;background:#0ea5e9;color:#fff;border-radius:8px;font-weight:700;font-size:14px;text-decoration:none;">Send a Welcome Message \u2192</a>
                            </div>
                            <p style="font-size:12px;color:#94a3b8;text-align:center;">SuperAdPro \u2014 AI Marketing & Advertising Platform</p>
                        </div>
                        """,
                        text_body=f"{first_name} ({username}) just joined your SuperAdPro team! Send them a welcome message."
                    )
            except Exception:
                pass

            # Auto welcome message from sponsor via Team Messenger
            try:
                sponsor_obj = db.query(User).filter(User.id == sponsor_id).first()
                if sponsor_obj:
                    from sqlalchemy import text as _text
                    db.execute(_text(
                        "INSERT INTO team_messages (from_user_id, to_user_id, message, is_read) VALUES (:from_id, :to_id, :msg, false)"
                    ), {
                        "from_id": sponsor_id,
                        "to_id": user.id,
                        "msg": f"Hey {first_name}! \U0001f44b Welcome to SuperAdPro! I'm {sponsor_obj.first_name or sponsor_obj.username}, your sponsor. If you need any help getting started, just message me here. First steps: set up your profile, check out the Training Centre, and share your referral link to start building your team. Let's go! \U0001f680",
                    })
                    db.commit()
            except Exception:
                pass

        # Create in-app notification for the new user — surfaces actionable
        # first step (activate Basic membership) plus link straight to /upgrade.
        try:
            notif = Notification(
                user_id=user.id,
                type="system",
                icon="👋",
                title="Welcome to SuperAdPro!",
                message=(f"Hey {first_name}, welcome aboard! Your account is set up. "
                         f"To unlock the AI tools and start earning, activate your membership. "
                         f"Then activate a Campaign Tier to enable Watch-to-Earn and start earning commissions."),
                link="/upgrade",
            )
            db.add(notif)
            db.commit()
        except Exception:
            db.rollback()

        # Enrol in nurture sequence — first email fires 24hrs after registration
        try:
            from .database import NurtureSequence
            from datetime import timedelta
            nurture = NurtureSequence(
                user_id     = user.id,
                next_email  = 1,
                next_send_at = datetime.utcnow() + timedelta(hours=24),
            )
            db.add(nurture)
            db.commit()
        except Exception as e:
            logger.warning(f"Nurture enrol failed for {email}: {e}")

        response = JSONResponse({"success": True, "redirect": "/dashboard?new=1"})
        set_secure_cookie(response, user.id)
        return response

    except Exception as exc:
        logger.error(f"api_register error: {exc}", exc_info=True)
        db.rollback()
        return JSONResponse({"error": f"Registration failed: {exc}"}, status_code=500)
