@app.get("/account/2fa-setup")
def totp_setup_page_legacy(request: Request):
    """Legacy URL — redirects to canonical React route at /2fa-setup.
    Kept for any old links, bookmarks, or stale email templates that still
    point to /account/2fa-setup. The actual React route is registered as
    /2fa-setup in App.jsx, so serving index.html here would fall through
    to the SPA's catch-all <Navigate to="/" /> and dump users on the
    dashboard. 301 permanent redirect tells clients to update."""
    return RedirectResponse(url="/2fa-setup", status_code=301)
@app.get("/2fa-setup")
def totp_setup_page(request: Request):
    """Serve React SPA — 2FA setup page is at /2fa-setup in App.jsx.
    Required because there is no global SPA catch-all; every React route
    needs an explicit FastAPI handler that returns index.html so the SPA
    boots and React Router takes over."""
    if _react_index.exists():
        return _spa_shell()
    return RedirectResponse(url="/account", status_code=302)
@app.post("/account/2fa-verify")
def totp_verify(
    request: Request,
    totp_code: str = Form(),
    db: Session = Depends(get_db),
    user: User = Depends(get_current_user)
):
    """Verify the TOTP code and enable 2FA."""
    if not user: return RedirectResponse(url="/?login=1", status_code=302)
    import pyotp
    if not user.totp_secret:
        return RedirectResponse(url="/account?error=setup_2fa_first", status_code=303)
    totp = pyotp.TOTP(user.totp_secret)
    if totp.verify(totp_code, valid_window=1):
        user.totp_enabled = True
        db.commit()
        return RedirectResponse(url="/account?saved=2fa_enabled", status_code=303)
    else:
        return RedirectResponse(url="/2fa-setup?error=invalid_code", status_code=303)
@app.post("/account/2fa-disable")
def totp_disable(
    request: Request,
    totp_code: str = Form(),
    db: Session = Depends(get_db),
    user: User = Depends(get_current_user)
):
    """Disable 2FA after verifying current code. Returns JSON for SPA consumption.
    On success: {success: true, message}
    On failure: {success: false, error}
    """
    if not user:
        return JSONResponse({"success": False, "error": "Not signed in"}, status_code=401)
    import pyotp
    if not user.totp_secret or not user.totp_enabled:
        return JSONResponse({"success": False, "error": "Two-factor authentication is not currently enabled on this account."}, status_code=400)
    totp = pyotp.TOTP(user.totp_secret)
    if not totp_code or not totp_code.strip():
        return JSONResponse({"success": False, "error": "Please enter your current 2FA code to disable two-factor authentication."}, status_code=400)
    if totp.verify(totp_code.strip(), valid_window=1):
        user.totp_enabled = False
        user.totp_secret = None
        db.commit()
        return JSONResponse({"success": True, "message": "Two-factor authentication has been disabled. You can re-enable it any time from this page."})
    return JSONResponse({"success": False, "error": "Invalid 2FA code. Please try again."}, status_code=400)
