# ── GDPR DATA EXPORT & DELETION ──
@app.get("/api/account/export-data")
def gdpr_export_data(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """GDPR Article 15: Export all user data as JSON.

    Must include EVERY personal data point the platform stores about the
    user — not just data from one of three commission tables. Bug fixed
    7 May 2026: previously exported only Commission rows, omitting
    CourseCommission (Course Academy commissions) and
    CreditMatrixCommission (Credit Nexus commissions). Members
    requesting their data export under GDPR Article 15 received an
    INCOMPLETE export, which is itself a GDPR violation.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    import json as _jgdpr

    # All commissions across all 3 tables, normalised into one list.
    # Each row tagged with `source` so the recipient (member or DPA
    # auditor) can see which stream a commission came from.
    commissions_all = []
    for c in db.query(Commission).filter(Commission.to_user_id == user.id).all():
        commissions_all.append({
            "source": "grid_or_membership",
            "amount": float(c.amount_usdt or 0),
            "type": c.commission_type,
            "status": c.status,
            "date": c.created_at.isoformat() if c.created_at else None,
        })
    for c in db.query(CreditMatrixCommission).filter(CreditMatrixCommission.earner_id == user.id).all():
        commissions_all.append({
            "source": "credit_nexus",
            "amount": float(c.amount or 0),
            "type": c.commission_type,
            "level": c.level,
            "status": c.status,
            "pack_price": float(c.pack_price or 0),
            "date": c.created_at.isoformat() if c.created_at else None,
        })
    for c in db.query(CourseCommission).filter(CourseCommission.earner_id == user.id).all():
        commissions_all.append({
            "source": "course",
            "amount": float(c.amount or 0),
            "type": c.commission_type,
            "course_tier": c.course_tier,
            "status": "paid",  # CourseCommission has no status column — always paid when written
            "date": c.created_at.isoformat() if c.created_at else None,
        })

    data = {
        "user": {
            "id": user.id, "username": user.username, "email": user.email,
            "first_name": user.first_name, "last_name": user.last_name,
            "niche": user.niche, "membership_tier": user.membership_tier,
            "created_at": user.created_at.isoformat() if user.created_at else None,
        },
        "commissions": commissions_all,
        "withdrawals": [{"amount": float(w.amount_usdt), "status": w.status, "date": w.created_at.isoformat() if w.created_at else None}
                        for w in db.query(Withdrawal).filter(Withdrawal.user_id == user.id).all()],
        "notifications": [{"title": n.title, "message": n.message, "date": n.created_at.isoformat() if n.created_at else None}
                          for n in db.query(Notification).filter(Notification.user_id == user.id).all()],
        "achievements": [{"badge": a.badge_id, "title": a.title, "date": a.earned_at.isoformat() if a.earned_at else None}
                         for a in db.query(Achievement).filter(Achievement.user_id == user.id).all()],
        "funnel_pages": [{"title": p.title, "slug": p.slug, "views": p.views, "leads": p.leads_captured}
                         for p in db.query(FunnelPage).filter(FunnelPage.user_id == user.id).all()],
    }
    return JSONResponse(data, headers={"Content-Disposition": f'attachment; filename="superadpro-data-{user.username}.json"'})
@app.post("/api/account/delete-data")
async def gdpr_delete_data(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """GDPR: Delete all user data. Requires confirmation."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    body = await request.json()
    if body.get("confirm") != "DELETE_MY_DATA":
        return JSONResponse({"error": "Please confirm by sending confirm: DELETE_MY_DATA"}, status_code=400)
    # Delete user's data (keep commission records for financial audit)
    db.query(Notification).filter(Notification.user_id == user.id).delete()
    db.query(Achievement).filter(Achievement.user_id == user.id).delete()
    # Null out member_leads FK before deleting funnel pages to avoid FK violation
    from sqlalchemy import text as _sql_text_gdpr
    _funnel_ids_gdpr = [r.id for r in db.query(FunnelPage).filter(FunnelPage.user_id == user.id).all()]
    if _funnel_ids_gdpr:
        db.execute(_sql_text_gdpr("UPDATE member_leads SET source_funnel_id = NULL WHERE source_funnel_id = ANY(:ids)"), {"ids": _funnel_ids_gdpr})
    db.query(FunnelPage).filter(FunnelPage.user_id == user.id).delete()
    db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user.id).delete()
    # Anonymise the user record
    user.email = f"deleted_{user.id}@removed.com"
    user.username = f"deleted_{user.id}"
    user.first_name = None
    user.last_name = None
    user.avatar_url = None
    user.wallet_address = None
    user.is_active = False
    user.password_hash = "DELETED"
    db.commit()
    logger.info(f"GDPR deletion: user {user.id} data removed and anonymised")
    return JSONResponse({"ok": True, "message": "Your data has been deleted and your account anonymised."})

def check_achievements(db: Session, user: User):
    """Check and award any new badges the user has earned."""
    existing = {a.badge_id for a in db.query(Achievement).filter(Achievement.user_id == user.id).all()}
    _earn = compute_user_earnings(db, user.id)
    _desc = compute_descendant_counts(db, user.id)
    earned = _earn["total_earned"]
    team = _desc["total"]
    new_badges = []

    checks = {
        "first_login": True,
        "profile_complete": bool(getattr(user, 'avatar_url', None) and user.first_name),
        "first_referral": team >= 1,
        "team_of_5": team >= 5,
        "team_of_10": team >= 10,
        "team_of_25": team >= 25,
        "team_of_50": team >= 50,
        "first_100": earned >= 100,
        "earned_500": earned >= 500,
        "earned_1000": earned >= 1000,
        "earned_5000": earned >= 5000,
        "founding_member": bool(getattr(user, 'is_founding_member', False)),
        "first_funnel": db.query(FunnelPage).filter(FunnelPage.user_id == user.id).first() is not None,
        "first_linkhub": db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user.id).first() is not None,
        # Grid completion bonus paid — awarded the first time a member's
        # 36-seat grid completes AND the bonus actually pays out (not just
        # rolls over due to lack of qualification). Single badge per member,
        # not per tier — keeps the badge meaningful rather than spammy.
        # Added 26 May 2026 alongside the bonus-pool top-up migration.
        "grid_bonus_paid": db.query(Grid).filter(
            Grid.owner_id == user.id,
            Grid.is_complete == True,
            Grid.bonus_paid == True,
        ).first() is not None,
    }

    for badge_id, earned_it in checks.items():
        if earned_it and badge_id not in existing and badge_id in BADGES:
            b = BADGES[badge_id]
            db.add(Achievement(user_id=user.id, badge_id=badge_id, title=b["title"], icon=b["icon"]))
            send_notification(db, user.id, "achievement", b["icon"],
                f'Badge earned: {b["title"]}!', b["desc"], "/achievements")
            new_badges.append(badge_id)

    if new_badges:
        db.commit()
    return new_badges
def _old_achievements_DISABLED(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if not user: return RedirectResponse(url="/?login=1")
    check_achievements(db, user)
    earned = db.query(Achievement).filter(Achievement.user_id == user.id).order_by(Achievement.earned_at.desc()).all()
    earned_ids = {a.badge_id for a in earned}
    ctx = get_dashboard_context(request, user, db)
    ctx["earned"] = earned
    ctx["earned_ids"] = earned_ids
    ctx["all_badges"] = BADGES
    ctx["active_page"] = "achievements"
    return templates.TemplateResponse("achievements.html", ctx)
# ═══════════════════════════════════════════════════════════════
#  DAILY CRON — MEMBERSHIP AUTO-RENEWAL
#  Called by Railway cron job daily at 00:05 UTC
#  Protected by CRON_SECRET env var
# ═══════════════════════════════════════════════════════════════

@app.post("/cron/process-renewals")
def cron_process_renewals(
    request: Request,
    db: Session = Depends(get_db)
):
    from fastapi.responses import JSONResponse
    from datetime import datetime

    # Verify cron secret — must match CRON_SECRET env var
    cron_secret = os.environ.get("CRON_SECRET", "")
    auth_header = request.headers.get("Authorization", "")
    provided    = auth_header.replace("Bearer ", "").strip()

    if not cron_secret or provided != cron_secret:
        logging.warning(f"Cron renewal: unauthorised attempt from {request.client.host if request.client else 'unknown'}")
        return JSONResponse({"error": "Unauthorised"}, status_code=401)

    started_at = datetime.utcnow()
    logging.info(f"[CRON] process-renewals started at {started_at.isoformat()}")

    try:
        results = process_auto_renewals(db)
        finished_at = datetime.utcnow()
        duration_ms = int((finished_at - started_at).total_seconds() * 1000)

        logging.info(
            f"[CRON] process-renewals complete — "
            f"renewed={len(results.get('renewed', []))}, "
            f"warned={len(results.get('warned', []))}, "
            f"grace={len(results.get('grace_extended', []))}, "
            f"lapsed={len(results.get('lapsed', []))}, "
            f"duration={duration_ms}ms"
        )

        return JSONResponse({
            "success":       True,
            "run_at":        started_at.strftime("%Y-%m-%d %H:%M:%S UTC"),
            "duration_ms":   duration_ms,
            "renewed":       len(results.get("renewed", [])),
            "warned":        len(results.get("warned", [])),
            "grace_started": len(results.get("grace_extended", [])),
            "lapsed":        len(results.get("lapsed", [])),
        })

    except Exception as e:
        logging.error(f"[CRON] process-renewals FAILED: {e}")
        return JSONResponse({
            "success": False,
            "error":   str(e),
            "run_at":  started_at.strftime("%Y-%m-%d %H:%M:%S UTC"),
        }, status_code=500)
@app.get("/cron/process-renewals")
def cron_process_renewals_get(request: Request, secret: str = "", db: Session = Depends(get_db)):
    """GET version of renewal cron — auth via ?secret= query param for cron-job.org."""
    from fastapi.responses import JSONResponse
    from datetime import datetime
    cron_secret = os.environ.get("CRON_SECRET", "")
    if not cron_secret or secret != cron_secret:
        return JSONResponse({"error": "Unauthorised"}, status_code=401)
    try:
        results = process_auto_renewals(db)
        def _cnt(v):
            return v if isinstance(v, int) else len(v or [])
        errs = results.get("errors", []) or []
        return {
            "ok": True,
            "renewed": _cnt(results.get("renewed", [])),
            "warned": _cnt(results.get("warned", [])),
            "grace_started": _cnt(results.get("grace_extended", [])),
            "lapsed": _cnt(results.get("lapsed", [])),
            "backfilled": _cnt(results.get("backfilled", [])),
            "email_queued": _cnt(results.get("email_queued", 0)),
            "errors": _cnt(errs),
            "error_detail": errs[:10] if isinstance(errs, list) else [],
        }
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)


# ── Withdrawal retry cron ────────────────────────────────────────────
# Runs every 5 minutes via cron-job.org. Sweeps pending withdrawals
# whose backoff window has elapsed and re-attempts them. Per-row
# attempts/backoff state lives on the withdrawals table; the heavy
# lifting is in withdrawals.process_pending_withdrawals_batch.
#
# Schedule on cron-job.org:
#   GET  https://www.superadpro.com/cron/process-pending-withdrawals?secret=<CRON_SECRET>
#   every 5 minutes
#
# Why GET + POST: cron-job.org sends GET; manual triggers (curl from
# an admin's terminal during incident response) often default to POST.
# Both auth via the same query-string secret to keep the entry surface
# uniform with the other crons in this file.
# ── Security watchdog (2026-06-03 hardening) ──────────────────────────
# Path-INDEPENDENT breach detector. Polls DB STATE rather than hooking
# specific endpoints, so it catches a privileged action no matter which
# route performed it — the core lesson of the 2026-06-03 breach, where the
# attacker used endpoints nobody was watching. Run every 60s via Railway
# cron (/cron/security-watch). Alerts on new admins, admin balance
# adjustments, and new withdrawals. First run silently baselines so there
# is no alert storm on deploy. See SECURITY.md.
_SECWATCH_RECIPIENT = "stevelawsonmarketing@gmail.com"
# Smoke-alarm thresholds (USDT). Tuned to ignore cent-level rounding while
# catching the kind of injection/drain that could move real money.
_SECWATCH_BALANCE_DIVERGENCE_USDT = 1.00   # SUM(balance) rising faster than SUM(total_earned)
_SECWATCH_TREASURY_DROP_USDT      = 1.00   # treasury USDT leaving with no 'paid' withdrawal behind it

def _secwatch_get(db, key, default=""):
    row = db.query(AppConfig).filter(AppConfig.key == key).first()
    return row.value if (row and row.value is not None) else default

def _secwatch_set(db, key, value):
    row = db.query(AppConfig).filter(AppConfig.key == key).first()
    if row:
        row.value = str(value)
    else:
        db.add(AppConfig(key=key, value=str(value)))

def _secwatch_send_alert(events):
    """Best-effort consolidated security alert email. Never raises."""
    try:
        from .email_utils import send_email
        rows = "".join(
            f'<div style="background:#fef2f2;border-left:3px solid #dc2626;'
            f'border-radius:8px;padding:12px 14px;margin:10px 0;font-size:13px;'
            f'line-height:1.5;color:#334155;">{e}</div>' for e in events
        )
        subject = f"\U0001F6A8 SuperAdPro SECURITY ALERT \u2014 {len(events)} privileged event(s)"
        html_body = f"""
        <div style="font-family:Helvetica Neue,Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">
          <h2 style="color:#dc2626;margin:0 0 8px;">Privileged activity detected</h2>
          <p style="font-size:14px;color:#475569;line-height:1.6;margin:0 0 8px;">
            The security watchdog detected the following privileged action(s) on the
            live platform. <strong>If this was not you, treat it as an active
            intrusion:</strong> set <code>MAINTENANCE_MODE=on</code>, confirm
            <code>WITHDRAWALS_ENABLED</code> is unset (withdrawals frozen), and review
            <code>/admin/security-audit</code>.
          </p>
          {rows}
          <p style="font-size:12px;color:#94a3b8;margin-top:16px;">
            Detected {datetime.utcnow().isoformat()}Z \u00b7 SuperAdPro security watchdog
          </p>
        </div>
        """
        send_email(to_email=_SECWATCH_RECIPIENT, subject=subject, html_body=html_body)
        return True
    except Exception as _e:
        try:
            logging.error(f"[secwatch] alert email failed: {_e}")
        except Exception:
            pass
        return False

def run_security_watch(db, dry=False):
    """Poll DB state for privileged actions. Returns a summary dict.
    Markers persist in app_config so each event is alerted exactly once."""
    from sqlalchemy import func
    events = []

    last_wd  = int((_secwatch_get(db, "secwatch_last_withdrawal_id", "0") or "0"))
    last_adj = int((_secwatch_get(db, "secwatch_last_admin_adj_id", "0") or "0"))
    known_admins_raw = _secwatch_get(db, "secwatch_known_admin_ids", "")
    initialized = _secwatch_get(db, "secwatch_initialized", "")

    cur_max_wd  = db.query(func.max(Withdrawal.id)).scalar() or 0
    cur_max_adj = (db.query(func.max(Commission.id))
                     .filter(Commission.commission_type == "admin_adjustment").scalar()) or 0
    admin_rows = db.query(User.id, User.username).filter(User.is_admin == True).all()  # noqa: E712
    cur_admin_ids = {int(r[0]) for r in admin_rows}

    # First run: baseline silently — never alert on pre-existing history.
    if not initialized:
        if not dry:
            _secwatch_set(db, "secwatch_last_withdrawal_id", cur_max_wd)
            _secwatch_set(db, "secwatch_last_admin_adj_id", cur_max_adj)
            _secwatch_set(db, "secwatch_known_admin_ids",
                          ",".join(str(i) for i in sorted(cur_admin_ids)))
            # Baseline the synthetic-balance (Check 4) and treasury (Check 5)
            # detectors in the same pass, so a single run fully arms the
            # watchdog rather than needing a confusing second run.
            _b = float(db.query(func.coalesce(func.sum(User.balance), 0)).scalar() or 0)
            _e = float(db.query(func.coalesce(func.sum(User.total_earned), 0)).scalar() or 0)
            _secwatch_set(db, "secwatch_sum_balance", round(_b, 2))
            _secwatch_set(db, "secwatch_sum_earned", round(_e, 2))
            try:
                from .walletconnect_payments import health_check as _bsc_health
                _t = _bsc_health().get("treasury_usdt")
            except Exception:
                _t = None
            _pw = float(db.query(func.coalesce(func.sum(Withdrawal.amount_usdt), 0))
                          .filter(Withdrawal.status == "paid").scalar() or 0)
            if _t is not None:
                _secwatch_set(db, "secwatch_treasury_usdt", round(float(_t), 2))
                _secwatch_set(db, "secwatch_paid_wd_total", round(_pw, 2))
            _secwatch_set(db, "secwatch_initialized", "1")
            db.commit()
        return {"status": "baselined", "admins": sorted(cur_admin_ids),
                "max_withdrawal_id": cur_max_wd, "max_admin_adj_id": cur_max_adj}

    known_admins = {int(x) for x in known_admins_raw.split(",") if x.strip().isdigit()}

    # 1) New admin accounts (there is no legitimate make-admin flow in prod)
    new_admins = cur_admin_ids - known_admins
    if new_admins:
        for r in admin_rows:
            if int(r[0]) in new_admins:
                events.append(f"<strong>NEW ADMIN</strong> \u2014 user_id {r[0]} "
                              f"(@{r[1]}) now has is_admin=True. There is no "
                              f"legitimate make-admin flow in production.")

    # 2) New admin balance adjustments
    if cur_max_adj > last_adj:
        for c in (db.query(Commission)
                    .filter(Commission.commission_type == "admin_adjustment",
                            Commission.id > last_adj).all()):
            events.append(f"<strong>BALANCE ADJUSTMENT</strong> \u2014 commission "
                          f"#{c.id} \u2192 user_id {c.to_user_id}, {c.amount_usdt} "
                          f"USDT (status {c.status}).")

    # 3) New withdrawals
    if cur_max_wd > last_wd:
        for w in (db.query(Withdrawal).filter(Withdrawal.id > last_wd).all()):
            events.append(f"<strong>WITHDRAWAL</strong> \u2014 #{w.id}, user_id "
                          f"{w.user_id}, {w.amount_usdt} USDT \u2192 {w.wallet_address} "
                          f"[{w.network or '?'}/{w.status}].")

    # 4) Synthetic-balance signature (aggregate, ledger-invariant).
    # Every legitimate credit to user.balance also bumps total_earned by the
    # same amount (commissions, course payouts, sponsor shares, P2P-in).
    # Withdrawals/spends lower balance only; P2P nets to zero across its two
    # legs. So SUM(balance) can never rise faster than SUM(total_earned) for
    # legitimate activity. A positive divergence = balance appeared without a
    # matching earnings record = the synthetic-balance signature (3-Jun breach
    # shape), independent of which write path injected it. A legitimate admin
    # balance adjustment credits balance without total_earned and will also
    # surface here — it is itemised in Check 2 of the same alert.
    cur_sum_balance = float(db.query(func.coalesce(func.sum(User.balance), 0)).scalar() or 0)
    cur_sum_earned  = float(db.query(func.coalesce(func.sum(User.total_earned), 0)).scalar() or 0)
    base_balance_raw = _secwatch_get(db, "secwatch_sum_balance", "")
    base_earned_raw  = _secwatch_get(db, "secwatch_sum_earned", "")
    bal_first = (base_balance_raw == "" or base_earned_raw == "")
    if not bal_first:
        try:
            d_bal      = cur_sum_balance - float(base_balance_raw)
            d_earned   = cur_sum_earned - float(base_earned_raw)
            # Balance rise explained by recorded admin-adjustment CREDITS since
            # the last poll (same window Check 2 uses: id > last_adj). Netting
            # these out means a legitimate, 2FA-gated admin adjustment is
            # reported once (by Check 2) instead of double-alarming here.
            # Anything NOT explained by an admin-adjustment credit — balance
            # that appeared through some other path — still trips this alarm.
            # Fails safe: a credit lacking the 'Credit' note prefix just
            # under-nets, biasing toward alarming rather than missing.
            admin_credit = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
                Commission.commission_type == "admin_adjustment",
                Commission.id > last_adj,
                Commission.notes.like("Credit%"),
            ).scalar() or 0)
            divergence = (d_bal - d_earned) - admin_credit
            if divergence > _SECWATCH_BALANCE_DIVERGENCE_USDT:
                events.append(
                    f"<strong>SYNTHETIC-BALANCE SIGNAL</strong> \u2014 member balance "
                    f"rose ${d_bal:,.2f}, earnings rose ${d_earned:,.2f}, and only "
                    f"${admin_credit:,.2f} of that rise is a recorded admin "
                    f"adjustment \u2014 leaving ${divergence:,.2f} unexplained. "
                    f"Balance appeared with no earnings and no admin-adjustment "
                    f"record behind it; treat as a synthetic-balance injection "
                    f"through a non-standard path and lock down.")
        except (ValueError, TypeError):
            bal_first = True  # corrupt marker — re-baseline this cycle

    # 5) Treasury USDT drain (BSC live rail). Funds leaving the treasury with
    # no 'paid' withdrawal to account for them = a direct on-chain drain, the
    # one egress no app lock can stop. Best-effort on-chain read; a failed OR
    # SLOW RPC read skips this cycle rather than false-alarming or wiping the
    # baseline. The read is hard-bounded to 8s in a worker thread: health_check
    # makes 4 sequential BSC RPC calls (15s timeout each), so on a slow free-tier
    # moment it could otherwise burn 30-60s — and because the alert mailer fires
    # AFTER this check, an unbounded read here delays every withdrawal alert by
    # exactly that long. The bound caps the whole cycle; a missed tick's treasury
    # read is recovered by the next responsive tick (drain persists in balance).
    cur_treasury = None
    try:
        from .walletconnect_payments import health_check as _bsc_health
        import concurrent.futures as _cf
        _tex = _cf.ThreadPoolExecutor(max_workers=1)
        _tfut = _tex.submit(lambda: _bsc_health().get("treasury_usdt"))
        try:
            cur_treasury = _tfut.result(timeout=8)
        finally:
            _tex.shutdown(wait=False)  # never block on a hung RPC thread
    except Exception as _te:
        cur_treasury = None
        try:
            logging.error(f"[secwatch] treasury read skipped (failed/slow): {_te}")
        except Exception:
            pass
    cur_paid_wd_total = float(
        db.query(func.coalesce(func.sum(Withdrawal.amount_usdt), 0))
          .filter(Withdrawal.status == "paid").scalar() or 0)
    treasury_first = True
    if cur_treasury is not None:
        base_treasury_raw = _secwatch_get(db, "secwatch_treasury_usdt", "")
        base_paid_wd_raw  = _secwatch_get(db, "secwatch_paid_wd_total", "")
        treasury_first = (base_treasury_raw == "" or base_paid_wd_raw == "")
        if not treasury_first:
            try:
                drop        = float(base_treasury_raw) - float(cur_treasury)
                newly_paid  = cur_paid_wd_total - float(base_paid_wd_raw)
                # A drain requires the treasury to actually FALL on-chain. A drop
                # in the paid-withdrawal total (newly_paid < 0 — records voided,
                # deleted, status-changed, or a stale re-baseline) is a bookkeeping
                # change, NOT egress; clamp it to 0 so it can't inflate a phantom
                # drain when no USDT left. And require drop>threshold so a tick
                # where the treasury did not fall never alarms. A real on-chain
                # drain still makes drop>0 and fires. (Fixes the 7-Jun false
                # TREASURY DRAIN SIGNAL: treasury fell $0 but paid-wd total fell
                # $687, yielding a phantom $687 "drain".)
                unexplained = drop - max(0.0, newly_paid)
                if drop > _SECWATCH_TREASURY_DROP_USDT and unexplained > _SECWATCH_TREASURY_DROP_USDT:
                    events.append(
                        f"<strong>TREASURY DRAIN SIGNAL</strong> \u2014 BSC treasury "
                        f"USDT fell ${drop:,.2f}; approved/paid withdrawals only "
                        f"account for ${newly_paid:,.2f}; ${unexplained:,.2f} left "
                        f"the treasury with no withdrawal record behind it. Possible "
                        f"direct on-chain drain \u2014 lock down and check the "
                        f"treasury key.")
            except (ValueError, TypeError):
                treasury_first = True  # corrupt marker — re-baseline this cycle

    if dry:
        return {"status": "dry_run", "events": len(events), "detail": events,
                "admins": sorted(cur_admin_ids),
                "sum_balance": round(cur_sum_balance, 2),
                "sum_earned": round(cur_sum_earned, 2),
                "treasury_usdt": cur_treasury,
                "paid_withdrawal_total": round(cur_paid_wd_total, 2)}

    sent = _secwatch_send_alert(events) if events else True
    # Advance markers only if there was nothing to alert, or the alert sent.
    # If the mailer failed while events existed, leave markers so the next
    # run retries — we'd rather re-alert than silently lose a breach signal.
    if sent:
        _secwatch_set(db, "secwatch_last_withdrawal_id", cur_max_wd)
        _secwatch_set(db, "secwatch_last_admin_adj_id", cur_max_adj)
        if new_admins:
            _secwatch_set(db, "secwatch_known_admin_ids",
                          ",".join(str(i) for i in sorted(cur_admin_ids)))
        # Advance Check 4/5 baselines. On the first cycle (markers absent)
        # this silently establishes the baseline so there is no alarm storm.
        _secwatch_set(db, "secwatch_sum_balance", round(cur_sum_balance, 2))
        _secwatch_set(db, "secwatch_sum_earned", round(cur_sum_earned, 2))
        if cur_treasury is not None:
            # Only move the treasury baseline when the on-chain read succeeded,
            # so a transient RPC failure can't erase the reference point.
            _secwatch_set(db, "secwatch_treasury_usdt", round(float(cur_treasury), 2))
            _secwatch_set(db, "secwatch_paid_wd_total", round(cur_paid_wd_total, 2))
        db.commit()

    return {"status": "checked", "events": len(events),
            "alerted": bool(events) and sent, "email_ok": sent,
            "detail": events, "admins": sorted(cur_admin_ids)}


@app.get("/cron/security-watch")
async def cron_security_watch(request: Request, secret: str = "", test: int = 0,
                              dry: int = 0,
                              db: Session = Depends(get_db)):
    """Security watchdog cron. Polls DB state for privileged actions (new
    admins, balance adjustments, withdrawals) and emails an alert. Intended
    to run every 60s via Railway cron. Protected by CRON_SECRET.
      ?test=1 - send a test alert to verify the email channel end-to-end
      ?dry=1  - report findings without emailing or advancing markers
    See SECURITY.md."""
    _valid_secrets = {s for s in (os.getenv("CRON_SECRET", ""), os.getenv("ADMIN_SECRET", "")) if s}
    # Auth: a valid CRON_SECRET (how the Railway cron calls it) OR a logged-in
    # admin session (so Steve can just tap the link from his phone — no secret
    # to paste into the URL). The /cron origin-verify lock + maintenance
    # allowlist still apply; this only changes who is accepted at the handler.
    _admin_session = False
    try:
        _admin_session = _maintenance_admin_bypass(request)
    except Exception:
        _admin_session = False
    if not ((secret and secret in _valid_secrets) or _admin_session):
        raise HTTPException(status_code=403, detail="Forbidden")
    if test:
        ok = _secwatch_send_alert([
            "<strong>TEST</strong> \u2014 this is a test of the SuperAdPro security "
            "alert channel. If you received this email, alerting works."])
        return {"status": "test_sent", "email_ok": ok, "recipient": _SECWATCH_RECIPIENT}
    return run_security_watch(db, dry=bool(dry))


@app.get("/admin/api/balance-reconciliation")
def admin_balance_reconciliation(
    request: Request,
    limit: int = 50,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """
    Read-only integrity review: accounts whose wallet balance exceeds their
    lifetime earnings.

    INVARIANT: every legitimate credit to user.balance also bumps
    total_earned by the same amount (commissions, course payouts, sponsor
    shares, P2P-in). Withdrawals and spends only lower balance. So for any
    legitimate account, balance <= total_earned. A row where
    balance > total_earned means balance was credited without an earnings
    record — either a legitimate admin balance adjustment (shown per-row via
    its admin_adjustment commission total) or a synthetic-balance injection.

    Session-authenticated admin; GET so it's reachable from a phone URL bar.
    Reads only — never writes. Companion to the security-watch Check 4
    aggregate alarm; this is the per-account drill-down for review.
    """
    _require_admin(user)
    from sqlalchemy import func

    sum_balance = float(db.query(func.coalesce(func.sum(User.balance), 0)).scalar() or 0)
    sum_earned  = float(db.query(func.coalesce(func.sum(User.total_earned), 0)).scalar() or 0)

    tol = 0.01
    rows = (db.query(User)
              .filter(func.coalesce(User.balance, 0)
                      > func.coalesce(User.total_earned, 0) + tol)
              .all())

    flagged = []
    for u in rows:
        bal = float(u.balance or 0)
        earned = float(u.total_earned or 0)
        excess = bal - earned
        adj_total = float(
            db.query(func.coalesce(func.sum(Commission.amount_usdt), 0))
              .filter(Commission.to_user_id == u.id,
                      Commission.commission_type == "admin_adjustment",
                      Commission.status == "paid").scalar() or 0)
        flagged.append({
            "user_id": u.id,
            "username": u.username,
            "balance": round(bal, 2),
            "total_earned": round(earned, 2),
            "excess": round(excess, 2),
            "admin_adjustment_total": round(adj_total, 2),
            "explained_by_admin_adj": (adj_total + tol) >= excess,
        })
    flagged.sort(key=lambda r: r["excess"], reverse=True)
    unexplained = [f for f in flagged if not f["explained_by_admin_adj"]]

    return {
        "invariant": "balance <= total_earned for legitimate accounts",
        "aggregate": {
            "sum_balance": round(sum_balance, 2),
            "sum_total_earned": round(sum_earned, 2),
            "divergence": round(sum_balance - sum_earned, 2),
            "note": "divergence <= 0 is normal (members spend/withdraw); "
                    "a positive aggregate divergence is itself a red flag.",
        },
        "flagged_count": len(flagged),
        "unexplained_count": len(unexplained),
        "note": "Per-row excess covered by admin_adjustment commissions is "
                "likely benign; unexplained excess warrants investigation.",
        "accounts": flagged[:max(1, min(limit, 500))],
    }


@app.post("/cron/process-pending-withdrawals")
def cron_process_pending_withdrawals_post(
    request: Request, secret: str = "", db: Session = Depends(get_db)
):
    cron_secret = os.environ.get("CRON_SECRET", "")
    if not cron_secret or secret != cron_secret:
        return JSONResponse({"error": "Unauthorised"}, status_code=401)
    # ── Maintenance gate ──
    # If withdrawals are halted via the admin panic button, the cron
    # must also pause — otherwise queued withdrawals from before
    # maintenance was flipped would continue dispatching.
    if is_any_maintenance(db):
        return {"ok": True, "skipped": True, "reason": "maintenance_mode"}
    try:
        from app.withdrawals import process_pending_withdrawals_batch
        counts = process_pending_withdrawals_batch(db)
        return {"ok": True, **counts}
    except Exception as e:
        logger.error(f"Withdrawal cron failed: {e}")
        return JSONResponse({"error": str(e)}, status_code=500)


