# API: Pending commissions (dashboard countdown card)
# ─────────────────────────────────────────────

@app.get("/api/pending-commissions")
def api_pending_commissions(user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """List the current member's pending commissions for the dashboard
    countdown card. Includes the trigger member's display name (so the
    card can say "Fred upgraded — 2d 14h left") and the expiry time."""
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from .database import PendingCommission
    now = datetime.utcnow()
    rows = db.query(PendingCommission).filter(
        PendingCommission.recipient_id == user.id,
        PendingCommission.status == "pending",
        PendingCommission.expires_at > now,
    ).order_by(PendingCommission.expires_at.asc()).all()
    out = []
    for pc in rows:
        trigger = db.query(User).filter(User.id == pc.trigger_id).first()
        trigger_name = (trigger.first_name if trigger and trigger.first_name
                        else trigger.username if trigger else f"user {pc.trigger_id}")
        out.append({
            "id": pc.id,
            "amount": float(pc.amount_usdt or 0),
            "commission_type": pc.commission_type,
            "package_tier": pc.package_tier,
            "required_tier": pc.required_tier,
            "trigger_id": pc.trigger_id,
            "trigger_name": trigger_name,
            "expires_at": pc.expires_at.isoformat() + "Z",
            "seconds_remaining": max(0, int((pc.expires_at - now).total_seconds())),
            "created_at": pc.created_at.isoformat() + "Z",
        })
    return {"pending": out, "total_amount": round(sum(r["amount"] for r in out), 2)}


# ─────────────────────────────────────────────
# Re-engagement notification (Layer 3)
# ─────────────────────────────────────────────
# Sends a single notification to lapsed members nudging them to come
# back. Translation key handled client-side so each user sees the
# message in their preferred language.
#
# Idempotent — uses a sentinel notification.type ("reengagement") plus
# is_read=False to dedup. A user with an unread re-engagement
# notification will not get another one. If they read it (clicks the
# bell), reactivate, then lapse again, a fresh one will be created
# next cron run because the previous one is now is_read=True OR the
# user is_active=True flipped at some point in between.

REENGAGEMENT_NOTIF_TYPE = "reengagement"
REENGAGEMENT_TRANSLATION_KEY = "notification.reengagement_lapsed"
REENGAGEMENT_LINK = "/upgrade"

def _create_reengagement_notification(db: Session, user_id: int) -> bool:
    """Create a re-engagement notification for the given user, IF they
    don't already have an unread one. Returns True if created, False if
    one was already pending. Caller is responsible for db.commit()."""
    existing = db.query(Notification).filter(
        Notification.user_id == user_id,
        Notification.type == REENGAGEMENT_NOTIF_TYPE,
        Notification.is_read == False,
    ).first()
    if existing:
        return False
    # Literal English fallback — frontend uses translation_key when
    # available. These plain strings are what an old/stale client
    # without the i18n key would display.
    send_notification(
        db=db,
        user_id=user_id,
        type=REENGAGEMENT_NOTIF_TYPE,
        icon="💛",
        title="Your SuperAdPro membership lapsed",
        message="Your network and earnings are still here waiting for you. Click below to reactivate.",
        link=REENGAGEMENT_LINK,
        translation_key=REENGAGEMENT_TRANSLATION_KEY,
    )
    return True


@app.get("/cron/reengagement-notifications")
def cron_reengagement_notifications(request: Request, secret: str = "", db: Session = Depends(get_db)):
    """Nightly cron — scans for lapsed users and creates a re-engagement
    notification for each. Idempotent: users with an unread reengagement
    notification are skipped. Auth via ?secret= query param.

    "Lapsed" = is_active=False AND has at least one confirmed membership
    Payment record. Same definition as the Command Centre Layer 1
    'lapsed' bucket so members and the system see the same set."""
    from fastapi.responses import JSONResponse
    cron_secret = os.environ.get("CRON_SECRET", "")
    if not cron_secret or secret != cron_secret:
        return JSONResponse({"error": "Unauthorised"}, status_code=401)
    try:
        # Find every user that's currently lapsed
        lapsed_user_ids = [row[0] for row in db.query(User.id).filter(
            User.is_active == False,
            User.id.in_(
                db.query(Payment.from_user_id).filter(
                    Payment.payment_type.like("membership%"),
                    Payment.status.in_(["confirmed", "paid"]),
                )
            ),
        ).all()]

        created = 0
        skipped = 0
        for uid in lapsed_user_ids:
            if _create_reengagement_notification(db, uid):
                created += 1
            else:
                skipped += 1
        db.commit()
        return {"ok": True, "lapsed_total": len(lapsed_user_ids), "created": created, "skipped_already_pending": skipped}
    except Exception as e:
        db.rollback()
        import traceback
        logger.error(f"Re-engagement cron error: {traceback.format_exc()}")
        return JSONResponse({"error": str(e)}, status_code=500)


# ──────────────────────────────────────────────────────────────────────
# DAILY BRIEFING CRON
# ──────────────────────────────────────────────────────────────────────
# Generates a morning briefing for Steve summarising platform health,
# notable activity in the last 24 hours, and any anomalies. Sends to a
# configured email address (DAILY_BRIEFING_EMAIL env var) and stores the
# briefing in the daily_briefings table for history.
#
# Architecture:
#   1. Compute today's metrics (signups, commissions, audit, anomalies)
#   2. Read LAUNCH_LOG.md from the repo (human-curated context)
#   3. Send both to Grok 4.1 Fast (via grok_service.ai_text_generate)
#   4. Email result via Brevo (sender = same as autoresponder)
#   5. Save row in daily_briefings table
#
# Trigger: Railway cron at 06:00 UTC daily, GET to this endpoint with
# ?secret=<CRON_SECRET>. Manual trigger possible: just hit the URL.
# Dryrun mode: ?dryrun=1 → computes metrics + AI summary but does NOT
# send the email or write to DB. Use this to preview output before
# scheduling.
#
# Decided 10 May 2026 with Steve, launch-day morning. The reasoning:
# we need a way for him to see daily platform health AND a way for
# any future Claude session to load context fast. The email arrives
# pre-formatted; he can forward it to a fresh Claude chat as the first
# message and that Claude is briefed instantly. Doesn't solve the
# "Claude auto-loads context" problem (architecturally impossible)
# but cuts the daily friction to a single forward.
# ──────────────────────────────────────────────────────────────────────

def _compute_daily_metrics(db: Session) -> dict:
    """Snapshot platform health for the daily briefing. Read-only.
    
    All counts/sums are over the last 24 hours unless otherwise noted.
    Designed to be cheap (under 200ms) and self-contained — no external
    API calls, no auth context, no side effects.
    """
    from .database import (
        User, Commission, Withdrawal, Payment, Notification,
        WalletConnectPaymentOrder, NowPaymentsOrder, OnchainOrphanTransfer,
    )
    
    now = datetime.utcnow()
    day_ago = now - timedelta(hours=24)
    
    metrics = {}
    
    # ── Total platform state ────────────────────────────────────
    metrics["total_members"] = db.query(User).count()
    metrics["active_members"] = db.query(User).filter(User.is_active == True).count()
    # 'pro_members' was a meaningful split under the Basic/Pro dual-tier
    # model. Under flat-pricing the meaningful split is founding vs
    # non-founding paying members. 100 founding spots total, so this
    # count is bounded above by 100.
    metrics["founding_members"] = db.query(User).filter(
        User.is_active == True,
        User.is_founding_member == True,
    ).count()
    
    # ── Last 24h activity ───────────────────────────────────────
    metrics["signups_24h"] = db.query(User).filter(
        User.created_at >= day_ago
    ).count()
    
    commissions_24h = db.query(Commission).filter(
        Commission.created_at >= day_ago,
        Commission.status == "paid",
    ).all()
    metrics["commissions_count_24h"] = len(commissions_24h)
    metrics["commissions_total_24h"] = float(sum(
        decimal.Decimal(str(c.amount_usdt or 0)) for c in commissions_24h
    ))
    
    # Break down by commission type so anomalies show up clearly
    by_type = {}
    for c in commissions_24h:
        ct = c.commission_type or "unknown"
        by_type[ct] = by_type.get(ct, 0) + float(c.amount_usdt or 0)
    metrics["commissions_by_type_24h"] = {
        k: round(v, 2) for k, v in sorted(by_type.items(), key=lambda x: -x[1])
    }
    
    metrics["withdrawals_24h_count"] = db.query(Withdrawal).filter(
        Withdrawal.requested_at >= day_ago,
        Withdrawal.status.in_(["paid", "completed"]),
    ).count()
    metrics["withdrawals_24h_total"] = float(db.query(
        func.coalesce(func.sum(Withdrawal.amount_usdt), 0)
    ).filter(
        Withdrawal.requested_at >= day_ago,
        Withdrawal.status.in_(["paid", "completed"]),
    ).scalar() or 0)
    
    # ── Health checks ───────────────────────────────────────────
    # Audit: commissions on the same payment to the same recipient (the
    # double-pay bug class fixed 9 May). Should always return 0.
    # Inline the same logic as /admin/api/audit-double-pays so the cron
    # doesn't need to call its own endpoint.
    suspect_commissions = db.execute(
        text("""
            SELECT to_user_id, from_user_id, COUNT(*) as cnt
            FROM commissions
            WHERE commission_type IN (
                'membership_sponsor',
                'gift_membership_sponsor',
                'membership_upgrade_sponsor'
            )
            AND status = 'paid'
            GROUP BY to_user_id, from_user_id
            HAVING COUNT(*) > 1
        """)
    ).fetchall()
    metrics["audit_double_pays"] = len(suspect_commissions)
    
    # Stuck-lapsed: members marked is_active=False but no membership
    # record explaining why. Was the symptom of the test1/test2 bug
    # fixed 7 May; should always be 0 going forward.
    metrics["stuck_lapsed_count"] = db.query(User).filter(
        User.is_active == False,
        User.id.in_(
            db.query(Payment.from_user_id).filter(
                Payment.payment_type.like("membership%"),
                Payment.status.in_(["confirmed", "paid"]),
            )
        ),
    ).count()
    
    # Orphaned WC transfers (someone paid but the amount didn't match
    # any active intent — usually a wallet quirk, sometimes a real bug)
    metrics["orphan_wc_transfers_24h"] = db.query(OnchainOrphanTransfer).filter(
        OnchainOrphanTransfer.seen_at >= day_ago,
    ).count()
    
    # ── Top 3 commission earners last 24h (helps spot anomalies) ──
    top_earners = db.execute(
        text("""
            SELECT u.username, COALESCE(SUM(c.amount_usdt), 0) as earned
            FROM commissions c
            JOIN users u ON u.id = c.to_user_id
            WHERE c.created_at >= :day_ago AND c.status = 'paid'
            GROUP BY u.username
            ORDER BY earned DESC
            LIMIT 3
        """),
        {"day_ago": day_ago}
    ).fetchall()
    metrics["top_earners_24h"] = [
        {"username": row[0], "earned": float(row[1])} for row in top_earners
    ]
    
    return metrics


def _read_launch_log() -> str:
    """Read LAUNCH_LOG.md from the repo root. Returns empty string if
    the file doesn't exist yet (first-run case)."""
    import os
    log_path = os.path.join(os.path.dirname(__file__), "..", "LAUNCH_LOG.md")
    log_path = os.path.abspath(log_path)
    try:
        with open(log_path, "r", encoding="utf-8") as f:
            return f.read()
    except FileNotFoundError:
        return ""
    except Exception as e:
        logger.warning(f"[daily-briefing] LAUNCH_LOG.md read failed: {e}")
        return ""


def _format_metrics_for_email(metrics: dict) -> str:
    """Render the metrics dict as a readable text block for inclusion
    in the email AND as the AI's prompt input."""
    lines = []
    lines.append("PLATFORM HEALTH")
    lines.append(f"  Total members: {metrics['total_members']}")
    lines.append(f"  Active members: {metrics['active_members']} (Founding: {metrics['founding_members']}/100)")
    lines.append("")
    lines.append("LAST 24 HOURS")
    lines.append(f"  New signups: {metrics['signups_24h']}")
    lines.append(f"  Commissions paid: {metrics['commissions_count_24h']} totalling ${metrics['commissions_total_24h']:.2f}")
    if metrics["commissions_by_type_24h"]:
        for ct, amt in metrics["commissions_by_type_24h"].items():
            lines.append(f"    - {ct}: ${amt:.2f}")
    lines.append(f"  Withdrawals: {metrics['withdrawals_24h_count']} totalling ${metrics['withdrawals_24h_total']:.2f}")
    lines.append(f"  Orphan wallet transfers: {metrics['orphan_wc_transfers_24h']}")
    lines.append("")
    lines.append("HEALTH CHECKS")
    audit = "✅ 0" if metrics["audit_double_pays"] == 0 else f"❌ {metrics['audit_double_pays']} suspect"
    lines.append(f"  Double-pay audit: {audit}")
    stuck = "✅ 0" if metrics["stuck_lapsed_count"] == 0 else f"⚠️  {metrics['stuck_lapsed_count']} users"
    lines.append(f"  Stuck-lapsed users: {stuck}")
    if metrics["top_earners_24h"]:
        lines.append("")
        lines.append("TOP EARNERS (24h)")
        for e in metrics["top_earners_24h"]:
            lines.append(f"  {e['username']}: ${e['earned']:.2f}")
    return "\n".join(lines)


def _deterministic_briefing(metrics: dict, today_str: str) -> str:
    """Build the morning-briefing prose DETERMINISTICALLY from the metrics.

    Integrity rule (30 May 2026): the briefing summary must NEVER be authored
    by an LLM. A prior Grok-written summary fabricated a "16 expired-but-active
    members, renewal cron didn't fire" incident that did not exist — inventing
    both a count and a root-cause around normal data. A "never invent numbers"
    instruction does not hold a generative model fed a large suggestive context.

    Every fact and every number below is read straight from `metrics`. Anomalies
    are flagged only when a real metric crosses a real threshold. There is no
    generative step, so a fabricated fact is structurally impossible. This is the
    single source of truth for the email body and the JSON `summary`.
    """
    m = metrics

    # ── Detect real anomalies (thresholds, not judgement) ──────────────
    anomalies = []
    if m.get("audit_double_pays", 0) > 0:
        anomalies.append(
            f"Double-pay audit flagged {m['audit_double_pays']} suspect "
            f"commission pair(s) — same payment paid to the same recipient "
            f"more than once. This is real money and needs investigation "
            f"(/admin/api/sweep-double-pays)."
        )
    if m.get("stuck_lapsed_count", 0) > 0:
        anomalies.append(
            f"{m['stuck_lapsed_count']} stuck-lapsed member(s): paid, valid "
            f"renewal data, but flagged inactive — locked out of a product "
            f"they paid for. List at /admin/api/stuck-lapsed-members."
        )
    if m.get("orphan_wc_transfers_24h", 0) > 0:
        anomalies.append(
            f"{m['orphan_wc_transfers_24h']} orphan wallet transfer(s) in the "
            f"last 24h — funds arrived without matching an active order. "
            f"Reconcile before they age."
        )

    # ── Headline ────────────────────────────────────────────────────────
    parts = []
    if anomalies:
        n = len(anomalies)
        parts.append(
            f"{n} item{'s' if n > 1 else ''} need{'s' if n == 1 else ''} your "
            f"attention today.\n\n" + "\n".join(f"- {a}" for a in anomalies)
        )
    else:
        parts.append(
            "All health checks clean — no double-pays, no stuck-lapsed members, "
            "no orphan transfers. Nothing needs action on the integrity side."
        )

    # ── Platform state (always factual, from metrics) ────────────────────
    parts.append(
        f"Platform: {m['total_members']} total members, {m['active_members']} "
        f"active ({m['founding_members']}/100 founding seats filled)."
    )

    # ── Last 24h activity ────────────────────────────────────────────────
    activity = (
        f"Last 24h: {m['signups_24h']} new signup"
        f"{'s' if m['signups_24h'] != 1 else ''}, "
        f"{m['commissions_count_24h']} commission"
        f"{'s' if m['commissions_count_24h'] != 1 else ''} paid totalling "
        f"${m['commissions_total_24h']:.2f}"
    )
    by_type = m.get("commissions_by_type_24h") or {}
    if by_type:
        bits = ", ".join(f"{ct} ${amt:.2f}" for ct, amt in by_type.items())
        activity += f" ({bits})"
    activity += (
        f". {m['withdrawals_24h_count']} withdrawal"
        f"{'s' if m['withdrawals_24h_count'] != 1 else ''} totalling "
        f"${m['withdrawals_24h_total']:.2f}."
    )
    parts.append(activity)

    top = m.get("top_earners_24h") or []
    if top:
        lead = top[0]
        parts.append(f"Top earner (24h): {lead['username']} at ${lead['earned']:.2f}.")

    # ── Watch line (deterministic, only on real conditions) ──────────────
    if anomalies:
        watch = "Watch today: the flagged item(s) above."
    elif m.get("founding_members", 0) >= 100:
        watch = (
            "Watch today: founding seats are full (100/100) — new activations "
            "are correctly gated to $20 Partner pricing."
        )
    else:
        watch = "Watch today: nothing pressing — platform is steady."
    parts.append(watch)

    return "\n\n".join(parts)


@app.get("/cron/daily-briefing")
async def cron_daily_briefing(
    request: Request,
    secret: str = "",
    dryrun: int = 0,
    db: Session = Depends(get_db),
):
    """Daily morning briefing — computes platform metrics, asks Grok to
    summarise alongside LAUNCH_LOG.md context, emails the result to the
    address in DAILY_BRIEFING_EMAIL, and stores in daily_briefings table.
    
    Auth: ?secret=<CRON_SECRET>
    Dryrun: ?dryrun=1 — computes everything but skips the email send and
    DB write. Returns the would-be output as JSON for preview.
    """
    from fastapi.responses import JSONResponse
    cron_secret = os.environ.get("CRON_SECRET", "")
    if not cron_secret or secret != cron_secret:
        return JSONResponse({"error": "Unauthorised"}, status_code=401)
    
    started_at = datetime.utcnow()
    today_str = started_at.strftime("%Y-%m-%d")
    
    try:
        # Skip if today's briefing already ran (idempotency for cron retries)
        if not dryrun:
            from .database import DailyBriefing
            existing = db.query(DailyBriefing).filter(
                DailyBriefing.briefing_date == today_str
            ).first()
            if existing:
                return {
                    "ok": True,
                    "skipped": True,
                    "reason": f"Briefing for {today_str} already exists (id={existing.id})",
                }
        
        # Step 1: gather data
        metrics = _compute_daily_metrics(db)
        metrics_text = _format_metrics_for_email(metrics)
        launch_log = _read_launch_log()

        # ── Membership renewals (22 Jun 2026) ────────────────────────────────
        # There is no standalone renewal scheduler. Rather than add another
        # cron service that can silently 401/misconfigure, renewals run on the
        # back of THIS cron: it's confirmed-live, runs once a day, and emails
        # Steve the result every morning — so a renewal stoppage can't go
        # unnoticed. Idempotent per member-month (period_key) so a same-day
        # retry can't double-charge. Money operation: skipped during
        # maintenance (the money-cron wall) and on dryrun. Best-effort: a
        # renewal failure must never break the briefing.
        if not dryrun and not MAINTENANCE_MODE:
            try:
                _rr = process_auto_renewals(db)
                metrics_text += (
                    "\n\nMEMBERSHIP RENEWALS (this run):"
                    f"\n  renewed:        {len(_rr.get('renewed', []))}"
                    f"\n  low-bal warned: {len(_rr.get('warned', []))}"
                    f"\n  grace started:  {len(_rr.get('grace_extended', []))}"
                    f"\n  lapsed:         {len(_rr.get('lapsed', []))}"
                    f"\n  backfilled:     {len(_rr.get('backfilled', []))}"
                )
            except Exception as _re:
                logger.error(f"[daily-briefing] renewal processing FAILED: {_re}")
                metrics_text += "\n\nMEMBERSHIP RENEWALS: ⚠️ ERROR — renewals did NOT process this run (see logs)"

        # Step 2: build the briefing summary DETERMINISTICALLY.
        # The summary is generated by rule from the metrics — NOT by an LLM.
        # A prior Grok-authored summary fabricated a "16 expired-but-active
        # members / renewal cron didn't fire" incident that did not exist
        # (30 May 2026). A generative step over a large context cannot be
        # trusted with facts Steve makes launch decisions on, and a
        # "never invent numbers" instruction does not prevent it. With a
        # deterministic generator there is no step that can invent a fact.
        ai_started = datetime.utcnow()
        summary = _deterministic_briefing(metrics, today_str)
        ai_ms = int((datetime.utcnow() - ai_started).total_seconds() * 1000)
        
        # Step 3: build the email content
        recipient = os.environ.get("DAILY_BRIEFING_EMAIL", "")
        recipient_name = os.environ.get("DAILY_BRIEFING_NAME", "Steve")
        
        # The "copy block" at the bottom — what Steve forwards to a new
        # Claude chat as the first message. Includes everything Claude
        # needs to be useful immediately.
        copy_block = (
            "═══ COPY EVERYTHING BELOW THIS LINE TO BRIEF CLAUDE ═══\n\n"
            f"Daily SuperAdPro briefing — {today_str}\n\n"
            "Please read LAUNCH_LOG.md from the repo and brief me on "
            "platform status. Today's metrics:\n\n"
            f"{metrics_text}\n\n"
            "AI summary:\n"
            f"{summary}\n"
        )
        
        from .brevo_service import send_email, wrap_email_html
        
        html_body = wrap_email_html(
            f"""
            <h2 style="font-family:Sora,sans-serif;color:#0f172a;margin:0 0 16px">
                SuperAdPro — Daily Briefing
            </h2>
            <p style="color:#64748b;font-size:13px;margin:0 0 24px">
                {today_str} · Generated by Grok at {started_at.strftime('%H:%M UTC')}
            </p>

            <div style="background:#f8fafc;border-left:4px solid #2563eb;padding:18px 22px;border-radius:8px;margin-bottom:24px">
                <div style="white-space:pre-wrap;font-family:Sora,sans-serif;color:#0f172a;line-height:1.6">{summary}</div>
            </div>

            <h3 style="font-family:Sora,sans-serif;color:#0f172a;margin:24px 0 12px;font-size:16px">
                Raw metrics
            </h3>
            <pre style="background:#0f172a;color:#cbd5e1;padding:16px;border-radius:8px;font-size:12px;line-height:1.6;overflow-x:auto;white-space:pre-wrap;font-family:'Monaco','Menlo',monospace">{metrics_text}</pre>

            <h3 style="font-family:Sora,sans-serif;color:#0f172a;margin:24px 0 12px;font-size:16px">
                Brief Claude in a new chat
            </h3>
            <p style="color:#64748b;font-size:13px;margin:0 0 12px">
                Copy the block below and paste it as your first message in a new Claude chat.
                Claude will read LAUNCH_LOG.md and have full context on today's status.
            </p>
            <pre style="background:#fef3c7;color:#0f172a;padding:16px;border-radius:8px;font-size:12px;line-height:1.6;overflow-x:auto;white-space:pre-wrap;font-family:'Monaco','Menlo',monospace;border:1px solid #fde68a">{copy_block}</pre>
            """
        )
        
        # Step 4: send the email (unless dryrun)
        email_sent = False
        if not dryrun and recipient:
            try:
                await send_email(
                    to_email=recipient,
                    to_name=recipient_name,
                    subject=f"SuperAdPro — Daily Briefing — {today_str}",
                    html_content=html_body,
                )
                email_sent = True
            except Exception as e:
                logger.error(f"[daily-briefing] Email send failed: {e}")
        
        # Step 5: persist (unless dryrun)
        briefing_id = None
        if not dryrun:
            from .database import DailyBriefing
            import json as _json
            briefing = DailyBriefing(
                briefing_date=today_str,
                metrics_json=_json.dumps(metrics, default=str),
                summary_text=summary,
                launch_log_md=launch_log if launch_log else None,
                email_sent_to=recipient if email_sent else None,
                email_sent_at=datetime.utcnow() if email_sent else None,
                generation_ms=ai_ms,
            )
            db.add(briefing)
            db.commit()
            briefing_id = briefing.id
        
        duration_ms = int((datetime.utcnow() - started_at).total_seconds() * 1000)
        logger.info(f"[CRON] daily-briefing complete: {today_str} email_sent={email_sent} duration={duration_ms}ms")
        
        return {
            "ok": True,
            "dryrun": bool(dryrun),
            "date": today_str,
            "metrics": metrics,
            "summary": summary,
            "email_sent": email_sent,
            "email_recipient": recipient if email_sent else None,
            "briefing_id": briefing_id,
            "duration_ms": duration_ms,
            "ai_generation_ms": ai_ms,
        }
    except Exception as e:
        import traceback
        logger.error(f"[daily-briefing] FAILED: {traceback.format_exc()}")
        return JSONResponse({"ok": False, "error": str(e)}, status_code=500)


@app.get("/admin/daily-briefing-status")
async def admin_daily_briefing_status(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin-auth check: did today's (and recent) daily briefings run?

    Surfaces the actual rows in `daily_briefings` so we can tell at a
    glance whether the cron is firing properly, whether the AI generation
    is working, and whether emails are being dispatched. Useful when the
    Railway cron-worker container is reporting 'deployment crashed' and
    we need to disambiguate 'cron didn't fire' from 'cron fired and the
    work succeeded but the container exited non-zero'.

    Added 26 May 2026 after the Railway cron-worker crash investigation.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from .database import DailyBriefing
    recent = db.query(DailyBriefing).order_by(
        DailyBriefing.briefing_date.desc()
    ).limit(7).all()
    today_str = datetime.utcnow().strftime("%Y-%m-%d")
    rows = []
    for b in recent:
        rows.append({
            "id": b.id,
            "briefing_date": b.briefing_date,
            "is_today": b.briefing_date == today_str,
            "email_sent_to": b.email_sent_to,
            "email_sent_at": b.email_sent_at.isoformat() + "Z" if b.email_sent_at else None,
            "generation_ms": b.generation_ms,
            "created_at": b.created_at.isoformat() + "Z" if b.created_at else None,
            "summary_preview": (b.summary_text or "")[:160],
        })
    today_ran = any(r["is_today"] for r in rows)
    return {
        "today_utc": today_str,
        "today_ran": today_ran,
        "today_emailed": next((r["email_sent_to"] for r in rows if r["is_today"]), None),
        "recent": rows,
    }


@app.get("/admin/trigger-daily-briefing")
async def admin_trigger_daily_briefing(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin-auth wrapper around /cron/daily-briefing. Lets the admin
    fire the briefing without needing to paste CRON_SECRET. Idempotent
    via the same daily_briefings UNIQUE constraint as the cron path —
    if today's briefing already ran, returns the existing row.

    Added 26 May 2026 for the cron-worker investigation.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    # Reuse the cron endpoint body. The auth gate inside expects
    # ?secret=, so we pull it from env and call internally — keeping
    # the cron's idempotency + email + DB write logic in one place.
    cron_secret = os.environ.get("CRON_SECRET", "")
    if not cron_secret:
        return JSONResponse(
            {"error": "CRON_SECRET not configured in environment"},
            status_code=500,
        )
    # Re-enter cron_daily_briefing with the correct secret. It returns
    # a dict (success) or JSONResponse (auth/error path).
    result = await cron_daily_briefing(
        request=request, secret=cron_secret, dryrun=0, db=db,
    )
    return result


@app.get("/admin/double-pay-scan")
async def admin_double_pay_scan(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Detailed inspection of any (to_user_id, from_user_id) pair that
    has more than one explicit-type sponsor commission. Mirrors the
    detection the daily briefing uses, but returns the actual rows
    rather than a count — so we can tell whether each finding is a
    real double-pay (same event paid twice) or a legitimate sequence
    (signup commission + later upgrade commission, both expected).

    Added 26 May 2026 to investigate the briefing's audit_double_pays=1
    finding when the existing admin endpoint reported 0 suspects.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from .database import Commission
    # Pull all suspect (to, from) pairs first
    suspect_pairs = db.execute(text("""
        SELECT to_user_id, from_user_id, COUNT(*) as cnt,
               SUM(amount_usdt) as total_amt
        FROM commissions
        WHERE commission_type IN (
            'membership_sponsor',
            'gift_membership_sponsor',
            'membership_upgrade_sponsor'
        )
        AND status = 'paid'
        GROUP BY to_user_id, from_user_id
        HAVING COUNT(*) > 1
        ORDER BY COUNT(*) DESC, SUM(amount_usdt) DESC
    """)).fetchall()

    findings = []
    for pair in suspect_pairs:
        # Fetch each commission for this pair so we can classify
        rows = db.query(Commission).filter(
            Commission.to_user_id == pair.to_user_id,
            Commission.from_user_id == pair.from_user_id,
            Commission.commission_type.in_([
                "membership_sponsor",
                "gift_membership_sponsor",
                "membership_upgrade_sponsor",
            ]),
            Commission.status == "paid",
        ).order_by(Commission.created_at).all()

        # Get the recipient + payer usernames for human-readable output
        recipient = db.query(User).filter(User.id == pair.to_user_id).first()
        payer = db.query(User).filter(User.id == pair.from_user_id).first()

        # Classify: if types are heterogeneous (e.g. one signup + one upgrade)
        # it's likely a legitimate sequence. If types are identical it's a
        # real duplicate.
        types_present = {r.commission_type for r in rows}
        is_real_duplicate = (len(types_present) == 1) and (len(rows) > 1)

        findings.append({
            "to_user_id": pair.to_user_id,
            "to_username": recipient.username if recipient else None,
            "from_user_id": pair.from_user_id,
            "from_username": payer.username if payer else None,
            "commission_count": int(pair.cnt),
            "total_paid": float(pair.total_amt or 0),
            "types_present": sorted(types_present),
            "verdict": ("LIKELY_DUPLICATE" if is_real_duplicate
                        else "LIKELY_LEGITIMATE_SEQUENCE"),
            "commissions": [{
                "id": r.id,
                "type": r.commission_type,
                "amount": float(r.amount_usdt or 0),
                "package_tier": r.package_tier,
                "created_at": r.created_at.isoformat() + "Z" if r.created_at else None,
                "notes": r.notes,
            } for r in rows],
        })

    return {
        "suspect_pair_count": len(suspect_pairs),
        "real_duplicate_count": sum(1 for f in findings if f["verdict"] == "LIKELY_DUPLICATE"),
        "legitimate_sequence_count": sum(1 for f in findings if f["verdict"] == "LIKELY_LEGITIMATE_SEQUENCE"),
        "findings": findings,
    }


@app.get("/admin/reverse-commission")
async def admin_reverse_commission(
    request: Request,
    commission_id: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-off admin endpoint to reverse a specific commission row.

    Critical: the wallet field debited depends on commission_type, because
    different commission types credit different fields at payment time.
    This must match the credit pattern in _activate_membership (for
    membership_sponsor) and _pay_direct_sponsor / _pay_unilevel_chain in
    grid.py (for grid commissions).

    Field map (verified 26 May 2026 from current code):
      membership_sponsor / gift_membership_sponsor /
      membership_upgrade_sponsor → balance + total_earned
      direct_sponsor (grid)      → campaign_balance + total_earned + grid_earnings
      uni_level (grid)           → campaign_balance + total_earned + level_earnings
      grid_completion_bonus      → campaign_balance + total_earned + bonus_earnings
      grid_completion_bonus_topup→ campaign_balance + total_earned + bonus_earnings

    Idempotent: re-running on an already-reversed row returns the existing
    state without re-debiting.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    if not commission_id:
        return JSONResponse({"error": "commission_id required"}, status_code=400)
    from .database import Commission as _Commission
    com = db.query(_Commission).filter(_Commission.id == commission_id).first()
    if not com:
        return JSONResponse({"error": f"Commission {commission_id} not found"}, status_code=404)
    if com.status == "reversed":
        return {
            "ok": True,
            "already_reversed": True,
            "commission_id": commission_id,
            "notes": com.notes,
        }
    if com.status != "paid":
        return JSONResponse(
            {"error": f"Commission {commission_id} has status='{com.status}', "
                      f"only 'paid' rows are reversible via this endpoint"},
            status_code=400,
        )
    recipient = db.query(User).filter(User.id == com.to_user_id).first()
    if not recipient:
        return JSONResponse({"error": f"Recipient user {com.to_user_id} not found"}, status_code=404)

    from decimal import Decimal as _Decimal
    amt = _Decimal(str(com.amount_usdt or 0))
    ctype = com.commission_type or ""

    # Snapshot full wallet state for audit
    def _snap():
        return {
            "balance":          float(getattr(recipient, "balance", 0) or 0),
            "campaign_balance": float(getattr(recipient, "campaign_balance", 0) or 0),
            "total_earned":     float(getattr(recipient, "total_earned", 0) or 0),
            "grid_earnings":    float(getattr(recipient, "grid_earnings", 0) or 0),
            "level_earnings":   float(getattr(recipient, "level_earnings", 0) or 0),
            "bonus_earnings":   float(getattr(recipient, "bonus_earnings", 0) or 0),
            "upline_earnings":  float(getattr(recipient, "upline_earnings", 0) or 0),
        }
    before = _snap()

    # Route the debit to the correct fields per commission_type
    fields_debited = []
    if ctype in ("membership_sponsor", "gift_membership_sponsor", "membership_upgrade_sponsor"):
        # Membership commissions credit balance + total_earned only
        recipient.balance      = _Decimal(str(recipient.balance or 0))      - amt
        recipient.total_earned = _Decimal(str(recipient.total_earned or 0)) - amt
        fields_debited = ["balance", "total_earned"]
    elif ctype == "direct_sponsor":
        recipient.campaign_balance = _Decimal(str(recipient.campaign_balance or 0)) - amt
        recipient.total_earned     = _Decimal(str(recipient.total_earned or 0))     - amt
        recipient.grid_earnings    = _Decimal(str(getattr(recipient, "grid_earnings", 0) or 0)) - amt
        fields_debited = ["campaign_balance", "total_earned", "grid_earnings"]
    elif ctype == "uni_level":
        recipient.campaign_balance = _Decimal(str(recipient.campaign_balance or 0)) - amt
        recipient.total_earned     = _Decimal(str(recipient.total_earned or 0))     - amt
        recipient.level_earnings   = _Decimal(str(getattr(recipient, "level_earnings", 0) or 0)) - amt
        fields_debited = ["campaign_balance", "total_earned", "level_earnings"]
    elif ctype in ("grid_completion_bonus", "grid_completion_bonus_topup"):
        recipient.campaign_balance = _Decimal(str(recipient.campaign_balance or 0)) - amt
        recipient.total_earned     = _Decimal(str(recipient.total_earned or 0))     - amt
        recipient.bonus_earnings   = _Decimal(str(getattr(recipient, "bonus_earnings", 0) or 0)) - amt
        fields_debited = ["campaign_balance", "total_earned", "bonus_earnings"]
    else:
        return JSONResponse(
            {"error": f"Unknown commission_type '{ctype}' — cannot determine "
                      f"which wallet fields to debit. Reversal aborted; "
                      f"commission row still status='paid'. Add the type to "
                      f"the reverse-commission field map if this is legitimate."},
            status_code=400,
        )

    com.status = "reversed"
    appended = (f"\n\n[REVERSED 26 May 2026 by admin {user.username}: ${float(amt):.2f} "
                f"debited from recipient ({recipient.username}) wallet fields: "
                f"{', '.join(fields_debited)}]")
    com.notes = (com.notes or "") + appended
    db.commit()
    after = _snap()
    return {
        "ok": True,
        "commission_id": commission_id,
        "recipient_id": com.to_user_id,
        "recipient_username": recipient.username,
        "commission_type": ctype,
        "amount_reversed": float(amt),
        "fields_debited": fields_debited,
        "wallet_before": before,
        "wallet_after": after,
    }


@app.get("/admin/fix-starthere-wallet")
async def admin_fix_starthere_wallet(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot correction for the starthere wallet (user 349).

    Earlier today the /admin/reverse-commission endpoint debited the
    WRONG fields when reversing commission 603 (membership_sponsor):
      - Debited campaign_balance (wrong — membership commissions credit
        balance, not campaign_balance)
      - Debited upline_earnings (wrong — membership_sponsor commissions
        don't credit upline_earnings, so this pushed it to -10)
      - Did NOT debit balance (the actual overpayment field)
      - Did correctly debit total_earned (this is the same for both
        membership and grid commissions, so leave it alone)

    Corrections this endpoint applies to user 349 (starthere):
      campaign_balance: +10  (refund our incorrect debit)
      upline_earnings:  +10  (back to 0 from -10)
      balance:         -10  (actually debit the overpayment)
      total_earned:     unchanged (correctly already -10 from current)

    Idempotent: if balance hasn't been touched yet (i.e. the broken
    reversal hasn't been corrected), runs the fix and returns
    'corrected'. If it has been run already, returns 'already_corrected'
    without re-applying.

    Pure one-shot for this specific bug. Will be removed after Steve
    confirms wallet looks right.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from decimal import Decimal as _Decimal
    target = db.query(User).filter(User.id == 349).first()
    if not target:
        return JSONResponse({"error": "User 349 (starthere) not found"}, status_code=404)

    upline = float(getattr(target, "upline_earnings", 0) or 0)
    if upline >= 0:
        # Already corrected (no negative upline_earnings = fix already ran)
        return {
            "ok": True,
            "already_corrected": True,
            "user_id": 349,
            "username": target.username,
            "current": {
                "balance":          float(getattr(target, "balance", 0) or 0),
                "campaign_balance": float(getattr(target, "campaign_balance", 0) or 0),
                "upline_earnings":  upline,
                "total_earned":     float(getattr(target, "total_earned", 0) or 0),
            },
        }

    before = {
        "balance":          float(getattr(target, "balance", 0) or 0),
        "campaign_balance": float(getattr(target, "campaign_balance", 0) or 0),
        "upline_earnings":  upline,
        "total_earned":     float(getattr(target, "total_earned", 0) or 0),
    }
    target.campaign_balance = _Decimal(str(target.campaign_balance or 0)) + _Decimal("10.00")
    target.upline_earnings  = _Decimal(str(target.upline_earnings or 0))  + _Decimal("10.00")
    target.balance          = _Decimal(str(target.balance or 0))          - _Decimal("10.00")
    db.commit()
    after = {
        "balance":          float(target.balance or 0),
        "campaign_balance": float(target.campaign_balance or 0),
        "upline_earnings":  float(target.upline_earnings or 0),
        "total_earned":     float(target.total_earned or 0),
    }
    return {
        "ok": True,
        "corrected": True,
        "user_id": 349,
        "username": target.username,
        "actions": [
            "campaign_balance += $10 (refunded incorrect debit)",
            "upline_earnings += $10 (corrected back to 0 from -10)",
            "balance -= $10 (actually debited the overpayment)",
        ],
        "wallet_before": before,
        "wallet_after": after,
    }


@app.get("/admin/nowpayments-mark-abandoned")
async def admin_nowpayments_mark_abandoned(
    request: Request,
    order_id: int = 0,
    confirm: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Mark a stuck NOWPayments order as 'abandoned' so it stops
    appearing in stuck-order monitors. Use this when the user is
    already active via another rail (Stripe, WalletConnect, balance
    upgrade, gift) and the NOWPayments order was a parallel attempt
    that never completed.

    Refuses if the user is NOT currently active for the order's
    product type — defensive guard against marking real stuck
    customers as abandoned. If a user is inactive AND has a waiting
    order, that's a stuck customer needing /admin/nowpayments-wrong-
    asset-recover, not abandonment.

    Requires ?confirm=1 to actually update. Returns preview otherwise.

    Added 26 May 2026 to clean up matcher noise from prior-session
    resolutions (e.g. jerrygoff sorted via Stripe self-healing on
    25 May has a stuck NOWPayments order from the same day).
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    if not order_id:
        return JSONResponse({"error": "order_id required"}, status_code=400)
    from .database import NowPaymentsOrder as _NPOrder
    order = db.query(_NPOrder).filter(_NPOrder.id == order_id).first()
    if not order:
        return JSONResponse({"error": f"Order {order_id} not found"}, status_code=404)
    if order.status not in ("waiting", "wrong_asset", "confirming", "pending"):
        return JSONResponse(
            {"error": f"Order {order_id} has status='{order.status}', not a "
                      f"stuck state. Refusing to abandon a terminal-state order."},
            status_code=400,
        )
    target = db.query(User).filter(User.id == order.user_id).first()
    if not target:
        return JSONResponse({"error": f"Order owner user {order.user_id} not found"}, status_code=404)

    # Defensive check: only allow abandoning if the user already has
    # the product. This is the whole reason this endpoint exists —
    # to clear noise from users who are sorted, not to mass-clear real
    # stuck customers.
    user_has_product = False
    reason = ""
    if order.product_type == "membership":
        user_has_product = bool(target.is_active)
        reason = f"User is_active={target.is_active}, tier={target.membership_tier}"
    elif order.product_type == "grid":
        # Check if they have ANY grid (any tier) — relaxed check, because
        # the typical "stuck grid order" abandonment case is a Tier 1
        # user who later bought via another rail OR who'll buy soon.
        # Strict check would block legitimate cleanup of expired attempts.
        from .database import Grid as _Grid
        grid_count = db.query(_Grid).filter(_Grid.owner_id == target.id).count()
        user_has_product = grid_count > 0
        reason = f"User has {grid_count} grid(s)"
    elif order.product_type in ("nexus", "credit_matrix"):
        # Check if they have any credit matrix purchase. Less strict —
        # abandonment is fine if they're an active member (Free → can't
        # buy nexus, so if they're active they made it past gating).
        user_has_product = bool(target.is_active)
        reason = f"User is_active={target.is_active}"
    else:
        user_has_product = bool(target.is_active)
        reason = f"Unknown product_type={order.product_type}; using is_active as proxy"

    if not user_has_product:
        return JSONResponse(
            {"error": f"REFUSED: User {target.username} does not appear to have the "
                      f"product this order was for. Marking abandoned could miss a "
                      f"real stuck customer. {reason}. If you're sure, investigate "
                      f"manually before abandoning."},
            status_code=400,
        )

    if not confirm:
        return {
            "preview": True,
            "order_id": order_id,
            "user_id": target.id,
            "username": target.username,
            "product_type": order.product_type,
            "current_status": order.status,
            "would_set_status": "abandoned",
            "user_state_check": reason,
            "instruction": "Re-call with &confirm=1 to mark abandoned.",
        }

    order.status = "abandoned"
    db.commit()
    logger.info(
        f"NOWPayments order {order_id} marked abandoned by admin {user.username} — "
        f"user {target.username} already has product ({reason})"
    )
    return {
        "ok": True,
        "order_id": order_id,
        "user_id": target.id,
        "username": target.username,
        "new_status": "abandoned",
        "user_state_check": reason,
    }


@app.get("/admin/nowpayments-orphan-matcher")
async def admin_nowpayments_orphan_matcher(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Match orphan BSC USDT transfers from the NOWPayments payout
    address against NOWPayments orders that are stuck waiting.

    Background (26 May 2026): when a user pays NOWPayments via an
    alternative network (e.g. USDT-ERC20 for a USDT-BSC invoice),
    NOWPayments converts and forwards the funds to our BSC treasury
    via their payout wallet 0xa96be652...709becd09. Our BSC scanner
    correctly notices the inbound transfer but doesn't match it to
    any WalletConnect order (because the order is in NOWPayments,
    not WalletConnect) — so it gets filed as an OnchainOrphanTransfer.

    Meanwhile the NOWPayments order is in 'wrong_asset' or 'waiting'
    state because our IPN handler rejected it (now fixed by the
    value-based guard in commit dad99cc5).

    This endpoint joins the two by amount proximity (±5% to absorb
    NOWPayments' conversion fee) and time window (NOWPayments order
    created within the same calendar day as the orphan transfer).

    Read-only. Recovery for each match is via
    /admin/nowpayments-wrong-asset-recover?order_id=N&confirm=1
    using the existing value-based recovery endpoint.

    Added 26 May 2026 after Robert Brooks case revealed this whole
    class of payments had been silently stuck.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from .database import OnchainOrphanTransfer as _Orphan, NowPaymentsOrder as _NPOrder
    NP_PAYOUT_ADDRESS = "0xa96be652a08d9905f15b7fbe2255708709becd09"
    AMOUNT_TOLERANCE = 0.06  # 6% — covers NOWPayments fee + slippage

    # Pull all unresolved orphan transfers from the NOWPayments payout address
    orphans = db.query(_Orphan).filter(
        _Orphan.from_address == NP_PAYOUT_ADDRESS,
        _Orphan.resolved == False,
    ).order_by(_Orphan.seen_at.desc()).all()

    # Pull all stuck NOWPayments orders (wrong_asset or waiting > 1h old)
    from datetime import datetime as _dt, timedelta as _td
    cutoff_old = _dt.utcnow() - _td(hours=1)
    stuck_orders = db.query(_NPOrder).filter(
        _NPOrder.status.in_(["wrong_asset", "waiting", "confirming"]),
        _NPOrder.created_at < cutoff_old,
    ).order_by(_NPOrder.created_at.desc()).all()

    matches = []
    unmatched_orphans = []
    matched_orphan_ids = set()
    matched_order_ids = set()

    # For each orphan, try to find the best matching order
    for orph in orphans:
        orph_amount = float(orph.amount_usdt or 0)
        # Dust filter — sub-cent transfers are noise, not real payments
        if orph_amount < 1.0:
            continue
        best_match = None
        best_ratio_diff = 1.0
        for o in stuck_orders:
            if o.id in matched_order_ids:
                continue
            inv = float(o.price_usd or 0)
            if inv <= 0:
                continue
            # Orphan should be within tolerance of invoice (after NP fee)
            ratio = orph_amount / inv
            ratio_diff = abs(1.0 - ratio)
            if ratio_diff > AMOUNT_TOLERANCE:
                continue
            # Time check: order created within 48h before the orphan arrival
            # (NOWPayments cross-chain conversions can take time)
            if not o.created_at or not orph.seen_at:
                continue
            time_delta = (orph.seen_at - o.created_at).total_seconds()
            if time_delta < 0 or time_delta > 172800:  # 48h
                continue
            # Better match = closer amount ratio
            if ratio_diff < best_ratio_diff:
                best_match = o
                best_ratio_diff = ratio_diff
        if best_match:
            target = db.query(User).filter(User.id == best_match.user_id).first()
            matches.append({
                "orphan_id": orph.id,
                "orphan_tx_hash": orph.tx_hash,
                "orphan_amount_usdt": orph_amount,
                "orphan_seen_at": orph.seen_at.isoformat() + "Z" if orph.seen_at else None,
                "order_id": best_match.id,
                "order_internal_id": best_match.internal_order_id,
                "order_np_payment_id": best_match.np_payment_id,
                "order_status": best_match.status,
                "invoice_usd": float(best_match.price_usd or 0),
                "value_ratio": round(orph_amount / float(best_match.price_usd or 1), 3),
                "user_id": best_match.user_id,
                "username": target.username if target else None,
                "email": target.email if target else None,
                "is_active_now": bool(target.is_active) if target else None,
                "product_type": best_match.product_type,
                "product_key": best_match.product_key,
                "order_created_at": best_match.created_at.isoformat() + "Z" if best_match.created_at else None,
                "hours_in_transit": round((orph.seen_at - best_match.created_at).total_seconds() / 3600, 1),
                "recovery_url": f"/admin/nowpayments-wrong-asset-recover?order_id={best_match.id}&confirm=1",
            })
            matched_orphan_ids.add(orph.id)
            matched_order_ids.add(best_match.id)
        else:
            unmatched_orphans.append({
                "orphan_id": orph.id,
                "tx_hash": orph.tx_hash,
                "amount_usdt": orph_amount,
                "seen_at": orph.seen_at.isoformat() + "Z" if orph.seen_at else None,
                "note": "No NOWPayments order found within amount tolerance + 48h window",
            })

    # Stuck orders with no matching orphan (e.g. customer hasn't paid yet,
    # or payment came in via a different address)
    unmatched_orders = [{
        "order_id": o.id,
        "internal_order_id": o.internal_order_id,
        "user_id": o.user_id,
        "status": o.status,
        "invoice_usd": float(o.price_usd or 0),
        "created_at": o.created_at.isoformat() + "Z" if o.created_at else None,
        "hours_stuck": round((_dt.utcnow() - o.created_at).total_seconds() / 3600, 1) if o.created_at else None,
    } for o in stuck_orders if o.id not in matched_order_ids]

    return {
        "np_payout_address": NP_PAYOUT_ADDRESS,
        "amount_tolerance_pct": AMOUNT_TOLERANCE * 100,
        "matches_found": len(matches),
        "matches": matches,
        "unmatched_orphans_from_np_count": len(unmatched_orphans),
        "unmatched_orphans_from_np": unmatched_orphans,
        "stuck_orders_with_no_matching_payment_count": len(unmatched_orders),
        "stuck_orders_with_no_matching_payment": unmatched_orders[:20],  # cap for readability
        "note": (
            "Each match is a customer who paid via NOWPayments cross-chain "
            "conversion that landed in your treasury but didn't credit their "
            "account. Recover each via the recovery_url. After recovery, the "
            "orphan should also be marked resolved (separate step — TODO)."
        ),
    }


@app.get("/admin/nowpayments-wrong-asset-sweep")
async def admin_nowpayments_wrong_asset_sweep(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Find every NOWPayments order marked 'wrong_asset' that would have
    passed the new value-based guard (delivered ≥ 95% of invoice). These
    are users wrongly rejected by the old currency-string-equality guard
    (e.g. legitimate cross-chain USDT conversions like USDTETH→USDTBSC).

    Returns each affected user with the invoice amount, actually-paid
    amount, the user state, and a one-click recovery URL.

    Caught 26 May 2026 after Robert Brooks (user 416) reported his
    $15.005681 USDT cross-chain payment was rejected.

    Read-only. Recovery is a separate endpoint requiring confirmation.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from .database import NowPaymentsOrder as _NPOrder
    UNDERPAYMENT_THRESHOLD = 0.95
    stuck = db.query(_NPOrder).filter(
        _NPOrder.status == "wrong_asset"
    ).order_by(_NPOrder.created_at.desc()).all()
    out = []
    for o in stuck:
        invoice_usd = float(o.price_usd or 0)
        delivered = float(o.actually_paid or 0)
        ratio = (delivered / invoice_usd) if invoice_usd > 0 else 0
        would_pass = ratio >= UNDERPAYMENT_THRESHOLD
        owner = db.query(User).filter(User.id == o.user_id).first() if hasattr(o, "user_id") else None
        out.append({
            "order_id": o.id,
            "internal_order_id": o.internal_order_id,
            "np_payment_id": o.np_payment_id,
            "user_id": o.user_id,
            "username": owner.username if owner else None,
            "email": owner.email if owner else None,
            "is_active_now": bool(owner.is_active) if owner else None,
            "product_type": o.product_type,
            "product_key": o.product_key,
            "price_usd": invoice_usd,
            "actually_paid_usdt": delivered,
            "pay_currency": getattr(o, "pay_currency", None),
            "outcome_currency": getattr(o, "outcome_currency", None),
            "value_ratio": round(ratio, 3),
            "would_pass_new_guard": would_pass,
            "verdict": (
                "RECOVERABLE — payment delivered full value, was wrongly rejected. "
                "Use /admin/nowpayments-wrong-asset-recover?order_id=N&confirm=1"
                if would_pass else
                "GENUINE UNDERPAYMENT — delivered less than 95% of invoice. "
                "Leave as-is (or refund via NOWPayments dashboard)."
            ),
            "created_at": o.created_at.isoformat() + "Z" if o.created_at else None,
        })
    recoverable = sum(1 for r in out if r["would_pass_new_guard"] and not r["is_active_now"])
    return {
        "total_wrong_asset_orders": len(out),
        "recoverable_count": recoverable,
        "orders": out,
        "note": (
            "Orders marked 'wrong_asset' that would have passed the new "
            "value-based guard (delivered ≥ 95% of invoice). These users "
            "paid in full but were rejected due to the old currency-string-"
            "equality guard. Recover each via "
            "/admin/nowpayments-wrong-asset-recover?order_id=N&confirm=1"
        ),
    }


@app.get("/admin/nowpayments-wrong-asset-recover")
async def admin_nowpayments_wrong_asset_recover(
    request: Request,
    order_id: int = 0,
    confirm: int = 0,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Recover a NOWPayments order wrongly rejected as 'wrong_asset' by
    the old guard. Re-validates value delivered (must be ≥ 95% of
    invoice) before activating. Routes to the correct activation engine
    based on order.product (membership / campaign tier / nexus pack).

    Safety:
      - Refuses if order is not status='wrong_asset' (no double-activation)
      - Refuses if owner is already active for the same product
      - Re-validates the value ratio (so this can't be used to bypass
        the underpayment guard for genuine scams)
      - Requires ?confirm=1; preview-only without it

    Added 26 May 2026 alongside the new value-based guard.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    if not order_id:
        return JSONResponse({"error": "order_id required"}, status_code=400)
    from .database import NowPaymentsOrder as _NPOrder
    order = db.query(_NPOrder).filter(_NPOrder.id == order_id).first()
    if not order:
        return JSONResponse({"error": f"Order {order_id} not found"}, status_code=404)
    if order.status != "wrong_asset":
        return JSONResponse(
            {"error": f"Order {order_id} has status='{order.status}', not 'wrong_asset'. "
                      f"This endpoint only recovers wrong-asset rejections."},
            status_code=400,
        )

    # Re-validate value (defence in depth — can't bypass underpayment guard)
    UNDERPAYMENT_THRESHOLD = 0.95
    invoice_usd = float(order.price_usd or 0)
    delivered = float(order.actually_paid or 0)
    ratio = (delivered / invoice_usd) if invoice_usd > 0 else 0
    if ratio < UNDERPAYMENT_THRESHOLD:
        return JSONResponse(
            {"error": f"Order delivered ${delivered:.4f} against ${invoice_usd} invoice "
                      f"(ratio={ratio:.3f} < {UNDERPAYMENT_THRESHOLD}). This is a genuine "
                      f"underpayment, not a wrongly-rejected cross-chain conversion. "
                      f"Not recovering — refund via NOWPayments dashboard if appropriate."},
            status_code=400,
        )

    target = db.query(User).filter(User.id == order.user_id).first()
    if not target:
        return JSONResponse({"error": f"Order owner user {order.user_id} not found"}, status_code=404)
    if target.is_active and order.product_type == "membership":
        return JSONResponse(
            {"error": f"User {target.username} is already active. Order may have "
                      f"been recovered via another path. Mark order finished manually."},
            status_code=400,
        )

    if not confirm:
        return {
            "preview": True,
            "order_id": order_id,
            "user_id": target.id,
            "username": target.username,
            "email": target.email,
            "product_type": order.product_type,
            "product_key": order.product_key,
            "invoice_usd": invoice_usd,
            "delivered_usdt": delivered,
            "value_ratio": round(ratio, 3),
            "value_check": "PASS (>= 95%)",
            "instruction": "Re-call with &confirm=1 to fulfil the order.",
        }

    # Confirmed — activate. Route by product_type. Currently the wrong_asset
    # guard only existed in the membership branch, but recovery should be
    # robust to other products getting the same treatment in future.
    try:
        if order.product_type == "membership":
            # product_key encodes the variant: membership_partner / membership_founder
            tier_for_activation = (
                "founding" if order.product_key and "founder" in order.product_key.lower()
                else "partner"
            )
            _activate_membership(
                db=db,
                user=target,
                tier=tier_for_activation,
                source="nowpayments-wrong-asset-recovery",
                subscription_id=None,
                is_upgrade=False,
                billing="monthly",
            )
        elif order.product_type == "grid":
            # Grid / Campaign Tier — extract tier number from product_key
            # (e.g. "grid_1" → tier 1). Same path the crypto rail uses.
            # process_tier_purchase handles: 40% direct sponsor, 6.25% × 8
            # uni-level, completion bonus pool, spillover fill into all
            # upline grids at this tier, sequential lock check.
            #
            # Caveat: process_tier_purchase will REJECT if the buyer
            # doesn't own the prerequisite tier (sequential lock rule
            # added 26 May 2026). For most stuck recoveries this is fine
            # because the customer is buying Tier 1 first, but Tier 2+
            # recoveries via this path would need their lower tiers
            # already owned. Surface the rejection clearly.
            from .grid import process_tier_purchase
            try:
                package_tier = int((order.product_key or "").split("_")[1])
            except (ValueError, IndexError):
                return JSONResponse(
                    {"error": f"Could not parse tier number from product_key "
                              f"'{order.product_key}'. Expected format 'grid_N'."},
                    status_code=400,
                )
            result = process_tier_purchase(db=db, buyer_id=target.id, package_tier=package_tier)
            if not result.get("success"):
                return JSONResponse(
                    {"error": f"Grid activation failed: {result.get('error', 'unknown')}. "
                              f"Order remains status='wrong_asset' for re-try.",
                     "result": result},
                    status_code=500,
                )
        elif order.product_type in ("nexus", "credit_matrix"):
            # Credit Nexus pack
            from .credit_matrix import purchase_credit_pack
            pack_key = order.product_key or ""
            result = purchase_credit_pack(
                db, target, pack_key,
                payment_ref=f"np_recovery_{order.np_payment_id}",
                payment_method="nowpayments",
            )
            if not result.get("success"):
                return JSONResponse(
                    {"error": f"Nexus pack activation failed: {result.get('error', 'unknown')}",
                     "result": result},
                    status_code=500,
                )
        else:
            return JSONResponse(
                {"error": f"Product type '{order.product_type}' recovery not "
                          f"implemented. Supported: membership, grid, nexus."},
                status_code=501,
            )
        # Mark order as recovered + write a Payment row for audit
        order.status = "finished"
        from .database import Payment as _Payment
        db.add(_Payment(
            from_user_id=target.id,
            amount_usdt=delivered,
            payment_type=f"nowpayments_recovery_{order.product_type}",
            tx_hash=f"np_recovery_{order.np_payment_id}",
            status="confirmed",
        ))
        db.commit()
        db.refresh(target)
        logger.warning(
            f"Wrong-asset recovery activated user {target.id} ({target.username}) "
            f"from NOWPayments order {order_id} (np_payment={order.np_payment_id}), "
            f"product_type={order.product_type}, product_key={order.product_key}, "
            f"delivered=${delivered:.4f} of ${invoice_usd}, "
            f"admin={user.username}"
        )
        return {
            "ok": True,
            "recovered": True,
            "order_id": order_id,
            "user_id": target.id,
            "username": target.username,
            "product_type": order.product_type,
            "product_key": order.product_key,
            "delivered_usdt": delivered,
            "new_state": {
                "is_active": bool(target.is_active),
                "membership_tier": target.membership_tier,
                "is_founding_member": bool(getattr(target, "is_founding_member", False)),
                "founding_spot_number": getattr(target, "founding_spot_number", None),
            },
        }
    except Exception as e:
        import traceback
        logger.exception(f"Wrong-asset recovery FAILED for order {order_id}")
        try:
            db.rollback()
        except Exception:
            pass
        return JSONResponse(
            {"error": f"Activation failed: {str(e)}", "trace": traceback.format_exc()[:2000]},
            status_code=500,
        )


@app.get("/admin/stripe-stuck-users-sweep")
async def admin_stripe_stuck_users_sweep(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Find every user who has a stripe_customer_id set but is_active=False.
    These are users who at minimum reached Stripe checkout — and possibly
    paid — but never got activated on our side. Likely victims of webhook
    handler crashes (e.g. the founder spot collision bug fixed 26 May
    2026 in commit 44d69699).

    Read-only — does not auto-recover. Shows enough info for Steve to
    triage and decide whether each needs /admin/stripe-recover-user.

    Added 26 May 2026 after Sylvia + Mary both turned out to be victims
    of the same handler crash. There may be others.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from .database import StripeCharge as _StripeCharge
    stuck = db.query(User).filter(
        User.stripe_customer_id.isnot(None),
        User.is_active == False,
    ).order_by(User.created_at.desc()).all()
    out = []
    for u in stuck:
        charges = db.query(_StripeCharge).filter(
            _StripeCharge.user_id == u.id
        ).order_by(_StripeCharge.created_at.desc()).all()
        out.append({
            "user_id": u.id,
            "username": u.username,
            "email": u.email,
            "created_at": u.created_at.isoformat() + "Z" if u.created_at else None,
            "stripe_customer_id": u.stripe_customer_id,
            "stripe_subscription_id": getattr(u, "stripe_subscription_id", None),
            "membership_tier": u.membership_tier,
            "stripe_charges_count": len(charges),
            "stripe_charges_total_cents": sum(c.amount_cents or 0 for c in charges),
            "verdict": (
                "HAS CHARGES — likely paid but stuck. Verify in Stripe Dashboard, "
                "then run /admin/stripe-recover-user."
                if charges else
                "NO CHARGES — reached checkout but may not have paid. Verify in "
                "Stripe Dashboard by customer ID before recovering."
            ),
            "recovery_url": (
                f"/admin/stripe-recover-user/{u.id}?tier=founding&amount_cents=1500"
            ),
        })
    return {
        "stuck_count": len(out),
        "stuck_users": out,
        "note": (
            "These users have stripe_customer_id set but is_active=False. "
            "At minimum they reached Stripe checkout. Cross-reference with "
            "Stripe Dashboard before recovering — some may have abandoned "
            "checkout without paying."
        ),
    }


@app.get("/admin/founder-spots-audit")
async def admin_founder_spots_audit(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Inspect the current state of founder spot allocation.

    Returns: total active founders, max spot number taken, gaps in the
    spot sequence, and any users with founding_spot_number set but
    is_founding_member=False (orphaned spot numbers — the cause of the
    Sylvia Douna activation failure on 26 May 2026).

    Added 26 May 2026 after the COUNT+1 vs MAX+1 allocation bug surfaced.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    active_count = db.execute(text(
        "SELECT COUNT(*) AS c FROM users WHERE is_founding_member = TRUE"
    )).scalar() or 0

    max_spot = db.execute(text(
        "SELECT COALESCE(MAX(founding_spot_number), 0) AS m "
        "FROM users WHERE founding_spot_number IS NOT NULL"
    )).scalar() or 0

    # All users with a spot number assigned, ordered
    all_spots = db.execute(text(
        "SELECT id, username, founding_spot_number, is_founding_member, "
        "       is_active, membership_tier, created_at "
        "FROM users WHERE founding_spot_number IS NOT NULL "
        "ORDER BY founding_spot_number"
    )).fetchall()

    spot_numbers = [r.founding_spot_number for r in all_spots]
    # Gaps: which numbers between 1 and max_spot are NOT in spot_numbers
    gaps = [n for n in range(1, int(max_spot) + 1) if n not in spot_numbers]
    # Orphans: spot number set but is_founding_member is False
    orphans = [{
        "user_id": r.id,
        "username": r.username,
        "founding_spot_number": r.founding_spot_number,
        "is_active": bool(r.is_active),
        "membership_tier": r.membership_tier,
        "created_at": r.created_at.isoformat() + "Z" if r.created_at else None,
    } for r in all_spots if not r.is_founding_member]

    return {
        "active_founder_count": int(active_count),
        "max_spot_taken": int(max_spot),
        "next_spot_to_assign": int(max_spot) + 1 if int(max_spot) < 100 else None,
        "spots_remaining": max(0, 100 - int(max_spot)),
        "discrepancy": int(max_spot) - int(active_count),
        "gaps_in_sequence": gaps,
        "orphans_count": len(orphans),
        "orphans": orphans,
        "all_spots_count": len(all_spots),
    }


@app.get("/admin/stripe-user-debug")
async def admin_stripe_user_debug(
    request: Request,
    user_id: int = 0,
    username: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only diagnostic for 'Stripe customer says they paid but
    their account isn't active.' Shows the user's full Stripe state:
    customer_id, subscription_id, all StripeCharge rows, all Payment
    rows. Lets us see whether Stripe webhooks ever reached us, and if
    so what happened.

    Either user_id or username can be passed.

    Added 26 May 2026 for the Sylvia Douna / Mary cases (similar to
    jerrygoff on 25 May): Stripe charged the customer but neither
    checkout.session.completed nor invoice.paid arrived/processed, so
    the user is stuck inactive with no Payment row.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from .database import StripeCharge as _StripeCharge, Payment as _Payment
    if user_id:
        target = db.query(User).filter(User.id == user_id).first()
    elif username:
        target = db.query(User).filter(User.username == username).first()
    else:
        return JSONResponse({"error": "Pass user_id or username"}, status_code=400)
    if not target:
        return JSONResponse({"error": "User not found"}, status_code=404)

    # Pull all StripeCharge rows for this user
    charges = db.query(_StripeCharge).filter(
        _StripeCharge.user_id == target.id
    ).order_by(_StripeCharge.created_at.desc()).all()
    charge_rows = [{
        "id": c.id,
        "kind": c.kind,
        "product": c.product,
        "amount_cents": c.amount_cents,
        "currency": c.currency,
        "stripe_charge_id": c.stripe_charge_id,
        "stripe_payment_intent_id": c.stripe_payment_intent_id,
        "stripe_subscription_id": c.stripe_subscription_id,
        "stripe_session_id": c.stripe_session_id,
        "description": c.description,
        "created_at": c.created_at.isoformat() + "Z" if c.created_at else None,
    } for c in charges]

    # Pull all Payment rows for this user. Payment uses from_user_id
    # (not user_id) — the schema treats payments as a transfer with a
    # FROM (payer) and optional TO (recipient, e.g. for P2P).
    payments = db.query(_Payment).filter(
        _Payment.from_user_id == target.id
    ).order_by(_Payment.created_at.desc()).limit(20).all()
    payment_rows = [{
        "id": p.id,
        "payment_type": p.payment_type,
        "amount_usdt": float(p.amount_usdt or 0),
        "tx_hash": p.tx_hash,
        "status": p.status,
        "created_at": p.created_at.isoformat() + "Z" if p.created_at else None,
    } for p in payments]

    # Diagnostic summary
    diagnosis = []
    if not target.stripe_customer_id:
        diagnosis.append("NO STRIPE CUSTOMER ID — user never reached Stripe checkout, "
                         "or customer was created but the webhook didn't write it back. "
                         "Lookup in Stripe Dashboard by email may show a customer record.")
    if target.stripe_customer_id and not charge_rows:
        diagnosis.append("HAS STRIPE CUSTOMER ID BUT NO CHARGE ROWS — "
                         "checkout.session.completed never reached our webhook. "
                         "This is the jerrygoff/sylvia/mary failure mode. The "
                         "self-healing invoice.paid branch (25 May, 4fbc88c) "
                         "would normally cover this, but only if invoice.paid "
                         "itself arrived. If neither arrived, manual recovery "
                         "via /admin/stripe-recover-user/{user_id} is needed.")
    if charge_rows and not target.is_active:
        diagnosis.append("HAS CHARGE ROWS BUT NOT ACTIVE — webhook arrived "
                         "and wrote the charge but _activate_membership failed "
                         "or wasn't called. Check Railway logs for the user_id "
                         "at the charge's created_at timestamp.")
    if target.is_active and charge_rows:
        diagnosis.append("ACTIVE WITH CHARGE ROWS — looks healthy. If user "
                         "reports otherwise, check they're looking at the "
                         "correct account.")

    return {
        "user": {
            "id": target.id,
            "username": target.username,
            "email": target.email,
            "is_active": bool(target.is_active),
            "membership_tier": target.membership_tier,
            "is_founding_member": bool(getattr(target, "is_founding_member", False)),
            "stripe_customer_id": target.stripe_customer_id,
            "stripe_subscription_id": getattr(target, "stripe_subscription_id", None),
            "activated_at": target.activated_at.isoformat() + "Z" if target.activated_at else None,
            "created_at": target.created_at.isoformat() + "Z" if target.created_at else None,
        },
        "stripe_charges_count": len(charge_rows),
        "stripe_charges": charge_rows,
        "payments_count": len(payment_rows),
        "payments": payment_rows,
        "diagnosis": diagnosis,
        "recovery_url_template": (
            "/admin/stripe-recover-user/{user_id}?tier=founding&amount_cents=1500 "
            "(or tier=partner&amount_cents=2000)"
        ),
    }


@app.get("/cron/stuck-lapsed-alert")
async def cron_stuck_lapsed_alert(
    request: Request,
    secret: str = "",
    dryrun: int = 0,
    db: Session = Depends(get_db),
):
    """Hourly check: any users in stuck-lapsed state we haven't already
    alerted on? If yes, email Steve with the list and stamp their
    stuck_lapsed_alerted_at so we don't re-alert.

    Same detection criteria as /admin/api/stuck-lapsed-members:
        is_active=False
        AND has a future MembershipRenewal.next_renewal_date
        AND not in grace period
        AND has at least one paid membership Payment

    On reactivation via /admin/api/reactivate-stuck-lapsed, the flag is
    cleared so the user is eligible to alert again if they re-stick.

    Auth: ?secret=<CRON_SECRET>
    Dryrun: ?dryrun=1 — detects but doesn't email or stamp.

    Built 10 May 2026 to complement the daily briefing — that runs once
    a day and would miss a stuck-lapsed user who appears between briefings.
    """
    from fastapi.responses import JSONResponse
    cron_secret = os.environ.get("CRON_SECRET", "")
    if not cron_secret or secret != cron_secret:
        return JSONResponse({"error": "Unauthorised"}, status_code=401)

    started_at = datetime.utcnow()

    try:
        from .database import MembershipRenewal
        now = datetime.utcnow()

        # Same query as /admin/api/stuck-lapsed-members but filtered to
        # users we haven't already alerted on this stuck-cycle.
        candidates = (
            db.query(User, MembershipRenewal)
              .join(MembershipRenewal, MembershipRenewal.user_id == User.id)
              .filter(
                  User.is_active == False,
                  User.stuck_lapsed_alerted_at.is_(None),
                  MembershipRenewal.next_renewal_date > now,
                  MembershipRenewal.in_grace_period == False,
              )
              .all()
        )

        new_stuck = []
        for u, r in candidates:
            has_paid_payment = db.query(Payment).filter(
                Payment.from_user_id == u.id,
                Payment.payment_type.like("membership%"),
                Payment.status.in_(["confirmed", "paid"]),
            ).first()
            if not has_paid_payment:
                continue

            new_stuck.append({
                "user_id": u.id,
                "username": u.username,
                "first_name": u.first_name or "",
                "membership_tier": u.membership_tier,
                "next_renewal_date": r.next_renewal_date.isoformat(),
                "user_obj": u,
            })

        if not new_stuck:
            return {
                "ok": True,
                "new_stuck_count": 0,
                "checked_at": now.isoformat(),
            }

        # Build the alert email
        rows_html = ""
        for s in new_stuck:
            rows_html += (
                f"<tr>"
                f"<td style='padding:8px 12px;border-bottom:1px solid #e2e8f0;font-family:Sora,sans-serif'>{s['username']}</td>"
                f"<td style='padding:8px 12px;border-bottom:1px solid #e2e8f0;font-family:Sora,sans-serif'>{s['first_name']}</td>"
                f"<td style='padding:8px 12px;border-bottom:1px solid #e2e8f0;font-family:Sora,sans-serif'>Tier {s['membership_tier']}</td>"
                f"<td style='padding:8px 12px;border-bottom:1px solid #e2e8f0;font-family:Sora,sans-serif;color:#64748b;font-size:12px'>{s['next_renewal_date'][:10]}</td>"
                f"</tr>"
            )

        recipient = os.environ.get("DAILY_BRIEFING_EMAIL", "")
        recipient_name = os.environ.get("DAILY_BRIEFING_NAME", "Steve")
        email_sent = False

        if recipient and not dryrun:
            try:
                from .brevo_service import send_email, wrap_email_html
                html_body = wrap_email_html(
                    f"""
                    <h2 style="font-family:Sora,sans-serif;color:#0f172a;margin:0 0 8px">
                        ⚠️  Stuck-lapsed user{'s' if len(new_stuck) > 1 else ''} detected
                    </h2>
                    <p style="color:#64748b;font-size:13px;margin:0 0 24px">
                        {now.strftime('%Y-%m-%d %H:%M UTC')} — {len(new_stuck)} new
                    </p>

                    <p style="color:#0f172a;font-family:Sora,sans-serif;line-height:1.6;margin:0 0 16px">
                        The following member{'s have' if len(new_stuck) > 1 else ' has'} appeared as
                        <strong>stuck-lapsed</strong> — paid membership, intact renewal data, but
                        flagged inactive. They cannot use the platform until reactivated.
                    </p>

                    <table style="border-collapse:collapse;width:100%;margin:0 0 24px;border:1px solid #e2e8f0;border-radius:8px;overflow:hidden">
                        <thead>
                            <tr style="background:#f8fafc">
                                <th style="padding:10px 12px;text-align:left;font-family:Sora,sans-serif;font-size:13px;color:#475569">Username</th>
                                <th style="padding:10px 12px;text-align:left;font-family:Sora,sans-serif;font-size:13px;color:#475569">Name</th>
                                <th style="padding:10px 12px;text-align:left;font-family:Sora,sans-serif;font-size:13px;color:#475569">Tier</th>
                                <th style="padding:10px 12px;text-align:left;font-family:Sora,sans-serif;font-size:13px;color:#475569">Renews</th>
                            </tr>
                        </thead>
                        <tbody>{rows_html}</tbody>
                    </table>

                    <p style="color:#0f172a;font-family:Sora,sans-serif;line-height:1.6;margin:0 0 16px">
                        <strong>To investigate:</strong>
                        <a href="https://www.superadpro.com/admin/api/stuck-lapsed-members" style="color:#2563eb">/admin/api/stuck-lapsed-members</a>
                    </p>

                    <p style="color:#0f172a;font-family:Sora,sans-serif;line-height:1.6;margin:0 0 16px">
                        <strong>To reactivate (POST):</strong>
                        <code style="background:#f1f5f9;padding:2px 6px;border-radius:4px;font-size:12px">POST /admin/api/reactivate-stuck-lapsed</code>
                        — add <code>?dry_run=1</code> first to preview.
                    </p>

                    <p style="color:#64748b;font-size:12px;margin:24px 0 0">
                        You'll only get this email once per stuck user. If they're reactivated
                        and then re-stick, you'll be alerted again.
                    </p>
                    """
                )
                await send_email(
                    to_email=recipient,
                    to_name=recipient_name,
                    subject=f"⚠️  SuperAdPro — {len(new_stuck)} stuck-lapsed user{'s' if len(new_stuck) > 1 else ''}",
                    html_content=html_body,
                )
                email_sent = True
            except Exception as e:
                logger.error(f"[stuck-lapsed-alert] Email send failed: {e}")

        # Stamp the users so we don't re-alert next hour (only if email
        # actually sent — if email failed, leave flag null so we retry)
        stamped_ids = []
        if email_sent and not dryrun:
            for s in new_stuck:
                s["user_obj"].stuck_lapsed_alerted_at = now
                stamped_ids.append(s["user_id"])
            db.commit()

        duration_ms = int((datetime.utcnow() - started_at).total_seconds() * 1000)
        logger.info(
            f"[CRON] stuck-lapsed-alert: {len(new_stuck)} new, email_sent={email_sent}, "
            f"stamped={len(stamped_ids)}, duration={duration_ms}ms"
        )

        return {
            "ok": True,
            "dryrun": bool(dryrun),
            "new_stuck_count": len(new_stuck),
            "stuck_users": [
                {k: v for k, v in s.items() if k != "user_obj"}
                for s in new_stuck
            ],
            "email_sent": email_sent,
            "email_recipient": recipient if email_sent else None,
            "stamped_count": len(stamped_ids),
            "duration_ms": duration_ms,
        }
    except Exception as e:
        import traceback
        logger.error(f"[stuck-lapsed-alert] FAILED: {traceback.format_exc()}")
        return JSONResponse({"ok": False, "error": str(e)}, status_code=500)


@app.post("/api/command-centre/nudge-lapsed")
async def api_command_centre_nudge_lapsed(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Sponsor manual trigger: send a re-engagement notification to a
    specific lapsed direct. Body: { "member_id": <int> }. The member
    must be a direct referral of the requesting user AND currently
    lapsed (is_active=False with confirmed payment history)."""
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request body"}, status_code=400)
    member_id = body.get("member_id")
    if not isinstance(member_id, int):
        return JSONResponse({"error": "member_id required"}, status_code=400)

    # Validate: target must be a direct referral of requesting user
    target = db.query(User).filter(User.id == member_id, User.sponsor_id == user.id).first()
    if not target:
        # Privacy-safe error — don't tell sponsors whether the user exists at all,
        # only whether they're allowed to nudge them.
        return JSONResponse({"error": "Not your direct referral"}, status_code=403)

    # Validate: target must be currently lapsed
    if target.is_active:
        return JSONResponse({"error": "This member is currently active — no nudge needed"}, status_code=400)
    has_paid = db.query(Payment).filter(
        Payment.from_user_id == target.id,
        Payment.payment_type.like("membership%"),
        Payment.status.in_(["confirmed", "paid"]),
    ).first() is not None
    if not has_paid:
        # Never-paid users are a different bucket, different copy probably needed.
        # For now, decline rather than send the wrong message.
        return JSONResponse({"error": "This member has never paid — re-engagement notification only applies to lapsed members"}, status_code=400)

    created = _create_reengagement_notification(db, target.id)
    db.commit()
    return {
        "ok": True,
        "created": created,
        "already_pending": not created,
    }


