@app.get("/admin/security-audit")
def security_audit(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """READ-ONLY incident audit. Surfaces full blast radius of the
    activate-owner privilege-escalation: every admin account, every
    account carrying the owner-tN/owner-membership payment fingerprint,
    all accounts created today, balance anomalies, and — critically —
    every withdrawal in the last 48h (the 'did real money leave' check).
    Pure SELECTs; mutates nothing."""
    from fastapi.responses import JSONResponse
    _require_admin(user)
    try:
        from decimal import Decimal as _Dec
        def _safe(v):
            if isinstance(v, datetime):
                return v.isoformat() + "Z"
            if isinstance(v, _Dec):
                return float(v)
            return v
        def rows(sql):
            res = db.execute(text(sql))
            cols = list(res.keys())
            return [{c: _safe(v) for c, v in zip(cols, r)} for r in res.fetchall()]

        admins = rows("""
            SELECT id, username, email, is_active, is_admin,
                   balance, campaign_balance, created_at
            FROM users WHERE is_admin = true ORDER BY id""")

        fingerprint_payments = rows("""
            SELECT id, from_user_id, amount_usdt, payment_type, tx_hash,
                   status, created_at
            FROM payments
            WHERE tx_hash LIKE 'owner-%'
            ORDER BY created_at DESC LIMIT 200""")

        created_today = rows("""
            SELECT id, username, email, is_admin, is_active, balance,
                   campaign_balance, created_at
            FROM users WHERE created_at >= CURRENT_DATE ORDER BY id""")

        nonzero_balance_today = rows("""
            SELECT id, username, balance, campaign_balance, created_at
            FROM users
            WHERE created_at >= CURRENT_DATE
              AND (COALESCE(balance,0) > 0 OR COALESCE(campaign_balance,0) > 0)
            ORDER BY balance DESC""")

        # THE money-out check: any outgoing withdrawal in the last 48h.
        withdrawals_recent = rows("""
            SELECT id, user_id, amount_usdt, wallet_address, network,
                   tx_hash, status, requested_at, processed_at
            FROM withdrawals
            WHERE requested_at >= NOW() - INTERVAL '48 hours'
            ORDER BY requested_at DESC""")

        commissions_today = rows("""
            SELECT id, from_user_id, to_user_id, amount_usdt,
                   commission_type, status, created_at
            FROM commissions
            WHERE created_at >= CURRENT_DATE
            ORDER BY created_at DESC LIMIT 200""")

        return JSONResponse({
            "generated_at": datetime.utcnow().isoformat() + "Z",
            "summary": {
                "admin_accounts": len(admins),
                "fingerprint_payments": len(fingerprint_payments),
                "accounts_created_today": len(created_today),
                "nonzero_balance_created_today": len(nonzero_balance_today),
                "withdrawals_last_48h": len(withdrawals_recent),
                "withdrawals_paid_last_48h": sum(
                    1 for w in withdrawals_recent if w.get("status") == "paid"),
                "commissions_created_today": len(commissions_today),
            },
            "admin_accounts": admins,
            "withdrawals_last_48h": withdrawals_recent,
            "nonzero_balance_created_today": nonzero_balance_today,
            "accounts_created_today": created_today,
            "fingerprint_payments": fingerprint_payments,
            "commissions_created_today": commissions_today,
        }, status_code=200)
    except Exception as e:
        return JSONResponse({"error": str(e)}, status_code=500)

@app.get("/admin/incident-cleanup")
def incident_cleanup(confirm: str = "", user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Neutralise the 2026-06-03 attacker accounts. REVERSIBLE: uses
    status flags / deactivation, never deletes. Leaves real members,
    paid withdrawals (evidence), grid structure, and user 1 untouched.
    Requires &confirm=YES."""
    _require_admin(user)
    ATTACKER = [667, 668, 669, 670, 673, 674]
    ids = ",".join(str(i) for i in ATTACKER)
    if confirm != "YES":
        return JSONResponse({"error": f"Pass &confirm=YES to execute. Will neutralise accounts {ids}."}, status_code=400)
    try:
        before = [dict(r._mapping) for r in db.execute(text(
            f"SELECT id, username, is_admin, is_active, balance, campaign_balance FROM users WHERE id IN ({ids})"))]
        r1 = db.execute(text(
            f"UPDATE users SET is_admin=false, is_active=false, balance=0, campaign_balance=0 WHERE id IN ({ids})"))
        r2 = db.execute(text(
            f"UPDATE payments SET status='voided_incident_20260603' WHERE from_user_id IN ({ids}) AND tx_hash LIKE 'owner-%'"))
        r3 = db.execute(text(
            f"UPDATE commissions SET status='reversed_incident_20260603' WHERE from_user_id IN ({ids}) AND commission_type='admin_adjustment' AND created_at >= CURRENT_DATE"))
        db.commit()
        gp = db.execute(text(f"SELECT count(*) FROM grid_positions WHERE user_id IN ({ids})")).scalar()
        admins_after = [dict(r._mapping) for r in db.execute(text(
            "SELECT id, username FROM users WHERE is_admin = true ORDER BY id"))]
        active_attacker = db.execute(text(
            f"SELECT count(*) FROM users WHERE id IN ({ids}) AND (is_active=true OR is_admin=true)")).scalar()
        return JSONResponse({
            "status": "cleanup_complete",
            "attacker_ids": ATTACKER,
            "before": before,
            "accounts_neutralised": r1.rowcount,
            "fake_payments_voided": r2.rowcount,
            "attacker_commissions_reversed": r3.rowcount,
            "attacker_grid_positions_remaining": gp,
            "attacker_accounts_still_active_or_admin": active_attacker,
            "admins_after_should_be_only_user_1": admins_after,
            "untouched": "real members (650-666,671,672), paid withdrawals (evidence), grid structure, user 1",
        }, status_code=200)
    except Exception as e:
        db.rollback()
        return JSONResponse({"error": str(e)}, status_code=500)


