# ═══════════════════════════════════════════════════════════════════════
# Public video share system — PHASE 1 (Jul 2026, Steve)
# ═══════════════════════════════════════════════════════════════════════
# Members share ONE public link (/w/{token}); the page shows a rotating set
# of admin-approved campaigns, so a single weekly share stays evergreen.
#
# PHASE 1 IS TRACKING ONLY — none of this gates commission yet. Phase 2 adds
# share_qualified() once real data shows what an honest share actually
# produces, so the threshold is set from evidence, not a guess. Members are
# told this up-front (Steve: "make it clear... so nobody is surprised").

SHARE_PAGE_SLOTS   = 8    # videos shown per share page
SHARE_VIEW_SECONDS = 30   # watch time before a view counts — matches YouTube's
                          # view standard, so our CPM stays defensible.


def _share_fingerprint(request: Request) -> str:
    """Salted hash of IP + user-agent. Never store a raw IP: we only need it
    for dedup and rate limiting, so hashing keeps this table free of personal
    data while doing the same job."""
    import hashlib
    ip = (request.headers.get("x-forwarded-for") or
          (request.client.host if request.client else "") or "").split(",")[0].strip()
    ua = (request.headers.get("user-agent") or "")[:200]
    salt = os.environ.get("SECRET_KEY", "al-share")
    return hashlib.sha256(f"{salt}|{ip}|{ua}".encode()).hexdigest()


def _looks_like_bot(request: Request) -> bool:
    ua = (request.headers.get("user-agent") or "").lower()
    if not ua:
        return True
    return any(sig in ua for sig in (
        "bot", "crawler", "spider", "headless", "phantom", "puppeteer",
        "playwright", "selenium", "curl/", "wget", "python-requests", "scrapy",
    ))


def _get_or_create_share_link(db: Session, user: User) -> ShareLink:
    link = db.query(ShareLink).filter(ShareLink.user_id == user.id).first()
    if link:
        return link
    import secrets
    for _ in range(5):
        token = secrets.token_urlsafe(9)[:12]
        if not db.query(ShareLink.id).filter(ShareLink.token == token).first():
            link = ShareLink(user_id=user.id, token=token)
            db.add(link)
            db.commit()
            db.refresh(link)
            return link
    raise HTTPException(status_code=500, detail="Could not allocate share token")


def _rotate_share_campaigns(db: Session, exclude_user_id=None):
    """Pick the campaigns for one page render, weighted by pack level.

    A $1,000 advertiser bought ~160x the views of a $10 one, so they must
    appear proportionally more often — otherwise big advertisers quietly
    subsidise small ones and stop buying. Weight by owner_tier and starve
    campaigns that have already hit their target.
    """
    import random
    q = (db.query(VideoCampaign)
           .filter(VideoCampaign.status == "active",
                   VideoCampaign.share_approved.is_(True),
                   VideoCampaign.is_completed == False))
    if exclude_user_id:
        q = q.filter(VideoCampaign.user_id != exclude_user_id)
    pool = q.limit(400).all()
    if not pool:
        return []
    weights = []
    for c in pool:
        w = float(max(1, (c.owner_tier or 1))) ** 1.5      # bigger pack → more airtime
        w *= 1.0 + 0.5 * float(c.priority_level or 0)      # paid priority
        if c.is_featured:
            w *= 1.5
        target, done = int(c.views_target or 0), int(c.views_delivered or 0)
        if target > 0:
            w *= max(0.15, 1.0 - (done / float(target)))   # near-complete → less airtime
        weights.append(max(w, 0.01))
    picks, seen = [], set()
    for _ in range(min(SHARE_PAGE_SLOTS * 4, len(pool) * 3)):
        if len(picks) >= min(SHARE_PAGE_SLOTS, len(pool)):
            break
        c = random.choices(pool, weights=weights, k=1)[0]
        if c.id in seen:
            continue
        seen.add(c.id)
        picks.append(c)
    return picks


@app.get("/api/share/my-link")
def api_share_my_link(request: Request, user: User = Depends(get_current_user),
                      db: Session = Depends(get_db)):
    """The member's own share link + this week's sharing status (Phase 1:
    informational only — it does not affect commission yet)."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    link = _get_or_create_share_link(db, user)
    week_start = (datetime.utcnow() - timedelta(days=datetime.utcnow().weekday())).replace(
        hour=0, minute=0, second=0, microsecond=0)
    views_this_week = (db.query(func.count(ShareView.id))
                       .filter(ShareView.share_link_id == link.id,
                               ShareView.is_verified == True,
                               ShareView.is_self == False,
                               ShareView.verified_at >= week_start).scalar()) or 0
    shared_this_week = bool(link.last_shared_at and link.last_shared_at >= week_start)
    return {
        "token": link.token,
        "url": f"/w/{link.token}",
        "shared_this_week": shared_this_week,
        "last_shared_at": link.last_shared_at.isoformat() if link.last_shared_at else None,
        "verified_views_this_week": int(views_this_week),
        "share_count": int(link.share_count or 0),
        # Phase 1 honesty — surfaced in the UI so nobody is blindsided later.
        "phase": 1,
        "gates_commission": False,
        "notice": ("Sharing doesn't affect your commission yet. It will in a later "
                   "release — we're measuring real sharing first so the required "
                   "number is fair, and we'll tell you before it changes."),
    }


@app.post("/api/share/mark-shared")
def api_share_mark_shared(user: User = Depends(get_current_user),
                          db: Session = Depends(get_db)):
    """Member reports that they've posted their link. Recorded for analytics
    ONLY — deliberately NOT proof of sharing, because a button click is
    trivially faked. Qualification (Phase 2) reads verified public views."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    link = _get_or_create_share_link(db, user)
    link.last_shared_at = datetime.utcnow()
    link.share_count = (link.share_count or 0) + 1
    db.commit()
    return {"ok": True, "url": f"/w/{link.token}", "share_count": link.share_count}


@app.get("/api/share/{token}/page")
def api_share_page_data(token: str, db: Session = Depends(get_db)):
    """PUBLIC — the rotating video set for a share page. No auth: this is the
    first non-gated campaign surface, which is the entire point."""
    link = db.query(ShareLink).filter(ShareLink.token == token,
                                      ShareLink.is_active == True).first()
    if not link:
        return JSONResponse({"error": "Share page not found"}, status_code=404)
    sharer = db.query(User).filter(User.id == link.user_id).first()
    campaigns = _rotate_share_campaigns(db, exclude_user_id=link.user_id)
    return {
        "sharer": {"username": sharer.username if sharer else "a member"},
        "videos": [{
            "id": c.id,
            "title": c.title,
            "advertiser": (c.category or "Advertiser"),
            "embed_url": c.embed_url,
            "platform": c.platform,
            "cta_url": f"/campaign-cta/{c.id}" if c.cta_url else None,
        } for c in campaigns],
        "view_seconds": SHARE_VIEW_SECONDS,
    }


@app.post("/api/share/{token}/view-start")
@limiter.limit("40/minute")
async def api_share_view_start(token: str, request: Request, db: Session = Depends(get_db)):
    """PUBLIC — playback started. Creates the unverified start row that
    /view-complete checks against, mirroring the member watch anti-cheat:
    without a start row you cannot curl your way to a counted view."""
    link = db.query(ShareLink).filter(ShareLink.token == token,
                                      ShareLink.is_active == True).first()
    if not link:
        return JSONResponse({"error": "Not found"}, status_code=404)
    if _looks_like_bot(request):
        return {"ok": True, "tracked": False}
    body = await request.json()
    campaign_id = body.get("campaign_id")
    campaign = db.query(VideoCampaign).filter(VideoCampaign.id == campaign_id).first()
    if not campaign or not campaign.share_approved:
        return JSONResponse({"error": "Video not available"}, status_code=404)

    fp = _share_fingerprint(request)
    today = datetime.utcnow().strftime("%Y-%m-%d")
    # Dedup: one counted view per fingerprint per campaign per day.
    existing = (db.query(ShareView)
                .filter(ShareView.fingerprint == fp,
                        ShareView.campaign_id == campaign_id,
                        ShareView.view_date == today).first())
    if existing:
        return {"ok": True, "tracked": False, "reason": "already_viewed_today"}
    row = ShareView(share_link_id=link.id, campaign_id=campaign_id, fingerprint=fp,
                    view_date=today, started_at=datetime.utcnow())
    db.add(row)
    db.commit()
    return {"ok": True, "tracked": True, "view_id": row.id}


@app.post("/api/share/{token}/view-complete")
@limiter.limit("40/minute")
async def api_share_view_complete(token: str, request: Request, db: Session = Depends(get_db)):
    """PUBLIC — 30s reached. Verifies server-side that 30 real seconds elapsed
    since the start row; a script that posts both calls instantly is rejected."""
    body = await request.json()
    view_id = body.get("view_id")
    row = db.query(ShareView).filter(ShareView.id == view_id).first()
    if not row or row.is_verified:
        return {"ok": True, "verified": False}
    elapsed = (datetime.utcnow() - row.started_at).total_seconds()
    if elapsed < SHARE_VIEW_SECONDS - 2:          # 2s tolerance for clock/network skew
        return {"ok": True, "verified": False, "reason": "too_fast"}
    if _share_fingerprint(request) != row.fingerprint:
        return {"ok": True, "verified": False, "reason": "fingerprint_mismatch"}

    row.is_verified   = True
    row.verified_at   = datetime.utcnow()
    row.watched_secs  = int(min(elapsed, 3600))
    # Credit the advertiser's delivery — this is what they actually bought.
    db.query(VideoCampaign).filter(VideoCampaign.id == row.campaign_id).update(
        {VideoCampaign.views_delivered: (VideoCampaign.views_delivered or 0) + 1},
        synchronize_session=False)
    db.commit()
    return {"ok": True, "verified": True}


@app.get("/w/{token}")
def public_share_page(token: str, db: Session = Depends(get_db)):
    """PUBLIC share page shell — the SPA renders it from /api/share/{token}/page.

    We inject per-share Open Graph tags server-side. Facebook/X/WhatsApp fetch
    this URL with a scraper that does NOT run JavaScript, so whatever is in the
    static shell is what gets posted — the SPA's own <title> never reaches them.
    Without this, every share posted the shell's generic card. Naming the sharer
    also lifts click-through: a link from a person beats a link from a brand.
    """
    if not _react_index.exists():
        return RedirectResponse(url="/", status_code=302)

    sharer = None
    link = db.query(ShareLink).filter(ShareLink.token == token,
                                      ShareLink.is_active == True).first()
    if link:
        sharer = db.query(User.username).filter(User.id == link.user_id).scalar()

    base = os.environ.get("PUBLIC_BASE_URL", "https://www.advantagelife.club").rstrip("/")
    title = (f"{sharer}'s video showcase" if sharer else "This week's video showcase")
    desc = ("Videos from independent creators and businesses — watch whatever "
            "interests you. Updated continuously.")
    img = f"{base}/static/images/al-hero-bg.jpg"
    url = f"{base}/w/{token}"

    def esc(v: str) -> str:
        return (v.replace("&", "&amp;").replace("<", "&lt;")
                 .replace(">", "&gt;").replace('"', "&quot;"))

    og = (
        f'<meta property="og:site_name" content="AdvantageLife">'
        f'<meta property="og:type" content="website">'
        f'<meta property="og:title" content="{esc(title)}">'
        f'<meta property="og:description" content="{esc(desc)}">'
        f'<meta property="og:url" content="{esc(url)}">'
        f'<meta property="og:image" content="{esc(img)}">'
        f'<meta name="twitter:card" content="summary_large_image">'
        f'<meta name="twitter:title" content="{esc(title)}">'
        f'<meta name="twitter:description" content="{esc(desc)}">'
        f'<meta name="twitter:image" content="{esc(img)}">'
    )
    try:
        html = _react_index.read_text(encoding="utf-8")
        # Drop the shell's default OG/twitter tags so the scraper can't pick the
        # generic ones ahead of these, then inject the share-specific set.
        html = re.sub(r'<meta\s+(?:property="og:[^"]*"|name="twitter:[^"]*")[^>]*>', "", html)
        html = html.replace("<title>", f"{og}<title>", 1)
        html = re.sub(r"<title>.*?</title>", f"<title>{esc(title)} · AdvantageLife</title>",
                      html, count=1, flags=re.S)
        return HTMLResponse(html)
    except Exception as e:
        logger.warning(f"[share] OG injection failed for {token}: {e}")
        return _spa_shell()


@app.get("/api/leaderboard/weekly")
def api_leaderboard_weekly(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """AdvantageLife weekly pack leaderboard (whole platform). Ranks members by
    packs SOLD this week (active pack purchases made by their direct referrals),
    and also surfaces packs OWNED (their highest active level) and weekly REVENUE
    (sum of those purchase amounts). Resets Monday 00:00 UTC. The caller's own
    row is flagged and returned separately so the UI can pin 'your rank'."""
    from sqlalchemy.orm import aliased
    from sqlalchemy import func
    from datetime import datetime, timedelta

    now = datetime.utcnow()
    week_start = (now - timedelta(days=now.weekday())).replace(hour=0, minute=0, second=0, microsecond=0)
    next_reset = week_start + timedelta(days=7)

    Buyer = aliased(User)
    rows = (db.query(
                Buyer.sponsor_id.label("seller_id"),
                func.count(PackPurchase.id).label("sold"),
                func.coalesce(func.sum(PackPurchase.amount), 0).label("revenue"))
            .join(Buyer, Buyer.id == PackPurchase.user_id)
            .filter(PackPurchase.status == "active",
                    PackPurchase.created_at >= week_start,
                    Buyer.sponsor_id.isnot(None))
            .group_by(Buyer.sponsor_id)
            .all())

    stats = {r.seller_id: {"sold": int(r.sold or 0), "revenue": float(r.revenue or 0)} for r in rows}
    seller_ids = list(stats.keys())

    owned = {}
    uname = {}
    if seller_ids:
        for uid, lvl in (db.query(PackPurchase.user_id, func.max(PackPurchase.pack_level))
                         .filter(PackPurchase.user_id.in_(seller_ids), PackPurchase.status == "active")
                         .group_by(PackPurchase.user_id).all()):
            owned[uid] = int(lvl or 0)
        for uid, un in db.query(User.id, User.username).filter(User.id.in_(seller_ids)).all():
            uname[uid] = un

    board = [{
        "user_id": sid,
        "username": uname.get(sid, "member"),
        "sold": stats[sid]["sold"],
        "owned": owned.get(sid, 0),
        "revenue": round(stats[sid]["revenue"], 2),
    } for sid in seller_ids]
    board.sort(key=lambda m: (-m["sold"], -m["revenue"]))
    for i, m in enumerate(board):
        m["rank"] = i + 1

    you = None
    if user:
        you = next((m for m in board if m["user_id"] == user.id), None)
        if you is None:
            my_owned = (db.query(func.max(PackPurchase.pack_level))
                        .filter(PackPurchase.user_id == user.id, PackPurchase.status == "active").scalar()) or 0
            you = {"user_id": user.id, "username": user.username, "sold": 0,
                   "owned": int(my_owned), "revenue": 0.0, "rank": None}

    return {
        "week_start": week_start.isoformat(),
        "next_reset": next_reset.isoformat(),
        "members": [{"rank": m["rank"], "username": m["username"], "sold": m["sold"],
                     "owned": m["owned"], "revenue": m["revenue"],
                     "is_you": bool(user and m["user_id"] == user.id)} for m in board[:50]],
        "you": ({"rank": you["rank"], "username": you["username"], "sold": you["sold"],
                 "owned": you["owned"], "revenue": you["revenue"]} if you else None),
    }


@app.get("/api/my-team")
def api_my_team(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """The caller's DIRECT referrals (members who joined via their link) with each
    one's highest active pack level, join date, own pack-sale count and active
    status, plus a summary strip (totals, active count, packs the team has bought,
    the caller's pass-up earnings) and the caller's referral link path. Exposes
    only public profile fields for team members — no balances or emails."""
    from sqlalchemy import func
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    directs = db.query(User).filter(User.sponsor_id == user.id).order_by(User.created_at.desc()).all()
    direct_ids = [d.id for d in directs]

    owned, bought = {}, {}
    if direct_ids:
        for uid, lvl in (db.query(PackPurchase.user_id, func.max(PackPurchase.pack_level))
                         .filter(PackPurchase.user_id.in_(direct_ids), PackPurchase.status == "active")
                         .group_by(PackPurchase.user_id).all()):
            owned[uid] = int(lvl or 0)
        for uid, cnt in (db.query(PackPurchase.user_id, func.count(PackPurchase.id))
                         .filter(PackPurchase.user_id.in_(direct_ids), PackPurchase.status == "active")
                         .group_by(PackPurchase.user_id).all()):
            bought[uid] = int(cnt or 0)

    members = [{
        "username": d.username,
        "pack_level": owned.get(d.id, 0),
        "joined": d.created_at.isoformat() if d.created_at else None,
        "sold": int(d.pack_sale_count or 0),
        "is_active": bool(d.is_active),
    } for d in directs]

    passup = (db.query(func.coalesce(func.sum(PackCommission.amount), 0))
              .filter(PackCommission.earner_id == user.id, PackCommission.status == "paid").scalar()) or 0

    return {
        "referral_link": f"/join/{user.username}",
        "summary": {
            "total": len(directs),
            "active": sum(1 for d in directs if d.is_active),
            "team_packs": sum(bought.values()),
            "passup_earnings": round(float(passup), 2),
        },
        "members": members,
    }


@app.get("/api/leaderboard")
def api_leaderboard(db: Session = Depends(get_db)):
    """JSON data for the leaderboard: one ranked `members` board. Cached 5 min.

    Returns a single list of members measured LIVE from the canonical ledger
    helpers (compute_user_earnings + compute_descendant_counts), each carrying
    income / downline / signups. The frontend (pages/Leaderboard.jsx) re-sorts
    client-side on the metric toggle.

    History: this endpoint previously served five separate boards (referrals,
    sign-ups, grid, nexus, course) plus an activity feed and platform stats,
    consumed by the old multi-tab leaderboard. The 26 Jun 2026 redesign
    collapsed it to the single unified board; the dead board queries, bulk-load
    dicts, user_data() builder, activity feed and stats were removed with it.
    """
    # Check cache first (leaderboard is same for everyone)
    cache_key = "leaderboard:main"
    cached = cache_get(cache_key)
    if cached:
        return cached

    # ── Unified members board (redesigned leaderboard) ────────────────
    # ONE ranked list powering the new leaderboard, with three live metrics:
    #   income   = compute_user_earnings()['total_earned']  (paid ledger)
    #   downline = compute_descendant_counts()['total']      (recursive CTE)
    #   signups  = compute_user_earnings()['personal_referrals'] (direct refs)
    # Every displayed number is recomputed live from the canonical helpers —
    # NEVER the denormalised User.total_earned / total_team / personal_referrals
    # columns, which drift (same reason descendant counts + earnings have
    # dedicated helpers). Candidate pool is selected cheaply via those stored
    # counters (selection only — approximate ordering is fine), then measured
    # live. Bounded to a small union; per-user helper results are cached 60s
    # and this whole endpoint is cached 5 min, so the live recompute cost is
    # paid at most once per 5 minutes per cold replica.
    member_cands = {}
    for u in db.query(User).filter(User.is_active == True).order_by(User.total_earned.desc()).limit(30).all():
        member_cands[u.id] = u
    for u in db.query(User).filter(User.is_active == True).order_by(User.total_team.desc()).limit(30).all():
        member_cands[u.id] = u

    members_board = []
    for u in member_cands.values():
        earn = compute_user_earnings(db, u.id)
        desc = compute_descendant_counts(db, u.id)
        income = round(float(earn.get("total_earned") or 0), 2)
        downline = int(desc.get("total") or 0)
        signups = int(earn.get("personal_referrals") or 0)
        # Only real participants belong on the board — skip anyone with no
        # earnings, no downline and no sign-ups (would just be $0/0/0 noise).
        if income <= 0 and downline <= 0 and signups <= 0:
            continue
        members_board.append({
            "id": u.id,
            "username": u.username,
            "first_name": u.first_name or u.username,
            "avatar_url": u.avatar_url or None,
            "membership_tier": u.membership_tier or "free",
            "income": income,
            "downline": downline,
            "signups": signups,
        })
    # Default order = income desc; the frontend re-sorts client-side on toggle.
    members_board.sort(key=lambda m: m["income"], reverse=True)

    result = {"members": members_board}

    # Cache for 5 minutes (same for all users)
    cache_set(cache_key, result, ttl=300)

    return result
@app.get("/api/campaign-tiers")
def api_campaign_tiers(request: Request, user: User = Depends(get_current_user),
                       db: Session = Depends(get_db)):
    """JSON campaign tier data with active status from both campaigns and grids."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from .database import (GRID_PACKAGES, GRID_TIER_NAMES, CAMPAIGN_VIEW_TARGETS, GRID_COMPLETION_BONUS,
                           v2_live, V2_DIRECT_PCT, V2_PER_LEVEL_PCT, V2_UNILEVEL_DEPTH, V2_BONUS_POOL_PCT,
                           DIRECT_PCT, PER_LEVEL_PCT, UNILEVEL_DEPTH, NEW_GRID_SEATS)

    # Check active video campaigns (qualification)
    active_campaigns = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id,
        VideoCampaign.status == "active",
        VideoCampaign.is_completed == False
    ).all()
    active_campaign_tiers = {c.campaign_tier for c in active_campaigns}

    # Per-tier campaign progress: sum views_delivered across active campaigns
    # at each tier. Used by the active-tier card's progress bar so the member
    # can see how close they are to campaign completion (which is also the
    # gate for repurchasing the tier per product rule).
    progress_by_tier = {}
    for c in active_campaigns:
        tier = (c.campaign_tier if c.campaign_tier is not None else -1)
        if tier < 0:
            continue
        agg = progress_by_tier.setdefault(tier, {"views_delivered": 0, "views_target": 0})
        agg["views_delivered"] += int(c.views_delivered or 0)
        agg["views_target"]    += int(c.views_target or 0)

    # Check grids. A tier is "active/owned" ONLY if the owner GENUINELY
    # purchased it (owner_purchased=True) — NOT merely because a grid row
    # exists. Spillover from a downline auto-creates a Grid via
    # get_or_create_active_grid with owner_purchased=False; those must not
    # show the owner as having bought the tier (fixed 30 May 2026 — members
    # were seeing tiers ACTIVE that they never paid for).
    active_grids = db.query(Grid).filter(
        Grid.owner_id == user.id,
        Grid.is_complete == False,
        Grid.owner_purchased == True,  # noqa: E712 — genuine purchase only
    ).all()
    completed_grids = db.query(Grid).filter(
        Grid.owner_id == user.id,
        Grid.is_complete == True,
        Grid.owner_purchased == True,  # noqa: E712
    ).all()
    grid_by_tier = {}
    completed_tier_set = {g.package_tier for g in completed_grids}
    for g in active_grids:
        grid_by_tier[g.package_tier] = {
            "filled": g.positions_filled or 0,
            "pct": round((g.positions_filled or 0) / g.total_seats * 100),
            "advance": g.advance_number or 1,
        }

    # Admin always active at all tiers
    is_admin = user.is_admin

    # Commission rates — read straight off the same v2_live()-gated constants the
    # GRID PAYOUT uses (grid.py _pay_direct_sponsor / _pay_unilevel_chain /
    # _accrue_to_pool), so this display can never drift from what members are
    # actually paid. If GRID_V2_LIVE is ever flipped back to v1 this auto-reverts.
    _is_v2          = v2_live()
    _direct_pct     = V2_DIRECT_PCT     if _is_v2 else DIRECT_PCT
    _per_level_pct  = V2_PER_LEVEL_PCT  if _is_v2 else PER_LEVEL_PCT
    _uni_depth      = V2_UNILEVEL_DEPTH if _is_v2 else UNILEVEL_DEPTH

    # Build tier data
    tiers = []
    for tier_num in range(0, 9):
        price = GRID_PACKAGES.get(tier_num, 0)
        direct_comm = round(price * _direct_pct, 2)
        uni_level_per_member = round(price * _per_level_pct, 2)            # per single level ($1/level on Starter)
        uni_level_total = round(price * _per_level_pct * _uni_depth, 2)    # across all levels ($5 on Starter)
        # Bonus pool: v2 pays a fixed 25% pool over the 16 seats (V2_BONUS_POOL_PCT
        # × NEW_GRID_SEATS × price). v1 uses the seat-aware completion_bonus_for.
        bonus = round(price * NEW_GRID_SEATS * V2_BONUS_POOL_PCT, 2) if _is_v2 else completion_bonus_for(NEW_GRID_SEATS, price)
        views = CAMPAIGN_VIEW_TARGETS.get(tier_num, 0)
        is_active = is_admin or (tier_num in active_campaign_tiers) or (tier_num in grid_by_tier) or (tier_num in completed_tier_set)
        grid_info = grid_by_tier.get(tier_num)
        progress = progress_by_tier.get(tier_num)

        tiers.append({
            "tier": tier_num,
            "name": GRID_TIER_NAMES.get(tier_num, f"Tier {tier_num}"),
            "price": price,
            "views_target": views,
            "direct_commission": direct_comm,
            "uni_level_per_member": uni_level_per_member,
            "uni_level_total": uni_level_total,
            "completion_bonus": bonus,
            # Rate metadata so the page renders its labels from data, never
            # hard-coded percentages (the bug that left this page on v1 numbers).
            "direct_pct": round(_direct_pct * 100, 2),
            "per_level_pct": round(_per_level_pct * 100, 2),
            "uni_level_depth": _uni_depth,
            "bonus_pool_pct": round((V2_BONUS_POOL_PCT if _is_v2 else 0.20) * 100, 2),
            "plan_version": 2 if _is_v2 else 1,
            "is_active": is_active,
            "grid": grid_info,
            # Campaign progress on the user's active campaigns at this tier
            # (used by the active-tier card's progress bar). None when the
            # user has no active campaign at this tier.
            "campaign_progress": progress,
        })

    return {
        "tiers": tiers,
        "active_tiers": [t["tier"] for t in tiers if t["is_active"]],
        "completed_count": len(completed_grids),
    }



