@app.get("/api/passup-visualiser")
def api_passup_visualiser(request: Request, user: User = Depends(get_current_user),
                          db: Session = Depends(get_db)):
    """Pass-up chain visualisation data."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    # Build the chain upward
    chain = []
    current = user
    for _ in range(10):  # max depth
        sponsor = db.query(User).filter(User.id == current.sponsor_id).first() if current.sponsor_id else None
        if not sponsor:
            break
        chain.append({
            "id": sponsor.id, "username": sponsor.username, "first_name": sponsor.first_name,
            "is_admin": sponsor.is_admin, "level": len(chain) + 1,
        })
        current = sponsor
    # Direct downline
    downline = db.query(User).filter(User.sponsor_id == user.id).all()
    return {
        "user": {"id": user.id, "username": user.username, "first_name": user.first_name},
        "upline_chain": chain,
        "direct_downline": [{
            "id": d.id, "username": d.username, "first_name": d.first_name,
            "is_active": d.is_active, "personal_referrals": d.personal_referrals or 0,
        } for d in downline],
    }
@app.get("/api/funnels")
def api_funnels_list(request: Request, user: User = Depends(get_current_user),
                     db: Session = Depends(get_db)):
    """List user's SuperPages/funnels with campaign-dashboard metrics.

    Powers the enriched /pro/funnels view. Returns the funnel list with
    per-page engagement stats (visits, opt-ins, conversion rate, leads,
    hot leads, sequence open rate, conversions, earnings) plus a
    top-level 30-day rollup for the ROI strip at the top of the page.

    Attribution model (lands in Commit B, 18 May 2026):
      MemberLead.attribution_user_id is set when a captured lead
      activates Partner membership and email-matches a MemberLead.
      Per-page conversions = leads where attribution_user_id is set
      AND there's a Commission row paying the page owner (from the
      new user, type membership_sponsor/_renewal_sponsor, status=paid).
      Earnings = sum of those commission amounts in the 30-day window.

      A conversion only counts if the page owner actually got paid.
      If a lead converted via someone else's sponsor link, the funnel
      captured them but didn't earn — that's a $0 conversion and we
      don't credit it here (would mislead the page owner about which
      pages are actually making money).

    All metrics computed via grouped SQL queries — no N+1, single
    payload per dashboard load.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    from .database import FunnelPage, FunnelEvent, MemberLead, EmailSendLog, Commission
    from sqlalchemy import func as _func, and_ as _and

    now = datetime.utcnow()
    cutoff_30d = now - timedelta(days=30)
    cutoff_24h = now - timedelta(hours=24)

    # Fetch all funnels for the user. Single query — we'll batch the
    # related stats with grouped queries below rather than N+1ing.
    funnels = db.query(FunnelPage).filter(
        FunnelPage.user_id == user.id
    ).order_by(FunnelPage.created_at.desc()).all()

    # ── Slug repair (20 May 2026) ──
    # Steve found pages in /pro/funnels with green-dot 'published' status
    # but no View button. Root cause: their FunnelPage.slug was empty,
    # which made the gallery's `p.status === 'published' && p.slug`
    # condition false and hid the View link, leaving the published page
    # with no clickable preview path from the dashboard.
    #
    # This loop repairs any slug-less pages on the next gallery load.
    # Safe to run on every request because the if-not-slug check is cheap
    # and only fires for actually-broken rows. Slug generation is
    # collision-safe so two legacy pages with the same title won't clash.
    repaired_any = False
    for f in funnels:
        if not f.slug:
            f.slug = generate_unique_slug(db, user.username, f.title or 'page', exclude_page_id=f.id)
            repaired_any = True
    if repaired_any:
        try:
            db.commit()
        except Exception as _slug_err:
            db.rollback()
            logger.warning(f"Funnels API: slug repair failed: {_slug_err}")

    funnel_ids = [f.id for f in funnels]

    # ── Per-page 30-day visit count ──
    # FunnelEvent.event_type='view' is what /p/{slug} writes (dedup by
    # IP within 5 min, so the count is meaningfully unique-ish).
    views_30d_rows = {}
    if funnel_ids:
        rows = db.query(
            FunnelEvent.page_id,
            _func.count(FunnelEvent.id).label("c"),
        ).filter(
            FunnelEvent.page_id.in_(funnel_ids),
            FunnelEvent.event_type == "view",
            FunnelEvent.created_at >= cutoff_30d,
        ).group_by(FunnelEvent.page_id).all()
        views_30d_rows = {r.page_id: r.c for r in rows}

    # ── Per-page 30-day optin count ──
    # We prefer counting MemberLead rows (the CRM truth) over FunnelEvent
    # type=optin (which is more for analytics dashboards). source_funnel_id
    # is set by /api/leads/capture so it's the authoritative join.
    optins_30d_rows = {}
    if funnel_ids:
        rows = db.query(
            MemberLead.source_funnel_id,
            _func.count(MemberLead.id).label("c"),
        ).filter(
            MemberLead.source_funnel_id.in_(funnel_ids),
            MemberLead.created_at >= cutoff_30d,
        ).group_by(MemberLead.source_funnel_id).all()
        optins_30d_rows = {r.source_funnel_id: r.c for r in rows}

    # ── Per-page all-time lead counts (total, hot, new-24h) ──
    leads_total_rows = {}
    leads_hot_rows = {}
    leads_24h_rows = {}
    if funnel_ids:
        rows = db.query(
            MemberLead.source_funnel_id,
            _func.count(MemberLead.id).label("c"),
        ).filter(MemberLead.source_funnel_id.in_(funnel_ids)).group_by(
            MemberLead.source_funnel_id
        ).all()
        leads_total_rows = {r.source_funnel_id: r.c for r in rows}

        rows_hot = db.query(
            MemberLead.source_funnel_id,
            _func.count(MemberLead.id).label("c"),
        ).filter(
            MemberLead.source_funnel_id.in_(funnel_ids),
            MemberLead.is_hot == True,
        ).group_by(MemberLead.source_funnel_id).all()
        leads_hot_rows = {r.source_funnel_id: r.c for r in rows_hot}

        rows_24h = db.query(
            MemberLead.source_funnel_id,
            _func.count(MemberLead.id).label("c"),
        ).filter(
            MemberLead.source_funnel_id.in_(funnel_ids),
            MemberLead.created_at >= cutoff_24h,
        ).group_by(MemberLead.source_funnel_id).all()
        leads_24h_rows = {r.source_funnel_id: r.c for r in rows_24h}

    # ── Per-page most recent lead timestamp ──
    last_lead_rows = {}
    if funnel_ids:
        rows = db.query(
            MemberLead.source_funnel_id,
            _func.max(MemberLead.created_at).label("ts"),
        ).filter(MemberLead.source_funnel_id.in_(funnel_ids)).group_by(
            MemberLead.source_funnel_id
        ).all()
        last_lead_rows = {r.source_funnel_id: r.ts for r in rows}

    # ── Per-page open-rate (avg of leads' open ratios on this page) ──
    # Defined as: of all leads sourced from this page who have received
    # at least 1 email, what's the average (emails_opened / emails_sent)?
    # A lead with emails_sent=0 is excluded from the denominator entirely
    # — we're not punishing a page for leads that haven't yet been emailed.
    open_rate_rows = {}
    if funnel_ids:
        # Compute as sum(emails_opened) / sum(emails_sent) — this is the
        # "weighted" open rate (treats every email equally), not the
        # "averaged" rate (treats every lead equally). Weighted reads
        # truer for tiny lists where one chatty lead would skew an
        # averaged calculation.
        rows = db.query(
            MemberLead.source_funnel_id,
            _func.sum(MemberLead.emails_sent).label("sent"),
            _func.sum(MemberLead.emails_opened).label("opened"),
        ).filter(
            MemberLead.source_funnel_id.in_(funnel_ids),
            MemberLead.emails_sent > 0,
        ).group_by(MemberLead.source_funnel_id).all()
        for r in rows:
            sent = int(r.sent or 0)
            opened = int(r.opened or 0)
            open_rate_rows[r.source_funnel_id] = (opened / sent) if sent > 0 else 0.0

    # ── Per-page 30-day conversions + earnings (attribution layer) ──
    # Conversions: count of MemberLead rows where attribution_user_id is
    # set AND there exists a Commission row in the 30-day window paying
    # this page's owner from that attributed user. Earnings: sum of
    # those commission amounts.
    #
    # Wrapped in try/except — on environments where SKIP_MIGRATIONS is
    # set, the attribution_user_id column may not exist yet. We log
    # and fall through with empty dicts so the rest of the endpoint
    # still returns useful data (visits, opt-ins, leads). Once
    # SKIP_MIGRATIONS flips back to false on a deploy, this will start
    # returning real numbers automatically.
    conversions_30d_rows = {}
    earnings_30d_rows = {}
    if funnel_ids:
        try:
            # Join MemberLead -> Commission via attribution_user_id.
            # Commission.from_user_id = the attributed (paying) user.
            # Commission.to_user_id   = the page owner (= user.id, our caller).
            # We filter to membership-related commission types only —
            # courses, grids, etc don't count as "funnel conversions" because
            # they're separate purchase products, not the result of the
            # lead-capture-to-membership chain that the funnel tracks.
            commission_types = [
                "membership_sponsor",
                "Membership Sponsor",      # legacy capitalisation in historical rows
                "membership_renewal_sponsor",
                "gift_membership_sponsor",
            ]
            rows = db.query(
                MemberLead.source_funnel_id,
                _func.count(_func.distinct(MemberLead.id)).label("conv"),
                _func.coalesce(_func.sum(Commission.amount_usdt), 0).label("earned"),
            ).join(
                Commission,
                _and(
                    Commission.from_user_id == MemberLead.attribution_user_id,
                    Commission.to_user_id == user.id,
                    Commission.commission_type.in_(commission_types),
                    Commission.status == "paid",
                    Commission.paid_at >= cutoff_30d,
                ),
            ).filter(
                MemberLead.source_funnel_id.in_(funnel_ids),
                MemberLead.attribution_user_id.isnot(None),
            ).group_by(MemberLead.source_funnel_id).all()
            for r in rows:
                conversions_30d_rows[r.source_funnel_id] = int(r.conv or 0)
                earnings_30d_rows[r.source_funnel_id] = float(r.earned or 0)
        except Exception as _attr_err:
            # Roll back the transaction — once a query raises, the
            # SQLAlchemy session is in an aborted state and subsequent
            # queries (or the final db.commit on view tracking) will
            # also fail. Rolling back resets it cleanly.
            db.rollback()
            logger.warning(
                f"Funnels API: attribution join failed (likely missing "
                f"attribution_user_id column, run migration): {_attr_err}"
            )

    # ── Assemble per-funnel response ──
    # Phase 1.5: include the page's current campaign wiring so the
    # "Your Pages" cards can render a footer showing what's bound and
    # let the user click to edit. We resolve list_id → name + sequence_id
    # → title via a single batched query each, to avoid N+1 selects.
    bound_list_ids = [f.default_list_id for f in funnels if f.default_list_id]
    bound_seq_ids = [f.capture_sequence_id for f in funnels if f.capture_sequence_id]
    list_names = {}
    seq_titles = {}
    if bound_list_ids:
        from .database import LeadList as _LL
        for ll in db.query(_LL.id, _LL.name).filter(_LL.id.in_(bound_list_ids)).all():
            list_names[ll.id] = ll.name
    if bound_seq_ids:
        from .database import EmailSequence as _ES
        for es in db.query(_ES.id, _ES.title, _ES.num_emails).filter(_ES.id.in_(bound_seq_ids)).all():
            seq_titles[es.id] = {"title": es.title or "Sequence", "num_emails": int(es.num_emails or 0)}

    funnel_data = []
    for f in funnels:
        views_30d = int(views_30d_rows.get(f.id, 0))
        optins_30d = int(optins_30d_rows.get(f.id, 0))
        conversion_rate_30d = (optins_30d / views_30d) if views_30d > 0 else 0.0
        last_lead_at = last_lead_rows.get(f.id)
        bound_seq = seq_titles.get(f.capture_sequence_id) if f.capture_sequence_id else None
        funnel_data.append({
            "id": f.id,
            "title": f.title or "Untitled",
            "slug": f.slug or "",
            "status": f.status or "draft",
            "views": f.views or 0,                          # all-time, legacy field
            "leads_captured": f.leads_captured or 0,        # all-time, legacy field
            "is_ai_generated": f.is_ai_generated or False,
            "created_at": f.created_at.isoformat() if f.created_at else None,
            # Page content (JSON {els, canvasBg, ...}) so the dashboard card can
            # render a real scaled thumbnail. Frontend parses this -> exportHTML.
            "gjs_css": f.gjs_css or "",
            # New campaign-dashboard fields ─────────────────────
            "views_30d": views_30d,
            "optins_30d": optins_30d,
            "conversion_rate_30d": round(conversion_rate_30d, 4),
            "leads_total": int(leads_total_rows.get(f.id, 0)),
            "leads_hot": int(leads_hot_rows.get(f.id, 0)),
            "leads_new_24h": int(leads_24h_rows.get(f.id, 0)),
            "sequence_open_rate": round(float(open_rate_rows.get(f.id, 0.0)), 4),
            "last_lead_at": last_lead_at.isoformat() if last_lead_at else None,
            # Attribution + earnings (Commit B, live)
            "conversions_30d": int(conversions_30d_rows.get(f.id, 0)),
            "earnings_30d": round(float(earnings_30d_rows.get(f.id, 0.0)), 2),
            # Phase 1.5 — campaign wiring state for the card footer
            "default_list_id": f.default_list_id,
            "default_list_name": list_names.get(f.default_list_id) if f.default_list_id else None,
            "capture_sequence_id": f.capture_sequence_id,
            "capture_sequence_title": bound_seq["title"] if bound_seq else None,
            "capture_sequence_num_emails": bound_seq["num_emails"] if bound_seq else None,
        })

    # ── Top-level 30-day rollup (for the ROI strip) ──
    total_visitors_30d = sum(views_30d_rows.values()) if views_30d_rows else 0
    total_leads_30d = sum(optins_30d_rows.values()) if optins_30d_rows else 0
    total_hot_leads = sum(leads_hot_rows.values()) if leads_hot_rows else 0
    total_conversions_30d = sum(conversions_30d_rows.values()) if conversions_30d_rows else 0
    total_earnings_30d = round(sum(earnings_30d_rows.values()), 2) if earnings_30d_rows else 0.0

    return {
        "funnels": funnel_data,
        "rollup_30d": {
            "visitors": total_visitors_30d,
            "leads": total_leads_30d,
            "hot_leads": total_hot_leads,
            "conversions": total_conversions_30d,
            "earnings": total_earnings_30d,
        },
    }
@app.get("/api/funnels/activity")
def api_funnels_activity(request: Request, user: User = Depends(get_current_user),
                         db: Session = Depends(get_db)):
    """Recent activity feed for the /pro/funnels Campaign Hub.

    Commit C of the Unified Campaign Hub (18 May 2026 series). Sits below
    the "My Pages" grid and surfaces the next thing the user should do.

    Returns five blocks plus a contextual next_action prompt:

      hot_leads          Top 3 unconverted leads with the strongest
                         engagement signal — to be called/emailed manually.
      new_24h            Most recent leads (last 24h) — "say hi" prompts.
      sequence_complete  Leads who've received every email in their
                         sequence and have nowhere else to go in the
                         autoresponder — broadcast targets.
      recent_commissions Most recent paid commissions to the user — keeps
                         the dopamine loop visible.
      next_action        Single contextual prompt: "🔥 You have N hot
                         leads ready to call" / "📧 N leads finished
                         your sequence" / "👋 New leads to greet" /
                         "📈 Drive traffic" / "💪 Steady state".

    Pure read aggregation — no schema changes, no writes, idempotent.
    Designed to be safe even when SKIP_MIGRATIONS is set (only touches
    columns that have existed since launch, except attribution_user_id
    which we read defensively inside try/except like /api/funnels does).
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    from .database import (
        FunnelPage, MemberLead, EmailSequence, Commission, User as _User,
    )
    from sqlalchemy import func as _func, or_ as _or

    now = datetime.utcnow()
    cutoff_24h = now - timedelta(hours=24)

    # ── Hot leads: top 3 unconverted leads ranked by engagement ──
    # "Unconverted" = attribution_user_id is null. If they've already
    # activated, they're not a lead the page owner can chase any more.
    # Ranking: prefer is_hot=True, then most recent click, then most
    # recent open. Anything with zero engagement falls out.
    # Defensive try/except around attribution_user_id filter — see notes
    # in /api/funnels above.
    hot_leads = []
    try:
        q = db.query(MemberLead, FunnelPage.title).outerjoin(
            FunnelPage, FunnelPage.id == MemberLead.source_funnel_id
        ).filter(
            MemberLead.user_id == user.id,
            MemberLead.attribution_user_id.is_(None),
            _or(
                MemberLead.is_hot == True,
                MemberLead.emails_opened > 0,
                MemberLead.emails_clicked > 0,
            ),
        ).order_by(
            MemberLead.is_hot.desc(),
            MemberLead.last_clicked_at.desc().nullslast(),
            MemberLead.last_opened_at.desc().nullslast(),
        ).limit(3).all()
        for ml, page_title in q:
            last_engaged = ml.last_clicked_at or ml.last_opened_at
            hot_leads.append({
                "id": ml.id,
                "name": ml.name or (ml.email.split("@")[0] if ml.email else "—"),
                "email": ml.email,
                "source_funnel_title": page_title or "—",
                "last_engagement_at": last_engaged.isoformat() if last_engaged else None,
                "opens": int(ml.emails_opened or 0),
                "clicks": int(ml.emails_clicked or 0),
                "is_hot": bool(ml.is_hot),
            })
    except Exception as _hot_err:
        db.rollback()
        logger.warning(f"activity: hot_leads query failed: {_hot_err}")

    # ── New leads in last 24h ──
    new_24h_count = 0
    new_24h = []
    try:
        new_24h_count = db.query(_func.count(MemberLead.id)).filter(
            MemberLead.user_id == user.id,
            MemberLead.created_at >= cutoff_24h,
        ).scalar() or 0
        q = db.query(MemberLead, FunnelPage.title).outerjoin(
            FunnelPage, FunnelPage.id == MemberLead.source_funnel_id
        ).filter(
            MemberLead.user_id == user.id,
            MemberLead.created_at >= cutoff_24h,
        ).order_by(MemberLead.created_at.desc()).limit(5).all()
        for ml, page_title in q:
            new_24h.append({
                "id": ml.id,
                "name": ml.name or (ml.email.split("@")[0] if ml.email else "—"),
                "email": ml.email,
                "source_funnel_title": page_title or "—",
                "created_at": ml.created_at.isoformat() if ml.created_at else None,
            })
    except Exception as _new_err:
        db.rollback()
        logger.warning(f"activity: new_24h query failed: {_new_err}")

    # ── Sequence-complete leads ──
    # Leads who've received every email in their sequence (emails_sent >=
    # sequence.num_emails) AND aren't yet attributed (no point broadcasting
    # to leads who already converted). These are the broadcast targets.
    # We count the total and return the 5 most recently-completed ones for
    # the preview list.
    seq_complete_count = 0
    seq_complete = []
    try:
        # Subquery: lead's emails_sent + their sequence's num_emails
        seq_q = db.query(MemberLead, EmailSequence, FunnelPage.title).join(
            EmailSequence, EmailSequence.id == MemberLead.email_sequence_id,
        ).outerjoin(
            FunnelPage, FunnelPage.id == MemberLead.source_funnel_id,
        ).filter(
            MemberLead.user_id == user.id,
            MemberLead.attribution_user_id.is_(None),
            MemberLead.emails_sent >= EmailSequence.num_emails,
            MemberLead.emails_sent > 0,
        )
        # Count first (cheap — no order/limit)
        seq_complete_count = seq_q.count()
        # Then top 5 for the preview
        for ml, seq, page_title in seq_q.order_by(
            MemberLead.updated_at.desc().nullslast(),
            MemberLead.created_at.desc(),
        ).limit(5).all():
            seq_complete.append({
                "id": ml.id,
                "name": ml.name or (ml.email.split("@")[0] if ml.email else "—"),
                "email": ml.email,
                "sequence_title": seq.title or "Sequence",
                "emails_sent": int(ml.emails_sent or 0),
                "source_funnel_title": page_title or "—",
            })
    except Exception as _seq_err:
        db.rollback()
        logger.warning(f"activity: sequence_complete query failed: {_seq_err}")

    # ── Recent paid commissions to this user ──
    # Lifetime feed (no time cutoff). 5 most recent. Joined to User for
    # username display. We filter to status='paid' only — pending rows
    # would be misleading on a "you earned this" feed.
    recent_commissions = []
    try:
        rows = db.query(Commission, _User.username).outerjoin(
            _User, _User.id == Commission.from_user_id
        ).filter(
            Commission.to_user_id == user.id,
            Commission.status == "paid",
        ).order_by(Commission.paid_at.desc().nullslast()).limit(5).all()
        # Map commission_type to friendlier labels for the feed.
        TYPE_LABELS = {
            "membership_sponsor": "Sponsor",
            "Membership Sponsor": "Sponsor",
            "membership_renewal_sponsor": "Renewal",
            "gift_membership_sponsor": "Gift sponsor",
            "founder_sponsor": "Founder sponsor",
            "founder_renewal_sponsor": "Founder renewal",
            "direct_sponsor": "Direct sponsor",
            "uni_level": "Team build",
            "course_sponsor": "Course sponsor",
            "course_passup": "Course pass-up",
            "grid_position": "Grid",
            "grid_passup": "Grid pass-up",
            "nexus_sponsor": "Credit Nexus",
        }
        for c, from_username in rows:
            recent_commissions.append({
                "amount_usdt": float(c.amount_usdt or 0),
                "type_raw": c.commission_type or "",
                "type_label": TYPE_LABELS.get(c.commission_type, (c.commission_type or "Commission").replace("_", " ").title()),
                "from_username": from_username or "—",
                "paid_at": c.paid_at.isoformat() if c.paid_at else None,
            })
    except Exception as _com_err:
        db.rollback()
        logger.warning(f"activity: recent_commissions query failed: {_com_err}")

    # ── Contextual next-action prompt ──
    # Priority ladder — first match wins. Each prompt is shaped so the
    # frontend can render it as a single pill with one CTA.
    hot_count = len(hot_leads)
    has_any_page = db.query(_func.count(FunnelPage.id)).filter(
        FunnelPage.user_id == user.id
    ).scalar() or 0
    has_any_lead = db.query(_func.count(MemberLead.id)).filter(
        MemberLead.user_id == user.id
    ).scalar() or 0

    if hot_count >= 1:
        next_action = {
            "emoji": "🔥",
            "label": f"You have {hot_count} hot lead{'s' if hot_count != 1 else ''} ready to engage",
            "cta_label": "Open SuperLeads →",
            "cta_url": "/pro/leads",
            "tone": "hot",
        }
    elif seq_complete_count >= 5:
        next_action = {
            "emoji": "📧",
            "label": f"{seq_complete_count} leads finished your sequence — time to broadcast",
            "cta_label": "Send broadcast →",
            "cta_url": "/pro/leads?tab=broadcast",
            "tone": "broadcast",
        }
    elif new_24h_count >= 1:
        next_action = {
            "emoji": "👋",
            "label": f"{new_24h_count} new lead{'s' if new_24h_count != 1 else ''} in the last 24h — say hi",
            "cta_label": "Open SuperLeads →",
            "cta_url": "/pro/leads",
            "tone": "new",
        }
    elif has_any_page == 0:
        next_action = {
            "emoji": "🚀",
            "label": "Start by building your first SuperPage",
            "cta_label": "Browse templates →",
            "cta_url": "#templates",
            "tone": "empty",
        }
    elif has_any_lead == 0:
        next_action = {
            "emoji": "📈",
            "label": "Drive traffic to your pages — share your referral link",
            "cta_label": "Get your link →",
            "cta_url": "/pro/refer",
            "tone": "traffic",
        }
    else:
        next_action = {
            "emoji": "💪",
            "label": "Steady state — keep promoting your pages",
            "cta_label": "Share a page →",
            "cta_url": "#your-pages",
            "tone": "steady",
        }

    return {
        "hot_leads": hot_leads,
        "new_24h": new_24h,
        "new_24h_count": int(new_24h_count),
        "sequence_complete": seq_complete,
        "sequence_complete_count": int(seq_complete_count),
        "recent_commissions": recent_commissions,
        "next_action": next_action,
    }
@app.get("/api/funnels/setup-options")
def api_funnels_setup_options(request: Request, user: User = Depends(get_current_user),
                              db: Session = Depends(get_db)):
    """Phase 1 (Campaign Hub): feed the campaign-setup modal.

    Returns the user's existing LeadLists and EmailSequences so the
    modal can present them as dropdown options. The modal also offers
    'Create new list' and 'Skip' — those are pure frontend states,
    no data needed for them here.

    Pro-only. Sorted by recency (most-recently-created first) so
    fresh items show up at the top of the dropdowns.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    from .database import LeadList, EmailSequence

    lists = db.query(LeadList).filter(
        LeadList.user_id == user.id
    ).order_by(LeadList.created_at.desc()).all()
    sequences = db.query(EmailSequence).filter(
        EmailSequence.user_id == user.id,
        EmailSequence.is_active == True,
    ).order_by(EmailSequence.created_at.desc()).all()

    return {
        "lists": [
            {
                "id": l.id,
                "name": l.name,
                "lead_count": int(l.lead_count or 0),
                "color": l.color or "#0ea5e9",
                "created_at": l.created_at.isoformat() if l.created_at else None,
            }
            for l in lists
        ],
        "sequences": [
            {
                "id": s.id,
                "title": s.title or "Untitled sequence",
                "num_emails": int(s.num_emails or 0),
                "niche": s.niche or "",
                "created_at": s.created_at.isoformat() if s.created_at else None,
            }
            for s in sequences
        ],
    }


@app.post("/api/funnels/{page_id}/wiring")
async def api_funnels_update_wiring(page_id: int, request: Request,
                                     user: User = Depends(get_current_user),
                                     db: Session = Depends(get_db)):
    """Phase 1.5 (Campaign Hub): update campaign binding on an existing page.

    Dedicated endpoint for the "Edit campaign wiring" modal on the My
    Pages cards. Same payload as the page-create modal:
      default_list_id          → bind to existing list
      create_new_list_name     → auto-create a list with this name + bind
      capture_sequence_id      → bind to existing sequence
      (passing null on either ID = explicit unbind)

    Separated from /api/funnels/save so the canvas editor's frequent
    saves don't accidentally clobber bindings — the binding endpoint
    requires explicit user action via the modal.

    Returns the resolved state for immediate UI refresh without a full
    /api/funnels reload.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)

    page = db.query(FunnelPage).filter(
        FunnelPage.id == page_id, FunnelPage.user_id == user.id
    ).first()
    if not page:
        return JSONResponse({"error": "Page not found"}, status_code=404)

    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    _apply_campaign_binding(db, user, page, body)
    db.commit()
    db.refresh(page)

    # Resolve names for the response so the UI updates immediately
    from .database import LeadList, EmailSequence
    list_name = None
    seq_title = None
    seq_num_emails = None
    if page.default_list_id:
        lst = db.query(LeadList).filter(LeadList.id == page.default_list_id).first()
        if lst:
            list_name = lst.name
    if page.capture_sequence_id:
        seq = db.query(EmailSequence).filter(EmailSequence.id == page.capture_sequence_id).first()
        if seq:
            seq_title = seq.title or "Sequence"
            seq_num_emails = int(seq.num_emails or 0)

    return {
        "success": True,
        "page_id": page.id,
        "default_list_id": page.default_list_id,
        "default_list_name": list_name,
        "capture_sequence_id": page.capture_sequence_id,
        "capture_sequence_title": seq_title,
        "capture_sequence_num_emails": seq_num_emails,
    }


@app.get("/api/linkhub-stats")
def api_linkhub_stats(request: Request, user: User = Depends(get_current_user),
                      db: Session = Depends(get_db)):
    """LinkHub stats for React page."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    profile = db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user.id).first()
    links_count = 0
    total_clicks = 0
    if profile:
        links = db.query(LinkHubLink).filter(LinkHubLink.profile_id == profile.id).all()
        links_count = len(links)
        total_clicks = sum(l.click_count or 0 for l in links)
    return {
        "views": profile.total_views if profile else 0,
        "clicks": total_clicks,
        "links": links_count,
    }
@app.get("/api/linkhub/editor-data")
def api_linkhub_editor_data(request: Request, user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """Full LinkHub profile + links data for React editor."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    import json as _json
    profile = db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user.id).first()
    links = []
    total_clicks = 0
    click_30d = 0
    if profile:
        db_links = db.query(LinkHubLink).filter(
            LinkHubLink.profile_id == profile.id
        ).order_by(LinkHubLink.sort_order).all()
        links = [{
            "id": l.id, "title": l.title, "url": l.url, "icon": l.icon or "🔗",
            "is_active": l.is_active, "click_count": l.click_count or 0,
            "sort_order": l.sort_order,
        } for l in db_links]
        total_clicks = sum(l.click_count or 0 for l in db_links)
        from datetime import timedelta
        cutoff = datetime.utcnow() - timedelta(days=30)
        click_30d = db.query(LinkHubClick).filter(
            LinkHubClick.profile_id == profile.id,
            LinkHubClick.clicked_at >= cutoff
        ).count()
    social_links = []
    if profile and profile.social_links:
        try: social_links = _json.loads(profile.social_links)
        except Exception: pass
    return {
        "username": user.username,
        "first_name": user.first_name or user.username or "",
        "profile": {
            "display_name": profile.display_name if profile else (user.first_name or user.username or ""),
            "bio": profile.bio if profile else "",
            "avatar_url": (profile.avatar_r2_url or profile.avatar_data or "") if profile else "",
            "bg_color": (profile.bg_color or "#0f172a") if profile else "#0f172a",
            "bg_image_url": (profile.bg_image or "") if profile else "",  # linkhub-specific bg only
            "text_color": (profile.text_color or "#ffffff") if profile else "#ffffff",
            "btn_color": (profile.btn_color or "#0ea5e9") if profile else "#0ea5e9",
            "btn_text_color": (profile.btn_text_color or "#ffffff") if profile else "#ffffff",
            "accent_color": (profile.accent_color or "#ffffff") if profile else "#ffffff",
            "font_family": (profile.font_family or "DM Sans") if profile else "DM Sans",
            "btn_style_type": (getattr(profile, 'btn_style_type', None) or "3d") if profile else "3d",
            "btn_radius": (getattr(profile, 'btn_radius', None) or "12px") if profile else "12px",
            "btn_font_size": (getattr(profile, 'btn_font_size', None) or 15) if profile else 15,
            "btn_align": (getattr(profile, 'btn_align', None) or "center") if profile else "center",
            "arrow_style": (getattr(profile, 'arrow_style', None) or "arrow") if profile else "arrow",
            "icon_size": (getattr(profile, 'icon_size', None) or 22) if profile else 22,
            "arrow_size": (getattr(profile, 'arrow_size', None) or 16) if profile else 16,
            "is_published": profile.is_published if profile else True,
            "total_views": profile.total_views if profile else 0,
        } if True else None,
        "links": links,
        "social_links": social_links,
        "total_clicks": total_clicks,
        "click_30d": click_30d,
    }
@limiter.limit("20/minute")
@app.post("/api/proseller/chat")
async def api_proseller_chat(request: Request, user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """ProSeller AI chat — sales assistant."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    body = await request.json()
    message = body.get("message", "").strip()
    if not message:
        return JSONResponse({"error": "Message required"}, status_code=400)
    history = body.get("history", [])
    try:
        messages = []
        for h in history[-10:]:
            if h.get("role") and h.get("content"):
                messages.append({"role": h["role"], "content": h["content"]})
        messages.append({"role": "user", "content": message})

        # System prompt — populated with verified facts from docs/commission-spec.md.
        # IMPORTANT: any change to product pricing, commission structure, or
        # platform features here MUST be reflected in commission-spec.md first
        # (or vice-versa). Caught 10 May 2026: previous version told Grok almost
        # nothing about SuperAdPro, so it hallucinated $27/mo pricing and
        # "unlimited traffic" framing — both wrong, both reputationally dangerous
        # if a member copy-pasted the response into a prospect DM.
        system_prompt = (
            f"You are ProSeller AI, a sales coach for SuperAdPro members. "
            f"The member you're helping is @{user.username or 'a member'}.\n\n"
            "═══ VERIFIED FACTS ABOUT SUPERADPRO — ONLY USE THESE NUMBERS ═══\n\n"
            "WHAT IT IS\n"
            "SuperAdPro is an affiliate marketing platform combining AI marketing tools "
            "with a multi-stream commission structure. It is NOT a traffic source, "
            "ad network, traffic-buying service, or get-rich-quick programme. Members "
            "use the platform's AI tools (SuperPages, LinkHub, ProSeller, Creative "
            "Studio, MyLeads) to build their own marketing funnels for any business "
            "they choose. The compensation plan is OPTIONAL — many members use the "
            "tools without ever referring anyone.\n\n"
            "MEMBERSHIP\n"
            "- Partner: $20/month or $200/year (saves about 2 months)\n"
            "- Founder: $15/month locked for life — first 100 members only, now all claimed\n"
            "- There is NO other pricing. Never invent prices like $27, $35, $47, $97 etc.\n\n"
            "FOUR INCOME STREAMS (only describe these — do not invent others)\n"
            "1. Membership commissions: sponsor earns $10/month for every active referral, "
            "   recurring for as long as they stay active.\n"
            "2. 4×4 Profit Grid (Campaign Tiers $20 to $1,000): 30% direct + 50% across "
            "   8 uni-level (6.25% each). Requires owning the tier to earn at that tier.\n"
            "3. Creative Studio Credit Commissions (packs $20 to $1,000): a flat 20% "
            "   of the pack price paid to the direct sponsor when a referral buys a credit "
            "   pack. Single level — no matrix, spillover, or completion bonus. No tier ownership required.\n"
            "4. Course Academy: pass-up structure, requires owning the course tier.\n\n"
            "WHAT YOU MUST NEVER DO\n"
            "- NEVER invent prices, percentages, or income figures not listed above\n"
            "- NEVER make income claims like 'I'm crushing it' or 'I'm earning $X/month'\n"
            "  (compliance risk — past results don't predict future earnings)\n"
            "- NEVER describe SuperAdPro as 'traffic', 'leads', 'unlimited X', or any "
            "  claim that the platform delivers customers/sales TO members\n"
            "- NEVER use fake urgency ('limited spots', 'price going up'), high-pressure "
            "  closes, or manipulative language\n"
            "- NEVER imply earnings are guaranteed, easy, fast, or passive\n"
            "- NEVER include the member's affiliate link unless they've given it to you\n"
            "- NEVER use ALL CAPS or excessive emojis\n\n"
            "WHAT GOOD RESPONSES LOOK LIKE\n"
            "- Honest, low-key, conversational. Curiosity over hype.\n"
            "- Lead with what the prospect cares about, not what the member wants to sell.\n"
            "- For objections: acknowledge the concern genuinely, share a true perspective, "
            "  invite them to look at it themselves rather than pushing.\n"
            "- For pitches: focus on the AI tools as utility, not the comp plan as opportunity.\n"
            "- Concise. People skim DMs. Two short paragraphs > one wall of text.\n\n"
            "HANDLING UNCERTAINTY\n"
            "If the member asks you something where you genuinely don't know the answer "
            "(e.g. 'what's the rule on X?'), say so plainly: 'I don't want to guess on "
            "that — best to check the official compensation plan page or ask in the member "
            "community.' DO NOT invent.\n"
        )

        from .grok_service import ai_text_generate
        reply = await ai_text_generate(
            system=system_prompt,
            messages=messages,
            max_tokens=1024,
            temperature=0.7,
        )
        return {"response": reply}
    except Exception as e:
        return {"response": f"Sorry, I'm temporarily unavailable. Error: {str(e)[:100]}"}
# /api/funnels/templates removed 26 May 2026 — never called from any
# frontend, and returned stale niche keys (forex/crypto/etc.) that the
# from-template endpoint no longer accepts. Frontend gets its template
# list from frontend/src/data/funnelTemplates.js.
@app.post("/api/funnels/duplicate/{page_id}")
def funnel_duplicate(page_id: int, request: Request, user: User = Depends(get_current_user),
                     db: Session = Depends(get_db)):
    """Duplicate an existing funnel page."""
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    original = db.query(FunnelPage).filter(FunnelPage.id == page_id, FunnelPage.user_id == user.id).first()
    if not original:
        return JSONResponse({"error": "Page not found"}, status_code=404)
    import re as _re
    new_page = FunnelPage(
        user_id=user.id,
        title=f"{original.title} (copy)",
        template_type=original.template_type,
        status="draft",
        headline=original.headline,
        subheadline=original.subheadline,
        body_copy=original.body_copy,
        cta_text=original.cta_text,
        cta_url=original.cta_url,
        video_url=original.video_url,
        image_url=original.image_url,
        sections_json=original.sections_json,
        color_scheme=original.color_scheme,
        accent_color=original.accent_color,
        custom_bg=original.custom_bg,
        font_family=original.font_family,
        custom_css=original.custom_css,
        gjs_components=original.gjs_components,
        gjs_styles=original.gjs_styles,
        gjs_html=original.gjs_html,
        gjs_css=original.gjs_css,
        meta_description=original.meta_description,
    )
    db.add(new_page)
    db.flush()
    slug_base = _re.sub(r'[^a-z0-9]+', '-', (original.title or 'page').lower()).strip('-')
    new_page.slug = f"{user.username.lower()}/{slug_base}-copy-{new_page.id}"
    db.commit()
    return JSONResponse({"success": True, "id": new_page.id, "edit_url": f"/funnels/visual/{new_page.id}"})
