# ── Creative Studio generate hardening (Option A) ──────────────────────────
# Max seconds to wait for a provider to ACCEPT a job (return a task_id).
# Providers normally ACK in 1-5s; this ceiling stops a momentarily-slow
# provider from hanging the request past Cloudflare's ~100s edge timeout, which
# would otherwise reach the member as a non-JSON "Network error".
_SC_SUBMIT_TIMEOUT_S = 45

# superscene_videos.client_token backs generate idempotency. On production
# SKIP_MIGRATIONS=true means the column lands only after the one-shot
# /admin/api/apply-superscene-idempotency endpoint is tapped. Until then we
# degrade to the old (non-idempotent) behaviour instead of 500-ing. Latches
# True once the column is confirmed present; re-probes cheaply while False so it
# self-activates the moment the column appears (no app restart needed).
_SC_CLIENT_TOKEN_OK = False
def _sc_idempotency_ready(db) -> bool:
    global _SC_CLIENT_TOKEN_OK
    if _SC_CLIENT_TOKEN_OK:
        return True
    try:
        from sqlalchemy import text as _t
        db.execute(_t("SELECT client_token FROM superscene_videos LIMIT 1"))
        _SC_CLIENT_TOKEN_OK = True
    except Exception:
        db.rollback()
        _SC_CLIENT_TOKEN_OK = False
    return _SC_CLIENT_TOKEN_OK


def _gen_crumb(user_id, step, detail=""):
    """TEMP 502 diagnostic: persist the last generate step reached per user in an
    isolated short-lived session that COMMITS immediately — so a 502 where the
    worker is killed / the edge gives up (no Python exception we can catch) still
    records exactly how far the request got. Never raises into generate."""
    try:
        from .database import SessionLocal
        from sqlalchemy import text as _t
        s = SessionLocal()
        try:
            s.execute(_t(
                "CREATE TABLE IF NOT EXISTS gen_diag (user_id INTEGER PRIMARY KEY, "
                "step TEXT, detail TEXT, at TIMESTAMP DEFAULT (now() AT TIME ZONE 'utc'))"
            ))
            s.execute(_t(
                "INSERT INTO gen_diag (user_id, step, detail, at) "
                "VALUES (:u, :s, :d, now() AT TIME ZONE 'utc') "
                "ON CONFLICT (user_id) DO UPDATE SET step=:s, detail=:d, at=now() AT TIME ZONE 'utc'"
            ), {"u": int(user_id or 0), "s": step, "d": (detail or "")[:200]})
            s.commit()
        finally:
            s.close()
    except Exception:
        pass


@app.get("/admin/api/gen-diag")
def admin_gen_diag(
    user_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read the last generate breadcrumb for a user (TEMP 502 diagnostic). The
    'step' is the furthest point reached before the worker died; 'age_seconds'
    confirms it's fresh from a just-now reproduce. Admin-only, GET."""
    from fastapi.responses import JSONResponse
    from sqlalchemy import text as _t
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    # Ensure the table exists so a missing ROW is unambiguous: it then means the
    # request died before the first breadcrumb (auth_ok), not that the table was
    # never created.
    try:
        db.execute(_t(
            "CREATE TABLE IF NOT EXISTS gen_diag (user_id INTEGER PRIMARY KEY, "
            "step TEXT, detail TEXT, at TIMESTAMP DEFAULT (now() AT TIME ZONE 'utc'))"
        ))
        db.commit()
    except Exception:
        db.rollback()
    # SELF-TEST the writer: call _gen_crumb for a sentinel user, then read it
    # back. If this round-trips, _gen_crumb works and a missing real-user crumb
    # genuinely means the request died before reaching any crumb. If it does NOT
    # round-trip, the breadcrumb instrument itself is broken (and prior "no
    # breadcrumb" reads prove nothing).
    crumb_works = None
    try:
        _gen_crumb(-777, "reader_selftest", "ping")
        chk = db.execute(_t("SELECT step FROM gen_diag WHERE user_id = -777")).fetchone()
        crumb_works = bool(chk and chk.step == "reader_selftest")
    except Exception:
        db.rollback()
        crumb_works = None

    # Also read the tiergate_enter sentinel (keyed -1): did the request reach the
    # top of the tier-gate at all?
    edge = None
    try:
        er = db.execute(_t(
            "SELECT step, EXTRACT(EPOCH FROM ((now() AT TIME ZONE 'utc') - at)) AS age_s "
            "FROM gen_diag WHERE user_id = -1"
        )).fetchone()
        if er:
            edge = {"step": er.step, "age_seconds": round(float(er.age_s), 1) if er.age_s is not None else None}
    except Exception:
        db.rollback()

    try:
        row = db.execute(_t(
            "SELECT step, detail, at, "
            "EXTRACT(EPOCH FROM ((now() AT TIME ZONE 'utc') - at)) AS age_s "
            "FROM gen_diag WHERE user_id = :u"
        ), {"u": user_id}).fetchone()
    except Exception as e:
        db.rollback()
        return JSONResponse({"ok": True, "found": False, "crumb_works": crumb_works,
                             "tiergate_enter": edge, "note": f"query error ({type(e).__name__})"})
    if not row:
        return JSONResponse({"ok": True, "found": False, "crumb_works": crumb_works,
                             "tiergate_enter": edge,
                             "note": ("reached tier-gate but died in its DB user-lookup"
                                      if (edge and edge.get("age_seconds") is not None and edge["age_seconds"] < 120)
                                      else "request died before even the tier-gate (earlier middleware / never reached app)")})
    return JSONResponse({
        "ok": True, "found": True, "crumb_works": crumb_works, "tiergate_enter": edge,
        "step": row.step, "detail": row.detail,
        "at": str(row.at),
        "age_seconds": round(float(row.age_s), 1) if row.age_s is not None else None,
    })


@app.get("/admin/api/grok-video-test")
async def admin_grok_video_test(
    request: Request,
    prompt: str = "a red sports car driving along a coastal road at sunset",
    image_url: str = "",
    poll: str = "",
    db: Session = Depends(get_db),
):
    """TEMP: empirically confirm xAI Grok Imagine video works with our live key
    BEFORE rerouting all generation to Grok. Admin-only, GET (tappable on mobile).

    Submit:  /admin/api/grok-video-test?prompt=...            (text-to-video)
             /admin/api/grok-video-test?prompt=...&image_url=  (image-to-video)
    Poll:    /admin/api/grok-video-test?poll=grok:REQUEST_ID   (check status + URL)
    """
    from fastapi.responses import JSONResponse
    from . import grok_imagine
    user = get_current_user(request, db)
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "Admin only"}, status_code=403)

    # Poll mode: check an in-flight job and return the finished video URL.
    if poll:
        try:
            res = await grok_imagine.poll_video_status(poll)
            return JSONResponse({"ok": True, "mode": "poll", "result": res})
        except Exception as e:
            return JSONResponse({"ok": False, "mode": "poll", "error": f"{type(e).__name__}: {e}"})

    # Submit mode: fire a real generation at xAI.
    image_urls = [image_url] if image_url.strip() else None
    try:
        res = await grok_imagine.generate_video(
            model_key="grok-video",
            prompt=prompt,
            duration=5,
            ratio="16:9",
            image_urls=image_urls,
            resolution="720p",
        )
        note = ("SUCCESS — Grok accepted the job. Copy task_id and poll it: "
                "/admin/api/grok-video-test?poll=<task_id>") if res.get("success") else \
               ("FAILED — this is the real reason Grok video won't run with our "
                "account (usually: video billing not enabled/funded on the xAI key).")
        return JSONResponse({"ok": True, "mode": "image-to-video" if image_urls else "text-to-video",
                             "result": res, "note": note})
    except Exception as e:
        return JSONResponse({"ok": False, "error": f"{type(e).__name__}: {e}"})


@app.post("/api/superscene/generate")
async def sc_generate(request: Request, db: Session = Depends(get_db)):
    """Thin guard so any crash returns JSON (never a non-JSON 'Network error')
    and surfaces the exception for diagnosis. Real logic in _sc_generate_impl."""
    try:
        return await _sc_generate_impl(request, db)
    except HTTPException:
        raise
    except Exception as e:
        import traceback
        logger.error("sc_generate crashed: %s\n%s", e, traceback.format_exc())
        try:
            db.rollback()
        except Exception:
            pass
        from fastapi.responses import JSONResponse
        return JSONResponse(status_code=500, content={
            "success": False,
            "error": f"{type(e).__name__}: {e}",
            "where": "sc_generate",
        })


async def _sc_generate_impl(request: Request, db: Session):
    """
    Submit a video generation task.
    Body: {model_key, prompt, duration, ratio, image_urls?, generate_audio?}
    """
    from .database import SuperSceneCredit, SuperSceneVideo
    from .superscene_evolink import generate_video, calc_credits, resolve_video_model

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")
    _gen_crumb(user.id, "auth_ok")

    body = await request.json()
    _gen_crumb(user.id, "body_parsed")
    model_key      = body.get("model_key", "kling3")
    prompt         = (body.get("prompt") or "").strip()
    duration       = int(body.get("duration", 10))
    ratio          = body.get("ratio", "16:9")
    resolution     = body.get("resolution", "1080p")
    neg_prompt     = (body.get("negative_prompt") or "").strip()
    image_urls     = body.get("image_urls") or []
    style_refs     = body.get("style_refs") or []
    gen_audio      = bool(body.get("generate_audio", False))
    seed           = body.get("seed")
    if seed is not None:
        seed = int(seed)

    if not prompt:
        raise HTTPException(status_code=400, detail="Prompt is required")
    if duration < 3 or duration > 30:
        raise HTTPException(status_code=400, detail="Duration must be between 3 and 30 seconds")

    # Smart routing: if model_key is a tier name, resolve to actual model
    tier_keys = {"quick", "standard", "premium", "ultra"}
    tier_used = model_key if model_key in tier_keys else None
    if tier_used:
        is_i2v = bool(image_urls and len(image_urls) > 0)
        model_key = resolve_video_model(tier_used, is_i2v=is_i2v)

    credits_needed = calc_credits(model_key, duration, with_audio=gen_audio)

    # ── Idempotency: reuse a prior result for the same client attempt ──
    # The frontend sends a stable client_token per generate attempt and reuses
    # it when the member manually retries after a dropped connection. If we
    # already have a row for (user, token), return it WITHOUT charging again.
    client_token = (body.get("client_token") or "").strip() or None
    idem_ready = _sc_idempotency_ready(db) if client_token else False
    if client_token and idem_ready:
        prior = (
            db.query(SuperSceneVideo)
              .filter(SuperSceneVideo.user_id == user.id,
                      SuperSceneVideo.client_token == client_token)
              .first()
        )
        if prior is not None:
            bal = _get_or_create_sc_credits(user.id, db).balance
            if prior.status == "failed":
                # Definitive prior failure (already refunded). Tell the client;
                # it mints a fresh token for a genuine new attempt.
                return {
                    "success": False,
                    "idempotent": True,
                    "status": "failed",
                    "detail": "The previous attempt failed and your credits were refunded. Please try again.",
                    "credits_remaining": bal,
                }
            return {
                "success": True,
                "idempotent": True,
                "task_id": prior.task_id,
                "video_id": prior.id,
                "mode": "image-to-video" if image_urls else "text-to-video",
                "credits_used": prior.credits_used,
                "credits_remaining": bal,
                "status": prior.status,
            }

    # Check balance
    credit_row = _get_or_create_sc_credits(user.id, db)
    if credit_row.balance < credits_needed:
        raise HTTPException(status_code=402, detail=f"Insufficient credits. Need {credits_needed}, have {credit_row.balance}.")

    # Deduct credits optimistically
    _gen_crumb(user.id, "balance_ok", f"need={credits_needed} have={credit_row.balance} model={model_key} i2v={bool(image_urls)}")
    credit_row.balance -= credits_needed
    db.commit()
    _gen_crumb(user.id, "deducted")

    # Submit to provider — route based on model, with a hard ceiling so a slow
    # provider ACK can't hang past Cloudflare's edge timeout (which would reach
    # the member as a non-JSON "Network error"). On timeout/error we refund and
    # return a clean, retryable JSON message.
    # All video generation routes to Grok Imagine (xAI) — see _route_generate_video.

    _gen_crumb(user.id, "provider_start", f"model={model_key}")
    try:
        result = await asyncio.wait_for(
            _route_generate_video(
                model_key, prompt, duration, ratio,
                image_urls=image_urls if image_urls else None,
                style_refs=style_refs if style_refs else None,
                generate_audio=gen_audio,
                resolution=resolution,
                negative_prompt=neg_prompt if neg_prompt else None,
                seed=seed,
            ),
            timeout=_SC_SUBMIT_TIMEOUT_S,
        )
    except asyncio.TimeoutError:
        credit_row.balance += credits_needed
        db.commit()
        _gen_crumb(user.id, "provider_done", "timeout")
        # NB: a 5xx here gets replaced by the edge (Cloudflare/Railway) with an
        # opaque HTML error page, hiding the reason from the member. Return 200
        # with success:false so our JSON actually reaches the frontend (which
        # treats "200 + no task_id" as a clean failure and shows .error).
        return JSONResponse(status_code=200, content={
            "success": False,
            "error": "The video service is taking longer than usual to respond. Your credits have not been charged — please try again in a moment.",
            "credits_remaining": credit_row.balance,
        })
    except HTTPException:
        raise
    except Exception as _provider_exc:
        credit_row.balance += credits_needed
        db.commit()
        _gen_crumb(user.id, "provider_done", f"exception={type(_provider_exc).__name__}")
        return JSONResponse(status_code=200, content={
            "success": False,
            "error": "Video generation could not be started. Your credits have not been charged — please try again.",
            "credits_remaining": credit_row.balance,
        })

    if not result["success"]:
        # Refund on failure
        real_err = str(result.get("error") or "Video generation failed")
        _gen_crumb(user.id, "provider_done", f"success=False err={real_err[:80]}")
        credit_row.balance += credits_needed
        db.commit()
        # The raw provider error (e.g. an upstream account-quota message) is for
        # admins/diagnostics only — members get a clean message. Return 200 so the
        # edge can't replace our JSON with a blank 502 page.
        member_msg = ("Video generation is temporarily unavailable right now. "
                      "Your credits have not been charged — please try again later.")
        shown = real_err if getattr(user, "is_admin", False) else member_msg
        return JSONResponse(status_code=200, content={
            "success": False,
            "error": shown,
            "credits_remaining": credit_row.balance,
        })

    task_id = result["task_id"]
    mode = result.get("mode", "text-to-video")
    _gen_crumb(user.id, "provider_ok", f"task={str(task_id)[:60]}")

    # Model name map for display
    model_names = {
        "kling-o3": "Kling O3", "kling3": "Kling 3.0",
        "seedance": "Seedance 1.5 Pro", "sora2": "Sora 2 Pro",
        "veo31": "Veo 3.1 Fast", "veo31-pro": "Veo 3.1 Pro 4K",
        "hailuo23": "Hailuo 2.3", "hailuo23-fast": "Hailuo 2.3 Fast",
        "hailuo02": "Hailuo 02", "wan26": "WAN 2.6",
        "grok-video": "Grok Imagine", "sora2-max": "Sora 2 Max",
        "kling-motion": "Kling Motion Control", "kling-edit": "Kling O3 Edit",
        "veo31-extend": "Veo 3.1 Extend",
    }

    # Record video
    video = SuperSceneVideo(
        user_id=user.id,
        task_id=task_id,
        model_key=model_key,
        model_name=model_names.get(model_key, model_key),
        prompt=prompt,
        duration=duration,
        ratio=ratio,
        status="pending",
        credits_used=credits_needed,
    )
    if client_token and idem_ready:
        video.client_token = client_token
    db.add(video)

    # ── Credit commissions are handled by the Credit Matrix ──
    # When members BUY credit packs, they enter the 3x3 matrix
    # Matrix pays level commissions + completion bonuses
    # No per-usage commission here — that would duplicate the matrix

    try:
        db.commit()
    except IntegrityError:
        # Concurrent retry with the same client_token lost the unique-index
        # race. Refund THIS request and return the row that won — never double
        # charge, never duplicate the record.
        db.rollback()
        credit_row = _get_or_create_sc_credits(user.id, db)
        credit_row.balance += credits_needed
        db.commit()
        winner = (
            db.query(SuperSceneVideo)
              .filter(SuperSceneVideo.user_id == user.id,
                      SuperSceneVideo.client_token == client_token)
              .first()
        )
        if winner is not None:
            return {
                "success": True,
                "idempotent": True,
                "task_id": winner.task_id,
                "video_id": winner.id,
                "mode": mode,
                "credits_used": winner.credits_used,
                "credits_remaining": credit_row.balance,
                "status": winner.status,
            }
        raise HTTPException(status_code=409, detail="Duplicate request. Please refresh and try again.")
    db.refresh(video)

    return {
        "success": True,
        "task_id": task_id,
        "video_id": video.id,
        "mode": mode,
        "credits_used": credits_needed,
        "credits_remaining": credit_row.balance,
    }
@app.get("/admin/api/apply-superscene-idempotency")
def admin_apply_superscene_idempotency(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot: add superscene_videos.client_token + the partial unique index
    that backs Creative Studio generate idempotency. Needed because
    SKIP_MIGRATIONS=true on production means run_migrations() doesn't apply it on
    deploy. Idempotent (ADD COLUMN / CREATE INDEX IF NOT EXISTS). Admin-only,
    GET (phone-friendly). Tap once after the deploy lands.
    """
    from fastapi.responses import JSONResponse
    from sqlalchemy import text as _text

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    results = {}

    # 1) Add the column (safe / idempotent).
    try:
        db.execute(_text(
            "ALTER TABLE superscene_videos ADD COLUMN IF NOT EXISTS client_token VARCHAR(64)"
        ))
        db.commit()
        results["column"] = "ok"
    except Exception as e:
        db.rollback()
        results["column"] = f"error: {e}"
        return JSONResponse({"ok": False, "results": results}, status_code=500)

    # 2) Interlock: a unique index would fail if duplicate non-null pairs exist.
    #    Brand-new column ⇒ all NULL, so this is normally zero; check anyway.
    dup = db.execute(_text(
        "SELECT COUNT(*) AS n FROM ("
        "  SELECT user_id, client_token FROM superscene_videos "
        "  WHERE client_token IS NOT NULL "
        "  GROUP BY user_id, client_token HAVING COUNT(*) > 1"
        ") d"
    )).fetchone()
    if dup and dup.n:
        results["index"] = f"refused — {dup.n} duplicate (user, token) pair(s) exist"
        return JSONResponse({"ok": False, "results": results}, status_code=409)

    # 3) Create the partial unique index.
    try:
        db.execute(_text(
            "CREATE UNIQUE INDEX IF NOT EXISTS uniq_superscene_video_client_token "
            "ON superscene_videos(user_id, client_token) WHERE client_token IS NOT NULL"
        ))
        db.commit()
        results["index"] = "ok"
    except Exception as e:
        db.rollback()
        results["index"] = f"error: {e}"
        return JSONResponse({"ok": False, "results": results}, status_code=500)

    global _SC_CLIENT_TOKEN_OK
    _SC_CLIENT_TOKEN_OK = True
    return JSONResponse({
        "ok": True,
        "results": results,
        "note": "Creative Studio generate idempotency is now active.",
    })


@app.get("/admin/api/apply-ad-studio-schema")
def admin_apply_ad_studio_schema(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot: create the ad_assets table that backs Ad Studio (the Creative
    Studio repositioning). Needed because SKIP_MIGRATIONS=true on production
    means SQLAlchemy create_all()/run_migrations() don't build it on deploy.
    Idempotent (CREATE TABLE / INDEX IF NOT EXISTS). Admin-only, GET
    (phone-friendly). Tap once after the deploy lands."""
    from fastapi.responses import JSONResponse
    from sqlalchemy import text as _text

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    results = {}

    # 1) The table.
    try:
        db.execute(_text("""
            CREATE TABLE IF NOT EXISTS ad_assets (
                id               SERIAL PRIMARY KEY,
                user_id          INTEGER NOT NULL REFERENCES users(id),
                kind             VARCHAR(10) NOT NULL DEFAULT 'image',
                style            VARCHAR(30),
                asset_url        TEXT,
                thumb_url        TEXT,
                destination_type VARCHAR(20) NOT NULL DEFAULT 'capture',
                destination_url  TEXT,
                capture_page_id  INTEGER,
                ad_tag           VARCHAR(40),
                has_qr           BOOLEAN NOT NULL DEFAULT FALSE,
                html5_export_url TEXT,
                client_token     VARCHAR(64),
                status           VARCHAR(20) DEFAULT 'pending',
                credits_used     INTEGER NOT NULL DEFAULT 0,
                created_at       TIMESTAMP DEFAULT (now() AT TIME ZONE 'utc'),
                expires_at       TIMESTAMP,
                completed_at     TIMESTAMP
            )
        """))
        db.commit()
        results["table"] = "ok"
    except Exception as e:
        db.rollback()
        results["table"] = f"error: {e}"
        return JSONResponse({"ok": False, "results": results}, status_code=500)

    # 2) Indexes: per-user gallery listing, expiry sweep, idempotency.
    for ddl in (
        "CREATE INDEX IF NOT EXISTS idx_ad_assets_user ON ad_assets(user_id)",
        "CREATE INDEX IF NOT EXISTS idx_ad_assets_expires ON ad_assets(expires_at)",
        "CREATE UNIQUE INDEX IF NOT EXISTS uniq_ad_assets_client_token "
        "ON ad_assets(user_id, client_token) WHERE client_token IS NOT NULL",
    ):
        try:
            db.execute(_text(ddl))
            db.commit()
        except Exception as e:
            db.rollback()
            results["index"] = f"error: {e}"
            return JSONResponse({"ok": False, "results": results}, status_code=500)
    results["index"] = "ok"

    return JSONResponse({
        "ok": True,
        "results": results,
        "note": "Ad Studio ad_assets table is ready.",
    })


