# ── Member Site & Blog platform — public rendering engine ────────────────────
# Server-rendered HTML (NOT React) for SEO. See app/blog_render.py.
from . import blog_render as _blogrender
import re as _re_blog


def _blog_slugify(val):
    out = _re_blog.sub(r"[^a-z0-9]+", "-", (val or "").lower()).strip("-")
    return out or "item"


def _blog_tags_for(post_ids, db):
    out = {}
    if not post_ids:
        return out
    rows = (db.query(BlogPostTag, BlogTag)
              .join(BlogTag, BlogPostTag.tag_id == BlogTag.id)
              .filter(BlogPostTag.post_id.in_(post_ids)).all())
    for pt, tag in rows:
        out.setdefault(pt.post_id, []).append((tag.name, tag.slug))
    return out


def _blog_post_view(post, tags_map):
    body = post.body or ""
    words = len(_re_blog.sub("<[^>]+>", " ", body).split())
    rm = max(1, round(words / 200)) if words else 4
    return _blogrender.PostView(
        title=post.title, slug=post.slug, excerpt=post.excerpt or "",
        cover_image=post.cover_image or "", body=body,
        published_at=post.published_at or post.created_at,
        read_minutes=rm, tags=tags_map.get(post.id, []), seed=post.id or 0,
        seo_title=post.seo_title or "", seo_description=post.seo_description or "",
        og_image=post.og_image or "", updated_at=getattr(post, "updated_at", None),
    )


def _ensure_blog_link_widgets_table(db: Session):
    """Lazy migration — one row per blog holding its link widgets as JSON.

    SKIP_MIGRATIONS=true on prod means tables aren't auto-created on deploy, so
    (like broadcast_log) we create this idempotently on first use. A standalone
    table — NOT a column on blogs — so it can never 500 a live blog read while a
    migration is pending, and needs no admin tap.
    """
    db.execute(text("""
        CREATE TABLE IF NOT EXISTS blog_link_widgets (
            blog_id INTEGER PRIMARY KEY,
            widgets_json TEXT,
            updated_at TIMESTAMP DEFAULT NOW()
        )
    """))


def _clean_link_widgets(raw):
    """Validate/normalise editor payload into the stored shape. Drops anything
    invalid; bounds everything. Returns list[{title, new_tab, links:[{label,url}]}].
    Caps: 8 widgets, 12 links each. URLs must be http(s) (auto-prefixed https://)."""
    out = []
    if not isinstance(raw, list):
        return out
    for w in raw[:8]:
        if not isinstance(w, dict):
            continue
        title = str(w.get("title") or "").strip()[:80]
        new_tab = bool(w.get("new_tab", True))
        links = []
        for ln in (w.get("links") or [])[:12]:
            if not isinstance(ln, dict):
                continue
            label = str(ln.get("label") or "").strip()[:80]
            url = str(ln.get("url") or "").strip()[:500]
            if not label or not url:
                continue
            low = url.lower()
            if low.startswith("javascript:") or low.startswith("data:"):
                continue
            if not (low.startswith("http://") or low.startswith("https://")):
                url = "https://" + url
            links.append({"label": label, "url": url})
        if title and links:
            out.append({"title": title, "new_tab": new_tab, "links": links})
    return out


_BUILTIN_SIDEBAR_BLOCKS = ["about", "subscribe", "popular", "topics"]


def _default_sidebar_layout(n_widgets, position="middle"):
    """Default block order. Honours the legacy top/middle/bottom position for
    where the link-widget group(s) sit relative to the built-ins."""
    lw = [f"lw:{i}" for i in range(max(0, n_widgets))]
    if position == "top":
        order = lw + ["about", "subscribe", "popular", "topics"]
    elif position == "bottom":
        order = ["about", "subscribe", "popular", "topics"] + lw
    else:
        order = ["about"] + lw + ["subscribe", "popular", "topics"]
    return [{"id": i, "show": True} for i in order]


def _reconcile_sidebar_layout(raw_layout, n_widgets):
    """Keep a valid, de-duped, fully-covered layout: every built-in block and
    every current link-widget group appears exactly once. Unknown/stale ids are
    dropped; newly-added blocks are appended in canonical order (visible)."""
    valid = set(_BUILTIN_SIDEBAR_BLOCKS) | {f"lw:{i}" for i in range(max(0, n_widgets))}
    out, seen = [], set()
    for e in (raw_layout or []):
        if not isinstance(e, dict):
            continue
        bid = e.get("id")
        if bid in valid and bid not in seen:
            out.append({"id": bid, "show": bool(e.get("show", True))})
            seen.add(bid)
    # append any valid ids not yet present, in canonical default order
    for e in _default_sidebar_layout(n_widgets):
        if e["id"] not in seen:
            out.append({"id": e["id"], "show": True})
            seen.add(e["id"])
    return out


def _get_blog_link_widgets(db: Session, blog_id: int):
    """Parsed config: {"widgets": [...], "layout": [{"id","show"},...]}.
    Tolerates the legacy list-only and {position,widgets} formats. Safe on
    every render."""
    try:
        _ensure_blog_link_widgets_table(db)
        row = db.execute(
            text("SELECT widgets_json FROM blog_link_widgets WHERE blog_id=:b"),
            {"b": blog_id}).fetchone()
        if not row or not row[0]:
            return {"widgets": [], "layout": _default_sidebar_layout(0)}
        data = json.loads(row[0])
        if isinstance(data, list):                         # oldest shape
            widgets = _clean_link_widgets(data)
            return {"widgets": widgets, "layout": _default_sidebar_layout(len(widgets))}
        widgets = _clean_link_widgets(data.get("widgets"))
        if "layout" in data:                               # current shape
            layout = _reconcile_sidebar_layout(data.get("layout"), len(widgets))
        else:                                              # {position,widgets}
            pos = str(data.get("position") or "middle").lower()
            layout = _default_sidebar_layout(len(widgets), pos if pos in ("top", "middle", "bottom") else "middle")
        return {"widgets": widgets, "layout": layout}
    except Exception:
        try:
            db.rollback()
        except Exception:
            pass
        return {"widgets": [], "layout": _default_sidebar_layout(0)}


def _save_blog_link_widgets(db: Session, blog_id: int, payload):
    """Upsert {widgets, layout}. Accepts a {widgets, layout} dict (or a bare
    widgets list). Reconciles the layout against the cleaned widget count.
    Returns the cleaned config dict."""
    if isinstance(payload, dict):
        widgets = _clean_link_widgets(payload.get("widgets"))
        layout = _reconcile_sidebar_layout(payload.get("layout"), len(widgets))
    else:
        widgets = _clean_link_widgets(payload)
        layout = _default_sidebar_layout(len(widgets))
    clean = {"widgets": widgets, "layout": layout}
    _ensure_blog_link_widgets_table(db)
    db.execute(text("""
        INSERT INTO blog_link_widgets (blog_id, widgets_json, updated_at)
        VALUES (:b, :j, NOW())
        ON CONFLICT (blog_id) DO UPDATE
            SET widgets_json = EXCLUDED.widgets_json, updated_at = NOW()
    """), {"b": blog_id, "j": json.dumps(clean)})
    db.commit()
    return clean


def _blog_context(blog, member, db, base_path):
    nav = []
    for m in (db.query(BlogMenu).filter(BlogMenu.blog_id == blog.id)
                .order_by(BlogMenu.position).all()):
        if m.link_type == "home":
            nav.append((m.label, base_path or "/"))
        elif m.link_type == "post":
            nav.append((m.label, f"{base_path}/p/{m.target}"))
        elif m.link_type == "tag":
            nav.append((m.label, f"{base_path}/t/{m.target}"))
        elif m.link_type == "external":
            nav.append((m.label, m.target or "#"))
        else:  # page
            nav.append((m.label, f"{base_path}/{m.target}"))
    social = []
    if blog.social_links:
        try:
            social = [(k, v) for k, v in json.loads(blog.social_links).items() if v]
        except Exception:
            social = []
    _lw = _get_blog_link_widgets(db, blog.id)
    return _blogrender.BlogRenderContext(
        blog_title=blog.title, tagline=blog.tagline or "", slug=blog.subdomain_slug,
        username=member.username if member else "member",
        theme=blog.theme or "banner", font=blog.font or "classic-serif",
        palette=getattr(blog, "palette", None) or "default",
        nav=nav, social=social, base_path=base_path,
        link_widgets=_lw["widgets"], sidebar_layout=_lw["layout"],
    )


def _resolve_blog(slug, db):
    # Public visibility = member-published AND NOT admin-suspended.
    return (db.query(Blog)
              .filter(Blog.subdomain_slug == slug,
                      Blog.is_published == True,            # noqa: E712
                      Blog.admin_suspended == False)        # noqa: E712
              .first())


def _blog_origin(request, slug):
    """(base_path, base_url) for rendering a blog: platform path on our own host,
    or root-relative + custom-domain origin when served via a bound custom domain."""
    bh = None
    try:
        bh = request.scope.get("blog_host")
    except Exception:
        bh = None
    if bh:
        return "", f"https://{bh}"
    return f"/sites/{slug}", _blogrender.BASE_URL


@app.get("/sites/{slug}")
def blog_public_feed(slug: str, request: Request, db: Session = Depends(get_db)):
    """Public blog home (post feed), server-rendered in the member's theme."""
    blog = _resolve_blog(slug, db)
    if not blog:
        return HTMLResponse("<h2>Site not found</h2>", status_code=404)
    member = db.query(User).filter(User.id == blog.member_id).first()
    base, _burl = _blog_origin(request, slug)
    ctx = _blog_context(blog, member, db, base)
    ctx.base_url = _burl
    ctx.csp_nonce = getattr(request.state, "csp_nonce", "")
    _pv = request.query_params.get("theme")
    if _pv and _pv in _blogrender.THEMES:
        ctx.theme = _pv
    _pp = request.query_params.get("palette")
    if _pp and (_pp == "default" or _pp in _blogrender.PALETTES):
        ctx.palette = _pp
    from sqlalchemy import or_ as _or, and_ as _and
    _now = datetime.utcnow()
    _pub = _or(BlogPost.status == "published",
               _and(BlogPost.status == "scheduled", BlogPost.scheduled_at != None,  # noqa: E711
                    BlogPost.scheduled_at <= _now))
    posts = (db.query(BlogPost)
               .filter(BlogPost.blog_id == blog.id, _pub)
               .order_by(BlogPost.published_at.desc().nullslast(),
                         BlogPost.created_at.desc()).limit(50).all())
    tags_map = _blog_tags_for([p.id for p in posts], db)
    ctx.posts = [_blog_post_view(p, tags_map) for p in posts]
    return HTMLResponse(_blogrender.render_blog_feed(ctx))


@app.get("/sites/{slug}/p/{post_slug}")
def blog_public_post(slug: str, post_slug: str, request: Request, db: Session = Depends(get_db)):
    """Public single-post page, server-rendered, with view counting."""
    blog = _resolve_blog(slug, db)
    if not blog:
        return HTMLResponse("<h2>Site not found</h2>", status_code=404)
    post = (db.query(BlogPost)
              .filter(BlogPost.blog_id == blog.id, BlogPost.slug == post_slug).first())
    if not post:
        return HTMLResponse("<h2>Post not found</h2>", status_code=404)
    _now = datetime.utcnow()
    _is_public = (post.status == "published" or
                  (post.status == "scheduled" and post.scheduled_at and post.scheduled_at <= _now))
    if not _is_public:
        # only the blog's owner may preview a draft/scheduled-future post (?preview=1)
        _viewer = get_current_user(request, db)
        if not (request.query_params.get("preview") == "1" and _viewer and _viewer.id == blog.member_id):
            return HTMLResponse("<h2>Post not found</h2>", status_code=404)
    member = db.query(User).filter(User.id == blog.member_id).first()
    base, _burl = _blog_origin(request, slug)
    ctx = _blog_context(blog, member, db, base)
    ctx.base_url = _burl
    ctx.csp_nonce = getattr(request.state, "csp_nonce", "")
    _pv = request.query_params.get("theme")
    if _pv and _pv in _blogrender.THEMES:
        ctx.theme = _pv
    _pp = request.query_params.get("palette")
    if _pp and (_pp == "default" or _pp in _blogrender.PALETTES):
        ctx.palette = _pp
    ctx.post = _blog_post_view(post, _blog_tags_for([post.id], db))
    ctx.comments_enabled = bool(blog.comments_enabled)
    if ctx.comments_enabled:
        _cmts = (db.query(BlogComment)
                   .filter(BlogComment.post_id == post.id, BlogComment.status == "approved")
                   .order_by(BlogComment.created_at.asc()).all())
        ctx.comments = [(c.author_name, c.body,
                         c.created_at.strftime("%b %-d, %Y") if c.created_at else "") for c in _cmts]
    ua = request.headers.get("user-agent", "").lower()
    _bots = ("googlebot", "bingbot", "slurp", "duckduckbot", "baiduspider", "yandexbot",
             "curl", "python-requests", "wget", "headlesschrome", "facebot", "semrush", "ahrefsbot")
    if request.query_params.get("preview") != "1" and ua and not any(b in ua for b in _bots):
        try:
            post.view_count = (post.view_count or 0) + 1
            db.add(BlogPostView(post_id=post.id,
                                referrer=(request.headers.get("referer", "") or "")[:300] or None))
            db.commit()
        except Exception:
            db.rollback()
    return HTMLResponse(_blogrender.render_blog_post(ctx))


def _provision_blog(member, db, with_samples=True):
    """Create a member's blog + starter content. Returns existing if present."""
    existing = db.query(Blog).filter(Blog.member_id == member.id).first()
    if existing:
        return existing
    base_slug = _blog_slugify(member.username)
    slug, n = base_slug, 1
    while db.query(Blog).filter(Blog.subdomain_slug == slug).first():
        n += 1
        slug = f"{base_slug}-{n}"
    blog = Blog(member_id=member.id, title=f"{member.username}'s Blog",
                tagline="Notes, ideas, and updates", subdomain_slug=slug,
                theme="banner", font="classic-serif", comments_enabled=True,
                is_published=True, policy_accepted_at=datetime.utcnow())
    db.add(blog); db.commit(); db.refresh(blog)
    if with_samples:
        db.add(BlogPost(blog_id=blog.id, slug="welcome", title="Welcome to my new site",
                        excerpt="This is your first post — edit it or delete it and make this space your own.",
                        body=("<p class='lead-para'>This is your very first post. Everything you see here "
                              "is yours to change.</p><p>Head into the editor to write your first real "
                              "article, swap the theme, or connect your own domain.</p>"),
                        status="published", published_at=datetime.utcnow()))
        db.add(BlogPage(blog_id=blog.id, slug="about", title="About",
                        body="<p>Tell your readers who you are.</p>", status="published",
                        show_in_nav=True, nav_order=1))
        db.add(BlogMenu(blog_id=blog.id, label="Home", link_type="home", position=0))
        db.add(BlogMenu(blog_id=blog.id, label="About", link_type="page", target="about", position=1))
        db.commit()
    return blog


