def _blog_post_brief(p, blog_slug, tags_map, news_map=None):
    return {
        "id": p.id, "title": p.title, "slug": p.slug, "status": p.status,
        "views": p.view_count or 0, "excerpt": p.excerpt or "",
        "tags": [n for n, _ in tags_map.get(p.id, [])],
        "published_at": (p.published_at.isoformat() if p.published_at else None),
        "updated_at": (p.updated_at.isoformat() if getattr(p, "updated_at", None) else None),
        "scheduled_at": (p.scheduled_at.isoformat() if getattr(p, "scheduled_at", None) else None),
        "url": f"/sites/{blog_slug}/p/{p.slug}",
        "newsletter_sent_at": (news_map or {}).get(p.id),
    }


@app.get("/api/blog/me")
def api_blog_me(request: Request, db: Session = Depends(get_db)):
    """Current member's blog + stats + posts (or {blog: null} if not launched)."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    blog = db.query(Blog).filter(Blog.member_id == user.id).first()
    if not blog:
        return {"blog": None, "is_pro": is_pro(user),
                "theme_accents": _blogrender.theme_default_accents()}
    posts = (db.query(BlogPost).filter(BlogPost.blog_id == blog.id)
               .order_by(BlogPost.created_at.desc()).all())
    tags_map = _blog_tags_for([p.id for p in posts], db)
    news_map = _blog_newsletter_map([p.id for p in posts], db)
    published = sum(1 for p in posts if p.status == "published")
    drafts = sum(1 for p in posts if p.status == "draft")
    scheduled = sum(1 for p in posts if p.status == "scheduled")
    total_views = sum((p.view_count or 0) for p in posts)
    return {
        "is_pro": is_pro(user),
        "theme_accents": _blogrender.theme_default_accents(),
        "blog": {
            "id": blog.id, "title": blog.title, "tagline": blog.tagline or "",
            "slug": blog.subdomain_slug, "theme": blog.theme or "banner",
            "palette": getattr(blog, "palette", None) or "default",
            "font": blog.font or "classic-serif",
            "social": _blog_social_dict(blog),
            "comments_enabled": bool(blog.comments_enabled),
            "url": f"/sites/{blog.subdomain_slug}",
            "is_published": bool(blog.is_published),
            "admin_suspended": bool(blog.admin_suspended),
            "published": published, "drafts": drafts, "scheduled": scheduled,
            "total_views": total_views, "subscribers": _blog_subscriber_count(blog, db),
            "pending_comments": (db.query(BlogComment).join(BlogPost, BlogComment.post_id == BlogPost.id)
                                 .filter(BlogPost.blog_id == blog.id, BlogComment.status == "pending").count()),
        },
        "posts": [_blog_post_brief(p, blog.subdomain_slug, tags_map, news_map) for p in posts],
    }


@app.post("/api/blog/launch")
@limiter.limit("10/hour")
def api_blog_launch(request: Request, db: Session = Depends(get_db)):
    """One-click 'Launch my site' — provision the member's blog + starter content."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "Your own website is included with Partner membership. Activate to launch your site."}, status_code=403)
    existing = db.query(Blog).filter(Blog.member_id == user.id).first()
    if existing:
        return {"ok": True, "slug": existing.subdomain_slug,
                "url": f"/sites/{existing.subdomain_slug}", "already": True}
    blog = _provision_blog(user, db, with_samples=True)
    return {"ok": True, "slug": blog.subdomain_slug, "url": f"/sites/{blog.subdomain_slug}"}


_VALID_THEMES = {"banner", "classic-sidebar", "journal", "bento", "cinematic", "glass"}
_VALID_PALETTES = {"default", "forest", "cobalt", "plum", "terracotta", "rose", "slate", "ink"}


@app.patch("/api/blog")
@limiter.limit("60/minute")
async def api_blog_update(payload: dict = Body(...), request: Request = None, db: Session = Depends(get_db)):
    """Owner-gated blog updates. Appearance now (theme/palette); Settings fields
    (title/tagline/social/comments) extend this later. Unknown values rejected."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    blog = _member_blog(user, db)
    if not blog:
        return JSONResponse({"error": "Launch your site first."}, status_code=400)
    if "theme" in payload:
        t = (payload.get("theme") or "").strip()
        if t in _VALID_THEMES:
            blog.theme = t
    if "palette" in payload:
        p = (payload.get("palette") or "").strip()
        if p in _VALID_PALETTES:
            blog.palette = p
    if "title" in payload:
        t = (payload.get("title") or "").strip()[:120]
        if t:
            blog.title = t
    if "tagline" in payload:
        blog.tagline = (payload.get("tagline") or "").strip()[:200]
    if "comments_enabled" in payload:
        blog.comments_enabled = bool(payload.get("comments_enabled"))
    if "is_published" in payload:
        blog.is_published = bool(payload.get("is_published"))
    if "social" in payload and isinstance(payload.get("social"), dict):
        import json as _json
        allowed = {"instagram", "x", "youtube", "tiktok", "linkedin", "facebook", "website"}
        clean = {}
        for k, v in payload["social"].items():
            if k in allowed and v:
                v = str(v).strip()[:300]
                if v.startswith("http://") or v.startswith("https://"):
                    clean[k] = v
        blog.social_links = _json.dumps(clean) if clean else None
    db.commit()
    return {"ok": True, "theme": blog.theme, "palette": getattr(blog, "palette", "default") or "default",
            "title": blog.title, "tagline": blog.tagline or "",
            "comments_enabled": bool(blog.comments_enabled), "is_published": bool(blog.is_published), "social": _blog_social_dict(blog)}


@app.get("/api/blog/link-widgets")
def api_blog_link_widgets_get(request: Request, db: Session = Depends(get_db)):
    """Owner: current link widgets for their blog."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    blog = _member_blog(user, db)
    if not blog:
        return JSONResponse({"error": "Launch your site first."}, status_code=400)
    return {"ok": True, **_get_blog_link_widgets(db, blog.id)}


