@app.post("/api/blog/upload-image")
@limiter.limit("40/minute")
async def api_blog_upload_image(file: UploadFile = File(...), request: Request = None, db: Session = Depends(get_db)):
    """Upload a blog image (cover or inline) to R2; return a real public URL.
    Reuses the funnel image pipeline (validate -> optimise -> R2). SVG is
    disallowed for blog images since it can carry scripts (XSS)."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "Partner membership required."}, status_code=403)
    allowed = {"image/jpeg", "image/png", "image/gif", "image/webp"}
    if file.content_type not in allowed:
        return JSONResponse({"error": "Only JPEG, PNG, GIF and WebP images are allowed."}, status_code=400)
    contents = await file.read()
    if len(contents) > 5 * 1024 * 1024:
        return JSONResponse({"error": "Image too large. Maximum size is 5MB."}, status_code=400)
    import uuid, os
    ext = os.path.splitext(file.filename or "image.jpg")[1].lower().lstrip(".")
    if ext not in {"jpg", "jpeg", "png", "gif", "webp"}:
        ext = "jpg"
    try:
        from app.image_optimise import optimise_image
        contents, ext, ctype = optimise_image(contents, ext)
    except Exception:
        ctype = file.content_type
    from app.r2_storage import r2_available, upload_image
    if r2_available():
        url = upload_image(contents, "blog-images", ext, ctype)
    else:
        upload_dir = os.path.join(os.path.dirname(os.path.dirname(__file__)), "static", "uploads")
        os.makedirs(upload_dir, exist_ok=True)
        filename = f"blog_{user.id}_{uuid.uuid4().hex[:12]}.{ext}"
        with open(os.path.join(upload_dir, filename), "wb") as fh:
            fh.write(contents)
        url = f"/static/uploads/{filename}"
    return JSONResponse({"success": True, "url": url})


@app.get("/admin/api/blog-post-debug")
def admin_blog_post_debug(post_id: int = 0, request: Request = None,
                          user: User = Depends(get_current_user),
                          db: Session = Depends(get_db)):
    """Read-only: why a post's image isn't showing. Dumps the stored body's
    <img> srcs and what survives sanitize (the public render), plus R2 config.
    Tappable: /admin/api/blog-post-debug?post_id=N  (N from /my-site/edit/N)
    """
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "Admin only"}, status_code=403)
    import re as _r
    from . import blog_render as _br
    p = db.query(BlogPost).filter(BlogPost.id == post_id).first()
    if not p:
        return JSONResponse({"error": "post not found", "post_id": post_id}, status_code=404)

    def _srcs(html):
        return _r.findall(r'<img\b[^>]*\bsrc\s*=\s*["\']([^"\']+)["\']', html or "", _r.I)

    raw_srcs = _srcs(p.body)
    sanitized = _br.sanitize_html(p.body or "")
    san_srcs = _srcs(sanitized)

    def _classify(s):
        if not s:                   return "empty"
        if s.startswith("data:"):   return "data-URL (base64) — STRIPPED by public sanitizer (data: not allowed)"
        if s.startswith("http"):    return "absolute http(s) — OK"
        if s.startswith("/"):       return "relative path — renders only if that path is served"
        return "other/unknown"

    import os as _os
    # Cover + OG are separate fields (not body). A cover base64/data-URL would
    # render as a broken placeholder at the top of the post even with empty body.
    cover = getattr(p, "cover_image", None)
    og = getattr(p, "og_image", None)
    # All posts in this blog, so we can spot content that's in a different post.
    siblings = (db.query(BlogPost).filter(BlogPost.blog_id == p.blog_id)
                  .order_by(BlogPost.id.desc()).limit(20).all())
    return {
        "post_id": p.id, "status": p.status, "title": p.title,
        "body_length": len(p.body or ""),
        "img_count_stored": len(raw_srcs),
        "stored_img_srcs": [{"src": s[:120], "kind": _classify(s)} for s in raw_srcs[:6]],
        "img_count_after_sanitize": len(san_srcs),
        "sanitize_dropped_images": len(raw_srcs) - len(san_srcs),
        "cover_image": {"src": (cover or "")[:120], "kind": _classify(cover or "")} if cover else None,
        "og_image": {"src": (og or "")[:120], "kind": _classify(og or "")} if og else None,
        "R2_PUBLIC_URL_set": bool(_os.getenv("R2_PUBLIC_URL", "").strip()),
        "all_posts_in_blog": [
            {"id": s.id, "title": s.title, "status": s.status,
             "body_len": len(s.body or ""),
             "has_cover": bool(getattr(s, "cover_image", None)),
             "cover_kind": _classify(getattr(s, "cover_image", "") or "")}
            for s in siblings
        ],
        "note": ("Check cover_image AND stored_img_srcs. data-URL = base64 (added "
                 "on old bundle) → stripped/broken on render. Use all_posts_in_blog "
                 "to find which post actually holds your content."),
    }


@app.get("/admin/api/blog-sanitize-all")
def admin_blog_sanitize_all(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """One-time/idempotent: sanitize all stored post bodies and migrate any
    legacy base64 cover images to R2."""
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "Admin only"}, status_code=403)
    posts = db.query(BlogPost).all()
    bodies, covers = 0, 0
    for p in posts:
        clean = _blogrender.sanitize_html(p.body or "")
        if clean != (p.body or ""):
            p.body = clean; bodies += 1
        if p.cover_image and p.cover_image.startswith("data:"):
            newc = _normalize_blog_image(p.cover_image, user)
            if newc != p.cover_image:
                p.cover_image = newc; p.og_image = newc or None; covers += 1
    db.commit()
    return JSONResponse({"ok": True, "posts": len(posts),
                         "bodies_sanitized": bodies, "covers_migrated": covers})


@app.get("/admin/api/blog-takedown")
def admin_blog_takedown(request: Request, member_id: int, restore: int = 0,
                        user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Admin kill-switch: take a member's whole site offline (restore=0) or
    bring it back (restore=1). Offline sites 404 to the public."""
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "Admin only"}, status_code=403)
    blog = db.query(Blog).filter(Blog.member_id == member_id).first()
    if not blog:
        return JSONResponse({"error": "No blog for that user."}, status_code=404)
    blog.admin_suspended = not bool(restore)
    db.commit()
    return JSONResponse({"ok": True, "slug": blog.subdomain_slug,
                         "admin_suspended": blog.admin_suspended,
                         "state": "restored" if restore else "taken down"})


