_BRANDKIT_FONTS = {"Sora", "DM Sans", "Inter", "Montserrat", "Poppins", "Roboto", "Lato", "Open Sans"}

@app.post("/api/superscene/brand-kit")
async def sc_brand_kit_save(request: Request, db: Session = Depends(get_db)):
    """Create or update the member's brand kit (validated)."""
    import re
    from .database import BrandKit
    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")
    body = await request.json()

    def _hex(v, default):
        v = (v or "").strip()
        return v if re.match(r"^#[0-9a-fA-F]{6}$", v) else default
    def _font(v, default):
        v = (v or "").strip()
        return v if v in _BRANDKIT_FONTS else default

    bk = db.query(BrandKit).filter_by(user_id=user.id).first()
    if not bk:
        bk = BrandKit(user_id=user.id); db.add(bk)
    bk.business_name = (body.get("business_name") or "")[:120]
    if "logo_url" in body:
        bk.logo_url = body.get("logo_url") or None
    bk.primary_color = _hex(body.get("primary_color"), "#0a1438")
    bk.accent_color  = _hex(body.get("accent_color"), "#06b6d4")
    bk.heading_font  = _font(body.get("heading_font"), "Sora")
    bk.body_font     = _font(body.get("body_font"), "DM Sans")
    bk.cta_text = (body.get("cta_text") or "")[:120]
    bk.cta_url  = (body.get("cta_url") or "")[:300]
    bk.show_intro    = bool(body.get("show_intro", True))
    bk.show_outro    = bool(body.get("show_outro", True))
    bk.show_logo_bug = bool(body.get("show_logo_bug", True))
    bk.captions      = bool(body.get("captions", True))
    db.commit()
    return {"success": True}


@app.post("/api/superscene/brand-kit/logo")
async def sc_brand_kit_logo(file: UploadFile = File(...), user: User = Depends(get_current_user),
                            db: Session = Depends(get_db)):
    """Upload a brand logo to R2 (persistent) and store it on the member's brand kit."""
    from fastapi.responses import JSONResponse
    from .database import BrandKit
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    allowed = {"image/png", "image/jpeg", "image/webp", "image/svg+xml"}
    if file.content_type not in allowed:
        return JSONResponse({"error": "Logo must be PNG, JPEG, WebP or SVG."}, status_code=400)
    contents = await file.read()
    if len(contents) > 4 * 1024 * 1024:
        return JSONResponse({"error": "Logo too large (max 4MB)."}, status_code=400)
    import os
    ext = os.path.splitext(file.filename or "logo.png")[1].lower().lstrip(".")
    if ext not in {"png", "jpg", "jpeg", "webp", "svg"}:
        ext = "png"
    from app.r2_storage import r2_available, upload_image
    if not r2_available():
        return JSONResponse({"error": "Storage unavailable, please try again later."}, status_code=503)
    url = upload_image(contents, "brand-kits/logos", ext, file.content_type)
    bk = db.query(BrandKit).filter_by(user_id=user.id).first()
    if not bk:
        bk = BrandKit(user_id=user.id); db.add(bk)
    bk.logo_url = url
    db.commit()
    return JSONResponse({"success": True, "url": url})


# ── SuperScene — Lip Sync (OmniHuman 1.5 via EvoLink) ────────

@app.post("/api/superscene/lipsync/generate")
async def sc_lipsync_generate(request: Request, db: Session = Depends(get_db)):
    """Generate lip-synced avatar video using OmniHuman 1.5.
    Body: {image_url, audio_url}
    """
    from .database import SuperSceneCredit, SuperSceneVideo
    import httpx

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    body = await request.json()
    image_url = (body.get("image_url") or "").strip()
    audio_url = (body.get("audio_url") or "").strip()

    if not image_url or not audio_url:
        raise HTTPException(status_code=400, detail="Both image_url and audio_url are required")

    # Lip sync costs 8 credits (~$0.80 revenue vs ~$0.50 cost = 37% margin)
    credits_needed = 8
    credit_row = _get_or_create_sc_credits(user.id, db)
    if credit_row.balance < credits_needed:
        raise HTTPException(status_code=402, detail=f"Insufficient credits. Need {credits_needed}, have {credit_row.balance}.")

    credit_row.balance -= credits_needed
    db.commit()

    api_key = os.getenv("EVOLINK_API_KEY", "")
    if not api_key:
        credit_row.balance += credits_needed
        db.commit()
        raise HTTPException(status_code=503, detail="EvoLink API key not configured")

    payload = {
        "model": "omnihuman-1.5",
        "image_urls": [image_url],
        "audio_url": audio_url,
    }

    try:
        async with httpx.AsyncClient(timeout=30.0) as client:
            resp = await client.post(
                "https://api.evolink.ai/v1/videos/generations",
                json=payload,
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                },
            )
            data = resp.json()

        logger.info(f"OmniHuman response ({resp.status_code}): {data}")

        if resp.status_code in (200, 201):
            task_id = data.get("id") or data.get("task_id")
            if task_id:
                # Save to videos table
                video = SuperSceneVideo(
                    user_id=user.id, task_id=str(task_id), model_key="omnihuman",
                    model_name="OmniHuman 1.5", prompt="Lip sync avatar",
                    duration=0, ratio="9:16", status="pending", credits_used=credits_needed,
                )
                db.add(video)
                db.commit()
                return {
                    "success": True,
                    "task_id": str(task_id),
                    "credits_used": credits_needed,
                    "credits_remaining": credit_row.balance,
                }
            credit_row.balance += credits_needed
            db.commit()
            raise HTTPException(status_code=502, detail="No task_id in response")

        credit_row.balance += credits_needed
        db.commit()
        err = data.get("error", {}).get("message", "OmniHuman generation failed") if isinstance(data.get("error"), dict) else str(data.get("error", "Failed"))
        raise HTTPException(status_code=502, detail=err)

    except HTTPException:
        raise
    except Exception as e:
        credit_row.balance += credits_needed
        db.commit()
        logger.exception("OmniHuman error")
        raise HTTPException(status_code=502, detail=str(e))

# ── SuperScene — AI Image Generator ──────────────────────────

@app.post("/api/superscene/image/generate")
async def sc_image_generate(request: Request, db: Session = Depends(get_db)):
    """Generate an image using EvoLink (Nano Banana 2, Seedream, GPT Image).
    Body: {model, prompt, quality, size, n?, image_urls?}
    """
    import httpx

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    body = await request.json()
    model_id   = body.get("model", "nano-banana-2")
    prompt     = (body.get("prompt") or "").strip()
    quality    = body.get("quality", "1K")
    size       = body.get("size", "1:1")
    n          = int(body.get("n", 1))
    image_urls = body.get("image_urls") or []

    if not prompt:
        raise HTTPException(status_code=400, detail="Prompt is required")

    # Credit cost based on quality — applies to ALL models including Gemini
    credit_map = {"1K": 1, "2K": 2, "4K": 4}
    credits_needed = credit_map.get(quality, 2) * n

    credit_row = _get_or_create_sc_credits(user.id, db)
    if credit_row.balance < credits_needed:
        raise HTTPException(status_code=402, detail=f"Insufficient credits. Need {credits_needed}, have {credit_row.balance}.")

    credit_row.balance -= credits_needed
    db.commit()

    # ── Gemini route — cheapest provider ──
    if model_id == "gemini-free":
        gemini_key = os.getenv("GEMINI_API_KEY", "")
        if not gemini_key:
            # Refund credits
            credit_row.balance += credits_needed
            db.commit()
            raise HTTPException(status_code=503, detail="Gemini API key not configured")

        try:
            gemini_model = "gemini-2.5-flash-image"
            url = f"https://generativelanguage.googleapis.com/v1beta/models/{gemini_model}:generateContent?key={gemini_key}"

            payload = {
                "contents": [{"role": "user", "parts": [{"text": prompt}]}],
                "generationConfig": {
                    "responseModalities": ["IMAGE", "TEXT"],
                }
            }

            async with httpx.AsyncClient(timeout=120.0) as client:
                resp = await client.post(url, json=payload)

            # Check for non-JSON error responses (403 HTML pages etc)
            content_type = resp.headers.get("content-type", "")
            if "application/json" not in content_type:
                logger.error(f"Gemini image: non-JSON response ({resp.status_code}): {resp.text[:300]}")
                credit_row.balance += credits_needed
                db.commit()
                raise HTTPException(status_code=502, detail=f"Gemini API returned error {resp.status_code}. Try another model.")

            data = resp.json()
            logger.info(f"Gemini image response ({resp.status_code}): {str(data)[:500]}")

            if resp.status_code != 200:
                error_msg = data.get("error", {}).get("message", str(data)[:200])
                logger.error(f"Gemini image error: {error_msg}")
                credit_row.balance += credits_needed
                db.commit()
                raise HTTPException(status_code=502, detail=f"Gemini: {error_msg}")

            candidates = data.get("candidates", [])
            if candidates:
                parts = candidates[0].get("content", {}).get("parts", [])
                images = []
                for part in parts:
                    if "inlineData" in part:
                        mime = part["inlineData"].get("mimeType", "image/png")
                        b64 = part["inlineData"].get("data", "")
                        if b64:
                            images.append(f"data:{mime};base64,{b64}")

                if images:
                    return {
                        "success": True,
                        "images": images,
                        "credits_used": credits_needed,
                        "credits_remaining": credit_row.balance,
                    }

            # No images returned — refund
            credit_row.balance += credits_needed
            db.commit()
            raise HTTPException(status_code=502, detail="Gemini image generation returned no images. Try a different prompt.")

        except HTTPException:
            raise
        except Exception as e:
            logger.error(f"Gemini image generation failed: {e}")
            credit_row.balance += credits_needed
            db.commit()
            raise HTTPException(status_code=502, detail=f"Gemini image generation failed: {str(e)[:200]}")

    # Route to Grok Imagine direct for grok-image models (no EvoLink markup)
    if model_id in ("grok-image", "grok-image-pro"):
        from .grok_imagine import generate_image as grok_img
        api_model = "grok-imagine-image-pro" if model_id == "grok-image-pro" else "grok-imagine-image"
        grok_result = await grok_img(prompt, n=n, model_id=api_model)
        if grok_result["success"]:
            return {
                "success": True,
                "images": grok_result["images"],
                "credits_used": credits_needed,
                "credits_remaining": credit_row.balance,
            }
        else:
            credit_row.balance += credits_needed
            db.commit()
            raise HTTPException(status_code=502, detail=grok_result.get("error", "Grok image generation failed"))

    api_key = os.getenv("EVOLINK_API_KEY", "")
    if not api_key:
        credit_row.balance += credits_needed
        db.commit()
        raise HTTPException(status_code=503, detail="EvoLink API key not configured")

    payload = {
        "model": model_id,
        "prompt": prompt,
        "quality": quality,
        "size": size,
        "n": n,
    }
    if image_urls:
        payload["image_urls"] = image_urls

    try:
        async with httpx.AsyncClient(timeout=60.0) as client:
            resp = await client.post(
                "https://api.evolink.ai/v1/images/generations",
                json=payload,
                headers={
                    "Authorization": f"Bearer {api_key}",
                    "Content-Type": "application/json",
                },
            )
            data = resp.json()

        logger.info(f"EvoLink image response ({resp.status_code}): {str(data)[:500]}")

        if resp.status_code in (200, 201):
            # Check if async (has task_id) or sync (has images directly)
            task_id = data.get("id") or data.get("task_id")
            images = data.get("data") or data.get("images") or []

            # If images returned directly
            if images and isinstance(images, list):
                urls = []
                for img in images:
                    if isinstance(img, dict):
                        urls.append(img.get("url") or img.get("image_url") or "")
                    elif isinstance(img, str):
                        urls.append(img)
                if urls and urls[0]:
                    return {
                        "success": True,
                        "images": urls,
                        "credits_used": credits_needed,
                        "credits_remaining": credit_row.balance,
                    }

            # If async, return task_id for polling
            if task_id:
                return {
                    "success": True,
                    "task_id": str(task_id),
                    "async": True,
                    "credits_used": credits_needed,
                    "credits_remaining": credit_row.balance,
                }

            # Fallback — check results
            results = data.get("results") or []
            if results:
                return {
                    "success": True,
                    "images": results if isinstance(results[0], str) else [r.get("url", "") for r in results],
                    "credits_used": credits_needed,
                    "credits_remaining": credit_row.balance,
                }

            credit_row.balance += credits_needed
            db.commit()
            return {"success": False, "error": "No images in response", "raw": data}

        credit_row.balance += credits_needed
        db.commit()
        err = data.get("error", {}).get("message", "Image generation failed") if isinstance(data.get("error"), dict) else str(data.get("error", "Failed"))
        raise HTTPException(status_code=502, detail=err)

    except HTTPException:
        raise
    except Exception as e:
        credit_row.balance += credits_needed
        db.commit()
        logger.exception("Image generation error")
        raise HTTPException(status_code=502, detail=str(e))
@app.get("/api/superscene/image/status/{task_id}")
async def sc_image_poll(task_id: str, request: Request, db: Session = Depends(get_db)):
    """Poll image generation status (for async models)."""
    import httpx

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    api_key = os.getenv("EVOLINK_API_KEY", "")
    try:
        async with httpx.AsyncClient(timeout=15.0) as client:
            resp = await client.get(
                f"https://api.evolink.ai/v1/tasks/{task_id}",
                headers={"Authorization": f"Bearer {api_key}", "Content-Type": "application/json"},
            )
            data = resp.json()

        if resp.status_code == 200:
            status = data.get("status", "pending")
            images = []
            if status == "completed":
                results = data.get("results") or data.get("data") or []
                for r in results:
                    if isinstance(r, str):
                        images.append(r)
                    elif isinstance(r, dict):
                        images.append(r.get("url") or r.get("image_url") or "")
            return {"status": status, "images": images}

        return {"status": "pending", "images": []}
    except Exception as e:
        logger.exception("Image poll error")
        raise HTTPException(status_code=502, detail=str(e))

# ── Image-to-Image (Reimagine) — fal.ai FLUX Dev ─────────────

@app.post("/api/superscene/image/reimagine")
async def sc_image_reimagine(request: Request, db: Session = Depends(get_db)):
    """Transform an uploaded image using AI (image-to-image).
    Body: {image_url, prompt, strength?, num_inference_steps?, guidance_scale?, seed?}
    Uses fal.ai FLUX.1 [dev] image-to-image endpoint.
    Cost: 2 credits per generation.
    """
    import httpx

    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"success": False, "error": "Not authenticated"}, status_code=401)

    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"success": False, "error": "Invalid request body"}, status_code=400)

    image_url = (body.get("image_url") or "").strip()
    prompt    = (body.get("prompt") or "").strip()
    strength  = float(body.get("strength", 0.75))
    steps     = int(body.get("num_inference_steps", 40))
    guidance  = float(body.get("guidance_scale", 3.5))
    seed      = body.get("seed")

    if not image_url:
        return JSONResponse({"success": False, "error": "Image URL is required"}, status_code=400)
    if not prompt:
        return JSONResponse({"success": False, "error": "Prompt is required"}, status_code=400)

    # Clamp strength to valid range
    strength = max(0.05, min(1.0, strength))

    # Cost: 2 credits per reimagine
    credits_needed = 2
    credit_row = _get_or_create_sc_credits(user.id, db)
    if credit_row.balance < credits_needed:
        return JSONResponse({"success": False, "error": f"Insufficient credits. Need {credits_needed}, have {credit_row.balance}."}, status_code=402)

    credit_row.balance -= credits_needed
    db.commit()

    fal_key = os.getenv("FAL_KEY", "")
    if not fal_key:
        credit_row.balance += credits_needed
        db.commit()
        return JSONResponse({"success": False, "error": "Image transformation service not configured"}, status_code=503)

    payload = {
        "image_url": image_url,
        "prompt": prompt,
        "strength": strength,
        "num_inference_steps": steps,
        "guidance_scale": guidance,
    }
    if seed is not None:
        payload["seed"] = int(seed)

    try:
        async with httpx.AsyncClient(timeout=120.0) as client:
            resp = await client.post(
                "https://fal.run/fal-ai/flux/dev/image-to-image",
                json=payload,
                headers={
                    "Authorization": f"Key {fal_key}",
                    "Content-Type": "application/json",
                },
            )
            data = resp.json()

        logger.info(f"fal.ai img2img response ({resp.status_code}): {str(data)[:500]}")

        if resp.status_code == 200:
            images = data.get("images") or []
            urls = [img.get("url") or img for img in images if isinstance(img, dict)]
            if not urls:
                urls = [img for img in images if isinstance(img, str)]

            if urls:
                return {
                    "success": True,
                    "images": urls,
                    "credits_used": credits_needed,
                    "credits_remaining": credit_row.balance,
                    "seed": data.get("seed"),
                }

        # Failed — refund credits
        credit_row.balance += credits_needed
        db.commit()
        err = data.get("detail") or data.get("error") or "Image transformation failed"
        if isinstance(err, dict):
            err = err.get("message", str(err))
        return JSONResponse({"success": False, "error": str(err)[:300]}, status_code=502)

    except Exception as e:
        credit_row.balance += credits_needed
        db.commit()
        logger.exception("Image reimagine error")
        return JSONResponse({"success": False, "error": str(e)[:300]}, status_code=502)
# ── SuperScene Pipeline — Long-form Video Production ─────────

@app.post("/api/superscene/pipeline/analyse")
async def sc_pipeline_analyse(request: Request, db: Session = Depends(get_db)):
    """Build a storyboard from a brief OR a script.
    Body: {brief? | script?, style?, voice?, quality?|model_key?, aspect?, resolution?, title?}
    If only a brief is given, Grok writes the narration script first.
    Returns: {success, pipeline_id, script, scenes, estimated_credits, ...}.
    No video credits are charged here — only 1 credit for the analysis step.
    """
    from .database import SuperScenePipeline, SuperScenePipelineScene, SuperSceneCredit
    from .superscene_pipeline import analyse_script
    from .superscene_evolink import resolve_video_model, calc_credits
    from .explainer_catalog import is_valid_voice, is_valid_style

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    body = await request.json()
    script     = (body.get("script") or "").strip()
    brief      = (body.get("brief") or "").strip()
    style      = body.get("style", "cinematic")
    quality    = body.get("quality")            # standard|premium -> model_key
    model_key  = body.get("model_key", "kling3")
    voice      = body.get("voice", "en-GB-SoniaNeural")
    resolution = body.get("resolution", "1080p")
    aspect     = body.get("aspect", "16:9")
    title      = body.get("title", "")

    # Quality tier wins over an explicit model_key when supplied by the wizard
    if quality:
        model_key = resolve_video_model(quality)

    # Validate look & sound against the catalog (integrity)
    if not is_valid_voice(voice):
        raise HTTPException(status_code=400, detail="Unknown voice")
    if not is_valid_style(style):
        raise HTTPException(status_code=400, detail="Unknown style")
    if aspect not in ("16:9", "9:16", "1:1"):
        raise HTTPException(status_code=400, detail="Unknown aspect ratio")

    if not script and not brief:
        raise HTTPException(status_code=400, detail="A brief or a script is required")
    if len(script) > 20000:
        raise HTTPException(status_code=400, detail="Script must be under 20,000 characters")
    if len(brief) > 4000:
        raise HTTPException(status_code=400, detail="Brief must be under 4,000 characters")

    # Need at least 1 credit for the analysis step
    credit_row = db.query(SuperSceneCredit).filter_by(user_id=user.id).first()
    if not credit_row or credit_row.balance < 1:
        raise HTTPException(status_code=402, detail="Insufficient credits for script analysis")

    # Deduct 1 credit (covers brief->script + scene breakdown)
    credit_row.balance -= 1
    db.commit()

    # Brief -> script via Grok when no script was supplied
    if not script:
        from .grok_service import ai_text_generate
        sys_prompt = (
            "You are an expert short-form video scriptwriter. Write a tight, "
            "spoken-word narration script for an explainer video from the brief. "
            "Natural, confident, conversational. Output ONLY the words to be "
            "spoken: no scene labels, no stage directions, no headings."
        )
        try:
            script = (await ai_text_generate(
                prompt=f"Brief:\n{brief}\n\nWrite the narration script now.",
                system=sys_prompt, max_tokens=1200,
            ) or "").strip()
        except Exception as e:
            credit_row.balance += 1; db.commit()
            raise HTTPException(status_code=502, detail=f"Script generation failed: {e}")
        if not script:
            credit_row.balance += 1; db.commit()
            raise HTTPException(status_code=502, detail="Script generation returned empty")

    # Break the script into scenes (runs on Grok)
    result = await analyse_script(script, style)
    if not result["success"]:
        credit_row.balance += 1; db.commit()
        raise HTTPException(status_code=502, detail=result.get("error", "Script analysis failed"))

    scenes = result["scenes"]

    if not title:
        seed = brief or script
        title = seed[:60].strip().replace("\n", " ")
        if len(seed) > 60:
            title += "\u2026"

    pipeline = SuperScenePipeline(
        user_id=user.id, title=title, script=script, style=style,
        model_key=model_key, voice=voice, resolution=resolution, aspect=aspect,
        status="draft", total_scenes=len(scenes), credits_used=1,
    )
    db.add(pipeline)
    db.flush()

    for s in scenes:
        db.add(SuperScenePipelineScene(
            pipeline_id=pipeline.id,
            scene_number=s.get("scene_number", 0),
            narration_text=s.get("narration_text", ""),
            visual_prompt=s.get("visual_prompt", ""),
            transition_type=s.get("transition_type", "cut"),
            duration_seconds=s.get("estimated_duration", 10),
            status="pending",
        ))
    db.commit()

    # No-charge estimates for the Look & sound step (per quality tier, so the
    # cost updates live when the member switches Standard/Premium).
    def _est(mk):
        return sum(calc_credits(mk, int(round(float(s.get("estimated_duration", 10) or 10)))) for s in scenes)
    estimates = {tier: _est(resolve_video_model(tier)) for tier in ("standard", "premium")}
    est = estimates.get(quality if quality in estimates else "premium", _est(model_key))

    return {
        "success": True,
        "pipeline_id": pipeline.id,
        "title": pipeline.title,
        "script": script,
        "total_scenes": len(scenes),
        "scenes": scenes,
        "estimated_credits": est,
        "estimates": estimates,
        "credits_remaining": credit_row.balance,
    }
def _reconcile_stale_pipelines(user_id, current_pipeline_id, db):
    """Self-heal stranded credits. FastAPI BackgroundTasks don't survive a
    redeploy, so a run interrupted mid-flight can leave scenes 'generating' with
    credits charged but never refunded. Refund any of the user's OTHER pipelines
    that are non-terminal with no progress for 20+ minutes (safely past a real
    run), and mark them failed. Returns credits refunded."""
    from datetime import datetime, timedelta
    from .database import SuperScenePipeline, SuperScenePipelineScene, SuperSceneCredit
    cutoff = datetime.utcnow() - timedelta(minutes=20)
    stale = db.query(SuperScenePipeline).filter(
        SuperScenePipeline.user_id == user_id,
        SuperScenePipeline.id != current_pipeline_id,
        SuperScenePipeline.status.in_(["generating", "assembling"]),
        SuperScenePipeline.updated_at < cutoff,
    ).all()
    if not stale:
        return 0
    credit_row = db.query(SuperSceneCredit).filter_by(user_id=user_id).first()
    refunded = 0
    for sp in stale:
        for sc in db.query(SuperScenePipelineScene).filter_by(pipeline_id=sp.id).all():
            charged = int(sc.credits_charged or 0)
            if sc.status != "completed" and charged > 0 and int(sc.credits_refunded or 0) == 0:
                if credit_row:
                    credit_row.balance += charged
                sc.credits_refunded = charged
                sp.credits_used = max(0, int(sp.credits_used or 0) - charged)
                refunded += charged
        sp.status = "failed"
        if not sp.error_message:
            sp.error_message = "Generation was interrupted — credits refunded"
    db.commit()
    logger.info(f"Reconciled {len(stale)} stale pipeline(s) for user {user_id}; refunded {refunded} credits")
    return refunded


@app.post("/api/superscene/pipeline/{pipeline_id}/generate")
async def sc_pipeline_generate(pipeline_id: int, request: Request, background_tasks: BackgroundTasks, db: Session = Depends(get_db)):
    """Start generating all scenes for a pipeline.
    This kicks off the background orchestrator that:
    1. Generates voiceover for each scene
    2. Generates video for each scene (sequential for continuity)
    3. Assembles the final video with FFmpeg
    """
    from .database import SuperScenePipeline, SuperScenePipelineScene, SuperSceneCredit
    from .superscene_evolink import calc_credits

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    pipeline = db.query(SuperScenePipeline).filter_by(id=pipeline_id, user_id=user.id).first()
    if not pipeline:
        raise HTTPException(status_code=404, detail="Pipeline not found")
    if pipeline.status not in ("draft", "failed"):
        raise HTTPException(status_code=400, detail=f"Pipeline is already {pipeline.status}")

    # Apply the final Look & sound choices (chosen after analyse) before charging.
    try:
        body = await request.json()
    except Exception:
        body = {}
    if body:
        from .superscene_evolink import resolve_video_model
        from .explainer_catalog import is_valid_voice, is_valid_style
        if body.get("voice"):
            if not is_valid_voice(body["voice"]):
                raise HTTPException(status_code=400, detail="Unknown voice")
            pipeline.voice = body["voice"]
        if body.get("style"):
            if not is_valid_style(body["style"]):
                raise HTTPException(status_code=400, detail="Unknown style")
            pipeline.style = body["style"]
        if body.get("aspect"):
            if body["aspect"] not in ("16:9", "9:16", "1:1"):
                raise HTTPException(status_code=400, detail="Unknown aspect ratio")
            pipeline.aspect = body["aspect"]
        if body.get("quality"):
            pipeline.model_key = resolve_video_model(body["quality"])
        db.commit()

    scenes = db.query(SuperScenePipelineScene).filter_by(pipeline_id=pipeline.id).order_by(SuperScenePipelineScene.scene_number).all()
    if not scenes:
        raise HTTPException(status_code=400, detail="No scenes in pipeline")

    # Self-heal: refund this user's earlier runs that were interrupted mid-flight
    # (a redeploy kills in-flight background tasks, stranding charged credits).
    try:
        _reconcile_stale_pipelines(user.id, pipeline.id, db)
    except Exception:
        logger.warning("Stale-pipeline reconcile failed", exc_info=True)

    # Calculate total cost and stamp each scene's charge so a failed
    # scene can be refunded exactly what it cost (per-scene accounting).
    total_credits = 0
    for scene in scenes:
        dur = int(scene.duration_seconds or 10)
        scene_cost = calc_credits(pipeline.model_key, dur)
        scene.credits_charged = scene_cost
        scene.credits_refunded = 0
        total_credits += scene_cost

    credit_row = db.query(SuperSceneCredit).filter_by(user_id=user.id).first()
    if not credit_row or credit_row.balance < total_credits:
        raise HTTPException(status_code=402, detail=f"Need {total_credits} credits, have {credit_row.balance if credit_row else 0}")

    # Deduct credits
    credit_row.balance -= total_credits
    pipeline.credits_used += total_credits
    pipeline.status = "generating"
    db.commit()

    # Start background orchestrator
    background_tasks.add_task(
        _run_pipeline,
        pipeline_id=pipeline.id,
        user_id=user.id,
    )

    return {
        "success": True,
        "pipeline_id": pipeline.id,
        "status": "generating",
        "total_scenes": len(scenes),
        "credits_used": total_credits,
        "credits_remaining": credit_row.balance,
    }
@app.get("/api/superscene/pipeline/{pipeline_id}/status")
async def sc_pipeline_status(pipeline_id: int, request: Request, db: Session = Depends(get_db)):
    """Get pipeline progress."""
    from .database import SuperScenePipeline, SuperScenePipelineScene

    user = get_current_user(request, db)
