@app.post("/api/superscene/pipeline/{pipeline_id}/update-scene")
async def sc_pipeline_update_scene(pipeline_id: int, request: Request, db: Session = Depends(get_db)):
    """Update a scene's narration or visual prompt before generation.
    Body: {scene_number, narration_text?, visual_prompt?, duration_seconds?}
    """
    from .database import SuperScenePipeline, SuperScenePipelineScene

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    pipeline = db.query(SuperScenePipeline).filter_by(id=pipeline_id, user_id=user.id).first()
    if not pipeline:
        raise HTTPException(status_code=404, detail="Pipeline not found")
    if pipeline.status not in ("draft", "failed"):
        raise HTTPException(status_code=400, detail="Cannot edit scenes while generating")

    body = await request.json()
    scene_num = body.get("scene_number")
    if scene_num is None:
        raise HTTPException(status_code=400, detail="scene_number is required")

    scene = db.query(SuperScenePipelineScene).filter_by(pipeline_id=pipeline.id, scene_number=scene_num).first()
    if not scene:
        raise HTTPException(status_code=404, detail=f"Scene {scene_num} not found")

    if "narration_text" in body:
        scene.narration_text = body["narration_text"]
    if "visual_prompt" in body:
        scene.visual_prompt = body["visual_prompt"]
    if "duration_seconds" in body:
        scene.duration_seconds = body["duration_seconds"]

    db.commit()
    return {"success": True, "scene_number": scene_num}


# ═══════════════════════════════════════════════════════════════════
# BRAND POSTER GENERATOR
#
# Inside Creative Studio. Generates complete branded marketing posters
# from a curated 6-template library via xAI Grok Imagine.
#
# Access: gated to Credit Nexus pack owners (any tier). Non-pack-owners
# see the preview gallery but cannot generate.
#
# Flow:
#   1. GET /api/posters/access-check     — am I unlocked?
#   2. GET /api/posters/templates        — gallery (always public-ish)
#   3. GET /api/posters/template/{slug}  — template details + input form
#   4. POST /api/posters/generate        — make 4 candidates (gated)
#   5. POST /api/posters/generation/{id}/choose — pick favourite
#   6. GET /api/posters/my-generations   — history
#   7. GET /go/{share_slug}              — public viral landing page
# ═══════════════════════════════════════════════════════════════════

@app.post("/api/upload/reference-photo")
async def upload_reference_photo(file: UploadFile = File(...),
                                  user: User = Depends(get_current_user),
                                  db: Session = Depends(get_db)):
    """Upload a reference photo for use in Brand Poster Generator.
    Returns the public R2 URL.

    Accepts JPEG, PNG, WebP up to 10MB. Stored under 'bpg-references/'.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    allowed_types = {"image/jpeg", "image/png", "image/webp"}
    if file.content_type not in allowed_types:
        return JSONResponse(
            {"error": "Only JPEG, PNG, and WebP are accepted."}, status_code=400
        )

    contents = await file.read()
    if len(contents) > 10 * 1024 * 1024:
        return JSONResponse({"error": "Photo too large. Max 10MB."}, status_code=400)

    import os
    ext = os.path.splitext(file.filename or "photo.jpg")[1].lower().lstrip(".")
    if ext not in {"jpg", "jpeg", "png", "webp"}:
        ext = "jpg"

    from app.r2_storage import r2_available, upload_image
    if not r2_available():
        return JSONResponse(
            {"error": "Photo upload service is offline. Please try again shortly."},
            status_code=503,
        )

    url = upload_image(contents, "bpg-references", ext, file.content_type)
    return {"url": url}


@app.get("/api/posters/access-check")
def bpg_access_check(request: Request, db: Session = Depends(get_db)):
    """Lightweight probe: does this member have BPG access?

    Returns a dict with access status plus pack-ownership context
    so the frontend can show personalised upsell messaging.
    """
    from .poster_gating import get_member_pack_summary

    user = get_current_user(request, db)
    poster_cost = _bpg_credit_cost()
    if not user:
        return {"authenticated": False, "has_access": False, "pack_count": 0,
                "highest_tier_key": None, "total_invested_usd": 0.0,
                "credit_balance": 0, "poster_cost": poster_cost}

    from .database import SuperSceneCredit
    summary = dict(get_member_pack_summary(db, user))
    _cr = db.query(SuperSceneCredit).filter_by(user_id=user.id).first()
    credit_balance = int(_cr.balance) if _cr else 0
    summary["credit_balance"] = credit_balance
    summary["poster_cost"] = poster_cost
    summary["has_access"] = credit_balance >= poster_cost
    return {"authenticated": True, **summary}


@app.get("/api/posters/templates")
def bpg_list_templates(request: Request, db: Session = Depends(get_db)):
    """Return all active templates for the gallery.

    Always returns the catalogue regardless of access — non-pack
    members can still BROWSE the gallery to see what they'd unlock.
    They just can't generate. Access check happens at /generate.

    Pulls preview_image_url + thumbnail_url from the DB row when one
    exists (templates are lazy-created in the DB on first generation
    or via the admin seed endpoint). Returns null for those fields if
    the template hasn't been seeded yet.
    """
    from .poster_templates import get_active_templates
    from .database import PosterTemplate, SuperSceneCredit

    user = get_current_user(request, db)
    poster_cost = _bpg_credit_cost()
    credit_balance = 0
    if user:
        _cr = db.query(SuperSceneCredit).filter_by(user_id=user.id).first()
        credit_balance = int(_cr.balance) if _cr else 0
    has_access = bool(user) and credit_balance >= poster_cost

    # Build a {slug: row} map from the DB so each template's preview/thumb
    # can be looked up in O(1) without N queries.
    db_rows = {row.slug: row for row in db.query(PosterTemplate).all()}

    templates = []
    for t in get_active_templates():
        row = db_rows.get(t["slug"])
        # Don't leak the master_prompt to the frontend — that's our IP
        templates.append({
            "slug": t["slug"],
            "name": t["name"],
            "description": t["description"],
            "category": t["category"],
            "sort_order": t["sort_order"],
            "aspect_ratio": t["aspect_ratio"],
            "supports_photo": t["supports_photo"],
            "share_slug": t.get("share_slug"),
            "preview_image_url": row.preview_image_url if row else None,
            "thumbnail_url": row.thumbnail_url if row else None,
        })

    return {
        "authenticated": bool(user),
        "has_access": has_access,
        "credit_balance": credit_balance,
        "poster_cost": poster_cost,
        "templates": templates,
    }


