# ── Brand Poster Generator: credit pricing + refund ───────────────────────
# Generating a poster runs the image model N times (one per candidate). Per
# Steve's Creative Studio pricing rule the member is charged 2x the cost of
# the most-expensive AI provider that serves the tool. For BPG that provider
# is xAI grok-imagine (APPROX_COST_USD_PER_IMAGE). The price is DERIVED from
# the live cost constant + the credit catalogue so it can't silently drift:
# bump GROK_IMAGINE_MODEL to a pricier tier and the credit cost follows.
BPG_N_CANDIDATES = 4   # images produced per Generate click (see _bpg_run_generation)


def _bpg_credit_cost() -> int:
    """Creator-credit cost of one poster generation: 2x the most-expensive
    serving provider's cost, converted to whole credits and rounded up.
    At $0.05/image x 4 candidates x 2 = $0.40, and $0.20/credit -> 2 credits."""
    import math
    from .grok_imagine_service import APPROX_COST_USD_PER_IMAGE
    from .database import CREDIT_PACKS
    starter = CREDIT_PACKS.get("starter") or {"price": 20, "credits": 100}
    usd_per_credit = (float(starter["price"]) / float(starter["credits"])) or 0.20
    provider_cost_usd = float(APPROX_COST_USD_PER_IMAGE) * BPG_N_CANDIDATES
    retail_usd = provider_cost_usd * 2.0          # 2x most-expensive provider
    return max(1, math.ceil(retail_usd / usd_per_credit))


def _bpg_fail_and_refund(db, gen_id: int, error_message: str = None) -> int:
    """Atomically flip an in-flight poster generation ('generating'/'pending')
    to 'failed' and refund any Creator Credits it was charged — exactly once.

    Race-safe: the row is locked FOR UPDATE so the background runner, the
    stale-reconcile sweep, and the detail-endpoint age-flip serialise; only the
    first to see a non-terminal status refunds. credits_charged is zeroed after
    refund, so a failed generation can never be refunded twice. No external
    calls are made under the lock (the slow provider call runs in the caller,
    before this) — holding a txn across a slow call is what took the site down
    on 31 May 2026. Returns credits refunded (0 if already terminal/uncharged)."""
    from .database import PosterGeneration as _PG, SuperSceneCredit as _SSC
    gen = db.query(_PG).filter_by(id=gen_id).with_for_update().first()
    if not gen:
        return 0
    if gen.status not in ("generating", "pending"):
        return 0  # already resolved elsewhere — do not double-refund
    refunded = 0
    charged = int(gen.credits_charged or 0)
    if charged > 0:
        credit_row = db.query(_SSC).filter_by(user_id=gen.user_id).with_for_update().first()
        if credit_row:
            credit_row.balance = int(credit_row.balance or 0) + charged
            refunded = charged
        gen.credits_charged = 0   # net charge on a failed generation is zero
    gen.status = "failed"
    if error_message and not gen.error_message:
        gen.error_message = str(error_message)[:500]
    db.commit()
    if refunded:
        logger.info(f"BPG generation {gen_id} failed — refunded {refunded} credit(s) to user {gen.user_id}")
    return refunded


def _bpg_reconcile_stale_generations(user_id, db):
    """Self-heal: a BackgroundTask killed by a redeploy can strand a poster
    generation in 'generating' forever. Fail this user's generations stuck
    'generating'/'pending' for >5 min (well past the ~60s real run) so the
    result page stops waiting, refunding any credits charged. Mirrors the
    SuperScene _reconcile_stale_pipelines pattern."""
    from datetime import datetime as _dt, timedelta as _td
    from .database import PosterGeneration as _PG
    cutoff = _dt.utcnow() - _td(minutes=5)
    stale = db.query(_PG).filter(
        _PG.user_id == user_id,
        _PG.status.in_(["generating", "pending"]),
        _PG.created_at < cutoff,
    ).all()
    refunded = 0
    for g in stale:
        refunded += _bpg_fail_and_refund(db, g.id, "Generation was interrupted — please try again.")
    if stale:
        logger.info(f"BPG self-heal: failed {len(stale)} stale generation(s) for user {user_id}; refunded {refunded} credit(s)")
    return len(stale)


def _send_xai_credit_alert(status_code, detail):
    """Best-effort admin heads-up when xAI image generation is REFUSED with a
    credit/permission error (403 = out of image credits / no access, 402 =
    payment required). Lets the admin top up image credits BEFORE more members
    hit the wall, instead of finding out from a support message.

    Throttled to at most once per 6h via an app_config marker so a burst of
    failed generations can't spam the inbox. Mirrors _send_bsc_scan_failure_alert:
    best-effort, never raises (caller wraps in try/except), ops inbox recipient.
    """
    from .database import SessionLocal as _SessionLocal, AppConfig as _AppConfig
    from datetime import datetime as _dt, timedelta as _td
    THROTTLE_HOURS = 6
    KEY = "xai_credit_alert_last_sent"

    # ── throttle: mark-before-send so concurrent failures don't all email ──
    db = _SessionLocal()
    try:
        now = _dt.utcnow()
        cfg = db.query(_AppConfig).filter(_AppConfig.key == KEY).first()
        if cfg and cfg.value:
            try:
                if now - _dt.fromisoformat(cfg.value) < _td(hours=THROTTLE_HOURS):
                    return  # already alerted within the window — stay quiet
            except Exception:
                pass
        if cfg:
            cfg.value = now.isoformat()
            cfg.updated_at = now
        else:
            db.add(_AppConfig(key=KEY, value=now.isoformat(), updated_at=now))
        db.commit()
    except Exception:
        db.rollback()
        # throttle bookkeeping failed — fall through and still try one email
    finally:
        db.close()

    try:
        from .email_utils import send_email
        to_email = os.environ.get("ADMIN_ALERT_EMAIL", "stevelawsonmarketing@gmail.com")
        subject = "⚠️  Creative Studio: xAI image generation refused — likely out of credits"
        html_body = f"""
        <div style="font-family:Helvetica Neue,Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">
          <h2 style="color:#dc2626;margin:0 0 16px;">Brand Poster Generator is being refused by xAI</h2>
          <p style="font-size:14px;line-height:1.6;color:#334155;">
            xAI's image API returned <strong>HTTP {status_code}</strong> on a member's
            poster generation. This almost always means the xAI account is
            <strong>out of image-generation credits</strong> (image gen is billed
            separately from your Grok text usage, so text features keep working while
            image gen is blocked). Until topped up, members will see generation failures.
          </p>
          <div style="background:#f1f5f9;border-radius:10px;padding:16px;margin:16px 0;font-family:monospace;font-size:13px;color:#334155;word-break:break-all;">
            <div><strong>xAI status:</strong> {status_code}</div>
            <div style="margin-top:8px;"><strong>Detail:</strong> {(detail or '')[:400]}</div>
          </div>
          <p style="font-size:13px;color:#475569;line-height:1.6;">
            <strong>Fix:</strong> top up image credits at
            <a href="https://console.x.ai">console.x.ai</a> → Billing/Credits.
            Generation resumes immediately once credits are added — no deploy needed.
          </p>
          <p style="font-size:12px;color:#94a3b8;">You'll get at most one of these every {THROTTLE_HOURS}h.</p>
        </div>
        """
        send_email(to_email=to_email, subject=subject, html_body=html_body)
        logger.warning(f"xAI credit/permission alert emailed to admin (xAI status {status_code})")
    except Exception:
        logger.exception("Failed to send xAI credit alert email")


async def _bpg_run_generation(gen_id, rendered_prompt, reference_photo_url, aspect):
    """Background runner for ONE Brand Poster generation (fire-and-forget via
    FastAPI BackgroundTasks). Calls the AI provider WITHOUT holding any DB
    transaction open, then records the outcome in its own short-lived session.
    Never raises — logs instead — since it runs detached from the request.

    The slow provider call used to run inline inside the POST, holding the HTTP
    request (and a DB transaction) open for 45-60s; that 502'd at the gateway on
    long renders and lost the whole generation. Holding a DB transaction across
    a slow external call is also what took the site down on 31 May 2026 — so
    this deliberately opens the DB session ONLY after the provider call returns.

    Like every BackgroundTask it does not survive a redeploy; a run killed
    mid-flight leaves the row 'generating'. _bpg_reconcile_stale_generations
    (next generate) and the age-based flip in the detail endpoint both clear
    those, so the poller never waits forever."""
    from . import grok_imagine_service as grok_imagine
    from .database import SessionLocal as _SessionLocal, PosterGeneration as _PG
    import json as _json
    # ── slow external call: NO db session/transaction held across it ──
    try:
        result = await grok_imagine.generate_candidates(
            prompt=rendered_prompt, reference_url=reference_photo_url,
            aspect=aspect, n=4,
        )
    except Exception as exc:
        logger.exception(f"BPG bg generation {gen_id} crashed during Grok call")
        result = {"error": f"Generation crashed: {exc}"}

    # ── proactive heads-up: if xAI refused on a credit/permission error,
    #    email the admin ONCE (throttled) so image credits get topped up
    #    before more members hit the wall. 403 = out of credits / no access,
    #    402 = payment required. Best-effort; never affects the outcome write. ──
    if isinstance(result, dict) and "error" in result:
        _sc = result.get("status_code")
        _dt = (result.get("detail") or "").lower()
        if _sc in (402, 403) or any(k in _dt for k in ("credit", "insufficient", "billing", "quota")):
            try:
                _send_xai_credit_alert(_sc, result.get("detail") or result.get("error"))
            except Exception:
                logger.exception(f"BPG bg generation {gen_id}: xAI credit alert dispatch failed")

    # ── short-lived session purely to record the outcome ──
    db = _SessionLocal()
    try:
        gen = db.query(_PG).filter_by(id=gen_id).first()
        if not gen:
            logger.error(f"BPG bg generation {gen_id}: row not found when writing outcome")
            return
        if gen.status not in ("generating", "pending"):
            # Already resolved (e.g. self-heal flipped it failed). Don't clobber.
            logger.info(f"BPG bg generation {gen_id}: already '{gen.status}', leaving as-is")
            return
        if "error" in result:
            _bpg_fail_and_refund(db, gen_id, str(result.get("error") or "Image generation failed"))
        else:
            imgs = result.get("images", []) or []
            if not imgs:
                _bpg_fail_and_refund(db, gen_id, "No images returned — please try again")
            else:
                gen.candidate_urls = _json.dumps(imgs)
                gen.status = "ready"
                gen.completed_at = datetime.utcnow()
                db.commit()
        logger.info(f"BPG bg generation {gen_id} resolved")
    except Exception:
        logger.exception(f"BPG bg generation {gen_id}: error writing outcome")
        db.rollback()
    finally:
        db.close()


@app.post("/api/posters/generate")
async def bpg_generate(request: Request, background_tasks: BackgroundTasks, db: Session = Depends(get_db)):
    """THE main endpoint. Generate 4 candidate posters from a template.

    Body: {
      "template_slug": "one-income-risky",
      "inputs": {"headline_open": "...", "headline_main": "...", ...},
      "reference_photo_url": "https://pub-xxx.r2.dev/..." (optional)
    }

    Flow:
      1. Require auth + enough Creator Credits (charged per generation)
      2. Load template + assemble prompt via poster_templates.render_prompt
      3. Create a PosterGeneration row in 'generating', charging the credits
      4. Call Grok Imagine (async, in a BackgroundTask)
      5. On success: store candidate URLs, return them
      6. On failure: mark failed and auto-refund the charged credits
         (_bpg_fail_and_refund)
    """
    from .poster_templates import get_template_by_slug, render_prompt
    from .database import PosterTemplate, PosterGeneration, SuperSceneCredit
    from . import grok_imagine_service as grok_imagine

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    # Creator-credit gate: generating a poster costs credits (2x the most-
    # expensive serving provider cost — see _bpg_credit_cost). Fast pre-check
    # here; the charge is re-checked under a row lock at deduction time so two
    # concurrent generates can't overspend. A failed render is auto-refunded.
    cost = _bpg_credit_cost()
    _cr = db.query(SuperSceneCredit).filter_by(user_id=user.id).first()
    _bal = int(_cr.balance) if _cr else 0
    if _bal < cost:
        raise HTTPException(
            status_code=402,
            detail=f"Generating a poster costs {cost} Creator Credits — you have {_bal}. "
                   f"Top up your Creator Credits to keep generating.",
        )

    body = await request.json()
    template_slug = (body.get("template_slug") or "").strip()
    inputs = body.get("inputs", {}) or {}
    reference_photo_url = (body.get("reference_photo_url") or "").strip() or None

    template = get_template_by_slug(template_slug)
    if not template:
        raise HTTPException(status_code=404, detail="Template not found")

    # Ensure template row exists in DB (lazy upsert so seeding isn't required)
    template_row = db.query(PosterTemplate).filter_by(slug=template_slug).first()
    if not template_row:
        import json as _json
        template_row = PosterTemplate(
            slug=template["slug"],
            name=template["name"],
            description=template["description"],
            category=template["category"],
            sort_order=template["sort_order"],
            master_prompt=template["master_prompt"],
            input_fields=_json.dumps(template["input_fields"]),
            aspect_ratio=template["aspect_ratio"],
            supports_photo=template["supports_photo"],
            share_slug=template.get("share_slug"),
        )
        db.add(template_row)
        db.flush()

    # Build the final prompt with placeholders substituted. The username
    # is passed so the poster includes 'superadpro.com/ref/{username}'
    # as a visible URL — every BPG poster a member generates is then
    # attribution-ready when they share it on social media.
    try:
        rendered_prompt = render_prompt(template, inputs, username=user.username)
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc))

    # Sanity check rendered length — Grok Imagine has a prompt limit
    if len(rendered_prompt) > 6000:
        raise HTTPException(status_code=400, detail="Rendered prompt too long")

    # Create the generation record in 'generating' status and charge the
    # Creator Credits in the SAME transaction. Lock the credit row and RE-CHECK
    # the balance under the lock so two concurrent generates can't both pass the
    # pre-check and overspend. A failed render refunds this exact charge via
    # _bpg_fail_and_refund.
    import json as _json
    generation = PosterGeneration(
        user_id=user.id,
        template_id=template_row.id,
        input_values=_json.dumps(inputs),
        reference_photo_url=reference_photo_url,
        rendered_prompt=rendered_prompt,
        status="generating",
        credits_charged=cost,
    )
    db.add(generation)
    db.flush()
    gen_id = generation.id

    credit_row = db.query(SuperSceneCredit).filter_by(user_id=user.id).with_for_update().first()
    bal = int(credit_row.balance) if credit_row else 0
    if not credit_row or bal < cost:
        db.rollback()
        raise HTTPException(
            status_code=402,
            detail=f"Generating a poster costs {cost} Creator Credits — you have {bal}. "
                   f"Top up your Creator Credits to keep generating.",
        )
    credit_row.balance = bal - cost

    # Persist the 'generating' row AND the credit deduction together so the
    # background runner and the result-page poller can see it after this
    # request returns and the request-scoped session closes.
    db.commit()

    # Self-heal any of THIS user's earlier runs stranded 'generating' by a
    # mid-flight redeploy (BackgroundTasks don't survive one).
    try:
        _bpg_reconcile_stale_generations(user.id, db)
    except Exception:
        logger.warning("BPG stale-generation reconcile failed", exc_info=True)

    # Kick the render into the background and return IMMEDIATELY. Previously
    # this awaited a 45-60s provider call inline, holding the HTTP request open
    # the whole time — which 502'd at the gateway on long renders and lost the
    # generation. Now the request returns at once with status 'generating'; the
    # result page polls GET /api/posters/generation/{id} until 'ready'/'failed'.
    background_tasks.add_task(
        _bpg_run_generation,
        gen_id=gen_id,
        rendered_prompt=rendered_prompt,
        reference_photo_url=reference_photo_url,
        aspect=template["aspect_ratio"],
    )

    logger.info(f"BPG generation {gen_id} queued for user {user.username}, template {template_slug}")

    return {
        "success": True,
        "generation_id": gen_id,
        "status": "generating",
        "template_slug": template_slug,
    }


@app.get("/api/posters/generation/{generation_id}")
def bpg_generation_detail(generation_id: int, request: Request, db: Session = Depends(get_db)):
    """Get full details of one generation including all candidate URLs.
    Used by the result picker page to show the 4 candidates.

    Candidate URLs from xAI's imgen.x.ai are NOT directly browser-loadable:
      (a) they reject cross-origin <img src> requests with HTTP 403
      (b) they require Authorization: Bearer ${XAI_API_KEY} header which
          a basic <img> tag cannot send
      (c) they expire within 24-48 hours
    So we rewrite each xAI URL into a same-origin proxy URL the browser
    CAN load — `/api/posters/generation/{id}/candidate/{idx}/image` —
    which fetches via _bpg_fetch_xai_image server-side using the held
    Bearer token, then streams the bytes back inline.

    URLs that are already on our R2 bucket (post-save, after /choose)
    are kept as-is — they load fine cross-origin.
    """
    from .database import PosterGeneration, PosterTemplate
    import json as _json

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    gen = db.query(PosterGeneration).filter_by(id=generation_id, user_id=user.id).first()
    if not gen:
        raise HTTPException(status_code=404, detail="Generation not found")

    # Age-based self-heal: a generation stuck 'generating'/'pending' well past
    # the real run window was almost certainly orphaned by a redeploy (Background-
    # Tasks don't survive one). Flip it to 'failed' so the result-page poller
    # stops waiting instead of looping forever.
    if gen.status in ("generating", "pending") and gen.created_at:
        from datetime import timedelta as _td
        if gen.created_at < datetime.utcnow() - _td(minutes=5):
            _bpg_fail_and_refund(db, gen.id, "Generation timed out — please try again.")
            db.refresh(gen)

    tpl = db.query(PosterTemplate).filter_by(id=gen.template_id).first()

    raw_candidates = _json.loads(gen.candidate_urls or "[]")
    proxied_candidates = []
    for idx, url in enumerate(raw_candidates):
        if url and ("imgen.x.ai" in url or "x.ai" in url):
            proxied_candidates.append(
                f"/api/posters/generation/{gen.id}/candidate/{idx}/image"
            )
        else:
            # R2 or other already-browser-loadable URL — keep as-is
            proxied_candidates.append(url)

    # Same treatment for chosen_url — could be an xAI URL if /choose
    # didn't archive to R2 yet (or failed to).
    chosen_url = gen.chosen_url
    if chosen_url and ("imgen.x.ai" in chosen_url or "x.ai" in chosen_url):
        if gen.chosen_index is not None:
            chosen_url = f"/api/posters/generation/{gen.id}/candidate/{gen.chosen_index}/image"

    return {
        "id": gen.id,
        "template_slug": tpl.slug if tpl else None,
        "template_name": tpl.name if tpl else None,
        "status": gen.status,
        "candidates": proxied_candidates,
        "chosen_index": gen.chosen_index,
        "chosen_url": chosen_url,
        "error_message": gen.error_message,
        "created_at": gen.created_at.isoformat() if gen.created_at else None,
    }


@app.get("/api/posters/generation/{generation_id}/candidate/{index}/image")
def bpg_candidate_image_proxy(generation_id: int, index: int,
                              request: Request,
                              db: Session = Depends(get_db)):
    """Inline image proxy for browser <img src> rendering.

    Same fetch logic as /download but returns the image with
    Content-Disposition: inline (renderable in <img>) and a stricter
    Cache-Control because candidate URLs expire from xAI in ~24h
    anyway — once expired, the cached bytes here would be the only copy.
    Cache TTL is 23h: long enough that re-rendering the result page
    doesn't hammer xAI, short enough that a /choose archival to R2
    will be reflected on next page load.
    """
    from .database import PosterGeneration
    from fastapi.responses import Response
    import json as _json

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    generation = db.query(PosterGeneration).filter_by(
        id=generation_id, user_id=user.id
    ).first()
    if not generation:
        raise HTTPException(status_code=404, detail="Generation not found")

    candidates = _json.loads(generation.candidate_urls or "[]")
    if index < 0 or index >= len(candidates):
        raise HTTPException(
            status_code=400,
            detail=f"index out of range (have {len(candidates)} candidates)"
        )
    source_url = candidates[index]
    if not source_url:
        raise HTTPException(status_code=404, detail="No candidate URL at that index")

    try:
        if "imgen.x.ai" in source_url or "x.ai" in source_url:
            image_bytes = _bpg_fetch_xai_image(source_url)
        else:
            import urllib.request
            with urllib.request.urlopen(source_url, timeout=60) as resp:
                image_bytes = resp.read()
    except Exception as exc:
        logger.exception(
            f"BPG candidate proxy: fetch failed for gen {generation_id} "
            f"candidate {index}: {exc}"
        )
        if "imgen.x.ai" in source_url:
            raise HTTPException(
                status_code=410,
                detail="Original image expired. Please regenerate this poster.",
            )
        raise HTTPException(status_code=502, detail="Could not fetch poster image")

    return Response(
        content=image_bytes,
        media_type="image/jpeg",
        headers={
            "Content-Disposition": "inline",
            "Cache-Control": "private, max-age=82800",  # 23h
        },
    )


# Helper used by both /choose (R2 archival) and /download (live proxy).
# xAI Imagine returns URLs on imgen.x.ai that:
#   (a) reject default Python urllib User-Agent strings with HTTP 403
#       (verified 12 May 2026 during BPG seed work)
#   (b) are temporary — expire within ~24-48 hours
# The User-Agent + Bearer auth pattern below is the working recipe from
# /admin/bpg/seed-previews. Keep these in sync.
def _bpg_fetch_xai_image(image_url: str, timeout: int = 60) -> bytes:
    """Download an xAI Imagine image with the required headers.
    Raises urllib.error.HTTPError / URLError on failure.
    """
    import urllib.request
    import os as _os

    xai_key = _os.environ.get("XAI_API_KEY", "").strip()
    req = urllib.request.Request(
        image_url,
        headers={
            "User-Agent": "Mozilla/5.0 (compatible; SuperAdPro/1.0; +https://www.superadpro.com)",
            "Accept": "image/*,*/*;q=0.8",
            **({"Authorization": f"Bearer {xai_key}"} if xai_key else {}),
        },
    )
    with urllib.request.urlopen(req, timeout=timeout) as resp:
        return resp.read()


@app.post("/api/posters/generation/{generation_id}/choose")
async def bpg_choose_candidate(generation_id: int, request: Request, db: Session = Depends(get_db)):
    """Member picks one of the 4 candidates as their final choice.
    Body: {"chosen_index": 0|1|2|3}

    On choose we archive the chosen image to R2 so the URL stops being a
    short-lived imgen.x.ai link (expires ~24-48h) and becomes a permanent
    same-origin URL on superadpro.com. This fixes three things at once:
      1. Gallery thumbnails would have broken after a day or two
      2. Cross-origin Download button (browser ignores `download` attr on
         remote URLs) — same-origin R2 makes it work natively
      3. Members can re-download their own posters indefinitely

    If R2 is unavailable we degrade gracefully and store the xAI URL — the
    /download endpoint below proxies live as a safety net in that case.
    """
    from .database import PosterGeneration
    from . import r2_storage
    import json as _json

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    generation = db.query(PosterGeneration).filter_by(id=generation_id, user_id=user.id).first()
    if not generation:
        raise HTTPException(status_code=404, detail="Generation not found")

    if generation.status not in ("ready", "chosen"):
        raise HTTPException(status_code=400, detail=f"Cannot choose from status '{generation.status}'")

    body = await request.json()
    chosen_index = body.get("chosen_index") if isinstance(body, dict) else None
    if chosen_index is None or not isinstance(chosen_index, int):
        raise HTTPException(status_code=400, detail="chosen_index (0-3) required")

    candidates = _json.loads(generation.candidate_urls or "[]")
    if chosen_index < 0 or chosen_index >= len(candidates):
        raise HTTPException(status_code=400, detail=f"chosen_index out of range (have {len(candidates)} candidates)")

    xai_url = candidates[chosen_index]
    final_url = xai_url  # fallback if R2 archival fails

    # Archive to R2 for persistence + same-origin download
    if r2_storage.r2_available():
        try:
            image_bytes = _bpg_fetch_xai_image(xai_url)
            final_url = r2_storage.upload_image(
                image_bytes,
                folder="bpg-final",
                ext="jpg",
                content_type="image/jpeg",
            )
            logger.info(f"BPG choose: archived gen {generation_id} to R2 → {final_url}")
        except Exception as exc:
            # Don't fail the whole save if R2 hiccups — the /download proxy
            # endpoint can still serve the xAI URL live. Just log it.
            logger.warning(
                f"BPG choose: R2 archive failed for gen {generation_id}, "
                f"keeping xAI URL: {exc}"
            )

    generation.chosen_index = chosen_index
    generation.chosen_url = final_url
    generation.status = "chosen"
    db.commit()

    return {
        "success": True,
        "generation_id": generation_id,
        "chosen_url": generation.chosen_url,
    }


@app.get("/api/posters/generation/{generation_id}/download")
def bpg_download_poster(generation_id: int, request: Request,
                         index: int = None,
                         db: Session = Depends(get_db)):
    """Same-origin download endpoint for poster images.

    Two modes:
      - No `index` query param: download the member's chosen poster
        (uses generation.chosen_url; requires status='chosen')
      - `index=0..3`: download a specific candidate before/without saving
        (used by the result page's Download button when the member has
         selected a candidate but not yet clicked Save my choice)

    Returns the image as an attachment with Content-Disposition so the
    browser actually downloads it rather than navigating to the URL.
    This is needed because:
      (a) imgen.x.ai is cross-origin so the HTML `download` attribute
          is silently ignored by browsers
      (b) imgen.x.ai URLs expire after ~24-48h — by then a raw href
          would 404. Same-origin R2 URLs (after /choose) avoid this,
          but for un-saved candidates we proxy live.
    """
    from .database import PosterGeneration
    from fastapi.responses import Response
    import json as _json

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    generation = db.query(PosterGeneration).filter_by(id=generation_id, user_id=user.id).first()
    if not generation:
        raise HTTPException(status_code=404, detail="Generation not found")

    # Figure out which URL to serve
    if index is not None:
        # Candidate download (pre-save)
        candidates = _json.loads(generation.candidate_urls or "[]")
        if index < 0 or index >= len(candidates):
            raise HTTPException(status_code=400, detail=f"index out of range (have {len(candidates)} candidates)")
        source_url = candidates[index]
        filename_suffix = f"candidate-{index + 1}"
    else:
        # Chosen download (post-save)
        if not generation.chosen_url:
            raise HTTPException(status_code=400, detail="No chosen poster — pick one and save first, or pass ?index=N")
        source_url = generation.chosen_url
        filename_suffix = "final"

    # Fetch the bytes. If the URL is already on our R2 bucket the simple
    # urllib request still works (no special headers needed). For xAI URLs
    # we need the User-Agent + Bearer recipe.
    try:
        if "imgen.x.ai" in source_url or "x.ai" in source_url:
            image_bytes = _bpg_fetch_xai_image(source_url)
        else:
            # R2 or other same-origin source — plain fetch
            import urllib.request
            with urllib.request.urlopen(source_url, timeout=60) as resp:
                image_bytes = resp.read()
    except Exception as exc:
        logger.exception(f"BPG download: fetch failed for gen {generation_id}: {exc}")
        # If it's an xAI URL that's likely expired, give a useful error
        if "imgen.x.ai" in source_url:
            raise HTTPException(
                status_code=410,
                detail="Original image expired. Please regenerate this poster.",
            )
        raise HTTPException(status_code=502, detail=f"Could not fetch poster image")

    filename = f"superadpro-poster-{generation_id}-{filename_suffix}.jpg"
    return Response(
        content=image_bytes,
        media_type="image/jpeg",
        headers={
            "Content-Disposition": f'attachment; filename="{filename}"',
            "Cache-Control": "private, max-age=3600",
        },
    )


@app.get("/api/posters/my-generations")
def bpg_my_generations(request: Request, db: Session = Depends(get_db),
                       limit: int = 30):
    """History page — list this member's past generations."""
    from .database import PosterGeneration, PosterTemplate
    import json as _json

    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")

    limit = max(1, min(limit, 100))

    rows = (
        db.query(PosterGeneration, PosterTemplate)
        .join(PosterTemplate, PosterGeneration.template_id == PosterTemplate.id)
        .filter(PosterGeneration.user_id == user.id)
        .order_by(PosterGeneration.created_at.desc())
        .limit(limit)
        .all()
    )

    results = []
    for gen, tpl in rows:
        results.append({
            "id": gen.id,
            "template_slug": tpl.slug,
            "template_name": tpl.name,
            "status": gen.status,
            "chosen_url": gen.chosen_url,
            "candidate_count": len(_json.loads(gen.candidate_urls or "[]")),
            "created_at": gen.created_at.isoformat() if gen.created_at else None,
        })

    return {"generations": results, "count": len(results)}


def bpg_share_landing(share_slug: str, request: Request, db: Session = Depends(get_db)):
    """Public viral landing page. When a member shares a poster on social
    media, the link points here. Visitor lands on a SuperAdPro page
    promoting the same template, with the original member tracked as
    the source for attribution.

    No auth required — this is the public-facing recruitment surface.
    """
    from .database import PosterTemplate, PosterTemplateShare

    template = db.query(PosterTemplate).filter_by(share_slug=share_slug).first()
    if not template:
        # Don't 404 — share slug might be member-specific; just redirect to homepage
        return RedirectResponse(url="/", status_code=302)

    # Track the visit (no PII)
    import hashlib
    raw_ip = request.client.host if request.client else ""
    ip_hash = hashlib.sha256(raw_ip.encode()).hexdigest()[:64] if raw_ip else None

    share = PosterTemplateShare(
        share_slug=share_slug,
        template_id=template.id,
        sharer_user_id=0,  # Anonymous landing — actual sharer ID resolved via referrer if possible
        visitor_ip_hash=ip_hash,
        user_agent=(request.headers.get("user-agent") or "")[:300],
        referrer=(request.headers.get("referer") or "")[:500],
    )
    db.add(share)
    db.commit()

    # Render a public page promoting the template
    return HTMLResponse(content=f"""
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>{template.name} — SuperAdPro</title>
<meta name="description" content="{template.description}">
<style>
  body {{ margin: 0; font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Display', sans-serif;
         background: #0a1438; color: white; text-align: center; padding: 60px 20px; }}
  h1 {{ font-size: 36px; font-weight: 800; margin-bottom: 16px; }}
  .desc {{ font-size: 18px; color: #cbd5e1; max-width: 600px; margin: 0 auto 40px; line-height: 1.6; }}
  .cta {{ display: inline-block; background: linear-gradient(135deg, #0ea5e9, #38bdf8);
          color: #050d1a; padding: 16px 40px; border-radius: 12px; font-size: 18px;
          font-weight: 700; text-decoration: none; margin: 20px; }}
  .preview img {{ max-width: 400px; width: 100%; border-radius: 16px;
                  box-shadow: 0 20px 60px rgba(14,165,233,0.4); margin: 30px 0; }}
</style>
</head>
<body>
<h1>{template.name}</h1>
<p class="desc">{template.description}</p>
{f'<div class="preview"><img src="{template.preview_image_url}" alt="{template.name} example"></div>' if template.preview_image_url else ''}
<a class="cta" href="/signup">Join SuperAdPro Free →</a>
<p style="color: #94a3b8; font-size: 14px; margin-top: 40px;">
Make posters like this in 60 seconds. Brand Poster Generator inside Creative Studio.
</p>
</body>
</html>
""")


# ── BPG Admin: seed gallery preview images ──────────────────────────
# Generates one preview image per template by calling xAI Grok Imagine
# with each master prompt's default inputs. Uploads results to R2 and
# updates poster_templates.preview_image_url for each row.
#
# This is the one-shot setup endpoint we call once after first deploy
# of BPG, to populate the gallery with seed examples. After that, real
# member output starts to fill in via separate self-populating logic.
#
# Admin-only. Idempotent — re-running with force=true regenerates and
# overwrites.
@app.post("/admin/bpg/seed-previews")
async def bpg_admin_seed_previews(request: Request, db: Session = Depends(get_db),
                                   only_slug: str = None, force: bool = False):
    """Generate preview images for the BPG gallery.

    Query params:
      only_slug:  if provided, only regenerate that one template
      force:      if true, overwrite existing previews; otherwise skip
                  templates that already have preview_image_url set

    Returns a JSON summary with per-template results.
    """
    from .database import PosterTemplate
    from .poster_templates import POSTER_TEMPLATES, render_prompt
    from . import grok_imagine_service as grok_imagine
    from . import r2_storage
    import urllib.request

    # Admin gate
    user = get_current_user(request, db)
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")
    if not getattr(user, "is_admin", False):
        raise HTTPException(status_code=403, detail="Admin only")

    if not r2_storage.r2_available():
        raise HTTPException(status_code=503, detail="R2 storage not configured — cannot persist preview images")

    templates_to_process = POSTER_TEMPLATES
    if only_slug:
        templates_to_process = [t for t in POSTER_TEMPLATES if t["slug"] == only_slug]
        if not templates_to_process:
            raise HTTPException(
                status_code=404,
                detail=f"No template with slug '{only_slug}'. Available: "
                       + ", ".join(t["slug"] for t in POSTER_TEMPLATES),
            )

    results = []

    for template in templates_to_process:
        slug = template["slug"]
        row = db.query(PosterTemplate).filter_by(slug=slug).first()

        # Lazy-create the template row if it doesn't exist yet (first run)
        if not row:
            import json as _json
            row = PosterTemplate(
                slug=template["slug"],
                name=template["name"],
                description=template["description"],
                category=template["category"],
                sort_order=template["sort_order"],
                master_prompt=template["master_prompt"],
                input_fields=_json.dumps(template["input_fields"]),
                aspect_ratio=template["aspect_ratio"],
                supports_photo=template["supports_photo"],
                share_slug=template.get("share_slug"),
            )
            db.add(row)
            db.flush()

        # Skip if already seeded (unless force=true)
        if row.preview_image_url and not force:
            results.append({
                "slug": slug, "status": "skipped",
                "reason": "already has preview",
                "preview_url": row.preview_image_url,
            })
            continue

        # Build prompt from defaults
        defaults = {f["key"]: f.get("default", "") for f in template["input_fields"]}
        try:
            prompt = render_prompt(template, defaults)
        except ValueError as exc:
            results.append({"slug": slug, "status": "failed",
                            "error": f"prompt render: {exc}"})
            continue

        # Call Grok Imagine for 1 candidate (not 4 — gallery only needs one)
        try:
            grok_result = await grok_imagine.generate_candidates(
                prompt=prompt,
                reference_url=None,
                aspect=template["aspect_ratio"],
                n=1,
            )
        except Exception as exc:
            logger.exception(f"BPG seed: Grok call crashed for {slug}: {exc}")
            results.append({"slug": slug, "status": "failed",
                            "error": f"grok crash: {str(exc)[:200]}"})
            continue

        if "error" in grok_result:
            results.append({"slug": slug, "status": "failed",
                            "error": grok_result.get("error", "unknown")})
            continue

        urls = grok_result.get("images") or []
        if not urls:
            results.append({"slug": slug, "status": "failed",
                            "error": "no images returned"})
            continue

        # Download the image from xAI. Uses _bpg_fetch_xai_image helper
        # (defined near /api/posters/generation/{id}/choose) which has the
        # required User-Agent + Bearer auth headers. xAI's CDN rejects
        # default Python urllib User-Agent strings with HTTP 403.
        try:
            image_bytes = _bpg_fetch_xai_image(urls[0])
        except Exception as exc:
            logger.exception(f"BPG seed: download failed for {slug}: {exc}")
            results.append({"slug": slug, "status": "failed",
                            "error": f"download: {str(exc)[:200]}"})
            continue

        # Upload to R2
        try:
            r2_url = r2_storage.upload_image(
                image_bytes,
                folder="bpg-previews",
                ext="jpg",
                content_type="image/jpeg",
            )
        except Exception as exc:
            logger.exception(f"BPG seed: R2 upload failed for {slug}: {exc}")
            results.append({"slug": slug, "status": "failed",
                            "error": f"r2 upload: {str(exc)[:200]}"})
            continue

        # Update the template row with the new preview URL
        row.preview_image_url = r2_url
        db.commit()

        size_kb = len(image_bytes) // 1024
        results.append({
            "slug": slug,
            "status": "generated",
            "preview_url": r2_url,
            "size_kb": size_kb,
        })
        logger.info(f"BPG seed: {slug} → {r2_url} ({size_kb} KB)")

    succeeded = [r for r in results if r["status"] == "generated"]
    skipped = [r for r in results if r["status"] == "skipped"]
    failed = [r for r in results if r["status"] == "failed"]

    return {
        "success": True,
        "summary": {
            "generated": len(succeeded),
            "skipped": len(skipped),
            "failed": len(failed),
        },
        "results": results,
    }


