@app.get("/api/credit-matrix/commissions")
async def api_credit_matrix_commissions(user: User = Depends(get_current_user),
                                         db: Session = Depends(get_db),
                                         pack_key: str = None):
    """Get matrix commissions earned by the current user.

    Each item is now annotated with the pack tier of the matrix it came
    from (matrix_pack_key + pack_label), so the frontend can filter or
    chip-label commissions by tier. The optional pack_key query param
    filters commissions to only those earned from matrices of that tier.

    Necessary because a single user can own multiple active matrices
    (one per pack tier). Without per-tier info the commission history
    pane shows commissions that look unrelated to the matrix the
    visualiser is rendering.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from app.database import CreditMatrixCommission, CreditMatrix

    # Pre-load all of this user's matrices once so we can map matrix_id
    # → pack_key without N+1 queries against credit_matrices.
    user_matrices = db.query(CreditMatrix).filter(
        CreditMatrix.owner_id == user.id
    ).all()
    matrix_pack_map = {m.id: m.pack_key for m in user_matrices}

    query = db.query(CreditMatrixCommission).filter(
        CreditMatrixCommission.earner_id == user.id
    )

    # Optional filter: only commissions from matrices of a specific pack tier
    if pack_key:
        matching_matrix_ids = [
            mid for mid, pk in matrix_pack_map.items() if pk == pack_key
        ]
        if matching_matrix_ids:
            query = query.filter(CreditMatrixCommission.matrix_id.in_(matching_matrix_ids))
        else:
            # No matrix of that tier — return empty rather than ALL commissions
            return {
                "success": True,
                "commissions": [],
                "summary": {
                    "total_earned": 0.0, "l1_earned": 0.0, "l2_earned": 0.0,
                    "l3_earned": 0.0, "completion_bonuses": 0.0,
                    "total_transactions": 0,
                },
                "filter": {"pack_key": pack_key, "applied": True},
            }

    commissions = query.order_by(CreditMatrixCommission.created_at.desc()).limit(100).all()

    items = []
    for c in commissions:
        from_user = db.query(User).filter(User.id == c.from_user_id).first()
        comm_pack_key = matrix_pack_map.get(c.matrix_id)
        comm_pack = CREDIT_PACKS.get(comm_pack_key or "", {})
        items.append({
            "id": c.id,
            "from_user": from_user.username if from_user else "Unknown",
            "level": c.level,
            "rate": float(c.rate),
            "pack_price": float(c.pack_price),
            "amount": float(c.amount),
            "type": c.commission_type,
            "status": c.status,
            "matrix_id": c.matrix_id,
            "matrix_pack_key": comm_pack_key,
            "matrix_pack_label": comm_pack.get("label", comm_pack_key or "Unknown"),
            "created_at": c.created_at.isoformat() if c.created_at else None,
        })

    # Summary stats — over the returned (possibly filtered) set
    from decimal import Decimal
    total_earned = sum(Decimal(str(c.amount)) for c in commissions)
    l1_earned = sum(Decimal(str(c.amount)) for c in commissions if c.level == 1)
    l2_earned = sum(Decimal(str(c.amount)) for c in commissions if c.level == 2)
    l3_earned = sum(Decimal(str(c.amount)) for c in commissions if c.level == 3)
    bonuses = sum(Decimal(str(c.amount)) for c in commissions if c.commission_type == "matrix_completion")

    return {
        "success": True,
        "commissions": items,
        "summary": {
            "total_earned": float(total_earned),
            "l1_earned": float(l1_earned),
            "l2_earned": float(l2_earned),
            "l3_earned": float(l3_earned),
            "completion_bonuses": float(bonuses),
            "total_transactions": len(items),
        },
        "filter": {"pack_key": pack_key, "applied": bool(pack_key)},
    }
@app.get("/api/credit-matrix/stats")
async def api_credit_matrix_stats(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Credit-pack dashboard stats — FLAT 20% model (matrix retired 30 May 2026).

    Returns the data the back-office ledger view binds to: credit balance,
    referral earnings, paying-referral count, credits bought. No matrix
    structure (positions/fill/cycles) — those concepts no longer exist.

    referral_earnings reuses compute_user_earnings()['nexus_earnings'] so this
    figure is identical to every other surface (wallet card, analytics, etc.)
    and can't drift.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from app.database import CreditMatrixCommission, CreditPackPurchase, SuperSceneCredit
    from decimal import Decimal

    # Referral earnings — from the central live-ledger reader (matches all
    # other dashboards). direct_referral rows live in credit_matrix_commissions.
    earn = compute_user_earnings(db, user.id)
    referral_earnings = earn.get("nexus_earnings", 0.0)

    # Paying referrals: distinct people whose purchases paid this user a
    # direct_referral commission (i.e. their referrals who actually bought).
    paying_referrals = (
        db.query(func.count(func.distinct(CreditMatrixCommission.from_user_id)))
          .filter(
              CreditMatrixCommission.earner_id == user.id,
              CreditMatrixCommission.status == "paid",
          ).scalar() or 0
    )

    # Own purchases (buyer side)
    own_purchases = db.query(CreditPackPurchase).filter(
        CreditPackPurchase.user_id == user.id, CreditPackPurchase.status == "completed"
    ).all()
    total_spent = float(sum(Decimal(str(p.pack_price)) for p in own_purchases))
    total_credits_bought = sum(p.credits_awarded for p in own_purchases)

    # Current credit balance
    credit_record = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == user.id).first()
    credit_balance = int(credit_record.balance) if credit_record else 0

    # Buyer's purchase history (most recent first)
    purchases = [{
        "pack_key": p.pack_key,
        "pack_label": CREDIT_PACKS.get(p.pack_key, {}).get("label", p.pack_key),
        "pack_price": float(p.pack_price),
        "credits_awarded": p.credits_awarded,
        "created_at": p.created_at.isoformat() if p.created_at else None,
    } for p in sorted(own_purchases, key=lambda x: x.created_at or datetime.min, reverse=True)]

    return {
        "success": True,
        "stats": {
            "credit_balance": credit_balance,
            "referral_earnings": round(referral_earnings, 2),
            "paying_referrals": int(paying_referrals),
            "credits_bought": total_credits_bought,
            "total_spent": round(total_spent, 2),
            "referral_rate_pct": 20,
            "purchases": purchases,
        },
    }
@app.get("/api/credit-matrix/team-activity")
async def api_credit_matrix_team_activity(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Referral commission feed — FLAT 20% model (matrix retired 30 May 2026).

    Lists this user's recent direct_referral commissions: who bought, what
    pack, what the user earned, when. Replaces the old matrix-position team
    feed (positions no longer fill)."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from app.database import CreditMatrixCommission, CreditPackPurchase

    coms = (
        db.query(CreditMatrixCommission)
          .filter(
              CreditMatrixCommission.earner_id == user.id,
              CreditMatrixCommission.status == "paid",
          )
          .order_by(CreditMatrixCommission.created_at.desc())
          .limit(20).all()
    )

    activity = []
    for c in coms:
        buyer = db.query(User).filter(User.id == c.from_user_id).first()
        # Best-effort pack label: match the buyer's purchase nearest this commission
        pack_label = None
        pack_price = float(c.pack_price or 0)
        if buyer:
            pp = (
                db.query(CreditPackPurchase)
                  .filter(CreditPackPurchase.user_id == buyer.id,
                          CreditPackPurchase.status == "completed")
                  .order_by(CreditPackPurchase.created_at.desc()).first()
            )
            if pp:
                pack_label = CREDIT_PACKS.get(pp.pack_key, {}).get("label", pp.pack_key)
        activity.append({
            "username": buyer.username if buyer else "Unknown",
            "pack": pack_label or "Credit pack",
            "pack_price": pack_price,
            "earned": float(c.amount),
            "created_at": c.created_at.isoformat() if c.created_at else None,
        })

    return {"success": True, "activity": activity}
# ═══════════════════════════════════════════════════════════
#  CAMPAIGN ANALYTICS — Real view data for campaign owners
# ═══════════════════════════════════════════════════════════

@app.get("/api/campaign-analytics/overview")
async def api_campaign_analytics_overview(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Campaign analytics overview — all campaigns with view stats."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from datetime import date, timedelta
    from sqlalchemy import func

    campaigns = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id,
        VideoCampaign.status != "deleted",
    ).order_by(VideoCampaign.created_at.desc()).all()

    if not campaigns:
        return {"success": True, "campaigns": [], "totals": {"total_views": 0, "views_today": 0, "views_this_week": 0, "views_this_month": 0, "active_campaigns": 0, "avg_watch_duration": 0}}

    campaign_ids = [c.id for c in campaigns]
    today_str = str(date.today())
    week_ago = str(date.today() - timedelta(days=7))
    month_ago = str(date.today() - timedelta(days=30))

    # Total views
    total_views = sum(c.views_delivered or 0 for c in campaigns)

    # Views today (only count complete watches, not started-but-not-finished)
    views_today = db.query(func.count(VideoWatch.id)).filter(
        VideoWatch.campaign_id.in_(campaign_ids),
        VideoWatch.watch_date == today_str,
        VideoWatch.is_complete == True,  # noqa: E712
    ).scalar() or 0

    # Views this week (only count complete watches)
    views_week = db.query(func.count(VideoWatch.id)).filter(
        VideoWatch.campaign_id.in_(campaign_ids),
        VideoWatch.watch_date >= week_ago,
        VideoWatch.is_complete == True,  # noqa: E712
    ).scalar() or 0

    # Views this month (only count complete watches)
    views_month = db.query(func.count(VideoWatch.id)).filter(
        VideoWatch.campaign_id.in_(campaign_ids),
        VideoWatch.watch_date >= month_ago,
        VideoWatch.is_complete == True,  # noqa: E712
    ).scalar() or 0

    # Average watch duration (only count complete watches - started-but-not-finished
    # rows have duration_secs=0 which would drag the average toward zero)
    avg_duration = db.query(func.avg(VideoWatch.duration_secs)).filter(
        VideoWatch.campaign_id.in_(campaign_ids),
        VideoWatch.is_complete == True,  # noqa: E712
    ).scalar() or 30

    # Unique viewers (only count viewers who actually completed at least one watch)
    unique_viewers = db.query(func.count(func.distinct(VideoWatch.user_id))).filter(
        VideoWatch.campaign_id.in_(campaign_ids),
        VideoWatch.is_complete == True,  # noqa: E712
    ).scalar() or 0

    # ── NEW: Platform-wide viewer country breakdown (top 5, completed watches only) ──
    # Joins VideoWatch → User to group by country. Shows where your audience is.
    country_rows = db.query(
        User.country,
        func.count(func.distinct(VideoWatch.user_id)).label("viewers"),
    ).join(VideoWatch, VideoWatch.user_id == User.id).filter(
        VideoWatch.campaign_id.in_(campaign_ids),
        VideoWatch.is_complete == True,  # noqa: E712
        User.country.isnot(None),
        User.country != "",
    ).group_by(User.country).order_by(func.count(func.distinct(VideoWatch.user_id)).desc()).limit(5).all()

    top_countries = [{"country": row[0], "viewers": int(row[1])} for row in country_rows]

    # ── NEW: Hourly distribution across all campaigns (7×24 heatmap data) ──
    # Returns 168 cells: for each (day_of_week, hour), how many views landed there.
    # Uses SQL EXTRACT for portability; Postgres and SQLite both support it.
    # dow: 0=Sunday..6=Saturday (Postgres); hour: 0-23
    from sqlalchemy import extract
    hourly_rows = db.query(
        extract("dow", VideoWatch.watched_at).label("dow"),
        extract("hour", VideoWatch.watched_at).label("hour"),
        func.count(VideoWatch.id).label("views"),
    ).filter(
        VideoWatch.campaign_id.in_(campaign_ids),
        VideoWatch.is_complete == True,  # noqa: E712
    ).group_by("dow", "hour").all()

    # Build a 7×24 matrix, zero-filled
    heatmap = [[0 for _ in range(24)] for _ in range(7)]
    for row in hourly_rows:
        try:
            dow_idx = int(row[0]) if row[0] is not None else 0
            hr_idx = int(row[1]) if row[1] is not None else 0
            if 0 <= dow_idx <= 6 and 0 <= hr_idx <= 23:
                heatmap[dow_idx][hr_idx] = int(row[2])
        except (TypeError, ValueError):
            continue

    # Per-campaign stats (only count complete watches, not started-but-not-finished)
    campaign_data = []
    for c in campaigns:
        c_views_today = db.query(func.count(VideoWatch.id)).filter(
            VideoWatch.campaign_id == c.id,
            VideoWatch.watch_date == today_str,
            VideoWatch.is_complete == True,  # noqa: E712
        ).scalar() or 0

        c_views_week = db.query(func.count(VideoWatch.id)).filter(
            VideoWatch.campaign_id == c.id,
            VideoWatch.watch_date >= week_ago,
            VideoWatch.is_complete == True,  # noqa: E712
        ).scalar() or 0

        c_unique = db.query(func.count(func.distinct(VideoWatch.user_id))).filter(
            VideoWatch.campaign_id == c.id,
            VideoWatch.is_complete == True,  # noqa: E712
        ).scalar() or 0

        # ── NEW: Velocity — recent 7-day view rate, used to estimate days-to-completion ──
        # If a campaign is averaging 150 views/day and has 2000 left, ~14 days to go.
        recent_7d_views = db.query(func.count(VideoWatch.id)).filter(
            VideoWatch.campaign_id == c.id,
            VideoWatch.watch_date >= week_ago,
            VideoWatch.is_complete == True,  # noqa: E712
        ).scalar() or 0

        daily_rate = round(recent_7d_views / 7.0, 1) if recent_7d_views else 0
        remaining = max((c.views_target or 0) - (c.views_delivered or 0), 0)
        if daily_rate > 0 and remaining > 0:
            days_to_complete = round(remaining / daily_rate, 1)
        elif remaining == 0:
            days_to_complete = 0  # already complete
        else:
            days_to_complete = None  # not enough data

        completion_pct = round(((c.views_delivered or 0) / max(c.views_target or 1, 1)) * 100, 1)

        campaign_data.append({
            "id": c.id,
            "title": c.title,
            "platform": c.platform,
            "category": c.category or "General",
            "status": c.status,
            "tier": (c.campaign_tier if c.campaign_tier is not None else 1),
            "views_delivered": c.views_delivered or 0,
            "views_target": c.views_target or 0,
            "completion_pct": min(completion_pct, 100),
            "views_today": c_views_today,
            "views_this_week": c_views_week,
            "unique_viewers": c_unique,
            "daily_rate": daily_rate,
            "days_to_complete": days_to_complete,
            "cta_url": c.cta_url,
            "cta_clicks": c.cta_clicks or 0,
            "created_at": c.created_at.isoformat() if c.created_at else None,
        })

    return {
        "success": True,
        "campaigns": campaign_data,
        "totals": {
            "total_views": total_views,
            "views_today": views_today,
            "views_this_week": views_week,
            "views_this_month": views_month,
            "active_campaigns": sum(1 for c in campaigns if c.status == "active"),
            "unique_viewers": unique_viewers,
            "avg_watch_duration": round(float(avg_duration), 1),
        },
        "top_countries": top_countries,
        "hourly_heatmap": heatmap,
    }
@app.get("/api/campaign-analytics/{campaign_id}/daily")
async def api_campaign_analytics_daily(campaign_id: int, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Daily view breakdown for a specific campaign — last 30 days."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from datetime import date, timedelta
    from sqlalchemy import func

    campaign = db.query(VideoCampaign).filter(
        VideoCampaign.id == campaign_id,
        VideoCampaign.user_id == user.id,
    ).first()

    if not campaign:
        return JSONResponse({"error": "Campaign not found"}, status_code=404)

    # Last 30 days of daily views
    thirty_days_ago = str(date.today() - timedelta(days=30))

    daily_views = db.query(
        VideoWatch.watch_date,
        func.count(VideoWatch.id).label("views"),
        func.count(func.distinct(VideoWatch.user_id)).label("unique_viewers"),
        func.avg(VideoWatch.duration_secs).label("avg_duration"),
    ).filter(
        VideoWatch.campaign_id == campaign_id,
        VideoWatch.watch_date >= thirty_days_ago,
        VideoWatch.is_complete == True,  # noqa: E712
    ).group_by(VideoWatch.watch_date).order_by(VideoWatch.watch_date).all()

    # Fill in missing days with zero
    days = []
    current = date.today() - timedelta(days=29)
    daily_map = {row[0]: {"views": row[1], "unique": row[2], "avg_duration": round(float(row[3] or 30), 1)} for row in daily_views}

    for i in range(30):
        d = str(current + timedelta(days=i))
        data = daily_map.get(d, {"views": 0, "unique": 0, "avg_duration": 0})
        days.append({
            "date": d,
            "views": data["views"],
            "unique_viewers": data["unique"],
            "avg_duration": data["avg_duration"],
        })

    # Recent individual watches (last 20, completed only - owners shouldn't see
    # started-but-not-finished sessions as confirmed views)
    recent_watches = db.query(VideoWatch).filter(
        VideoWatch.campaign_id == campaign_id,
        VideoWatch.is_complete == True,  # noqa: E712
    ).order_by(VideoWatch.watched_at.desc()).limit(20).all()

    watch_log = []
    for w in recent_watches:
        viewer = db.query(User).filter(User.id == w.user_id).first()
        watch_log.append({
            "viewer": viewer.username if viewer else "Member",
            "duration": w.duration_secs or 30,
            "watched_at": w.watched_at.isoformat() if w.watched_at else None,
            "date": w.watch_date,
        })

    # ── NEW: Per-campaign country breakdown (top 5, completed watches only) ──
    country_rows = db.query(
        User.country,
        func.count(func.distinct(VideoWatch.user_id)).label("viewers"),
    ).join(VideoWatch, VideoWatch.user_id == User.id).filter(
        VideoWatch.campaign_id == campaign_id,
        VideoWatch.is_complete == True,  # noqa: E712
        User.country.isnot(None),
        User.country != "",
    ).group_by(User.country).order_by(func.count(func.distinct(VideoWatch.user_id)).desc()).limit(5).all()
    campaign_countries = [{"country": row[0], "viewers": int(row[1])} for row in country_rows]

    # ── NEW: Per-campaign hourly heatmap (7×24, completed watches only) ──
    from sqlalchemy import extract
    hourly_rows = db.query(
        extract("dow", VideoWatch.watched_at).label("dow"),
        extract("hour", VideoWatch.watched_at).label("hour"),
        func.count(VideoWatch.id).label("views"),
    ).filter(
        VideoWatch.campaign_id == campaign_id,
        VideoWatch.is_complete == True,  # noqa: E712
    ).group_by("dow", "hour").all()

    campaign_heatmap = [[0 for _ in range(24)] for _ in range(7)]
    for row in hourly_rows:
        try:
            dow_idx = int(row[0]) if row[0] is not None else 0
            hr_idx = int(row[1]) if row[1] is not None else 0
            if 0 <= dow_idx <= 6 and 0 <= hr_idx <= 23:
                campaign_heatmap[dow_idx][hr_idx] = int(row[2])
        except (TypeError, ValueError):
            continue

    return {
        "success": True,
        "campaign": {
            "id": campaign.id,
            "title": campaign.title,
            "views_delivered": campaign.views_delivered or 0,
            "views_target": campaign.views_target or 0,
            "status": campaign.status,
            "tier": (campaign.campaign_tier if campaign.campaign_tier is not None else 1),
        },
        "daily": days,
        "recent_watches": watch_log,
        "top_countries": campaign_countries,
        "hourly_heatmap": campaign_heatmap,
    }
