@app.post("/admin/api/migrate-import")
async def admin_api_migrate_import(
    file: UploadFile = File(...),
    secret: str = "",
    db: Session = Depends(get_db),
):
    """One-shot, idempotent AdvantageLife migration. Ingests the export JSON,
    derives the 3/6/9 pass-up tree, flags active subscribers as lifetime, and
    upserts into the users table by id (two-pass to avoid FK ordering issues)."""
    _check_migration_secret(secret)
    import json as _json, os as _os
    from collections import defaultdict as _dd, deque as _deque
    from datetime import datetime as _dt
    from sqlalchemy import text as _text

    data = _json.loads(await file.read())
    members = {u["id"]: u for u in data["members"]}
    N = len(members)

    # ── derive pass-up tree in join order ──
    children = _dd(list)
    for u in members.values():
        children[u["sponsor_id"]].append(u)
    for k in children:
        children[k].sort(key=lambda x: (x.get("created_at") or "", x["id"]))
    POS = {3, 6, 9}
    pass_up = {}
    roots = children.get(None, [])
    for r in roots:
        pass_up[r["id"]] = None
    dq = _deque(roots)
    while dq:
        node = dq.popleft()
        for i, kid in enumerate(children.get(node["id"], [])):
            pass_up[kid["id"]] = pass_up.get(node["id"]) if (i + 1) in POS else node["id"]
            dq.append(kid)

    def _parse(ts):
        if not ts:
            return None
        try:
            return _dt.fromisoformat(ts)
        except Exception:
            return None

    # ── PASS 1: upsert identities (relationships null for now) ──
    inserted = updated = 0
    for uid, u in members.items():
        gf = (u.get("stripe_status") == "active")
        row = db.query(User).filter(User.id == uid).first()
        if row is None:
            row = User(id=uid)
            db.add(row); inserted += 1
        else:
            updated += 1
        row.username = u.get("username")
        row.email = u.get("email")
        row.membership_tier = u.get("membership_tier") or "free"
        row.is_founding_member = bool(u.get("is_founding_member"))
        row.founding_spot_number = u.get("founding_spot_number")
        row.is_admin = bool(u.get("is_admin"))
        row.access_level = "lifetime" if gf else "free"
        row.is_active = gf
        row.pack_sale_count = 0
        row.activated_at = _parse(u.get("activated_at"))
        row.created_at = _parse(u.get("created_at")) or row.created_at
    db.commit()

    # ── PASS 2: genealogy + derived pass-up (all rows exist now) ──
    for uid, u in members.items():
        row = db.query(User).filter(User.id == uid).first()
        row.sponsor_id = u.get("sponsor_id")
        row.pass_up_sponsor_id = pass_up.get(uid)
    db.commit()

    # ── reset id sequence so new signups don't collide with imported ids ──
    seq_note = "ok"
    try:
        db.execute(_text("SELECT setval(pg_get_serial_sequence('users','id'), (SELECT MAX(id) FROM users))"))
        db.commit()
    except Exception as e:
        seq_note = f"seq_reset_failed: {e}"

    lifetime = sum(1 for u in members.values() if u.get("stripe_status") == "active")
    total_users = db.query(User).count()
    return {
        "ok": True,
        "members_in_file": N,
        "inserted": inserted,
        "updated": updated,
        "lifetime_flagged": lifetime,
        "free": N - lifetime,
        "total_users_in_db_now": total_users,
        "sequence_reset": seq_note,
        "note": "Idempotent. Passwords not set — account-claim flow happens at launch.",
    }


@app.get("/admin/api/grant-lifetime")
def admin_api_grant_lifetime(
    usernames: str = "",
    secret: str = "",
    db: Session = Depends(get_db),
):
    """Grant lifetime access to a comma-separated list of usernames — the
    hand-picked allow-list. Reusable at any time, idempotent."""
    _check_migration_secret(secret)
    wanted = [x.strip().lstrip("@") for x in usernames.split(",") if x.strip()]
    granted, notfound = [], []
    for uname in wanted:
        row = db.query(User).filter(User.username == uname).first()
        if row:
            row.access_level = "lifetime"
            row.is_active = True
            granted.append(uname)
        else:
            notfound.append(uname)
    db.commit()
    return {"ok": True, "granted": granted, "not_found": notfound,
            "total_lifetime_now": db.query(User).filter(User.access_level == "lifetime").count()}


@app.get("/admin/api/grant-pack")
def admin_api_grant_pack(
    usernames: str = "",
    level: int = 0,
    count: int = 1,
    secret: str = "",
    db: Session = Depends(get_db),
):
    """Gift free campaign pack(s) to members (Steve's loyal-member transition
    gift). Creates active PackPurchase rows flagged source='gift' — NO
    commission / pass-up fires (a gift is not a P2P sale). Each gift still
    requires the member to create their video ad + do their daily watch to run
    and earn, exactly like a bought pack. Mobile-tappable.

    Params: usernames (comma-separated), level (pack price: 10/20/50/100/200/
    400/600/800/1000), count (how many packs each member gets, default 1)."""
    _check_migration_secret(secret)

    pack = db.query(CampaignPack).filter(CampaignPack.level == level,
                                         CampaignPack.is_active == True).first()  # noqa: E712
    if not pack:
        valid = [p.level for p in db.query(CampaignPack).filter(CampaignPack.is_active == True).all()]  # noqa: E712
        return JSONResponse({"error": f"No active pack at level {level}. Valid: {sorted(valid)}"}, status_code=400)

    count = max(1, min(int(count), 20))  # sane bound
    wanted = [x.strip().lstrip("@") for x in usernames.split(",") if x.strip()]
    granted, notfound = [], []
    _dwr = pack.daily_watch_required if pack.daily_watch_required is not None else 1

    for uname in wanted:
        u = db.query(User).filter(func.lower(User.username) == uname.lower()).first()
        if not u:
            notfound.append(uname)
            continue
        for _ in range(count):
            db.add(PackPurchase(
                user_id=u.id, pack_id=pack.id, pack_level=pack.level,
                amount=0.0, payment_method="gift", status="active",
                source="gift", daily_watch_required=_dwr,
                activated_at=datetime.utcnow(), created_at=datetime.utcnow(),
            ))
        granted.append({"username": u.username, "packs": count})

    db.commit()
    return {"ok": True, "level": level, "count_each": count,
            "granted": granted, "not_found": notfound,
            "note": "Gift packs are active but need each member to submit a video ad before they deliver views. No commission fired."}


# ═══════════════════════════════════════════════════════════════════════
# ADVANTAGELIFE — P2P PACK SETTLEMENT API (7 Jul 2026, build-spec §4)
# The HTTP layer over al_settlement/al_engine. Rules enforced here, money
# logic lives in the engines — handlers CALL, never re-implement.
# Lifecycle: pending -> proof_submitted -> confirmed | disputed | expired | cancelled
# Payee locked at intent; counter advances at confirm; platform never holds funds.
# ═══════════════════════════════════════════════════════════════════════
from . import al_settlement as _als
from . import al_engine as _ale

def _al_user(user: User = Depends(get_current_user)):
    """AL-route auth guard: get_current_user returns None unauth (house
    pattern — every endpoint guards itself); this dependency raises the 401
    so no AL handler can ever run with user=None. First deploy 500'd on
    exactly this."""
    if not user:
        raise HTTPException(status_code=401, detail="Not authenticated")
    return user


AL_INTENT_TTL_HOURS = 48
AL_COMPANY_PAYOUT = {
    "method_type": "usdt_bsc",
    "details": os.environ.get("AL_COMPANY_USDT_ADDRESS", ""),
}


def _al_expire_stale(db):
    """Lazy expiry: pending intents older than the TTL expire on touch.
    Deterministic, no background task needed; admin sweep endpoint exists
    for a manual pass."""
    cutoff = datetime.utcnow() - timedelta(hours=AL_INTENT_TTL_HOURS)
    stale = (db.query(P2PIntent)
               .filter(P2PIntent.status == "pending",
                       P2PIntent.created_at < cutoff).all())
    for it in stale:
        it.status = "expired"
    if stale:
        db.commit()
    return len(stale)


def _al_payee_display(db, intent):
    if intent.earner_id is None:
        return {"username": "AdvantageLife", "display": "AdvantageLife (platform)",
                "is_company": True}
    u = db.query(User).filter(User.id == intent.earner_id).first()
    return {"username": u.username if u else "?",
            "display": (u.first_name or u.username) if u else "?",
            "is_company": False}


def _al_payout_options(intent):
    """The list of methods the buyer may pay (Option A). Handles both the new
    list snapshot and legacy single-dict snapshots; company sales offer the
    company payout."""
    import json as _j
    if intent.earner_id is None:
        return [AL_COMPANY_PAYOUT]
    try:
        snap = _j.loads(intent.payee_snapshot) if intent.payee_snapshot else None
    except Exception:
        snap = None
    if snap is None:
        return []
    if isinstance(snap, dict):        # legacy single-method intent
        return [snap]
    return snap                        # new: list of methods


def _al_payout_for(intent):
    """Back-comat single-method accessor: the buyer's chosen method if set,
    else the default (first) option."""
    opts = _al_payout_options(intent)
    if not opts:
        return None
    if intent.chosen_method:
        for o in opts:
            if o.get("method_type") == intent.chosen_method:
                return o
    return opts[0]


def _al_intent_json(db, intent, viewer_id=None):
    pack = db.query(CampaignPack).filter(CampaignPack.id == intent.pack_id).first()
    return {
        "intent_id": intent.id,
        "status": intent.status,
        "pack": {"level": intent.pack_level, "name": pack.name if pack else None,
                 "views": pack.views_target if pack else None},
        "amount": float(intent.amount or 0),
        "payee": _al_payee_display(db, intent),
        "payout": _al_payout_for(intent) if viewer_id == intent.buyer_id else None,
        "payout_options": _al_payout_options(intent) if viewer_id == intent.buyer_id else None,
        "chosen_method": intent.chosen_method,
        "buyer_id": intent.buyer_id,
        "tx_ref": intent.tx_ref,
        "created_at": intent.created_at.isoformat() if intent.created_at else None,
        "expires_at": ((intent.created_at + timedelta(hours=AL_INTENT_TTL_HOURS)).isoformat()
                       if intent.created_at and intent.status == "pending" else None),
        "confirmed_at": intent.confirmed_at.isoformat() if intent.confirmed_at else None,
    }


# ═══════════════════════════════════════════════════════════════════════
# AdvantageLife ADMIN — rebuilt for the pack / pass-up model (Jul 2026)
# ═══════════════════════════════════════════════════════════════════════
# The legacy AdminDashboard reports the retired business (grids, memberships,
# Creator Credits) and never touches PackCommission — the table AL actually
# pays from. These endpoints back the new AL admin, which reports what the
# platform IS now. Old panels stay untouched until fully replaced so nobody
# mistakes stale numbers for current ones.

_SHARE_DDL = [
    ("share_links", """
        CREATE TABLE IF NOT EXISTS share_links (
            id SERIAL PRIMARY KEY,
            user_id INTEGER UNIQUE REFERENCES users(id),
            token VARCHAR(24) UNIQUE NOT NULL,
            is_active BOOLEAN DEFAULT TRUE,
            share_count INTEGER DEFAULT 0,
            last_shared_at TIMESTAMP,
            created_at TIMESTAMP DEFAULT NOW()
        )"""),
    ("share_views", """
        CREATE TABLE IF NOT EXISTS share_views (
            id SERIAL PRIMARY KEY,
            share_link_id INTEGER REFERENCES share_links(id),
            campaign_id INTEGER REFERENCES video_campaigns(id),
            fingerprint VARCHAR(64),
            view_date VARCHAR(10),
            started_at TIMESTAMP DEFAULT NOW(),
            verified_at TIMESTAMP,
            watched_secs INTEGER DEFAULT 0,
            is_verified BOOLEAN DEFAULT FALSE,
            is_self BOOLEAN DEFAULT FALSE,
            created_at TIMESTAMP DEFAULT NOW()
        )"""),
]
_SHARE_COLS = [
    "ALTER TABLE video_campaigns ADD COLUMN IF NOT EXISTS share_approved BOOLEAN DEFAULT FALSE",
    "ALTER TABLE video_campaigns ADD COLUMN IF NOT EXISTS share_approved_at TIMESTAMP",
    "ALTER TABLE video_campaigns ADD COLUMN IF NOT EXISTS share_approved_by INTEGER",
]
_SHARE_IDX = [
    "CREATE INDEX IF NOT EXISTS ix_share_links_user ON share_links (user_id)",
    "CREATE INDEX IF NOT EXISTS ix_share_links_token ON share_links (token)",
    "CREATE INDEX IF NOT EXISTS ix_share_views_link ON share_views (share_link_id)",
    "CREATE INDEX IF NOT EXISTS ix_share_views_campaign ON share_views (campaign_id)",
    "CREATE INDEX IF NOT EXISTS ix_share_views_verified ON share_views (is_verified)",
    "CREATE INDEX IF NOT EXISTS ix_share_views_dedup ON share_views (fingerprint, campaign_id, view_date)",
    "CREATE INDEX IF NOT EXISTS ix_video_campaigns_share_approved ON video_campaigns (share_approved)",
]


@app.get("/admin/api/setup-share-tables")
def admin_setup_share_tables(request: Request,
                             user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """One-shot: create the video share system tables + the share_approved
    columns on video_campaigns.

    Same reason as setup-blog-tables: SKIP_MIGRATIONS=true on production means
    create_all()/run_migrations() don't build them on deploy. Idempotent
    (CREATE/ADD ... IF NOT EXISTS). Admin-only, GET (phone-friendly).
    Tap once after the deploy lands.
    """
    from sqlalchemy import text as _t
    if not user or not is_admin(user):
        raise HTTPException(status_code=403, detail="Access denied")
    results = {}
    for name, ddl in _SHARE_DDL:
        try:
            db.execute(_t(ddl)); db.commit(); results[name] = "ok"
        except Exception as e:
            db.rollback(); results[name] = f"error: {str(e)[:120]}"
    ok_cols = 0
    for stmt in _SHARE_COLS:
        try:
            db.execute(_t(stmt)); db.commit(); ok_cols += 1
        except Exception:
            db.rollback()
    results["video_campaigns share_* columns"] = f"{ok_cols}/{len(_SHARE_COLS)} ok"
    ok_idx = 0
    for stmt in _SHARE_IDX:
        try:
            db.execute(_t(stmt)); db.commit(); ok_idx += 1
        except Exception:
            db.rollback()
    results["indexes"] = f"{ok_idx}/{len(_SHARE_IDX)} ok"
    return {"ok": True, "results": results,
            "note": "Share system tables ready. Members can generate /w/{token} pages."}


@app.post("/admin/api/al/share-reset")
async def al_admin_share_reset(request: Request, user: User = Depends(_al_user),
                               db: Session = Depends(get_db)):
    """Clear a member's weekly share state so the card returns to 'not shared'.

    Testing aid: share state resets on Monday, which is useless when you need
    to see the un-shared card now. Clears last_shared_at only — verified
    ShareView rows are evidence and are never touched.
    """
    _require_admin(user)
    body = await request.json()
    uname = (body.get("username") or "").strip().lstrip("@")
    target = (db.query(User).filter(User.username == uname).first()
              if uname else user)
    if not target:
        return JSONResponse({"error": "user not found"}, status_code=404)
    link = db.query(ShareLink).filter(ShareLink.user_id == target.id).first()
    if not link:
        return JSONResponse({"error": "no share link for that user"}, status_code=404)
    link.last_shared_at = None
    link.share_count = 0
    db.commit()
    return {"ok": True, "username": target.username,
            "note": "Weekly share state cleared. Verified views were NOT touched."}


@app.get("/admin/api/al/share-performance")
def al_admin_share_performance(user: User = Depends(_al_user), db: Session = Depends(get_db)):
    """Proof the share system is working: who shared, and what real views their
    link actually produced.

    The share BUTTON proves nothing — no social platform reports back whether a
    post happened. What is provable is this: verified views recorded against a
    member's own /w/{token}, each one a stranger who watched 30+ seconds, checked
    server-side against a start row. This endpoint surfaces that evidence.
    """
    _require_admin(user)
    now = datetime.utcnow()
    week_start = (now - timedelta(days=now.weekday())).replace(hour=0, minute=0, second=0, microsecond=0)

    totals = {
        "links_created": db.query(func.count(ShareLink.id)).scalar() or 0,
        "members_who_shared": db.query(func.count(ShareLink.id))
                                .filter(ShareLink.last_shared_at.isnot(None)).scalar() or 0,
        "shared_this_week": db.query(func.count(ShareLink.id))
                              .filter(ShareLink.last_shared_at >= week_start).scalar() or 0,
        "views_started": db.query(func.count(ShareView.id)).scalar() or 0,
        "views_verified": db.query(func.count(ShareView.id))
                            .filter(ShareView.is_verified == True).scalar() or 0,
        "views_verified_week": db.query(func.count(ShareView.id))
                                 .filter(ShareView.is_verified == True,
                                         ShareView.verified_at >= week_start).scalar() or 0,
    }
    started = totals["views_started"] or 0
    totals["verify_rate_pct"] = (round(totals["views_verified"] / started * 100, 1)
                                 if started else None)

    # Per-member: link, whether they shared, and the views it actually produced.
    rows = (db.query(ShareLink, User.username)
              .join(User, User.id == ShareLink.user_id)
              .order_by(ShareLink.id.desc()).limit(100).all())
    verified_by_link, week_by_link = {}, {}
    if rows:
        ids = [l.id for l, _ in rows]
        for lid, n in (db.query(ShareView.share_link_id, func.count(ShareView.id))
                       .filter(ShareView.share_link_id.in_(ids), ShareView.is_verified == True)
                       .group_by(ShareView.share_link_id).all()):
            verified_by_link[lid] = int(n or 0)
        for lid, n in (db.query(ShareView.share_link_id, func.count(ShareView.id))
                       .filter(ShareView.share_link_id.in_(ids), ShareView.is_verified == True,
                               ShareView.verified_at >= week_start)
                       .group_by(ShareView.share_link_id).all()):
            week_by_link[lid] = int(n or 0)

    members = [{
        "username": un,
        "url": f"/w/{l.token}",
        "share_count": int(l.share_count or 0),
        "last_shared_at": l.last_shared_at.isoformat() if l.last_shared_at else None,
        "shared_this_week": bool(l.last_shared_at and l.last_shared_at >= week_start),
        "verified_views": verified_by_link.get(l.id, 0),
        "verified_views_week": week_by_link.get(l.id, 0),
    } for l, un in rows]
    members.sort(key=lambda m: -m["verified_views_week"])

    # Most recent verified views — the raw evidence trail.
    recent = (db.query(ShareView, ShareLink.token, User.username)
                .join(ShareLink, ShareLink.id == ShareView.share_link_id)
                .join(User, User.id == ShareLink.user_id)
                .filter(ShareView.is_verified == True)
                .order_by(ShareView.verified_at.desc()).limit(25).all())
    titles = {}
    if recent:
        for cid, t in db.query(VideoCampaign.id, VideoCampaign.title).filter(
                VideoCampaign.id.in_([v.campaign_id for v, _, _ in recent])).all():
            titles[cid] = t
    return {
        "totals": totals,
        "members": members,
        "recent_views": [{
            "sharer": un,
            "campaign": titles.get(v.campaign_id, f"#{v.campaign_id}"),
            "watched_secs": int(v.watched_secs or 0),
            "verified_at": v.verified_at.isoformat() if v.verified_at else None,
        } for v, tok, un in recent],
        "note": ("A share button can never prove a post happened — no platform reports back. "
                 "Verified views are the proof: each is a distinct viewer who watched 30+ seconds "
                 "on that member's own link, checked server-side against a start row."),
    }


@app.get("/admin/api/al/health")
def al_admin_health(user: User = Depends(_al_user), db: Session = Depends(get_db)):
    """AL-native health. The legacy /admin/api/health checks negative balances,
    stuck withdrawals and stuck grids — all SuperAdPro concepts that cannot
    occur here. These are the things that can actually go wrong on AL."""
    _require_admin(user)
    now = datetime.utcnow()
    issues = []

    def add(sev, kind, msg, count=0, hint=None):
        issues.append({"severity": sev, "type": kind, "message": msg,
                       "count": count, "hint": hint})

    # 1. Settlements stuck awaiting proof/confirmation — a buyer has paid (or
    #    hasn't) and the sale is in limbo. Real money, real member frustration.
    stale_cut = now - timedelta(hours=48)
    stuck = db.query(func.count(P2PIntent.id)).filter(
        P2PIntent.status.in_(("pending", "proof_submitted")),
        P2PIntent.created_at < stale_cut).scalar() or 0
    if stuck:
        add("warn", "stuck_intents", f"{stuck} settlement(s) unresolved for over 48h", stuck,
            "Check Settlements — buyer may have paid without the sale being confirmed.")

    disputed = db.query(func.count(P2PIntent.id)).filter(P2PIntent.status == "disputed").scalar() or 0
    if disputed:
        add("critical", "disputes", f"{disputed} disputed settlement(s) need a decision", disputed,
            "Resolve in Settlements — disputes block both members.")

    # 2. Company-fallback rate. Money reaching the company instead of members
    #    means members are failing the earning gates. Rising = comp plan pain.
    week = now - timedelta(days=7)
    rows = dict((t or "", int(c or 0)) for t, c in
                db.query(PackCommission.commission_type, func.count(PackCommission.id))
                  .filter(PackCommission.created_at >= week)
                  .group_by(PackCommission.commission_type).all())
    total_c = sum(rows.values())
    company_c = rows.get("direct_company", 0) + rows.get("pass_up_company", 0)
    if total_c and (company_c / total_c) > 0.25:
        pct = round(company_c / total_c * 100)
        add("warn", "company_fallback_high",
            f"{pct}% of this week's commissions fell to the company", company_c,
            "Members are failing the own-level or watch gate — check Members for gate status.")

    # 3. Genealogy integrity — an orphaned member breaks the pass-up chain.
    orphan_passup = db.query(func.count(User.id)).filter(
        User.sponsor_id.isnot(None), User.pass_up_sponsor_id.is_(None)).scalar() or 0
    if orphan_passup:
        add("warn", "passup_unassigned",
            f"{orphan_passup} member(s) have a sponsor but no pass-up sponsor", orphan_passup,
            "Pass-up chain can't resolve for these members.")

    # 4. Share pipeline
    waiting = db.query(func.count(VideoCampaign.id)).filter(
        VideoCampaign.share_approved.isnot(True), VideoCampaign.status == "active").scalar() or 0
    if waiting:
        add("info", "share_queue", f"{waiting} campaign(s) awaiting share approval", waiting,
            "Nothing reaches public share pages until approved.")

    approved = db.query(func.count(VideoCampaign.id)).filter(
        VideoCampaign.share_approved.is_(True), VideoCampaign.status == "active").scalar() or 0
    if approved == 0:
        add("info", "no_shareable", "No approved campaigns — public share pages will be empty", 0,
            "Approve campaigns so members' shared links show something.")

    # 5. Earners with no payout method can't be paid — the sale skips them.
    unpayable = db.query(func.count(User.id)).filter(
        User.pack_sale_count > 0,
        ~User.id.in_(db.query(PayoutMethod.user_id).distinct())).scalar() or 0
    if unpayable:
        add("warn", "no_payout_method",
            f"{unpayable} member(s) with sales have no payout method", unpayable,
            "Buyers have nowhere to send money — their commissions skip to the upline.")

    order = {"critical": 0, "warn": 1, "info": 2}
    issues.sort(key=lambda i: order.get(i["severity"], 3))
    return {
        "healthy": not any(i["severity"] in ("critical", "warn") for i in issues),
        "checked_at": now.isoformat(),
        "issues": issues,
        "note": ("AL-native checks. Balances, withdrawals and grids are SuperAdPro "
                 "concepts and cannot occur here — AL never holds member money."),
    }


@app.get("/admin/api/al/config-readiness")
def al_config_readiness(user: User = Depends(_al_user)):
    """Launch preflight: reports which critical env vars are SET on this deploy.

    Boolean-only — never returns a secret's value, only whether it's present.
    Grouped by subsystem so it's readable on mobile. Admin-only. This exists
    because a card checkout can succeed while the purchase never activates if
    the webhook secret is missing — 'money in, product not delivered'. This
    probe surfaces exactly those silent gaps before launch."""
    if not user.is_admin:
        raise HTTPException(status_code=403, detail="Admin access required")

    def has(name):
        v = os.environ.get(name)
        return bool(v and v.strip())

    def group(items):
        rows = [{"var": n, "set": has(n), "required": req} for (n, req) in items]
        missing_required = [r["var"] for r in rows if r["required"] and not r["set"]]
        return {"vars": rows, "missing_required": missing_required, "ok": not missing_required}

    groups = {
        "card_payments_stripe": group([
            ("STRIPE_SECRET_KEY", True),
            ("STRIPE_WEBHOOK_SECRET", True),
            ("STRIPE_PUBLISHABLE_KEY", False),
        ]),
        "crypto_join_and_p2p": group([
            ("AL_TREASURY_USDT_TRON", False),
            ("AL_TREASURY_USDT_ETH", False),
            ("AL_COMPANY_USDT_ADDRESS", True),
            ("TREASURY_ADDRESS_BSC", True),
            ("BSC_RPC_URL", False),
        ]),
        "credit_packs_crypto_nowpayments": group([
            ("NOWPAYMENTS_API_KEY", True),
            ("NOWPAYMENTS_IPN_SECRET", True),
        ]),
        "ai_tools_creative_studio": group([
            ("XAI_API_KEY", True),
            ("FAL_KEY", True),
            ("GEMINI_API_KEY", False),
            ("ANTHROPIC_API_KEY", False),
        ]),
        "email_delivery": group([
            ("EMAIL_PROVIDER", False),
            ("BREVO_API_KEY", False),
            ("AWS_ACCESS_KEY_ID", False),
            ("SES_SMTP_USER", False),
        ]),
        "brand_identity": group([
            ("BRAND_NAME", True),
            ("BASE_URL", True),
            ("SITE_URL", False),
        ]),
        "core_secrets": group([
            ("DATABASE_URL", True),
            ("SESSION_SECRET", True),
            ("MIGRATION_SECRET", True),
        ]),
    }

    all_missing = []
    for gname, g in groups.items():
        for v in g["missing_required"]:
            all_missing.append(gname + " / " + v)

    return {
        "deploy": os.environ.get("RAILWAY_ENVIRONMENT", "unknown"),
        "launch_ready": not all_missing,
        "missing_required_total": all_missing,
        "groups": groups,
        "note": ("Boolean-only: shows whether each var is set, never its value. "
                 "Email marks each provider optional individually because you need "
                 "ONE provider (Brevo OR SES), not all — confirm at least one."),
    }


@app.get("/admin/api/al/settlements-view")
def al_admin_settlements_view(status: str = "", user: User = Depends(_al_user),
                              db: Session = Depends(get_db)):
    """P2P settlement intents for the admin UI — who owes whom, proof state,
    and disputes. Previously these existed only as curl-only endpoints."""
    _require_admin(user)
    q = db.query(P2PIntent)
    if status:
        q = q.filter(P2PIntent.status == status)
    rows = q.order_by(P2PIntent.id.desc()).limit(150).all()
    ids = set()
    for i in rows:
        ids.add(i.buyer_id)
        if i.earner_id:
            ids.add(i.earner_id)
    names = {}
    if ids:
        for uid, un in db.query(User.id, User.username).filter(User.id.in_(ids)).all():
            names[uid] = un
    return {
        "counts": {st: db.query(func.count(P2PIntent.id)).filter(P2PIntent.status == st).scalar() or 0
                   for st in ("pending", "proof_submitted", "confirmed", "disputed", "expired", "cancelled")},
        "intents": [{
            "id": i.id,
            "buyer": names.get(i.buyer_id, "?"),
            "earner": names.get(i.earner_id, "COMPANY") if i.earner_id else "COMPANY",
            "pack_level": i.pack_level, "amount": float(i.amount or 0),
            "status": i.status, "commission_type": i.commission_type,
            "pass_up_depth": i.pass_up_depth, "tx_ref": i.tx_ref,
            "proof_url": i.proof_url,
        } for i in rows],
    }


@app.get("/admin/api/al/finances")
def al_admin_finances(user: User = Depends(_al_user), db: Session = Depends(get_db)):
    """AL finances on the REAL model.

    The critical distinction the cloned SuperAdPro dashboard gets wrong: pack
    money is 100% member-to-member and moves OFF-platform, so pack sales are
    member GMV, NOT platform revenue. The platform's actual income is:
      • $100 lifetime club joins (paid to the platform; sponsor earns nothing)
      • commissions that FELL to the company because a member failed a gate
    Company income rising is therefore not good news — it means members are
    failing to qualify. It's a warning light, not a revenue line.
    """
    _require_admin(user)
    now = datetime.utcnow()
    week_start = (now - timedelta(days=now.weekday())).replace(hour=0, minute=0, second=0, microsecond=0)

    lifetime_members = db.query(func.count(User.id)).filter(User.access_level == "lifetime").scalar() or 0

    # Member-to-member GMV (pack sales) — never platform revenue.
    gmv_all = float(db.query(func.coalesce(func.sum(PackPurchase.amount), 0))
                    .filter(PackPurchase.status == "active").scalar() or 0)
    gmv_week = float(db.query(func.coalesce(func.sum(PackPurchase.amount), 0))
                     .filter(PackPurchase.status == "active",
                             PackPurchase.created_at >= week_start).scalar() or 0)

    def _by_type(since=None):
        q = db.query(PackCommission.commission_type,
                     func.count(PackCommission.id),
                     func.coalesce(func.sum(PackCommission.amount), 0))
        if since is not None:
            q = q.filter(PackCommission.created_at >= since)
        return {(t or "unknown"): {"count": int(c or 0), "value": round(float(a or 0), 2)}
                for t, c, a in q.group_by(PackCommission.commission_type).all()}

    all_types, week_types = _by_type(), _by_type(week_start)
    company_keys = ("direct_company", "pass_up_company")
    to_company = round(sum(v["value"] for k, v in all_types.items() if k in company_keys), 2)
    to_members = round(sum(v["value"] for k, v in all_types.items() if k not in company_keys), 2)

    paid = float(db.query(func.coalesce(func.sum(PackCommission.amount), 0))
                 .filter(PackCommission.status == "paid").scalar() or 0)
    pending = float(db.query(func.coalesce(func.sum(PackCommission.amount), 0))
                    .filter(PackCommission.status == "pending").scalar() or 0)

    return {
        "platform_income": {
            "lifetime_joins": {"members": int(lifetime_members),
                               "value": round(lifetime_members * 100.0, 2)},
            "company_fallback_commissions": to_company,
            "total": round(lifetime_members * 100.0 + to_company, 2),
            "note": ("Company-fallback money is a warning light, not revenue: it only "
                     "arrives when a member failed the own-level / watch gate."),
        },
        "member_gmv": {"all_time": round(gmv_all, 2), "this_week": round(gmv_week, 2),
                       "note": "Pack sales are 100% member-to-member and move off-platform."},
        "commissions": {
            "to_members_all_time": to_members,
            "to_company_all_time": to_company,
            "member_share_pct": (round(to_members / (to_members + to_company) * 100, 1)
                                 if (to_members + to_company) > 0 else None),
            "paid": round(paid, 2), "pending": round(pending, 2),
            "by_type_all_time": all_types, "by_type_this_week": week_types,
        },
        "settlement_note": ("AdvantageLife never holds member money: buyers pay earners "
                            "directly using the payee's PayoutMethod. There are no member "
                            "balances and no withdrawal queue — those are SuperAdPro "
                            "concepts. Money-flow health is measured in Settlements "
                            "(intents, proofs, disputes), not in a payout queue."),
        "house_account_earnings": to_company,
    }


@app.get("/admin/api/al/overview")
def al_admin_overview(user: User = Depends(_al_user), db: Session = Depends(get_db)):
    """Platform pulse on the REAL model: packs, pass-ups, settlements, share queue."""
    _require_admin(user)
    now = datetime.utcnow()
    today = now.replace(hour=0, minute=0, second=0, microsecond=0)
    week_start = (now - timedelta(days=now.weekday())).replace(hour=0, minute=0, second=0, microsecond=0)

    def _sales(since):
        r = (db.query(func.count(PackPurchase.id), func.coalesce(func.sum(PackPurchase.amount), 0))
             .filter(PackPurchase.status == "active", PackPurchase.created_at >= since).first())
        return {"count": int(r[0] or 0), "value": round(float(r[1] or 0), 2)}

    # Commission split by type — 'company' rising is the early warning that
    # members are failing the earning gates.
    split = {}
    for ctype, cnt, amt in (db.query(PackCommission.commission_type,
                                     func.count(PackCommission.id),
                                     func.coalesce(func.sum(PackCommission.amount), 0))
                            .filter(PackCommission.created_at >= week_start)
                            .group_by(PackCommission.commission_type).all()):
        split[ctype or "unknown"] = {"count": int(cnt or 0), "value": round(float(amt or 0), 2)}

    return {
        "members": {
            "total": db.query(func.count(User.id)).scalar() or 0,
            "with_packs": db.query(func.count(func.distinct(PackPurchase.user_id)))
                            .filter(PackPurchase.status == "active").scalar() or 0,
            "new_this_week": db.query(func.count(User.id))
                               .filter(User.created_at >= week_start).scalar() or 0,
        },
        "sales": {"today": _sales(today), "week": _sales(week_start)},
        "commissions_this_week": split,
        "settlements": {st: db.query(func.count(P2PIntent.id))
                            .filter(P2PIntent.status == st).scalar() or 0
                        for st in ("pending", "proof_submitted", "disputed", "expired")},
        "share_queue": {
            "awaiting_approval": db.query(func.count(VideoCampaign.id))
                                   .filter(VideoCampaign.share_approved.isnot(True),
                                           VideoCampaign.status == "active").scalar() or 0,
            "approved": db.query(func.count(VideoCampaign.id))
                          .filter(VideoCampaign.share_approved.is_(True)).scalar() or 0,
            "verified_views_this_week": db.query(func.count(ShareView.id))
                                          .filter(ShareView.is_verified == True,
                                                  ShareView.verified_at >= week_start).scalar() or 0,
        },
    }


@app.get("/admin/api/al/share-queue")
def al_admin_share_queue(state: str = "pending", user: User = Depends(_al_user),
                         db: Session = Depends(get_db)):
    """Campaigns awaiting (or holding) approval for PUBLIC share pages.
    Members promote these to their own friends and family, so nothing goes
    public without a human deciding.

    NULL-safety matters here: `share_approved == False` does NOT match NULL
    (in SQL, NULL = false is NULL, not true). Campaigns created before the
    column existed can hold NULL, which would make them invisible to BOTH
    tabs — approved nowhere, pending nowhere. Pending therefore means
    "not TRUE", which correctly catches false AND null.
    """
    _require_admin(user)
    q = db.query(VideoCampaign).filter(VideoCampaign.status == "active")
    if state == "approved":
        q = q.filter(VideoCampaign.share_approved.is_(True))
    else:
        q = q.filter(VideoCampaign.share_approved.isnot(True))
    rows = q.order_by(VideoCampaign.created_at.desc()).limit(200).all()
    owners = {}
    if rows:
        for uid, un in db.query(User.id, User.username).filter(
                User.id.in_([r.user_id for r in rows])).all():
            owners[uid] = un
    return {"state": state, "campaigns": [{
        "id": c.id, "title": c.title, "description": (c.description or "")[:400],
        "category": c.category, "platform": c.platform, "embed_url": c.embed_url,
        "video_url": c.video_url, "cta_url": c.cta_url,
        "owner": owners.get(c.user_id, "?"), "owner_tier": c.owner_tier,
        "views_target": c.views_target, "views_delivered": c.views_delivered,
        "created_at": c.created_at.isoformat() if c.created_at else None,
        "share_approved_at": c.share_approved_at.isoformat() if c.share_approved_at else None,
    } for c in rows]}


@app.post("/admin/api/al/share-approve")
async def al_admin_share_approve(request: Request, user: User = Depends(_al_user),
                                 db: Session = Depends(get_db)):
    """Approve / revoke a campaign for public share pages."""
    _require_admin(user)
    body = await request.json()
    cid, approve = body.get("campaign_id"), bool(body.get("approve", True))
    c = db.query(VideoCampaign).filter(VideoCampaign.id == cid).first()
    if not c:
        return JSONResponse({"error": "Campaign not found"}, status_code=404)
    c.share_approved = approve
    c.share_approved_at = datetime.utcnow() if approve else None
    c.share_approved_by = user.id if approve else None
    db.commit()
    return {"ok": True, "campaign_id": cid, "share_approved": approve}


@app.get("/admin/api/al/pack-sales")
def al_admin_pack_sales(limit: int = 100, user: User = Depends(_al_user),
                        db: Session = Depends(get_db)):
    """Real money: pack purchases and the commissions they generated —
    direct, pass-up, or company (and which way it went)."""
    _require_admin(user)
    rows = (db.query(PackPurchase).filter(PackPurchase.status == "active")
              .order_by(PackPurchase.id.desc()).limit(min(limit, 300)).all())
    names = {}
    ids = {r.user_id for r in rows}
    coms = {}
    if rows:
        for c in db.query(PackCommission).filter(
                PackCommission.purchase_id.in_([r.id for r in rows])).all():
            coms.setdefault(c.purchase_id, []).append(c)
            if c.earner_id:
                ids.add(c.earner_id)
        for uid, un in db.query(User.id, User.username).filter(User.id.in_(ids)).all():
            names[uid] = un
    return {"sales": [{
        "id": r.id, "buyer": names.get(r.user_id, "?"), "pack_level": r.pack_level,
        "amount": float(r.amount or 0),
        "created_at": r.created_at.isoformat() if r.created_at else None,
        "commissions": [{
            "earner": names.get(c.earner_id) if c.earner_id else "COMPANY",
            "type": c.commission_type, "amount": float(c.amount or 0),
            "status": c.status, "pass_up_depth": c.pass_up_depth,
        } for c in coms.get(r.id, [])],
    } for r in rows]}


@app.get("/admin/api/al/members")
def al_admin_members(q: str = "", limit: int = 50, user: User = Depends(_al_user),
                     db: Session = Depends(get_db)):
    """Members on the AL model: pack owned, sales made, qualification state."""
    _require_admin(user)
    qq = db.query(User)
    if q:
        qq = qq.filter(User.username.ilike(f"%{q}%"))
    rows = qq.order_by(User.id.desc()).limit(min(limit, 200)).all()
    out = []
    for u in rows:
        out.append({
            "id": u.id, "username": u.username,
            "sponsor_id": u.sponsor_id, "pass_up_sponsor_id": u.pass_up_sponsor_id,
            "pack_sale_count": u.pack_sale_count or 0,
            "owned_level": _ale.owned_level(db, u.id),
            "watch_qualified": _ale.watch_qualified(db, u.id),
            "payable": _ale.payable(db, u.id),
            "is_admin": bool(u.is_admin),
            "created_at": u.created_at.isoformat() if u.created_at else None,
        })
    return {"members": out}


