@app.get("/api/al/packs/awaiting-ad")
def al_packs_awaiting_ad(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Active packs the member owns that still need a video ad before they
    start delivering views (campaign_id IS NULL). Drives the "create your ad"
    prompt — a pack earns nothing toward its view target until its ad is live."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    rows = (db.query(PackPurchase)
              .filter(PackPurchase.user_id == user.id,
                      PackPurchase.status == "active",
                      PackPurchase.campaign_id.is_(None))
              .order_by(PackPurchase.pack_level.desc()).all())
    out = []
    for r in rows:
        pack = db.query(CampaignPack).filter(CampaignPack.id == r.pack_id).first()
        out.append({
            "purchase_id": r.id,
            "pack_level": r.pack_level,
            "label": (pack.name if pack else f"${r.pack_level}"),
            "views_target": (pack.views_target if pack else 0),
            "daily_watch_required": r.daily_watch_required or 1,
            "source": r.source or "purchase",
        })
    return {"ok": True, "awaiting": out}


@app.post("/api/al/packs/{purchase_id}/submit-ad")
async def al_pack_submit_ad(purchase_id: int, request: Request,
                            user: User = Depends(get_current_user),
                            db: Session = Depends(get_db)):
    """The buyer creates the video advertisement for an active pack. This is the
    obligation that unlocks their earning: no ad = no campaign = no views
    delivered. Spawns a VideoCampaign with the pack's view target and links it
    back to the pack (campaign_id). The existing watch engine then delivers
    views and auto-completes it at the target."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    purchase = (db.query(PackPurchase)
                  .filter(PackPurchase.id == purchase_id,
                          PackPurchase.user_id == user.id).first())
    if not purchase:
        return JSONResponse({"error": "Pack not found"}, status_code=404)
    if purchase.status != "active":
        return JSONResponse({"error": "This pack isn't active."}, status_code=400)
    if purchase.campaign_id:
        return JSONResponse({"error": "This pack already has a live ad."}, status_code=400)

    body = await request.json()
    title = (body.get("title") or "").strip()
    video_url = (body.get("video_url") or "").strip()
    if not title or not video_url:
        return JSONResponse({"error": "A title and a video URL are both required."}, status_code=400)

    parsed = parse_video_url(video_url)
    if not parsed:
        return JSONResponse({"error": "That video URL isn't a supported platform (YouTube, Rumble, Vimeo)."}, status_code=400)

    pack = db.query(CampaignPack).filter(CampaignPack.id == purchase.pack_id).first()
    target = (pack.views_target if pack and pack.views_target else 0)

    campaign = VideoCampaign(
        user_id=user.id,
        title=title,
        description=(body.get("description") or "").strip() or None,
        platform=parsed["platform"],
        video_url=video_url,
        embed_url=parsed["embed_url"],
        video_id=parsed.get("video_id"),
        status="active",
        views_target=target,
        views_delivered=0,
        campaign_tier=purchase.pack_level,
        is_completed=False,
        created_at=datetime.utcnow(),
    )
    db.add(campaign)
    db.flush()  # need campaign.id

    purchase.campaign_id = campaign.id
    db.commit()

    return {"ok": True, "campaign_id": campaign.id,
            "views_target": target,
            "message": "Your ad is live — it'll start receiving views from members watching."}


@app.post("/api/al/packs/{pack_level}/intent")
async def al_create_intent(pack_level: int,
                           user: User = Depends(_al_user),
                           db: Session = Depends(get_db)):
    """Open a purchase intent: resolve + LOCK the payee, show the buyer
    exactly who to pay. One open intent per buyer."""
    if not _al_is_lifetime(user):
        return JSONResponse({"error": "Campaign packs are for lifetime members. Join for $100 (one time) to unlock packs.",
                             "action": "join", "join_url": "/join"}, status_code=403)
    _al_expire_stale(db)
    existing = (db.query(P2PIntent)
                  .filter(P2PIntent.buyer_id == user.id,
                          P2PIntent.status.in_(("pending", "proof_submitted")))
                  .first())
    if existing:
        return JSONResponse({"error": "You already have an open purchase — complete or cancel it first",
                             "intent": _al_intent_json(db, existing, user.id)}, status_code=409)
    try:
        intent = _als.create_intent(db, user.id, pack_level)
    except ValueError as e:
        return JSONResponse({"error": str(e)}, status_code=400)
    payout = _al_payout_for(intent)
    if intent.earner_id is not None and not payout:
        # Post-payability-gate this should be unreachable; belt-and-braces:
        # never hand a buyer an unpayable intent.
        intent.status = "cancelled"
        db.commit()
        logger.error(f"AL intent {intent.id}: resolved payee {intent.earner_id} has no payout method DESPITE gate")
        return JSONResponse({"error": "Could not prepare this purchase — try again shortly"}, status_code=500)
    out = _al_intent_json(db, intent, user.id)
    out["message"] = (f"Your payment goes directly to {out['payee']['display']} — "
                      "AdvantageLife never holds it. Pay the exact amount, then submit proof below.")
    return out


@app.post("/api/al/intents/{intent_id}/choose")
async def al_choose_method(intent_id: int, request: Request,
                           user: User = Depends(_al_user),
                           db: Session = Depends(get_db)):
    """Buyer records which of the seller's accepted methods they'll pay with
    (Option A multi-gateway). Must be one of the locked snapshot options."""
    intent = db.query(P2PIntent).filter(P2PIntent.id == intent_id).first()
    if not intent or intent.buyer_id != user.id:
        return JSONResponse({"error": "Intent not found"}, status_code=404)
    if intent.status not in ("pending", "proof_submitted"):
        return JSONResponse({"error": f"Intent is {intent.status}"}, status_code=400)
    body = await request.json()
    chosen = (body.get("method_type") or "").strip()
    valid = {o.get("method_type") for o in _al_payout_options(intent)}
    if chosen not in valid:
        return JSONResponse({"error": "That method isn't offered by this seller"}, status_code=400)
    intent.chosen_method = chosen
    db.commit()
    return {"ok": True, "chosen_method": chosen, "payout": _al_payout_for(intent)}


@app.post("/api/al/intents/{intent_id}/proof")
async def al_submit_proof(intent_id: int, request: Request,
                          user: User = Depends(_al_user),
                          db: Session = Depends(get_db)):
    intent = db.query(P2PIntent).filter(P2PIntent.id == intent_id).first()
    if not intent or intent.buyer_id != user.id:
        return JSONResponse({"error": "Intent not found"}, status_code=404)
    _al_expire_stale(db)
    if intent.status not in ("pending", "proof_submitted"):
        return JSONResponse({"error": f"Intent is {intent.status}"}, status_code=400)
    body = await request.json()
    tx_ref = (body.get("tx_ref") or "").strip()[:200]
    proof_url = (body.get("proof_url") or "").strip()[:500] or None
    if not tx_ref and not proof_url:
        return JSONResponse({"error": "Provide a transaction reference or proof"}, status_code=400)
    if tx_ref:
        dupe = (db.query(P2PIntent)
                  .filter(P2PIntent.tx_ref == tx_ref, P2PIntent.id != intent.id).first())
        if dupe:
            return JSONResponse({"error": "That transaction reference is already used"}, status_code=400)
    _als.submit_proof(db, intent.id, tx_ref=tx_ref or None, proof_url=proof_url)
    if intent.earner_id:
        seller = db.query(User).filter(User.id == intent.earner_id).first()
        amt = float(intent.amount or 0)
        # 1) In-app notification (bell)
        try:
            db.add(Notification(user_id=intent.earner_id, type="al_sale",
                                icon="💰", link="/my-sales",
                                title="Payment sent — confirm to release the pack",
                                message=f"{user.username} reports paying you ${amt:.2f} for a "
                                        f"Level {intent.pack_level} pack. Check your wallet, then "
                                        f"confirm at Confirm Sale to activate their pack."))
            db.commit()
        except Exception:
            db.rollback()
        # 2) Email — the notification a seller actually sees when away from the app
        try:
            if seller and seller.email:
                _base = os.environ.get("SITE_URL", "https://www.advantagelife.club").rstrip("/")
                _sub = f"💰 {user.username} paid you ${amt:.2f} — confirm to release their pack"
                _html = (
                    f"<div style=\"font-family:Inter,Arial,sans-serif;max-width:520px;margin:0 auto;color:#0a1f52\">"
                    f"<h2 style=\"color:#0a1f52\">You have an incoming pack sale</h2>"
                    f"<p><b>{user.username}</b> reports sending you <b>${amt:.2f}</b> for a "
                    f"Level {intent.pack_level} campaign pack.</p>"
                    f"<p><b>What to do:</b> check the wallet or account they paid, and once the money "
                    f"has arrived, confirm the sale to activate their pack and advance your counter.</p>"
                    f"<p style=\"margin:24px 0\"><a href=\"{_base}/my-sales\" "
                    f"style=\"background:#c8102e;color:#fff;font-weight:800;text-decoration:none;"
                    f"padding:14px 26px;border-radius:10px;display:inline-block\">Confirm this sale →</a></p>"
                    f"<p style=\"font-size:13px;color:#5a6584\">Only confirm once you have actually "
                    f"received the money. Member-to-member payments can't be reversed by AdvantageLife.</p>"
                    f"</div>")
                _text = (f"{user.username} reports paying you ${amt:.2f} for a Level {intent.pack_level} pack. "
                         f"Confirm once received: {_base}/my-sales")
                from .email_utils import send_email as _send
                _send(seller.email, _sub, _html, _text)
        except Exception:
            logger.exception("AL sale-notification email failed")
    return {"ok": True, "intent": _al_intent_json(db, intent, user.id)}


@app.post("/api/al/intents/{intent_id}/confirm")
async def al_confirm_intent(intent_id: int,
                            user: User = Depends(_al_user),
                            db: Session = Depends(get_db)):
    """The payee confirms money arrived (admin for company sales). This is the
    settlement moment: pack activates, counter advances. Idempotent."""
    intent = db.query(P2PIntent).filter(P2PIntent.id == intent_id).first()
    if not intent:
        return JSONResponse({"error": "Intent not found"}, status_code=404)
    if intent.status == "confirmed":
        return {"ok": True, "already": True, "intent": _al_intent_json(db, intent, user.id)}
    is_payee = intent.earner_id == user.id
    is_admin = bool(getattr(user, "is_admin", False))
    if not (is_payee or (intent.earner_id is None and is_admin) or is_admin):
        return JSONResponse({"error": "Only the person being paid can confirm this sale"}, status_code=403)
    if intent.status not in ("pending", "proof_submitted"):
        return JSONResponse({"error": f"Intent is {intent.status}"}, status_code=400)
    result = _als.confirm(db, intent.id, confirmed_by=user.id)
    buyer = db.query(User).filter(User.id == intent.buyer_id).first()
    try:
        db.add(Notification(user_id=intent.buyer_id, type="al_pack",
                            icon="🎉", link="/video-library",
                            title="Pack activated — you can create your campaign",
                            message=f"Your Level {intent.pack_level} campaign pack is live. "
                                    "Create your video campaign to start getting views, and "
                                    "you now earn at this level on your own sales."))
        db.commit()
    except Exception:
        db.rollback()
    # Email the buyer — the activation confirmation they'll actually see
    try:
        if buyer and buyer.email:
            _base = os.environ.get("SITE_URL", "https://www.advantagelife.club").rstrip("/")
            _sub = f"🎉 Your Level {intent.pack_level} pack is active — create your campaign"
            _html = (
                f"<div style=\"font-family:Inter,Arial,sans-serif;max-width:520px;margin:0 auto;color:#0a1f52\">"
                f"<h2 style=\"color:#0b7a3e\">Your pack is live 🎉</h2>"
                f"<p>Your payment was confirmed and your <b>Level {intent.pack_level}</b> campaign pack "
                f"is now active.</p>"
                f"<p><b>Two things you can do now:</b></p>"
                f"<ul><li>Create your video campaign to start getting real member views.</li>"
                f"<li>You now earn at this level on your own pack sales.</li></ul>"
                f"<p style=\"margin:24px 0\"><a href=\"{_base}/video-library\" "
                f"style=\"background:#c8102e;color:#fff;font-weight:800;text-decoration:none;"
                f"padding:14px 26px;border-radius:10px;display:inline-block\">Create your campaign →</a></p>"
                f"</div>")
            _text = (f"Your Level {intent.pack_level} pack is active. Create your campaign: {_base}/video-library")
            from .email_utils import send_email as _send
            _send(buyer.email, _sub, _html, _text)
    except Exception:
        logger.exception("AL pack-activation email failed")
    return {"ok": True, **result}


@app.post("/api/al/intents/{intent_id}/decline")
async def al_decline_intent(intent_id: int,
                            user: User = Depends(_al_user),
                            db: Session = Depends(get_db)):
    """Payee: 'I did not receive this' — freezes for admin resolution."""
    intent = db.query(P2PIntent).filter(P2PIntent.id == intent_id).first()
    if not intent or (intent.earner_id != user.id and not getattr(user, "is_admin", False)):
        return JSONResponse({"error": "Intent not found"}, status_code=404)
    if intent.status != "proof_submitted":
        return JSONResponse({"error": f"Intent is {intent.status}"}, status_code=400)
    intent.status = "disputed"
    intent.notes = ((intent.notes or "") + f" | disputed by {user.username} {datetime.utcnow().isoformat()}")[:2000]
    db.commit()
    return {"ok": True, "status": "disputed"}


