@app.get("/api/al/my-sales")
def al_my_sales(user: User = Depends(_al_user), db: Session = Depends(get_db)):
    """The payee's action queue: sales awaiting their confirmation, plus history."""
    _al_expire_stale(db)
    intents = (db.query(P2PIntent).filter(P2PIntent.earner_id == user.id)
                 .order_by(P2PIntent.id.desc()).limit(50).all())
    out = []
    for i in intents:
        j = _al_intent_json(db, i)
        buyer = db.query(User).filter(User.id == i.buyer_id).first()
        j["buyer"] = {"username": buyer.username if buyer else "?"}
        j["action_needed"] = i.status == "proof_submitted"
        # Surface the payout method so the confirm modal can show the right
        # label and, for reversible rails (Cash App / PayPal), the seller_note
        # warning. These already live in AL_PAYOUT_METHODS; my-sales just never
        # forwarded them.
        m = AL_PAYOUT_METHODS.get(i.chosen_method or "")
        j["method_label"] = m["label"] if m else None
        j["reversible"] = bool(m and m.get("reversible"))
        j["seller_note"] = m.get("seller_note") if m else None
        out.append(j)

    # Pass-up standing, computed from the authoritative counter (not the 50-row
    # window above — a member past 50 sales would miscount client-side).
    # 3/6/9 rule: the NEXT sale is slot = count + 1. Slots 3,6,9 pass up; after
    # the 9th, every sale is direct.
    count = user.pack_sale_count or 0
    next_slot = count + 1
    if next_slot > 9:
        passup = {"count": count, "next_slot": next_slot, "next_passes_up": False,
                  "sales_until_passup": None, "all_direct": True}
    else:
        nxt = next(p for p in (3, 6, 9) if next_slot <= p)
        passup = {"count": count, "next_slot": next_slot,
                  "next_passes_up": next_slot in (3, 6, 9),
                  "sales_until_passup": nxt - count, "all_direct": False}
    return {"sales": out, "passup": passup}


# ── Payout method registry: the five stablecoin rails members can receive
#    on. Stablecoins ONLY — pack prices are exact USD amounts and "send
#    exactly $X" must stay true between intent and payment (volatile coins
#    turn every sale into a rounding dispute). auto_verify marks chains the
#    platform scanner can annotate; settlement authority is ALWAYS the
#    payee's confirmation regardless.
AL_PAYOUT_METHODS = {
    "usdt_bsc":     {"label": "USDT · BNB Smart Chain (BEP-20)", "family": "evm",
                     "hint": 'Starts with "0x" — 42 characters', "auto_verify": True},
    "usdt_tron":    {"label": "USDT · TRON (TRC-20)", "family": "tron",
                     "hint": 'Starts with "T" — 34 characters', "auto_verify": False},
    "usdt_polygon": {"label": "USDT · Polygon", "family": "evm",
                     "hint": 'Starts with "0x" — 42 characters', "auto_verify": False},
    "usdt_eth":     {"label": "USDT · Ethereum (ERC-20)", "family": "evm",
                     "hint": 'Starts with "0x" — 42 characters. Note: buyers pay Ethereum gas.', "auto_verify": False},
    "usdc_bsc":     {"label": "USDC · BNB Smart Chain (BEP-20)", "family": "evm",
                     "hint": 'Starts with "0x" — 42 characters', "auto_verify": False},
    "usdc_polygon": {"label": "USDC · Polygon", "family": "evm",
                     "hint": 'Starts with "0x" — 42 characters', "auto_verify": False},
    "cashapp":      {"label": "Cash App", "family": "cashtag",
                     "hint": 'Your $Cashtag — starts with "$"', "auto_verify": False,
                     "reversible": True,
                     "seller_note": "Cash App payments can be reversed. Confirm only once the money shows as settled in your balance — not just received."},
    "paypal":       {"label": "PayPal", "family": "email",
                     "hint": "Your PayPal email address", "auto_verify": False,
                     "reversible": True,
                     "seller_note": "PayPal payments can be disputed for up to 180 days. Confirm only once the money is in your PayPal balance, and keep proof of the sale."},
    "wise":         {"label": "Wise", "family": "wise",
                     "hint": "Your Wise email or @Wisetag", "auto_verify": False,
                     "recv_note": "Send to your Wise account (email or Wisetag) — not a Wise card. Account-to-account Wise transfers are final and can't be reversed."},
    "zelle":        {"label": "Zelle", "family": "zelle",
                     "hint": "Your Zelle email or US phone number", "auto_verify": False,
                     "recv_note": "US bank accounts only. Zelle transfers are instant and final — there's no chargeback."},
    "revolut":      {"label": "Revolut", "family": "revtag",
                     "hint": "Your @Revtag, email or phone", "auto_verify": False,
                     "recv_note": "Send to your Revolut account (Revtag, email or phone) — not a Revolut card. Account-to-account transfers are final."},
}

_AL_ADDR_RE = {
    "evm":     re.compile(r"^0x[a-fA-F0-9]{40}$"),
    "tron":    re.compile(r"^T[1-9A-HJ-NP-Za-km-z]{33}$"),
    "cashtag": re.compile(r"^\$[a-zA-Z][a-zA-Z0-9_]{1,19}$"),
    "email":   re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$"),
    # Wise: email OR @Wisetag
    "wise":    re.compile(r"^(?:[^@\s]+@[^@\s]+\.[^@\s]+|@[a-zA-Z][a-zA-Z0-9]{2,29})$"),
    # Zelle: US email OR US phone
    "zelle":   re.compile(r"^(?:[^@\s]+@[^@\s]+\.[^@\s]+|\+?1?[\s\-.]?\(?\d{3}\)?[\s\-.]?\d{3}[\s\-.]?\d{4})$"),
    # Revolut: @Revtag OR email OR phone
    "revtag":  re.compile(r"^(?:@[a-zA-Z0-9]{4,20}|[^@\s]+@[^@\s]+\.[^@\s]+|\+?\d[\d\s\-.]{6,14}\d)$"),
}


def _al_validate_address(method_type: str, address: str):
    m = AL_PAYOUT_METHODS.get(method_type)
    if not m:
        return "Unknown payout method"
    if not _AL_ADDR_RE[m["family"]].match(address or ""):
        return f"That doesn't look like a valid address for {m['label']} ({m['hint']})"
    return None


@app.get("/api/al/payout-methods")
def al_list_payout_methods(user: User = Depends(_al_user), db: Session = Depends(get_db)):
    rows = (db.query(PayoutMethod).filter(PayoutMethod.user_id == user.id)
              .order_by(PayoutMethod.is_default.desc(), PayoutMethod.id).all())
    import json as _j
    out = []
    for r in rows:
        try:
            det = _j.loads(r.details) if r.details and r.details.strip().startswith("{") else {"address": r.details}
        except Exception:
            det = {"address": r.details}
        reg = AL_PAYOUT_METHODS.get(r.method_type, {})
        out.append({"id": r.id, "method_type": r.method_type,
                    "label": reg.get("label", r.method_type),
                    "address": det.get("address"),
                    "auto_verify": reg.get("auto_verify", False),
                    "is_default": bool(r.is_default)})
    return {"methods": out,
            "registry": [{"key": k, **v} for k, v in AL_PAYOUT_METHODS.items()]}


@app.post("/api/al/payout-methods")
async def al_add_payout_method(request: Request,
                               user: User = Depends(_al_user),
                               db: Session = Depends(get_db)):
    import json as _j
    body = await request.json()
    method_type = (body.get("method_type") or "").strip()
    address = (body.get("address") or "").strip()
    err = _al_validate_address(method_type, address)
    if err:
        return JSONResponse({"error": err}, status_code=400)
    dupe = (db.query(PayoutMethod)
              .filter(PayoutMethod.user_id == user.id,
                      PayoutMethod.method_type == method_type).first())
    if dupe:
        return JSONResponse({"error": "You already have a wallet for that method — delete it first to replace it"}, status_code=400)
    has_any = db.query(PayoutMethod.id).filter(PayoutMethod.user_id == user.id).first() is not None
    db.add(PayoutMethod(user_id=user.id, method_type=method_type,
                        details=_j.dumps({"address": address}),
                        is_default=not has_any))
    db.commit()
    return {"ok": True}


@app.post("/api/al/payout-methods/{method_id}/default")
def al_default_payout_method(method_id: int, user: User = Depends(_al_user),
                             db: Session = Depends(get_db)):
    row = db.query(PayoutMethod).filter(PayoutMethod.id == method_id,
                                        PayoutMethod.user_id == user.id).first()
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    db.query(PayoutMethod).filter(PayoutMethod.user_id == user.id).update({"is_default": False})
    row.is_default = True
    db.commit()
    return {"ok": True}


@app.post("/api/al/payout-methods/{method_id}/edit")
async def al_edit_payout_method(method_id: int, request: Request,
                                user: User = Depends(_al_user),
                                db: Session = Depends(get_db)):
    """Update the address on an existing receiving method (fix a typo without
    delete+re-add). Validates the new address against the method's family."""
    row = db.query(PayoutMethod).filter(PayoutMethod.id == method_id,
                                        PayoutMethod.user_id == user.id).first()
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    body = await request.json()
    new_addr = (body.get("address") or "").strip()
    err = _al_validate_address(row.method_type, new_addr)
    if err:
        return JSONResponse({"error": err}, status_code=400)
    import json as _j
    try:
        d = _j.loads(row.details) if row.details else {}
        if not isinstance(d, dict):
            d = {}
    except Exception:
        d = {}
    d["address"] = new_addr
    row.details = _j.dumps(d)
    db.commit()
    return {"ok": True}


@app.post("/api/al/payout-methods/{method_id}/delete")
def al_delete_payout_method(method_id: int, user: User = Depends(_al_user),
                            db: Session = Depends(get_db)):
    row = db.query(PayoutMethod).filter(PayoutMethod.id == method_id,
                                        PayoutMethod.user_id == user.id).first()
    if not row:
        return JSONResponse({"error": "Not found"}, status_code=404)
    was_default = bool(row.is_default)
    db.delete(row)
    db.flush()
    if was_default:
        nxt = db.query(PayoutMethod).filter(PayoutMethod.user_id == user.id).first()
        if nxt:
            nxt.is_default = True
    db.commit()
    remaining = db.query(PayoutMethod.id).filter(PayoutMethod.user_id == user.id).count()
    return {"ok": True, "remaining": remaining,
            "warning": None if remaining else "No payout method on file — sales will pass over you until you add one"}


