@app.get("/admin/api/al/secret-check")
def al_secret_check(secret: str = "", db: Session = Depends(get_db)):
    """Diagnose MIGRATION_SECRET mismatches WITHOUT revealing the secret:
    reports whether the env var is configured, both lengths, whitespace
    contamination, and whether the given value matches. Temporary
    bootstrap-debug tool — dies in the Phase 8 lockdown."""
    env = os.environ.get("MIGRATION_SECRET", "")
    out = {
        "env_configured": bool(env),
        "env_length": len(env),
        "env_has_leading_or_trailing_whitespace": env != env.strip(),
        "given_length": len(secret or ""),
        "match": bool(env) and secret == env,
        "match_after_strip": bool(env) and (secret or "").strip() == env.strip(),
    }
    if out["match"]:
        u1 = db.query(User).filter(User.id == 1).first()
        dupe = db.query(User.id).filter(User.username == "SuperAdPro").scalar()
        out["user_1"] = {"username": u1.username if u1 else None,
                         "first_name": u1.first_name if u1 else None}
        out["any_user_named_SuperAdPro"] = dupe
        from .database import USERNAME_AUDIT_LOG
        out["username_audit_memory"] = USERNAME_AUDIT_LOG[-5:]
        try:
            from sqlalchemy import text as _t
            rows = db.execute(_t(
                "SELECT id, at, user_id, from_name, to_name, source, LEFT(stack, 400) AS stack "
                "FROM al_username_audit ORDER BY id DESC LIMIT 12")).mappings().all()
            out["username_audit_db"] = [dict(r, at=str(r["at"])) for r in rows]
        except Exception as e:
            out["username_audit_db"] = f"unavailable: {e}"
    return out


@app.get("/admin/api/al/rename-user")
def al_rename_user(request: Request, secret: str = "", username: str = "", new_username: str = "",
                   apply: int = 0, db: Session = Depends(get_db)):
    """Bootstrap username rename (e.g. the brand account SuperAdPro ->
    AdvantageLife). Safe: genealogy + settlement reference user IDs, not
    names; the ref link simply becomes /ref/{new}. Dry-run default,
    &apply=1 to execute. MIGRATION_SECRET-gated; Phase 8 lockdown list."""
    _ms = os.environ.get("MIGRATION_SECRET", "")
    if not _ms or secret != _ms:
        # Temporary gate diagnostics (Phase 8 lockdown removes this whole
        # endpoint): lengths + param names only — never values.
        return JSONResponse({"error": "forbidden",
                             "given_secret_length": len(secret or ""),
                             "env_secret_length": len(_ms),
                             "params_received": sorted(request.query_params.keys())},
                            status_code=403)
    old_name = username.strip().lstrip("@")
    new_name = new_username.strip().lstrip("@")
    if not re.match(r"^[A-Za-z0-9_-]{3,30}$", new_name):
        return JSONResponse({"error": "new_username must be 3-30 chars: letters, numbers, _ or -"}, status_code=400)
    u = db.query(User).filter(User.username == old_name).first()
    if not u:
        return JSONResponse({"error": f"user '{old_name}' not found"}, status_code=404)
    clash = db.query(User).filter(User.username == new_name, User.id != u.id).first()
    if clash:
        return JSONResponse({"error": f"'{new_name}' is already taken (user {clash.id})"}, status_code=400)
    plan = {"user_id": u.id, "from": u.username, "to": new_name,
            "new_ref_link": f"https://www.advantagelife.club/ref/{new_name}",
            "note": "genealogy/settlement unaffected (ID-based); log in with the new username afterwards"}
    if not apply:
        return {"dry_run": True, **plan, "execute": "add &apply=1"}
    u.username = new_name
    db.commit()
    try:
        from sqlalchemy import text as _t
        db.execute(_t("INSERT INTO al_username_audit (user_id, from_name, to_name, source, stack) "
                      "VALUES (:u, :f, :tn, 'rename-endpoint', NULL)"),
                   {"u": u.id, "f": old_name, "tn": new_name})
        db.commit()
    except Exception:
        logger.exception("rename audit row failed")
    logger.info(f"AL rename: user {u.id} '{old_name}' -> '{new_name}'")
    return {"ok": True, **plan}


